import { GameClient } from '@features/canvas/components/GameClient';
import { WindowManagerProvider } from '@shared/components/FloatingWindow';
import { useEffect, useState } from 'react';
import { ToastContainer } from 'react-toastify';
// CSS is loaded via CDN or not needed in test environment
// import 'react-toastify/dist/ReactToastify.css';
import { ProtocolProvider } from '@app/providers';
import { authService, type UserInfo } from '@features/auth';
import { SessionSelector } from '@features/session/components/SessionSelector';
import { type SessionRole } from '@features/session/types/roles';
import { ErrorBoundary } from '@shared/components/ErrorBoundary';
import { logger } from '@shared/utils/logger';
import styles from './App.module.css';

interface AppState {
  isAuthenticated: boolean;
  userInfo: UserInfo | null;
  selectedSession: string | null;
  userRole: SessionRole | null;
  loading: boolean;
  error: string | null;
}

function App() {
  const [state, setState] = useState<AppState>({
    isAuthenticated: false,
    userInfo: null,
    selectedSession: null,
    userRole: null,
    loading: true,
    error: null
  });

  useEffect(() => {
    initializeAuth();
  }, []);

  const initializeAuth = async () => {
    try {
      console.log('App: Starting authentication initialization...');
      setState(prev => ({ ...prev, loading: true, error: null }));
      
      const isInitialized = await authService.initialize();
      console.log(`App: Authentication result: ${isInitialized}`);
      
      if (isInitialized) {
        const userInfo = authService.getUserInfo();
        console.log('App: User authenticated successfully:', userInfo);
        // If server injected initial data (page was rendered for a specific
        // game session), prefer that sessionCode so the client connects by code.
        // If the injected value is actually a session name (older behavior),
        // attempt to resolve it to the user's session_code by querying the server.
        const initData = (window as any).__INITIAL_DATA__;
        if (initData && initData.sessionCode) {
          logger.debug('App: Found server initial data, candidate:', initData.sessionCode);
          try {
            // Fetch user's sessions and try to match either by code or by name
            const sessions = await authService.getUserSessions();
            const byCode = sessions.find((s: any) => s.session_code === initData.sessionCode);
            const byName = sessions.find((s: any) => s.session_name === initData.sessionCode);
            const resolved = byCode ? byCode.session_code : (byName ? byName.session_code : null);
            if (resolved) {
              logger.debug('App: Resolved initial session to code:', resolved);
              setState(prev => ({
                ...prev,
                isAuthenticated: true,
                userInfo: userInfo || prev.userInfo,
                selectedSession: resolved,
                userRole: initData.userRole || prev.userRole,
                loading: false
              }));
              return;
            }
            // If resolution failed, fall back to using the injected value directly
            logger.warn('App: Could not resolve injected session value to a known session code; using value as-is');
          } catch (err) {
            logger.warn('Failed to resolve initial session against user sessions:', err);
          }
          setState(prev => ({
            ...prev,
            isAuthenticated: true,
            userInfo: userInfo || prev.userInfo,
            selectedSession: initData.sessionCode,
            userRole: initData.userRole || prev.userRole,
            loading: false
          }));
          return;
        }

        setState(prev => ({
          ...prev,
          isAuthenticated: true,
          userInfo,
          loading: false
        }));
      } else {
        // No authentication token found - redirect to server login using relative URL
        console.log('App: Authentication failed, redirecting to login...');
        window.location.href = '/users/login';
      }
    } catch (error) {
      console.error('App: Authentication initialization failed:', error);
      setState(prev => ({
        ...prev,
        error: 'Authentication failed. Please try again.',
        loading: false
      }));
    }
  };

  const handleSessionSelected = (sessionCode: string, role: SessionRole) => {
    setState(prev => ({
      ...prev,
      selectedSession: sessionCode,
      userRole: role
    }));
  };

  const handleAuthError = () => {
    setState(prev => ({
      ...prev,
      error: 'Authentication expired. Please login again.',
      isAuthenticated: false,
      userInfo: null
    }));
    
    setTimeout(() => {
      authService.logout();
    }, 2000);
  };

  if (state.loading) {
    return (
      <div className={`${styles.app} ${styles.loadingScreen}`}>
        <div className={styles.loadingContent}>
          <div className={styles.spinner}></div>
          <h2>Loading TTRPG System</h2>
          <p>Initializing authentication...</p>
        </div>
      </div>
    );
  }

  if (state.error) {
    return (
      <div className={`${styles.app} ${styles.errorScreen}`}>
        <div className={styles.errorContent}>
          <h2>Authentication Error</h2>
          <p>{state.error}</p>
        </div>
      </div>
    );
  }

  if (!state.isAuthenticated || !state.userInfo) {
    return (
      <div className={`${styles.app} ${styles.errorScreen}`}>
        <div className={styles.errorContent}>
          <h2>Not Authenticated</h2>
          <p>Redirecting to login...</p>
        </div>
      </div>
    );
  }

  if (!state.selectedSession) {
    return (
      <ErrorBoundary>
        <div className={styles.app}>
          <SessionSelector onSessionSelected={handleSessionSelected} />
        </div>
      </ErrorBoundary>
    );
  }

  return (
    <ErrorBoundary>
      <WindowManagerProvider>
        <div className={styles.app}>
          <ProtocolProvider sessionCode={state.selectedSession}>
            <GameClient 
              sessionCode={state.selectedSession}
              userInfo={state.userInfo}
              userRole={state.userRole!}
              onAuthError={handleAuthError}
            />
          </ProtocolProvider>
          <ToastContainer theme="dark" />
        </div>
      </WindowManagerProvider>
    </ErrorBoundary>
  );
}

export default App

import { useGameStore } from '@/store';
import { AssetPanel, BackgroundManagementPanel } from '@features/assets';
import { CharacterPanel } from '@features/character';
import { ChatPanel } from '@features/chat';
import { InitiativeTracker } from '@features/combat';
import { CompendiumPanel } from '@features/compendium';
import { FogPanel } from '@features/fog';
import { LightingPanel } from '@features/lighting';
import { type SessionRole, canInteract, isDM, isElevated } from '@features/session/types/roles';
import { MapPanel, TableManagementPanel, TablePanel, TableSyncPanel } from '@features/table';
import clsx from 'clsx';
import { useEffect, useState } from 'react';
import { ActionQueuePanel } from '../features/actions/components/ActionQueuePanel';
import { ActionsPanel } from '../features/actions/components/ActionsPanel';
import { ActionsQuickPanel } from '../features/actions/components/ActionsQuickPanel';
import { EntitiesPanel } from '../features/canvas/components/EntitiesPanel';
import PerformanceSettingsPanel from '../features/canvas/components/PerformanceSettingsPanel';
import { CustomizePanel } from '../features/character/components/CustomizePanel';
import { NetworkPanel } from '../features/network/components/NetworkPanel';
import { PlayerManagerPanel } from '../features/network/components/PlayerManagerPanel';
import styles from './RightPanel.module.css';

const isDevelopment = import.meta.env.DEV;

type TabId = 'tables' | 'table-tools' | 'characters' | 'entities' | 'chat' | 'lighting' | 'fog' |
             'sync' | 'players' | 'actions' | 'quick-actions' | 'queue' | 'compendium' | 'assets' |
             'network' | 'initiative' | 'performance' | 'backgrounds' | 'customize' | 'map';

const TAB_VISIBLE: Record<TabId, (role: SessionRole) => boolean> = {
  // DM tabs
  'tables':        isDM,
  'quick-actions': isDM,
  'players':       isDM,
  'lighting':      isDM,
  'fog':           isDM,
  'backgrounds':   isDM,
  'performance':   isDM,
  // Elevated tabs
  'compendium':    isElevated,
  // Interactive tabs (everyone except spectator)
  'characters':    canInteract,
  'chat':          canInteract,
  // All interactive roles
  'entities':      () => true,
  'initiative':    () => true,
  'customize':     () => true,
  // Map panel
  'map':           isDM,
  // Dev-only (always gated by isDevelopment at render time)
  'table-tools':   isDM,
  'sync':          isDM,
  'actions':       isDM,
  'queue':         isDM,
  'assets':        isDM,
  'network':       isDM,
};

const DEFAULT_TAB_ORDER: TabId[] = [
  'tables', 'compendium', 'quick-actions', 'characters', 'entities',
  'players', 'initiative', 'chat', 'lighting', 'fog',
  'backgrounds', 'map', 'performance', 'customize',
];

export function RightPanel(props: { sessionCode?: string; userInfo?: any; userRole?: string }) {
  const [activeTab, setActiveTab] = useState<TabId>('entities');
  const sessionRole = (useGameStore(s => s.sessionRole) ?? props.userRole ?? 'player') as SessionRole;

  const isVisible = (tab: TabId) => TAB_VISIBLE[tab]?.(sessionRole) ?? false;

  // If current tab becomes hidden, switch to first visible tab
  useEffect(() => {
    if (!isVisible(activeTab)) {
      const first = DEFAULT_TAB_ORDER.find(t => isVisible(t));
      if (first) setActiveTab(first);
    }
  }, [sessionRole]);

  const tab = (id: TabId, label: string) => {
    if (!isVisible(id)) return null;
    return (
      <button
        key={id}
        role="tab"
        aria-selected={activeTab === id}
        className={clsx(styles.tabButton, activeTab === id && 'active')}
        onClick={() => setActiveTab(id)}
      >
        {label}
      </button>
    );
  };

  return (
    <div className={styles.rightPanelContainer}>
      <div className={styles.tabsContainer} role="tablist" aria-label="Panel navigation">
        {tab('compendium', 'Compendium')}
        {tab('tables', 'Tables')}
        {tab('quick-actions', 'Quick Actions')}
        {tab('characters', 'Characters')}
        {tab('players', 'Players')}
        {tab('initiative', 'Initiative')}
        {tab('entities', 'Entities')}
        {tab('chat', 'Chat')}
        {tab('lighting', 'Lighting')}
        {tab('fog', 'Fog')}
        {tab('backgrounds', 'Backgrounds')}
        {tab('performance', 'Performance')}
        {tab('customize', 'Customize')}
        {tab('map', 'Map')}
        {isDevelopment && tab('table-tools', 'Table Tools')}
        {isDevelopment && tab('sync', 'Sync')}
        {isDevelopment && tab('actions', 'Actions')}
        {isDevelopment && tab('queue', 'Queue')}
        {isDevelopment && tab('assets', 'Assets')}
        {isDevelopment && tab('network', 'Network')}
      </div>
      <div className={styles.tabContent} role="tabpanel" aria-label={`${activeTab} panel`}>
        {activeTab === 'tables' && <TableManagementPanel />}
        {activeTab === 'quick-actions' && <ActionsQuickPanel renderEngine={window.rustRenderManager as any || null} />}
        {isDevelopment && activeTab === 'table-tools' && <TablePanel />}
        {isDevelopment && activeTab === 'sync' && <TableSyncPanel />}
        {activeTab === 'characters' && <CharacterPanel />}
        {activeTab === 'players' && <PlayerManagerPanel sessionCode={props.sessionCode!} userInfo={{...props.userInfo, role: sessionRole}} />}
        {activeTab === 'initiative' && <InitiativeTracker sessionCode={props.sessionCode!} userInfo={{...props.userInfo, role: sessionRole}} />}
        {isDevelopment && activeTab === 'actions' && <ActionsPanel renderEngine={window.rustRenderManager as any || null} />}
        {isDevelopment && activeTab === 'queue' && <ActionQueuePanel sessionCode={props.sessionCode!} userInfo={props.userInfo!} />}
        {activeTab === 'entities' && <EntitiesPanel />}
        {activeTab === 'chat' && <ChatPanel />}
        {activeTab === 'lighting' && <LightingPanel />}
        {activeTab === 'fog' && <FogPanel />}
        {activeTab === 'backgrounds' && <BackgroundManagementPanel isOpen={true} onClose={() => setActiveTab('entities')} renderEngine={window.rustRenderManager as any || null} />}
        {activeTab === 'performance' && <PerformanceSettingsPanel isVisible={true} onClose={() => setActiveTab('entities')} />}
        {activeTab === 'customize' && <CustomizePanel />}
        {activeTab === 'compendium' && <CompendiumPanel />}
        {isDevelopment && activeTab === 'assets' && <AssetPanel />}
        {isDevelopment && activeTab === 'network' && <NetworkPanel />}
        {activeTab === 'map' && <MapPanel />}
      </div>
    </div>
  );
}

import { authService, type UserInfo } from '@features/auth/services/auth.service';
import React, { createContext, useContext, useEffect, useState } from 'react';

type Permission = string;

interface AuthContextType {
  user: UserInfo | null;
  isAuthenticated: boolean;
  permissions: Permission[];
  login: (username: string, password: string) => Promise<boolean>;
  logout: () => void;
  loading: boolean;
  error: string;
  hasPermission: (permission: string) => boolean;
  requireAuth: <T>(operation: () => T) => T;
  updateUser: (userData: Partial<UserInfo>) => void;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<UserInfo | null>(null);
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  // Derive permissions from user data
  const permissions: Permission[] = user?.permissions || [];

  // Check if user has a specific permission
  const hasPermission = (permission: string): boolean => {
    if (!isAuthenticated || !user) return false;
    return permissions.includes(permission);
  };

  // Require authentication for an operation
  const requireAuth = <T,>(operation: () => T): T => {
    if (!isAuthenticated) {
      throw new Error('Authentication required for this operation');
    }
    return operation();
  };

  // Update user data
  const updateUser = (userData: Partial<UserInfo>) => {
    if (user) {
      const updatedUser = { ...user, ...userData };
      setUser(updatedUser);
      // Note: authService.updateUserInfo would need to be implemented if needed
    }
  };

  useEffect(() => {
    authService.initialize().then(() => {
      setUser(authService.getUserInfo());
      setIsAuthenticated(authService.isAuthenticated());
      setLoading(false);
    });
  }, []);

  const login = async (username: string, password: string) => {
    setLoading(true);
    setError('');
    try {
      // Call FastAPI login endpoint
      const response = await fetch('/users/login', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: new URLSearchParams({
          username,
          password
        }),
        credentials: 'include'
      });

      if (response.ok) {
        // Re-initialize auth service to get user info from cookie
        await authService.initialize();
        setUser(authService.getUserInfo());
        setIsAuthenticated(authService.isAuthenticated());
        setLoading(false);
        return true;
      } else {
        const errorText = await response.text();
        // Parse HTML error or use generic message
        const errorMatch = errorText.match(/error["']: ["']([^"']+)["']/i);
        const errorMessage = errorMatch ? errorMatch[1] : 'Login failed';
        setError(errorMessage);
        setLoading(false);
        return false;
      }
    } catch (e: any) {
      setError(e.message || 'Login failed');
      setLoading(false);
      setIsAuthenticated(false);
      return false;
    }
  };

  const logout = () => {
    authService.logout();
    setUser(null);
    setIsAuthenticated(false);
  };

  return (
    <AuthContext.Provider value={{ 
      user, 
      isAuthenticated, 
      permissions,
      login, 
      logout, 
      loading, 
      error,
      hasPermission,
      requireAuth,
      updateUser
    }}>
      {children}
    </AuthContext.Provider>
  );
};

// eslint-disable-next-line react-refresh/only-export-components
export { AuthContext };
// eslint-disable-next-line react-refresh/only-export-components
export const useAuth = () => {
  const ctx = useContext(AuthContext);
  if (!ctx) throw new Error('useAuth must be used within AuthProvider');
  return ctx;
};

import { authService } from '@features/auth';
import { ProtocolService } from '@lib/api/ProtocolService';
import { WebClientProtocol } from '@lib/websocket';
import React, { createContext, useContext, useEffect, useMemo, useState } from 'react';

interface ProtocolContextValue {
  protocol: WebClientProtocol | null;
  connectionState: 'disconnected' | 'connecting' | 'connected' | 'error';
  isConnected: boolean;
  connect: () => Promise<void>;
  disconnect: () => void;
}

const ProtocolContext = createContext<ProtocolContextValue | undefined>(undefined);

// eslint-disable-next-line react-refresh/only-export-components
export { ProtocolContext };

// eslint-disable-next-line react-refresh/only-export-components
export function useProtocol() {
  const ctx = useContext(ProtocolContext);
  if (!ctx && (globalThis as any).__VITEST__) {
    return {
      protocol: null,
      connectionState: 'disconnected' as const,
      isConnected: false,
      connect: async () => {},
      disconnect: () => {}
    } as ProtocolContextValue;
  }
  if (!ctx) throw new Error('useProtocol must be used within ProtocolProvider');
  return ctx;
}

interface ProviderProps {
  sessionCode: string;
  children: React.ReactNode;
}

export function ProtocolProvider({ sessionCode, children }: ProviderProps) {
  const [protocol, setProtocol] = useState<WebClientProtocol | null>(null);
  const [connectionState, setConnectionState] = useState<'disconnected' | 'connecting' | 'connected' | 'error'>('disconnected');

  useEffect(() => {
    let mounted = true;
    
    async function init() {
      setConnectionState('connecting');
      
      try {
        let resolved = sessionCode;
        let userId: number | undefined;
        
        try {
          const sessions = await authService.getUserSessions();
          const byCode = sessions.find((s: any) => s.session_code === sessionCode);
          const byName = sessions.find((s: any) => s.session_name === sessionCode);
          if (byCode) resolved = byCode.session_code;
          else if (byName) resolved = byName.session_code;
          
          const userInfo = authService.getUserInfo();
          if (userInfo?.id) userId = userInfo.id;
        } catch (e) {
          console.warn('[ProtocolProvider] Failed to resolve session', e);
        }

        const p = new WebClientProtocol(resolved, userId);
        if (!mounted) return;
        
        ProtocolService.setProtocol(p);
        setProtocol(p);
        
        await p.connect();
        if (!mounted) return;
        setConnectionState('connected');
      } catch (err) {
        console.error('[ProtocolProvider] Connection failed', err);
        setConnectionState('error');
      }
    }

    init();
    
    return () => {
      mounted = false;
      if (protocol) {
        protocol.disconnect();
      }
      ProtocolService.clearProtocol();
      setProtocol(null);
      setConnectionState('disconnected');
    };
  }, [sessionCode]);

  const value = useMemo(() => ({
    protocol,
    connectionState,
    isConnected: connectionState === 'connected',
    connect: async () => {
      if (!protocol) return;
      setConnectionState('connecting');
      await protocol.connect();
      setConnectionState('connected');
    },
    disconnect: () => {
      if (!protocol) return;
      protocol.disconnect();
      setConnectionState('disconnected');
    }
  }), [protocol, connectionState]);

  return (
    <ProtocolContext.Provider value={value}>
      {children}
    </ProtocolContext.Provider>
  );
}

import type { RenderEngine } from '@lib/wasm';
import { useActions, type ActionResult, type BatchAction, type TableInfo } from '@shared/hooks';
import panelStyles from '@shared/styles/PanelBase.module.css';
import clsx from 'clsx';
import { Loader2, Redo2, Undo2, X } from 'lucide-react';
import React, { useCallback, useState } from 'react';
import styles from './ActionsPanel.module.css';

interface ActionsPanelProps {
  renderEngine: RenderEngine | null;
  className?: string;
}

export const ActionsPanel: React.FC<ActionsPanelProps> = ({ renderEngine, className = '' }) => {
  const [activeTab, setActiveTab] = useState<'tables' | 'layers' | 'history'>('tables');
  const [selectedTable, setSelectedTable] = useState<string>('');
  const [logs, setLogs] = useState<string[]>([]);

  const actions = useActions(renderEngine, {
    onAction: (actionType, data) => {
      setLogs(prev => [...prev.slice(-19), `Action: ${actionType} - ${JSON.stringify(data)}`]);
    },
    onStateChange: (eventType, targetId) => {
      setLogs(prev => [...prev.slice(-19), `State Change: ${eventType} - ${targetId}`]);
    },
    onError: (error) => {
      setLogs(prev => [...prev.slice(-19), `Error: ${error}`]);
    },
  });

  // Form states
  const [tableForm, setTableForm] = useState({ name: '', width: 800, height: 600 });

  const logResult = useCallback((operation: string, result: ActionResult) => {
    const status = result.success ? 'OK' : 'Error';
    setLogs(prev => [...prev.slice(-19), `${status} ${operation}: ${result.message}`]);
  }, []);

  // Table Operations
  const handleCreateTable = useCallback(async () => {
    if (!tableForm.name.trim()) return;
    
    try {
      const result = await actions.createTable(tableForm.name, tableForm.width, tableForm.height);
      logResult('Create Table', result);
      if (result.success) {
        setTableForm({ name: '', width: 800, height: 600 });
      }
    } catch (error) {
      console.error('Failed to create table:', error);
    }
  }, [actions, tableForm, logResult]);

  const handleDeleteTable = useCallback(async (tableId: string) => {
    try {
      const result = await actions.deleteTable(tableId);
      logResult('Delete Table', result);
      if (result.success && selectedTable === tableId) {
        setSelectedTable('');
      }
    } catch (error) {
      console.error('Failed to delete table:', error);
    }
  }, [actions, selectedTable, logResult]);

  const handleUpdateTable = useCallback(async (tableId: string, updates: Partial<TableInfo>) => {
    try {
      const result = await actions.updateTable(tableId, updates);
      logResult('Update Table', result);
    } catch (error) {
      console.error('Failed to update table:', error);
    }
  }, [actions, logResult]);

  // Layer Operations
  const handleToggleLayerVisibility = useCallback(async (layer: string) => {
    const currentVisibility = actions.layerVisibility.get(layer) ?? true;
    try {
      const result = await actions.setLayerVisibility(layer, !currentVisibility);
      logResult(`Toggle Layer ${layer}`, result);
    } catch (error) {
      console.error('Failed to toggle layer visibility:', error);
    }
  }, [actions, logResult]);

  // Batch Operations
  const handleBatchTest = useCallback(async () => {
    const batchActions: BatchAction[] = [
      {
        type: 'create_table',
        params: { name: 'Batch Table 1', width: 400, height: 400 }
      },
      {
        type: 'create_table', 
        params: { name: 'Batch Table 2', width: 600, height: 600 }
      }
    ];
    
    try {
      const result = await actions.batchActions(batchActions);
      logResult('Batch Actions', result);
    } catch (error) {
      console.error('Failed to execute batch actions:', error);
    }
  }, [actions, logResult]);

  const renderTabContent = () => {
    switch (activeTab) {
      case 'tables':
        return (
          <div className={styles.actionsTabContent}>
            <div className={styles.actionsForm}>
              <h4>Create Table</h4>
              <div className={styles.formRow}>
                <input
                  type="text"
                  placeholder="Table name"
                  value={tableForm.name}
                  onChange={(e) => setTableForm(prev => ({ ...prev, name: e.target.value }))}
                />
              </div>
              <div className={styles.formRow}>
                <input
                  type="number"
                  placeholder="Width"
                  value={tableForm.width}
                  onChange={(e) => setTableForm(prev => ({ ...prev, width: parseInt(e.target.value) || 800 }))}
                />
                <input
                  type="number"
                  placeholder="Height"
                  value={tableForm.height}
                  onChange={(e) => setTableForm(prev => ({ ...prev, height: parseInt(e.target.value) || 600 }))}
                />
              </div>
              <button 
                onClick={handleCreateTable}
                disabled={!tableForm.name.trim() || actions.isLoading}
                className={clsx(styles.actionButton, styles.primary)}
              >
                Create Table
              </button>
            </div>

            <div className={styles.actionsList}>
              <h4>Tables ({actions.tables.size})</h4>
              {Array.from(actions.tables.values()).map(table => (
                <div key={table.table_id} className={clsx(styles.listItem, selectedTable === table.table_id && styles.selected)}>
                  <div className={styles.itemInfo} onClick={() => setSelectedTable(table.table_id)}>
                    <strong>{table.name}</strong>
                    <span>{table.width}x{table.height}</span>
                  </div>
                  <div className={styles.itemActions}>
                    <button 
                      onClick={() => handleUpdateTable(table.table_id, { scale_x: 1.5, scale_y: 1.5 })}
                      className={clsx(styles.actionButton, styles.small)}
                    >
                      Scale
                    </button>
                    <button 
                      onClick={() => handleDeleteTable(table.table_id)}
                      className={clsx(styles.actionButton, styles.small, styles.danger)}
                    >
                      Delete
                    </button>
                  </div>
                </div>
              ))}
            </div>
          </div>
        );

      case 'layers':
        return (
          <div className={styles.actionsTabContent}>
            <h4>Layer Visibility</h4>
            <div className={styles.layerControls}>
              {Array.from(actions.layerVisibility.entries()).map(([layer, visible]) => (
                <div key={layer} className={styles.layerItem}>
                  <label className={styles.layerToggle}>
                    <input
                      type="checkbox"
                      checked={visible}
                      onChange={() => handleToggleLayerVisibility(layer)}
                    />
                    <span className={styles.layerName}>{layer.replace('_', ' ')}</span>
                  </label>
                  <span className={styles.spriteCount}>
                    ({Array.from(actions.sprites.values()).filter(s => s.layer === layer).length})
                  </span>
                </div>
              ))}
            </div>
          </div>
        );

      case 'history':
        return (
          <div className={styles.actionsTabContent}>
            <div className={styles.historyControls}>
              <button 
                onClick={actions.undo}
                disabled={!actions.canUndo || actions.isLoading}
                className={styles.actionButton}
              >
                <Undo2 size={14} aria-hidden /> Undo
              </button>
              <button 
                onClick={actions.redo}
                disabled={!actions.canRedo || actions.isLoading}
                className={styles.actionButton}
              >
                <Redo2 size={14} aria-hidden /> Redo
              </button>
              <button 
                onClick={handleBatchTest}
                disabled={actions.isLoading}
                className={styles.actionButton}
              >
                Batch Test
              </button>
              <button 
                onClick={actions.refreshState}
                className={styles.actionButton}
              >
                Refresh
              </button>
            </div>
            
            <h4>Action History ({actions.actionHistory.length})</h4>
            <div className={styles.historyList}>
              {actions.actionHistory.slice(-10).reverse().map((entry, index) => (
                <div key={index} className={styles.historyItem}>
                  <div className={styles.historyType}>{entry.action_type}</div>
                  <div className={styles.historyTime}>
                    {new Date(entry.timestamp).toLocaleTimeString()}
                  </div>
                  {entry.reversible && <span className={styles.historyReversible}><Undo2 size={12} aria-hidden /></span>}
                </div>
              ))}
            </div>
          </div>
        );

      default:
        return null;
    }
  };

  return (
    <div className={clsx(styles.actionsPanel, className)}>
      <div className={styles.panelHeader}>
        <h3>Actions System</h3>
        {actions.isLoading && <div className={styles.loadingIndicator}><Loader2 size={14} className={panelStyles.spinning} aria-hidden /></div>}
        {actions.error && (
          <div className={styles.errorMessage}>
            {actions.error}
            <button onClick={actions.clearError} className={styles.clearError}><X size={12} aria-hidden /></button>
          </div>
        )}
      </div>

      <div className={styles.panelTabs}>
        {['tables', 'layers', 'history'].map(tab => (
          <button
            key={tab}
            onClick={() => setActiveTab(tab as any)}
            className={clsx(styles.tabButton, activeTab === tab && styles.active)}
          >
            {tab.charAt(0).toUpperCase() + tab.slice(1)}
          </button>
        ))}
      </div>

      <div className={styles.panelContent}>
        {renderTabContent()}
      </div>

      <div className={styles.panelFooter}>
        <div className={styles.actionLogs}>
          <h4>Recent Logs</h4>
          <div className={styles.logsContainer}>
            {logs.slice(-5).map((log, index) => (
              <div key={index} className={styles.logEntry}>
                {log}
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

import type { RenderEngine } from '@lib/wasm';
import { useActions } from '@shared/hooks';
import { Redo2, Undo2 } from 'lucide-react';
import React, { useCallback, useState } from 'react';

interface ActionsQuickPanelProps {
  renderEngine?: RenderEngine | null;
}

export const ActionsQuickPanel: React.FC<ActionsQuickPanelProps> = ({ renderEngine }) => {
  const [tableName, setTableName] = useState('');
  const [tableWidth, setTableWidth] = useState(800);
  const [tableHeight, setTableHeight] = useState(600);

  const actions = useActions(renderEngine || (window as any).rustRenderManager, {
    onAction: (actionType, data) => {
      console.log(`Action: ${actionType}`, data);
    },
    onStateChange: (eventType, targetId) => {
      console.log(`State Change: ${eventType}`, targetId);
    },
    onError: (error) => {
      console.error('Actions Error:', error);
    },
  });

  const handleCreateTable = useCallback(async () => {
    if (!tableName.trim()) {
      alert('Please enter a table name');
      return;
    }
    
    try {
      const result = await actions.createTable(tableName, tableWidth, tableHeight);
      if (result.success) {
        setTableName('');
        alert(`Table "${tableName}" created successfully!`);
      } else {
        alert(`Failed to create table: ${result.message}`);
      }
    } catch (error) {
      console.error('Failed to create table:', error);
      alert('Failed to create table');
    }
  }, [actions, tableName, tableWidth, tableHeight]);

  const handleDeleteSelectedTable = useCallback(async () => {
    const tables = Array.from(actions.tables.values());
    if (tables.length === 0) {
      alert('No tables to delete');
      return;
    }

    // For simplicity, delete the first table
    const table = tables[0];
    if (confirm(`Delete table "${table.name}"?`)) {
      try {
        const result = await actions.deleteTable(table.table_id);
        if (result.success) {
          alert(`Table "${table.name}" deleted successfully!`);
        } else {
          alert(`Failed to delete table: ${result.message}`);
        }
      } catch (error) {
        console.error('Failed to delete table:', error);
        alert('Failed to delete table');
      }
    }
  }, [actions]);

  const handleUndo = useCallback(() => {
    actions.undo();
  }, [actions]);

  const handleRedo = useCallback(() => {
    actions.redo();
  }, [actions]);

  const handleRefreshState = useCallback(() => {
    actions.refreshState();
  }, [actions]);

  return (
    <div className="game-panel">
      <div className="panel-header-compact">
        <h3 className="panel-title">Quick Actions</h3>
      </div>

      <div className="actions-quick-content">
        {/* Table Creation */}
        <div className="action-group">
          <h4>Create Table</h4>
          <div className="form-compact">
            <input
              type="text"
              placeholder="Table name"
              value={tableName}
              onChange={(e) => setTableName(e.target.value)}
              style={{ width: '100%', marginBottom: '4px', padding: '4px', fontSize: '12px' }}
            />
            <div style={{ display: 'flex', gap: '4px', marginBottom: '4px' }}>
              <input
                type="number"
                placeholder="Width"
                value={tableWidth}
                onChange={(e) => setTableWidth(parseInt(e.target.value) || 800)}
                style={{ flex: 1, padding: '4px', fontSize: '12px' }}
              />
              <input
                type="number"
                placeholder="Height"
                value={tableHeight}
                onChange={(e) => setTableHeight(parseInt(e.target.value) || 600)}
                style={{ flex: 1, padding: '4px', fontSize: '12px' }}
              />
            </div>
            <button 
              onClick={handleCreateTable}
              disabled={!tableName.trim() || actions.isLoading}
              style={{ 
                width: '100%', 
                padding: '6px', 
                fontSize: '12px',
                background: 'var(--color-success)',
                color: 'white',
                border: 'none',
                borderRadius: '4px',
                cursor: 'pointer'
              }}
            >
              Create Table
            </button>
          </div>
        </div>

        {/* Quick Actions */}
        <div className="action-group">
          <h4>Table Actions</h4>
          <div className="button-grid">
            <button 
              onClick={handleDeleteSelectedTable}
              disabled={actions.tables.size === 0 || actions.isLoading}
              style={{ 
                padding: '6px 8px', 
                fontSize: '11px',
                background: 'var(--color-danger)',
                color: 'white',
                border: 'none',
                borderRadius: '3px',
                cursor: 'pointer'
              }}
            >
              Delete Table
            </button>
            <button 
              onClick={handleRefreshState}
              disabled={actions.isLoading}
              style={{ 
                padding: '6px 8px', 
                fontSize: '11px',
                background: 'var(--color-accent)',
                color: 'white',
                border: 'none',
                borderRadius: '3px',
                cursor: 'pointer'
              }}
            >
              Refresh
            </button>
          </div>
        </div>

        {/* History Actions */}
        <div className="action-group">
          <h4>History</h4>
          <div className="button-grid">
            <button 
              onClick={handleUndo}
              disabled={!actions.canUndo || actions.isLoading}
              style={{ 
                padding: '6px 8px', 
                fontSize: '11px',
                background: 'var(--color-warning)',
                color: 'white',
                border: 'none',
                borderRadius: '3px',
                cursor: 'pointer'
              }}
            >
              <Undo2 size={14} aria-hidden /> Undo
            </button>
            <button 
              onClick={handleRedo}
              disabled={!actions.canRedo || actions.isLoading}
              style={{ 
                padding: '6px 8px', 
                fontSize: '11px',
                background: 'var(--color-warning)',
                color: 'white',
                border: 'none',
                borderRadius: '3px',
                cursor: 'pointer'
              }}
            >
              <Redo2 size={14} aria-hidden /> Redo
            </button>
          </div>
        </div>

        {/* Status */}
        <div className="action-status">
          <div style={{ fontSize: '11px', color: 'var(--text-muted)' }}>
            Tables: {actions.tables.size} | History: {actions.actionHistory.length}
            {actions.isLoading && <span> | Loading...</span>}
          </div>
          {actions.error && (
            <div style={{ fontSize: '11px', color: 'var(--color-danger)', marginTop: '4px' }}>
              Error: {actions.error}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

/**
 * Asset Management and Performance System Behavior Tests
 * Tests real asset loading, caching, optimization, and performance monitoring
 * Focus: Real expected behavior for efficient TTRPG asset management
 */
// @ts-nocheck
import { fireEvent, render, screen, waitFor } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import React from 'react';
import { describe, expect, it } from 'vitest';

describe('Asset Management System - Performance and Caching', () => {
  const mockUserInfo = { 
    id: 'dm1', 
    username: 'DM Mike', 
    role: 'dm' as const,
    permissions: ['upload_assets', 'manage_assets', 'optimize_assets'] 
  };

  describe('Asset Upload and Processing Pipeline', () => {
    it('should handle large image uploads with progress tracking', async () => {
      const user = userEvent.setup();
      
      // Functional file upload component with real behavior
      const FileUploadComponent = () => {
        const [uploadStatus, setUploadStatus] = React.useState('Ready');
        const [uploadProgress, setUploadProgress] = React.useState(0);
        const [isUploading, setIsUploading] = React.useState(false);
        
        const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
          const file = event.target.files?.[0];
          if (!file) return;
          
          setIsUploading(true);
          setUploadStatus('Uploading...');
          setUploadProgress(0);
          
          // Simulate upload progress
          for (let i = 0; i <= 100; i += 20) {
            await new Promise(resolve => setTimeout(resolve, 50));
            setUploadProgress(i);
          }
          
          setUploadStatus('Processing...');
          await new Promise(resolve => setTimeout(resolve, 100));
          
          setUploadStatus('Complete');
          setIsUploading(false);
        };
        
        return (
          <div data-testid="asset-upload">
            <input 
              type="file" 
              accept="image/*" 
              aria-label="Upload Image"
              onChange={handleFileUpload}
            />
            <div 
              data-testid="upload-progress" 
              style={{ display: isUploading ? 'block' : 'none' }}
            >
              {uploadProgress}%
            </div>
            <div data-testid="upload-status">{uploadStatus}</div>
            {uploadStatus === 'Processing...' && (
              <>
                <div>Generating thumbnails</div>
                <div>Optimizing for web</div>
              </>
            )}
            {uploadStatus === 'Complete' && (
              <div>dragon_battlemap.jpg uploaded successfully</div>
            )}
          </div>
        );
      };
      
      render(<FileUploadComponent />);
      
      // Create mock large image file (10MB)
      const largeImageFile = new File(
        [new ArrayBuffer(10 * 1024 * 1024)], // 10MB
        'dragon_battlemap.jpg',
        { type: 'image/jpeg' }
      );
      
      const fileInput = screen.getByLabelText(/upload image/i);
      
      // Upload file
      await user.upload(fileInput, largeImageFile);
      
      // Should show upload progress
      await waitFor(() => {
        expect(screen.getByTestId('upload-status')).toHaveTextContent('Uploading...');
        expect(screen.getByTestId('upload-progress')).toBeVisible();
      });
      
      // Simulate upload progress updates
      const progressElement = screen.getByTestId('upload-progress');
      
      // Should track progress from 0% to 100%
      await waitFor(() => {
        expect(progressElement).toHaveTextContent(/\d+%/);
      });
      
      // Should process image after upload
      await waitFor(() => {
        expect(screen.getByTestId('upload-status')).toHaveTextContent('Processing...');
      });
      
      // Should generate thumbnails and optimized versions
      await waitFor(() => {
        expect(screen.getByText(/generating thumbnails/i)).toBeInTheDocument();
        expect(screen.getByText(/optimizing for web/i)).toBeInTheDocument();
      });
      
      // Should complete successfully
      await waitFor(() => {
        expect(screen.getByTestId('upload-status')).toHaveTextContent('Complete');
        expect(screen.getByText(/dragon_battlemap.jpg uploaded successfully/i)).toBeInTheDocument();
      });
    });

    it('should validate file types and enforce size limits', async () => {
      const user = userEvent.setup();
      
      // Functional validation component
      const FileValidationComponent = () => {
        const [uploadError, setUploadError] = React.useState('');
        
        const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
          const file = event.target.files?.[0];
          if (!file) return;
          
          setUploadError('');
          
          // Validate file type
          if (!file.type.startsWith('image/')) {
            setUploadError('Invalid file type. Only images are allowed.');
            return;
          }
          
          // Validate file size (50MB limit)
          if (file.size > 50 * 1024 * 1024) {
            setUploadError('File size exceeds 50MB limit.');
            return;
          }
          
          // Simulate corrupted file detection for test files with simple text content
          if (file.type.includes('image') && file.size < 1000) {
            setUploadError('Invalid or corrupted image file.');
            return;
          }
        };
        
        return (
          <div data-testid="asset-upload">
            <input 
              type="file" 
              accept="image/*" 
              aria-label="Upload Image"
              onChange={handleFileUpload}
            />
            <div data-testid="upload-errors">{uploadError}</div>
          </div>
        );
      };
      
      render(<FileValidationComponent />);
      
      // Try to upload unsupported file type
      const textFile = new File(['Hello world'], 'document.txt', { type: 'text/plain' });
      const fileInput = screen.getByLabelText(/upload image/i);
      
      fireEvent.change(fileInput, { target: { files: [textFile] } });
      
      await waitFor(() => {
        expect(screen.getByTestId('upload-errors')).toHaveTextContent('Invalid file type. Only images are allowed.');
      });
      
      // Try to upload file that's too large (over 50MB limit)
      const oversizedFile = new File(
        [new ArrayBuffer(60 * 1024 * 1024)], // 60MB
        'huge_image.png',
        { type: 'image/png' }
      );
      
      fireEvent.change(fileInput, { target: { files: [oversizedFile] } });
      
      await waitFor(() => {
        expect(screen.getByTestId('upload-errors')).toHaveTextContent('File size exceeds 50MB limit.');
      });
      
      // Try to upload corrupted image
      const corruptedFile = new File(['corrupted data'], 'broken.jpg', { type: 'image/jpeg' });
      
      fireEvent.change(fileInput, { target: { files: [corruptedFile] } });
      
      await waitFor(() => {
        expect(screen.getByTestId('upload-errors')).toHaveTextContent('Invalid or corrupted image file.');
      });
    });

    it('should batch process multiple asset uploads efficiently', async () => {
      const user = userEvent.setup();
      
      // Functional batch upload component
      const BatchUploadComponent = () => {
        const [filesTotal, setFilesTotal] = React.useState(0);
        const [filesProcessed, setFilesProcessed] = React.useState(0);
        const [overallProgress, setOverallProgress] = React.useState(0);
        const [uploadComplete, setUploadComplete] = React.useState(false);
        
        const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
          const files = event.target.files;
          if (!files || files.length === 0) return;
          
          setFilesTotal(files.length);
          setFilesProcessed(0);
          setOverallProgress(0);
          setUploadComplete(false);
          
          // Process files sequentially
          for (let i = 0; i < files.length; i++) {
            await new Promise(resolve => setTimeout(resolve, 100));
            setFilesProcessed(i + 1);
            setOverallProgress(Math.round(((i + 1) / files.length) * 100));
          }
          
          setUploadComplete(true);
        };
        
        return (
          <div data-testid="batch-upload">
            <input 
              type="file" 
              multiple 
              accept="image/*" 
              aria-label="Upload Multiple Images"
              onChange={handleFileUpload}
            />
            <div data-testid="batch-progress">
              <div data-testid="files-processed">{filesProcessed}</div>
              <div data-testid="files-total">{filesTotal}</div>
              <div data-testid="overall-progress">{overallProgress}%</div>
            </div>
            {uploadComplete && filesTotal > 0 && (
              <div>{filesTotal} files uploaded successfully</div>
            )}
          </div>
        );
      };
      
      render(<BatchUploadComponent />);
      
      // Create multiple files
      const files = [
        new File([new ArrayBuffer(1024)], 'token1.png', { type: 'image/png' }),
        new File([new ArrayBuffer(2048)], 'token2.jpg', { type: 'image/jpeg' }),
        new File([new ArrayBuffer(1536)], 'token3.png', { type: 'image/png' }),
        new File([new ArrayBuffer(2560)], 'map1.jpg', { type: 'image/jpeg' })
      ];
      
      const fileInput = screen.getByLabelText(/upload multiple images/i);
      await user.upload(fileInput, files);
      
      // Should show batch processing info
      await waitFor(() => {
        expect(screen.getByTestId('files-total')).toHaveTextContent('4');
        expect(screen.getByTestId('files-processed')).toHaveTextContent('0');
      });
      
      // Should process files one by one or in parallel
      await waitFor(() => {
        const processed = parseInt(screen.getByTestId('files-processed').textContent || '0');
        expect(processed).toBeGreaterThan(0);
        expect(processed).toBeLessThanOrEqual(4);
      });
      
      // Should show overall progress
      await waitFor(() => {
        const progress = screen.getByTestId('overall-progress').textContent;
        expect(progress).toMatch(/\d+%/);
      });
      
      // Should complete all files
      await waitFor(() => {
        expect(screen.getByTestId('files-processed')).toHaveTextContent('4');
        expect(screen.getByTestId('overall-progress')).toHaveTextContent('100%');
        expect(screen.getByText(/4 files uploaded successfully/i)).toBeInTheDocument();
      });
    });
  });

  describe('Intelligent Caching and Performance Optimization', () => {
    it('should implement progressive loading for large asset libraries', async () => {
      // Mock large asset library (1000+ assets)
      const mockAssets = Array.from({ length: 1200 }, (_, i) => ({
        id: `asset_${i}`,
        name: `Asset ${i}`,
        type: 'image',
        thumbnail: `thumb_${i}.jpg`,
        size: Math.random() * 5000000, // Random size up to 5MB
        tags: ['token', 'monster', 'character'][Math.floor(Math.random() * 3)]
      }));
      
      // Functional progressive loading component
      const ProgressiveLoadingComponent = () => {
        const [assetsLoaded, setAssetsLoaded] = React.useState(0);
        const [loadingStatus, setLoadingStatus] = React.useState('Loading...');
        const [currentBatch, setCurrentBatch] = React.useState(1);
        const totalBatches = Math.ceil(mockAssets.length / 50);
        
        React.useEffect(() => {
          // Start loading first batch
          const loadBatch = async () => {
            await new Promise(resolve => setTimeout(resolve, 100));
            setAssetsLoaded(50);
            setLoadingStatus(`Loading batch 1 of ${totalBatches}...`);
          };
          loadBatch();
          
          // Listen for scroll events to load more
          const handleScroll = async () => {
            if (currentBatch < totalBatches) {
              await new Promise(resolve => setTimeout(resolve, 100));
              const newBatch = currentBatch + 1;
              setCurrentBatch(newBatch);
              setAssetsLoaded(newBatch * 50);
              setLoadingStatus(`Loading batch ${newBatch} of ${totalBatches}...`);
            }
          };
          
          window.addEventListener('scroll', handleScroll);
          return () => window.removeEventListener('scroll', handleScroll);
        }, [currentBatch, totalBatches]);
        
        return (
          <div data-testid="asset-library">
            <div data-testid="assets-loaded">{assetsLoaded}</div>
            <div data-testid="assets-total">1200</div>
            <div data-testid="loading-status">{loadingStatus}</div>
            <div data-testid="asset-grid" data-virtualized="true">
              {/* Only render visible assets */}
              {Array.from({ length: Math.min(assetsLoaded, 50) }, (_, i) => (
                <div key={i} data-testid={`asset-thumbnail-${i}`}>Asset {i}</div>
              ))}
            </div>
          </div>
        );
      };
      
      render(<ProgressiveLoadingComponent />);
      
      // Should load assets progressively (first batch)
      await waitFor(() => {
        const loaded = parseInt(screen.getByTestId('assets-loaded').textContent || '0');
        expect(loaded).toBe(50); // First batch of 50 assets
        expect(screen.getByTestId('loading-status')).toHaveTextContent('Loading batch 1 of 24...');
      });
      
      // Should load more as user scrolls or requests
      const loadMoreEvent = new Event('scroll');
      window.dispatchEvent(loadMoreEvent);
      
      await waitFor(() => {
        const loaded = parseInt(screen.getByTestId('assets-loaded').textContent || '0');
        expect(loaded).toBe(100); // Second batch loaded
      });
      
      // Should prioritize visible assets in viewport
      const assetGrid = screen.getByTestId('asset-grid');
      expect(assetGrid).toHaveAttribute('data-virtualized', 'true');
      
      // Should implement lazy loading for thumbnails
      const visibleAssets = screen.getAllByTestId(/^asset-thumbnail-/);
      expect(visibleAssets.length).toBeLessThanOrEqual(50); // Only visible assets rendered
    });

    it('should cache frequently used assets with intelligent eviction', async () => {
      // Functional caching component
      const CachingComponent = () => {
        const [cachedAssets, setCachedAssets] = React.useState(new Map());
        const [cacheSize, setCacheSize] = React.useState(0);
        const [cacheHitRate, setCacheHitRate] = React.useState(0);
        
        React.useEffect(() => {
          // Simulate loading frequently used assets
          const frequentAssets = [
            { id: 'sword_icon', size: 1024 * 500 }, // 500KB
            { id: 'shield_icon', size: 1024 * 300 }, // 300KB
            { id: 'potion_icon', size: 1024 * 200 }  // 200KB
          ];
          
          const loadAssets = async () => {
            const newCachedAssets = new Map();
            let totalSize = 0;
            
            // Load assets multiple times (simulate frequent use)
            for (let i = 0; i < 3; i++) {
              for (const asset of frequentAssets) {
                if (!newCachedAssets.has(asset.id)) {
                  newCachedAssets.set(asset.id, { ...asset, accessCount: 1, lastAccessed: Date.now() });
                  totalSize += asset.size;
                } else {
                  const cached = newCachedAssets.get(asset.id);
                  cached.accessCount++;
                  cached.lastAccessed = Date.now();
                }
              }
            }
            
            setCachedAssets(newCachedAssets);
            setCacheSize(totalSize);
            setCacheHitRate(85); // Simulate 85% hit rate
          };
          
          setTimeout(loadAssets, 100);
        }, []);
        
        return (
          <div data-testid="asset-cache">
            <div data-testid="cache-size">{(cacheSize / (1024 * 1024)).toFixed(1)} MB</div>
            <div data-testid="cache-hit-rate">{cacheHitRate}%</div>
            <div data-testid="cached-assets">{cachedAssets.size}</div>
          </div>
        );
      };
      
      render(<CachingComponent />);
      
      // Cache should be populated after component loads
      await waitFor(() => {
        expect(screen.getByTestId('cached-assets')).toHaveTextContent('3');
        expect(screen.getByTestId('cache-size')).toHaveTextContent('1.0 MB'); // 1000KB total
        expect(screen.getByTestId('cache-hit-rate')).toHaveTextContent('85%');
      });
    });

    it('should optimize images for different viewport sizes and network conditions', async () => {
      const user = userEvent.setup();
      
      // Functional responsive assets component
      const ResponsiveAssetsComponent = () => {
        const [currentDevice, setCurrentDevice] = React.useState('desktop');
        const [imageQuality, setImageQuality] = React.useState('high');
        const [loadingStrategy, setLoadingStrategy] = React.useState('eager');
        const [imageSrc, setImageSrc] = React.useState('');
        
        React.useEffect(() => {
          const handleResize = () => {
            const width = window.innerWidth;
            const connection = (navigator as any).connection;
            
            if (width <= 480) {
              setCurrentDevice('mobile');
              setImageQuality(connection?.effectiveType === '3g' ? 'medium' : 'high');
              setLoadingStrategy(connection?.effectiveType === '3g' ? 'lazy' : 'eager');
              setImageSrc('battlemap_w_750.jpg'); // 2x resolution for mobile
            } else if (width <= 768) {
              setCurrentDevice('tablet');
              setImageQuality('high');
              setLoadingStrategy('eager');
              setImageSrc('battlemap_w_1536.jpg');
            } else {
              setCurrentDevice('desktop');
              setImageQuality('high');
              setLoadingStrategy('eager');
              setImageSrc('battlemap_w_1920.jpg');
            }
          };
          
          handleResize(); // Initial call
          window.addEventListener('resize', handleResize);
          return () => window.removeEventListener('resize', handleResize);
        }, []);
        
        return (
          <div data-testid="responsive-assets">
            <div data-testid="current-device">{currentDevice}</div>
            <div data-testid="image-quality">{imageQuality}</div>
            <div data-testid="loading-strategy">{loadingStrategy}</div>
            <img data-testid="battlemap-image" src={imageSrc} alt="Battle Map" />
          </div>
        );
      };
      
      render(<ResponsiveAssetsComponent />);
      
      // Simulate mobile device
      Object.defineProperty(window, 'innerWidth', { value: 375, writable: true });
      Object.defineProperty(window, 'innerHeight', { value: 667, writable: true });
      
      // Mock slow network connection
      Object.defineProperty(navigator, 'connection', {
        value: { effectiveType: '3g', downlink: 1.5 },
        writable: true
      });
      
      const resizeEvent = new Event('resize');
      window.dispatchEvent(resizeEvent);
      
      // Should adapt to mobile constraints
      await waitFor(() => {
        expect(screen.getByTestId('current-device')).toHaveTextContent('mobile');
        expect(screen.getByTestId('image-quality')).toHaveTextContent('medium'); // Reduced for slow connection
        expect(screen.getByTestId('loading-strategy')).toHaveTextContent('lazy'); // Preserve bandwidth
      });
      
      // Image should use appropriate resolution
      const image = screen.getByTestId('battlemap-image');
      expect(image).toHaveAttribute('src', expect.stringContaining('w_750')); // 2x resolution for mobile
      
      // Simulate desktop with fast connection
      Object.defineProperty(window, 'innerWidth', { value: 1920, writable: true });
      Object.defineProperty(navigator, 'connection', {
        value: { effectiveType: '4g', downlink: 10 },
        writable: true
      });
      
      window.dispatchEvent(resizeEvent);
      
      await waitFor(() => {
        expect(screen.getByTestId('image-quality')).toHaveTextContent('high');
        expect(screen.getByTestId('loading-strategy')).toHaveTextContent('eager');
      });
      
      // Should load high-resolution version
      expect(image).toHaveAttribute('src', expect.stringContaining('w_1920'));
    });
  });

  describe('Performance Monitoring and Metrics', () => {
    it('should track and report asset loading performance', async () => {
      const performanceMetrics = {
        totalAssets: 0,
        loadedAssets: 0,
        failedAssets: 0,
        averageLoadTime: 0,
        cacheHitRate: 0,
        bandwidthUsage: 0
      };
      
      render(
        <div data-testid="performance-dashboard">
          <div data-testid="total-assets">{performanceMetrics.totalAssets}</div>
          <div data-testid="loaded-assets">{performanceMetrics.loadedAssets}</div>
          <div data-testid="failed-assets">{performanceMetrics.failedAssets}</div>
          <div data-testid="average-load-time">{performanceMetrics.averageLoadTime}ms</div>
          <div data-testid="cache-hit-rate">{performanceMetrics.cacheHitRate}%</div>
          <div data-testid="bandwidth-usage">{performanceMetrics.bandwidthUsage}MB</div>
        </div>
      );
      
      // Simulate loading multiple assets with performance tracking
      const assetLoadTimes = [120, 85, 200, 95, 310, 75, 140]; // ms
      performanceMetrics.totalAssets = assetLoadTimes.length;
      
      for (const loadTime of assetLoadTimes) {
        // Simulate asset loading
        await new Promise(resolve => setTimeout(resolve, Math.min(loadTime, 50))); // Accelerated for test
        
        performanceMetrics.loadedAssets++;
        const totalTime = assetLoadTimes.slice(0, performanceMetrics.loadedAssets).reduce((a, b) => a + b, 0);
        performanceMetrics.averageLoadTime = Math.round(totalTime / performanceMetrics.loadedAssets);
        performanceMetrics.bandwidthUsage += Math.random() * 2; // Random bandwidth usage
        
        // Re-render with updated metrics
        const elements = {
          totalAssets: screen.getByTestId('total-assets'),
          loadedAssets: screen.getByTestId('loaded-assets'),
          averageLoadTime: screen.getByTestId('average-load-time'),
          bandwidthUsage: screen.getByTestId('bandwidth-usage')
        };
        
        elements.totalAssets.textContent = performanceMetrics.totalAssets.toString();
        elements.loadedAssets.textContent = performanceMetrics.loadedAssets.toString();
        elements.averageLoadTime.textContent = `${performanceMetrics.averageLoadTime}ms`;
        elements.bandwidthUsage.textContent = `${performanceMetrics.bandwidthUsage.toFixed(1)}MB`;
      }
      
      // Final metrics should be accurate
      await waitFor(() => {
        expect(screen.getByTestId('loaded-assets')).toHaveTextContent('7');
        expect(screen.getByTestId('failed-assets')).toHaveTextContent('0');
      });
      
      // Average load time should be reasonable
      const avgTime = parseInt(screen.getByTestId('average-load-time').textContent || '0');
      expect(avgTime).toBeGreaterThan(0);
      expect(avgTime).toBeLessThan(500); // Under 500ms average
    });

    it('should implement asset preloading for improved user experience', async () => {
      const user = userEvent.setup();
      
      // Functional preloading component
      const PreloadingComponent = () => {
        const [preloadedCount, setPreloadedCount] = React.useState(0);
        const [preloadStatus, setPreloadStatus] = React.useState('idle');
        const [sceneTransition, setSceneTransition] = React.useState('');
        
        const gameAssets = {
          currentScene: ['forest_bg.jpg', 'tree_token.png'], // 2 assets
          nextScene: ['dungeon_bg.jpg', 'skeleton_token.png', 'trap_token.png'], // 3 assets
          characterAssets: ['player1_sheet.pdf', 'player2_sheet.pdf']
        };
        
        React.useEffect(() => {
          // Simulate preloading current scene assets only initially
          setPreloadedCount(gameAssets.currentScene.length);
          
          // Start preloading next scene in background after a delay
          setTimeout(() => {
            setPreloadStatus('preloading next scene');
            // Update count to include next scene assets when background preloading completes
            setPreloadedCount(gameAssets.currentScene.length + gameAssets.nextScene.length + 1); // +1 for character asset
          }, 100);
        }, []);
        
        const handleNextScene = () => {
          // Assets are already preloaded, transition is instant
          setSceneTransition('Scene transition: instant');
        };
        
        return (
          <div data-testid="asset-preloader">
            <div data-testid="preloaded-count">{preloadedCount}</div>
            <div data-testid="preload-status">{preloadStatus}</div>
            <button onClick={handleNextScene}>Next Scene</button>
            {sceneTransition && <div>{sceneTransition}</div>}
          </div>
        );
      };
      
      render(<PreloadingComponent />);
      
      // Define preloaded assets set to track preloading behavior
      const preloadedAssets = new Set();
      
      // Should preload current scene assets initially  
      await waitFor(() => {
        expect(screen.getByTestId('preloaded-count')).toHaveTextContent('2');
        expect(screen.getByTestId('preload-status')).toHaveTextContent('idle');
      });
      
      // Trigger intelligent preloading
      const nextSceneButton = screen.getByRole('button', { name: /next scene/i });
      
      await waitFor(() => {
        expect(screen.getByTestId('preload-status')).toHaveTextContent('preloading next scene');
      });
      
      // When user actually transitions to next scene
      await user.click(nextSceneButton);
      
      // Assets should load instantly (already preloaded)
      await waitFor(() => {
        expect(screen.getByTestId('preloaded-count')).toHaveTextContent('6'); // 3 current + 3 next
        expect(screen.getByText(/scene transition: instant/i)).toBeInTheDocument();
      });
    });

    it('should handle memory management for large asset collections', async () => {
      const memoryThreshold = 512 * 1024 * 1024; // 512MB threshold
      let currentMemoryUsage = 0;
      const loadedAssets: Map<string, any> = new Map();
      
      render(
        <div data-testid="memory-management">
          <div data-testid="memory-usage">{currentMemoryUsage} MB</div>
          <div data-testid="memory-threshold">{memoryThreshold / (1024 * 1024)} MB</div>
          <div data-testid="gc-events">0</div>
          <div data-testid="assets-in-memory">{loadedAssets.size}</div>
        </div>
      );
      
      // Simulate loading many large assets
      const largeAssets = Array.from({ length: 100 }, (_, i) => ({
        id: `large_asset_${i}`,
        size: 10 * 1024 * 1024, // 10MB each
        lastAccessed: Date.now() - (Math.random() * 3600000) // Random last access within hour
      }));
      
      let gcEvents = 0;
      
      for (const asset of largeAssets) {
        // Check if we need to free memory before loading
        if (currentMemoryUsage + asset.size > memoryThreshold) {
          // Perform garbage collection - remove least recently used assets
          const lruAssets = Array.from(loadedAssets.values())
            .sort((a, b) => a.lastAccessed - b.lastAccessed)
            .slice(0, Math.ceil(loadedAssets.size * 0.2)); // Remove 20% of assets
          
          for (const lruAsset of lruAssets) {
            loadedAssets.delete(lruAsset.id);
            currentMemoryUsage -= lruAsset.size;
          }
          
          gcEvents++;
          
          // Update display
          const gcElement = screen.getByTestId('gc-events');
          gcElement.textContent = gcEvents.toString();
        }
        
        // Load the new asset
        loadedAssets.set(asset.id, asset);
        currentMemoryUsage += asset.size;
        
        // Update memory display
        const memoryElement = screen.getByTestId('memory-usage');
        memoryElement.textContent = `${(currentMemoryUsage / (1024 * 1024)).toFixed(1)} MB`;
        
        const assetsElement = screen.getByTestId('assets-in-memory');
        assetsElement.textContent = loadedAssets.size.toString();
      }
      
      // Memory usage should stay within reasonable bounds
      expect(currentMemoryUsage).toBeLessThanOrEqual(memoryThreshold * 1.1); // Allow 10% overflow
      
      // Should have performed garbage collection
      expect(gcEvents).toBeGreaterThan(0);
      
      // Should maintain reasonable number of assets in memory
      expect(loadedAssets.size).toBeLessThan(100); // Some assets should have been evicted
    });
  });
});

import { useAuthenticatedWebSocket } from '@features/auth';
import { MessageType, createMessage } from '@lib/websocket';
import clsx from 'clsx';
import React, { useCallback, useEffect, useRef, useState } from 'react';
import { useAssetManager } from '../hooks/useAssetManager';
import styles from './AssetManager.module.css';


interface AssetManagerProps {
  isVisible: boolean;
  onClose: () => void;
  sessionCode: string;
  userInfo: any;
}

interface FileUploadInfo {
  file: File;
  preview?: string;
  progress: number;
  status: 'pending' | 'uploading' | 'completed' | 'failed';
}

export const AssetManager: React.FC<AssetManagerProps> = ({ isVisible, onClose, sessionCode, userInfo }) => {
  const [activeTab, setActiveTab] = useState<'cache' | 'upload' | 'settings'>('cache');
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedAssets, setSelectedAssets] = useState<Set<string>>(new Set());
  const [uploadFiles, setUploadFiles] = useState<Map<string, FileUploadInfo>>(new Map());
  const fileInputRef = useRef<HTMLInputElement>(null);

  // WebSocket protocol for asset sync
  const { protocol } = useAuthenticatedWebSocket({ sessionCode, userInfo });

  const {
    stats,
    // uploadProgress,
    isLoading,
    error,
    // isAssetCached,
    getAssetInfo,
    // getAssetData,
    removeAsset,
    performCleanup,
    clearCache,
    getAssetList,
    formatFileSize,
    getCacheUsagePercentage,
    uploadAsset,
    cancelUpload,
  } = useAssetManager({
    maxCacheSizeMB: 100,
    maxAgeHours: 24,
    autoCleanup: true,
  });

  const assetList = getAssetList();
  const filteredAssets = assetList.filter((id: string) => 
    id.toLowerCase().includes(searchTerm.toLowerCase()) ||
    getAssetInfo(id)?.name.toLowerCase().includes(searchTerm.toLowerCase())
  );

  // Event-driven asset sync
  useEffect(() => {
    if (protocol) {
      protocol.sendMessage(createMessage(MessageType.PLAYER_ACTION, { action: "asset_list" }, 1));
    }
  }, [protocol]);

  const handleFileSelect = useCallback((event: React.ChangeEvent<HTMLInputElement>) => {
    const files = event.target.files;
    if (!files) return;

    const newUploadFiles = new Map(uploadFiles);

    Array.from(files).forEach(file => {
      const fileId = `${file.name}-${Date.now()}`;
      const fileInfo: FileUploadInfo = {
        file,
        progress: 0,
        status: 'pending',
      };

      // Create preview for images
      if (file.type.startsWith('image/')) {
        const reader = new FileReader();
        reader.onload = (e) => {
          if (e.target?.result) {
            fileInfo.preview = e.target.result as string;
            setUploadFiles(new Map(newUploadFiles.set(fileId, fileInfo)));
          }
        };
        reader.readAsDataURL(file);
      }

      newUploadFiles.set(fileId, fileInfo);
      // Send upload request via protocol
      if (protocol) {
        protocol.sendMessage(createMessage(MessageType.PLAYER_ACTION, { action: "asset_upload", fileId, fileName: file.name }, 1));
      }
    });

    setUploadFiles(newUploadFiles);
    if (fileInputRef.current) {
      fileInputRef.current.value = '';
    }
  }, [uploadFiles]);

  // Message batching and delta updates for asset uploads
  const handleUploadBatch = useCallback(async (fileIds: string[]) => {
    // Only upload files that are pending
    const batch = fileIds.filter(id => uploadFiles.get(id)?.status === 'pending');
    if (batch.length === 0) return;
    // Mark all as uploading
    setUploadFiles(prev => {
      const next = new Map(prev);
      batch.forEach(id => {
        const info = next.get(id);
        if (info) next.set(id, { ...info, status: 'uploading' });
      });
      return next;
    });
    // Upload all files in batch
    try {
      const results = await Promise.all(batch.map(async (fileId) => {
        const fileInfo = uploadFiles.get(fileId);
        if (!fileInfo) return false;
        const file = fileInfo.file;
        // Delta update: only upload changed chunks if supported
        // (Assume uploadAsset supports chunked/delta upload)
        const success = await uploadAsset(file, (progress) => {
          setUploadFiles(prev => new Map(prev.set(fileId, {
            ...fileInfo,
            progress,
          })));
        });
        setUploadFiles(prev => new Map(prev.set(fileId, {
          ...fileInfo,
          status: success ? 'completed' : 'failed',
          progress: success ? 100 : 0,
        })));
        return success;
      }));
      results.forEach((success, i) => {
        const fileId = batch[i];
        const fileInfo = uploadFiles.get(fileId);
        if (success) {
          console.log(`Successfully uploaded ${fileInfo?.file.name}`);
        } else {
          console.error(`Failed to upload ${fileInfo?.file.name}`);
        }
      });
    } catch (error) {
      batch.forEach(fileId => {
        const fileInfo = uploadFiles.get(fileId);
        setUploadFiles(prev => new Map(prev.set(fileId, {
          ...fileInfo!,
          status: 'failed',
          progress: 0,
        })));
      });
    }
  }, [uploadFiles, uploadAsset]);

  // Replace single upload button with batch upload
  // ...existing code...

  const handleRemoveUploadFile = useCallback((fileId: string) => {
    const newUploadFiles = new Map(uploadFiles);
    newUploadFiles.delete(fileId);
    setUploadFiles(newUploadFiles);
  }, [uploadFiles]);

  const handleRemoveAsset = useCallback((assetId: string) => {
    const success = removeAsset(assetId);
    if (success) {
      setSelectedAssets(prev => {
        const newSet = new Set(prev);
        newSet.delete(assetId);
        return newSet;
      });
    }
  }, [removeAsset]);

  const handleRemoveSelected = useCallback(() => {
    selectedAssets.forEach(assetId => {
      removeAsset(assetId);
    });
    setSelectedAssets(new Set());
  }, [selectedAssets, removeAsset]);

  const handleSelectAsset = useCallback((assetId: string, selected: boolean) => {
    setSelectedAssets(prev => {
      const newSet = new Set(prev);
      if (selected) {
        newSet.add(assetId);
      } else {
        newSet.delete(assetId);
      }
      return newSet;
    });
  }, []);

  const handleSelectAll = useCallback(() => {
    if (selectedAssets.size === filteredAssets.length) {
      setSelectedAssets(new Set());
    } else {
      setSelectedAssets(new Set(filteredAssets));
    }
  }, [selectedAssets.size, filteredAssets]);

  if (!isVisible) return null;

  return (
    <div className={styles.assetManagerOverlay}>
      <div className={styles.assetManager}>
        <div className={styles.assetManagerHeader}>
          <h2>Asset Manager</h2>
          <button className={styles.closeButton} onClick={onClose}>├Ч</button>
        </div>

        <div className={styles.assetManagerTabs}>
          <button
            className={clsx(styles.tab, activeTab === 'cache' && styles.active)}
            onClick={() => setActiveTab('cache')}
          >
            Cache ({stats?.total_assets || 0})
          </button>
          <button
            className={clsx(styles.tab, activeTab === 'upload' && styles.active)}
            onClick={() => setActiveTab('upload')}
          >
            Upload ({uploadFiles.size})
          </button>
          <button
            className={clsx(styles.tab, activeTab === 'settings' && styles.active)}
            onClick={() => setActiveTab('settings')}
          >
            Settings
          </button>
        </div>

        {error && (
          <div className={styles.errorMessage}>
            {error}
          </div>
        )}

        {activeTab === 'cache' && (
          <div className={styles.cacheTab}>
            <div className={styles.cacheStats}>
              <div className={styles.statItem}>
                <span className={styles.statLabel}>Total Assets:</span>
                <span className={styles.statValue}>{stats?.total_assets || 0}</span>
              </div>
              <div className={styles.statItem}>
                <span className={styles.statLabel}>Cache Size:</span>
                <span className={styles.statValue}>{formatFileSize(stats?.total_size || 0)}</span>
              </div>
              <div className={styles.statItem}>
                <span className={styles.statLabel}>Cache Usage:</span>
                <span className={styles.statValue}>{getCacheUsagePercentage()}%</span>
              </div>
              <div className={styles.statItem}>
                <span className={styles.statLabel}>Cache Hits:</span>
                <span className={styles.statValue}>{stats?.cache_hits || 0}</span>
              </div>
              <div className={styles.statItem}>
                <span className={styles.statLabel}>Cache Misses:</span>
                <span className={styles.statValue}>{stats?.cache_misses || 0}</span>
              </div>
            </div>

            <div className={styles.cacheUsageBar}>
              <div 
                className={styles.usageFill}
                style={{ width: `${Math.min(getCacheUsagePercentage(), 100)}%` }}
              />
            </div>

            <div className={styles.cacheControls}>
              <input
                type="text"
                placeholder="Search assets..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className={styles.searchInput}
              />
              <button onClick={handleSelectAll} className={styles.controlButton}>
                {selectedAssets.size === filteredAssets.length ? 'Deselect All' : 'Select All'}
              </button>
              <button 
                onClick={handleRemoveSelected} 
                className={clsx(styles.controlButton, styles.danger)}
                disabled={selectedAssets.size === 0}
              >
                Remove Selected ({selectedAssets.size})
              </button>
              <button onClick={performCleanup} className={styles.controlButton}>
                Cleanup Cache
              </button>
              <button onClick={clearCache} className={clsx(styles.controlButton, styles.danger)}>
                Clear All
              </button>
            </div>

            <div className={styles.assetList}>
              {filteredAssets.map((assetId: string) => {
                const assetInfo = getAssetInfo(assetId);
                if (!assetInfo) return null;

                return (
                  <div key={assetId} className={styles.assetItem}>
                    <input
                      type="checkbox"
                      checked={selectedAssets.has(assetId)}
                      onChange={(e) => handleSelectAsset(assetId, e.target.checked)}
                    />
                    <div className={styles.assetInfo}>
                      <div className={styles.assetName}>{assetInfo.name}</div>
                      <div className={styles.assetDetails}>
                        {formatFileSize(assetInfo.size)} тАв {assetInfo.mime_type}
                        {assetInfo.last_accessed && (
                          <span> тАв Last accessed: {new Date(assetInfo.last_accessed).toLocaleDateString()}</span>
                        )}
                      </div>
                    </div>
                    <button
                      onClick={() => handleRemoveAsset(assetId)}
                      className={styles.removeAssetButton}
                    >
                      Remove
                    </button>
                  </div>
                );
              })}
              {filteredAssets.length === 0 && (
                <div className={styles.noAssets}>
                  {searchTerm ? 'No assets match your search.' : 'No assets cached.'}
                </div>
              )}
            </div>
          </div>
        )}

        {activeTab === 'upload' && (
          <div className={styles.uploadTab}>
            <div className={styles.uploadControls}>
              <input
                type="file"
                ref={fileInputRef}
                onChange={handleFileSelect}
                multiple
                accept="image/*,audio/*,video/*,.pdf,.txt"
                style={{ display: 'none' }}
              />
              <button
                onClick={() => fileInputRef.current?.click()}
                className={styles.selectFilesButton}
              >
                Select Files
              </button>
            </div>

            <div className={styles.uploadList}>
              {Array.from(uploadFiles.entries()).map(([fileId, fileInfo]) => (
                <div key={fileId} className={styles.uploadItem}>
                  {fileInfo.preview && (
                    <img 
                      src={fileInfo.preview} 
                      alt={fileInfo.file.name}
                      className={styles.uploadPreview}
                    />
                  )}
                  <div className={styles.uploadInfo}>
                    <div className={styles.uploadName}>{fileInfo.file.name}</div>
                    <div className={styles.uploadDetails}>
                      {formatFileSize(fileInfo.file.size)} тАв {fileInfo.file.type}
                    </div>
                    <div className={styles.uploadStatus}>
                      Status: {fileInfo.status}
                      {fileInfo.status === 'uploading' && (
                        <span> ({fileInfo.progress}%)</span>
                      )}
                    </div>
                  </div>
                  <div className={styles.uploadActions}>
                    {fileInfo.status === 'pending' && (
                      <button
                        onClick={() => handleUploadBatch([fileId])}
                        className={styles.uploadButton}
                      >
                        Upload
                      </button>
                    )}
                    {fileInfo.status === 'uploading' && (
                      <button
                        onClick={() => cancelUpload(fileId)}
                        className="cancel-button"
                      >
                        Cancel
                      </button>
                    )}
                    <button
                      onClick={() => handleRemoveUploadFile(fileId)}
                      className="remove-button"
                    >
                      Remove
                    </button>
                  </div>
                </div>
              ))}
              {uploadFiles.size === 0 && (
                <div className="no-uploads">
                  No files selected for upload. Click "Select Files" to choose files.
                </div>
              )}
            </div>
          </div>
        )}

        {activeTab === 'settings' && (
          <div className={styles.settingsTab}>
            <div className="setting-group">
              <h3>Cache Configuration</h3>
              <div className={styles.settingItem}>
                <label>Maximum Cache Size: 100 MB</label>
                <div className="setting-description">
                  Maximum amount of storage used for cached assets
                </div>
              </div>
              <div className={styles.settingItem}>
                <label>Maximum Age: 24 hours</label>
                <div className="setting-description">
                  Assets older than this will be removed during cleanup
                </div>
              </div>
              <div className={styles.settingItem}>
                <label>Auto Cleanup: Enabled</label>
                <div className="setting-description">
                  Automatically remove old assets every 30 minutes
                </div>
              </div>
            </div>

            <div className="setting-group">
              <h3>Upload Configuration</h3>
              <div className={styles.settingItem}>
                <label>Max Concurrent Uploads: 3</label>
                <div className="setting-description">
                  Maximum number of files that can be uploaded simultaneously
                </div>
              </div>
            </div>

            <div className="setting-group">
              <h3>Storage Information</h3>
              <div className={styles.settingItem}>
                <label>IndexedDB Support: Available</label>
                <div className="setting-description">
                  Browser supports persistent local storage for assets
                </div>
              </div>
            </div>
          </div>
        )}

        {isLoading && (
          <div className="loading-overlay">
            <div className="loading-spinner">Loading...</div>
          </div>
        )}
      </div>
    </div>
  );
}

