  const cancelUpload = useCallback((fileId: string): void => {
    safeSetUploadProgress(prev => {
      const newProgress = { ...prev };
      delete newProgress[fileId];
      return newProgress;
    });
  }, []);

  return {
    // State
    ...state,
    uploadProgress,
    
    // Methods
