}

export interface BackgroundLODLevel {
  minZoom: number;
  maxZoom: number;
  textureUrl: string;
  scale: number;
  quality: 'low' | 'medium' | 'high' | 'ultra';
}

export interface WeatherEffect {
  id: string;
  type: 'rain' | 'snow' | 'fog' | 'storm' | 'wind' | 'particles';
  intensity: number;
  direction: { x: number; y: number };
