            </div>

            {error && (
              <div className={styles.errorMessage} role="alert" aria-live="polite">
                <span className={styles.errorIcon}><AlertTriangle size={16} aria-hidden /></span>
                {error}
              </div>
            )}

            {success && (
              <div className={styles.successMessage} role="alert" aria-live="polite">
                <span className={styles.successIcon}><CheckCircle size={16} aria-hidden /></span>
                {success}
              </div>
            )}

            <form onSubmit={handleForgotPassword} className={styles.authForm}>
              <div className={styles.formGroup}>
                <label htmlFor="reset-email">Email Address</label>
                <input
                  id="reset-email"
                  type="email"
                  value={resetEmail}
                  onChange={(e) => {
                    setResetEmail(e.target.value);
                    // Clear errors when user types
                    if (error) setError(null);
                  }}
                  required
                  autoFocus
                  disabled={isLoading}
                  placeholder="Enter your email address"
                />
              </div>

              <div className={styles.formActions}>
                <button
                  type="button"
                  onClick={() => setShowForgotPassword(false)}
                  className={styles.secondaryBtn}
                  disabled={isLoading}
                >
                  Back to Sign In
                </button>
                <button
                  type="submit"
                  className={styles.primaryBtn}
                  disabled={isLoading || !resetEmail.trim()}
                >
                  {isLoading ? <LoadingSpinner size="small" /> : 'Send Reset Link'}
                </button>
              </div>
            </form>
          </div>
        </div>
      </ErrorBoundary>
    );
  }

  return (
    <ErrorBoundary>
