                    placeholder="Confirm your password"
                  />
                  <button
                    type="button"
                    className={styles.passwordToggle}
                    onClick={() => setShowConfirmPassword(!showConfirmPassword)}
                    disabled={isLoading}
                    aria-label={showConfirmPassword ? 'Hide password' : 'Show password'}
                  >
                    {showConfirmPassword ? <EyeOff size={16} aria-hidden /> : <Eye size={16} aria-hidden />}
                  </button>
                </div>
                {confirmPassword && registerData.password && confirmPassword !== registerData.password && (
                  <div className={styles.passwordMismatch}>
                    <AlertTriangle size={14} aria-hidden /> Passwords do not match
                  </div>
                )}
              </div>

              <div className={styles.formOptions}>
                <label className={styles.checkboxLabel}>
                  <input
                    type="checkbox"
                    checked={acceptTerms}
                    onChange={(e) => setAcceptTerms(e.target.checked)}
                    disabled={isLoading}
                    required
                  />
                  <span className={styles.checkmark}></span>
                  I agree to the{' '}
                  <a href="/terms" target="_blank" rel="noopener noreferrer">
                    Terms of Service
                  </a>{' '}
                  and{' '}
                  <a href="/privacy" target="_blank" rel="noopener noreferrer">
                    Privacy Policy
                  </a>
                </label>
              </div>

              <button
                type="submit"
                className={styles.primaryBtn}
                disabled={
                  isLoading || 
                  !registerData.username.trim() || 
                  !registerData.email.trim() || 
                  !registerData.password.trim() ||
                  !confirmPassword.trim() ||
                  registerData.password !== confirmPassword ||
                  !passwordStrength.isStrong ||
                  !acceptTerms
                }
              >
                {isLoading ? <LoadingSpinner size="small" /> : 'Create Account'}
              </button>
            </form>
          )}

          {/* Toggle Mode */}
          <div className={styles.authToggle}>
            <p>
              {isLoginMode ? "Don't have an account? " : "Already have an account? "}
              <button
                type="button"
                className={styles.toggleBtn}
                onClick={toggleMode}
                disabled={isLoading}
              >
                {isLoginMode ? 'Sign Up' : 'Sign In'}
              </button>
            </p>
          </div>
        </div>
      </div>
    </ErrorBoundary>
  );
};

