/**
 * React hook for authenticated WebSocket connection with protocol compliance
 * Manages connection state and provides protocol interface
 */
import { useProtocol } from '@lib/api';
import { WebClientProtocol } from '@lib/websocket';
import { useCallback, useEffect, useRef, useState } from 'react';
import type { UserInfo } from '../services/auth.service';
import { authService } from '../services/auth.service';

interface UseAuthenticatedWebSocketProps {
  sessionCode: string;
  userInfo: UserInfo;
}

export type ConnectionState = 'disconnected' | 'connecting' | 'connected' | 'error';

export function useAuthenticatedWebSocket({ sessionCode, userInfo }: UseAuthenticatedWebSocketProps) {
  // Prefer the centralized ProtocolContext if present
  let ctx: any = null;
  try { ctx = useProtocol(); } catch (e) { ctx = null; }

  const protocolRef = useRef<WebClientProtocol | null>(null);
  const [connectionState, setConnectionState] = useState<ConnectionState>('disconnected');
  const [error, setError] = useState<string | null>(null);

  // If ProtocolContext is available, mirror its values and return early
  if (ctx) {
    return {
      connectionState: ctx.connectionState as ConnectionState,
      error: null,
      protocol: ctx.protocol as WebClientProtocol | null,
      connect: ctx.connect,
      disconnect: ctx.disconnect,
      isConnected: ctx.connectionState === 'connected'
    };
  }

  const connect = useCallback(async () => {
    try {
      setConnectionState('connecting');
      setError(null);
      
      // Resolve sessionCode to canonical session_code if needed
      let resolvedCode = sessionCode;
      try {
        // Fetch user's sessions and try to resolve by code first, then by name
        const sessions = await authService.getUserSessions();
        const byCode = sessions.find((s: any) => s.session_code === sessionCode);
        const byName = sessions.find((s: any) => s.session_name === sessionCode);
        if (byCode) {
          resolvedCode = byCode.session_code;
        } else if (byName) {
          resolvedCode = byName.session_code;
          console.debug('[useAuthenticatedWebSocket] Resolved injected session name to code:', sessionCode, '->', resolvedCode);
        }
      } catch (e) {
        // If session resolution fails, continue with provided sessionCode but log it
        console.warn('[useAuthenticatedWebSocket] Failed to resolve sessionCode against user sessions:', e);
      }

      // If already connected, skip creating a new protocol (idempotent)
      if (protocolRef.current && protocolRef.current.isConnected()) {
        console.debug('[useAuthenticatedWebSocket] Already connected - skipping new connect for', resolvedCode);
        setConnectionState('connected');
        return;
      }

      // Create new protocol instance with the resolved canonical code
      const protocol = new WebClientProtocol(resolvedCode);
      protocolRef.current = protocol;

      // Connect to WebSocket with authentication
      await protocol.connect();

      setConnectionState('connected');
      // Log the actual resolved canonical code we connected to (not the injected candidate)
      console.log(`Connected to session ${resolvedCode} as ${userInfo.username} (${userInfo.role})`);
      
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : 'Connection failed';
      setError(errorMessage);
      setConnectionState('error');
      console.error('WebSocket connection error:', err);
      
      // Clear protocol reference on error
      protocolRef.current = null;
    }
  }, [sessionCode, userInfo]);

  const disconnect = useCallback(() => {
    if (protocolRef.current) {
      protocolRef.current.disconnect();
      protocolRef.current = null;
    }
    setConnectionState('disconnected');
    setError(null);
  }, []);

  const getProtocol = useCallback(() => protocolRef.current, []);

  // Monitor connection state using event-driven approach instead of polling
  useEffect(() => {
    if (!protocolRef.current) return;

    const handleConnectionStateChange = (state: 'connected' | 'disconnected' | 'timeout') => {
      console.log('[useAuthenticatedWebSocket] Connection state changed:', state);
      
      if (state === 'connected') {
        setConnectionState('connected');
        setError(null);
      } else if (state === 'disconnected') {
        setConnectionState('disconnected');
        setError('Connection lost');
      } else if (state === 'timeout') {
        setConnectionState('error');
        setError('Connection timeout - server not responding');
      }
    };

    // Subscribe to connection state changes
    const unsubscribe = protocolRef.current.onConnectionStateChange(handleConnectionStateChange);
    
    return () => {
      unsubscribe();
    };
  }, [protocolRef.current]);

  // Auto-connect on mount and disconnect on unmount
  useEffect(() => {
    connect();
    return () => disconnect();
  }, [connect, disconnect]);

  // Handle connection state changes
  useEffect(() => {
    if (connectionState === 'error' && error) {
  // Authentication errors should not be silently ignored; allow retry logic below
  // Auto-retry connection after 5 seconds for non-authentication errors
      
      if (!error.includes('Authentication failed')) {
        const retryTimer = setTimeout(() => connect(), 5000);
        return () => clearTimeout(retryTimer);
      }
    }
  }, [connectionState, error, connect]);

  return {
    connectionState,
    error,
    protocol: getProtocol(),
    connect,
    disconnect,
    isConnected: connectionState === 'connected'
  };
}

/**
 * Authentication service for JWT token management and user info
 * Integrates with FastAPI server authentication system
 */

export interface UserInfo {
  id: number;
  username: string;
  role: 'dm' | 'player';
 permissions: string[];
}

import type { SessionRole } from '@features/session/types/roles';

export interface SessionInfo {
  session_code: string;
  session_name: string;
  role: SessionRole;
  created_at: string;
}

class AuthService {
  private token: string | null = null;
  private userInfo: UserInfo | null = null;
  private lastRequestTime: number = 0;
  private requestCount: number = 0;
  private static RATE_LIMIT = 10; // max 10 requests per 10 seconds
  private static RATE_LIMIT_WINDOW = 10000; // 10 seconds

  /**
   * Login user with username and password
   */
  async login(username: string, password: string): Promise<{ success: boolean; message?: string }> {
    try {
      const response = await fetch('/users/login', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: new URLSearchParams({
          username,
          password
        }),
        credentials: 'include'
      });

      if (response.ok) {
        // Re-initialize to get user info from cookie
        await this.initialize();
        return { success: true };
      } else {
        const errorText = await response.text();
        // Try to extract error message from HTML response
        const errorMatch = errorText.match(/error[\"']: [\"']([^\"']+)[\"']/i);
        const errorMessage = errorMatch ? errorMatch[1] : 'Login failed';
        return { success: false, message: errorMessage };
      }
    } catch (error) {
 console.error('Login error:', error);
      return { success: false, message: 'Network error occurred' };
    }
  }

  /**
   * Register a new user
   */
  async register(username: string, password: string): Promise<{ success: boolean; message?: string }> {
    try {
      const response = await fetch('/users/register', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: new URLSearchParams({
          username,
          password
        }),
        credentials: 'include'
      });

      if (response.ok) {
        return { success: true, message: 'Registration successful. Please log in.' };
      } else {
        const errorText = await response.text();
        const errorMatch = errorText.match(/error[\"']: [\"']([^\"']+)[\"']/i);
        const errorMessage = errorMatch ? errorMatch[1] : 'Registration failed';
        return { success: false, message: errorMessage };
      }
    } catch (error) {
 console.error('Registration error:', error);
      return { success: false, message: 'Network error occurred' };
    }
  }

  /**
   * Extract JWT token from HTTP-only cookie set by FastAPI
   * Note: HTTP-only cookies cannot be read by JavaScript for security
   * Instead, we rely on server-side validation of the cookie
   */
  async extractToken(): Promise<string | null> {
    // Rate limiting - skip in test environment
    if (!((globalThis as any).__VITEST__ || import.meta.env?.MODE === 'test')) {
      const now = Date.now();
      if (now - this.lastRequestTime > AuthService.RATE_LIMIT_WINDOW) {
        this.requestCount = 0;
        this.lastRequestTime = now;
      }
      this.requestCount++;
      if (this.requestCount > AuthService.RATE_LIMIT) {
        throw new Error('Rate limit exceeded. Please wait before retrying.');
      }
    }
    // For HTTP-only cookies, we can't read them directly
    // Instead, we validate authentication by making a request to /users/me
    try {
      const response = await fetch('/users/me', {
        credentials: 'include',
        headers: { 'Accept': 'application/json' }
      });
      if (response.ok) {
        const userData = await response.json();
        this.userInfo = {
          id: userData.id,
          username: userData.username,
          role: userData.role || 'player',
          permissions: userData.permissions || []
        };
        this.token = 'authenticated-via-cookie';
        return this.token;
      } else if (response.status === 401) {
        return null;
      } else {
        return null;
      }
    } catch (error) {
      return null;
    }
    const urlToken = this.extractTokenFromURL();
    if (urlToken) {
      this.token = urlToken;
      return urlToken;
    }
    return null;
  }

  private extractTokenFromURL(): string | null {
    const params = new URLSearchParams(window.location.search);
    return params.get('token');
  }

  /**
   * Validate token with server and extract user info
   */
  async validateToken(token: string): Promise<UserInfo | null> {
    // Token refresh logic
    try {
      let response = await fetch('/users/me', {
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        },
        credentials: 'include'
      });
      if (response.status === 401) {
        // Try to refresh token
        const refreshResponse = await fetch('/users/refresh', {
          method: 'POST',
          credentials: 'include',
          headers: { 'Content-Type': 'application/json' }
        });
        if (refreshResponse.ok) {
          const refreshData = await refreshResponse.json();
          this.token = refreshData.token;
          response = await fetch('/users/me', {
            headers: {
              'Authorization': `Bearer ${this.token}`,
              'Content-Type': 'application/json'
            },
            credentials: 'include'
          });
        }
      }
      if (response.ok) {
        const userData = await response.json();
        this.userInfo = {
          id: userData.id,
          username: userData.username,
          role: userData.role || 'player',
          permissions: userData.permissions || []
        };
        return this.userInfo;
      }
    } catch (error) {
      return null;
    }
    return null;
  }

  /**
   * Get user's available sessions using cookie-based authentication
   */
  async getUserSessions(): Promise<SessionInfo[]> {
    try {
      const response = await fetch('/users/dashboard', {
        credentials: 'include', // Include HTTP-only cookies
        headers: {
          'Accept': 'application/json',
        }
      });

      if (response.ok) {
        const data = await response.json();
        return data.sessions || [];
      }
      throw new Error(`Failed to fetch sessions: ${response.statusText}`);
    } catch (error) {
 console.error('Failed to fetch user sessions:', error);
      throw error;
    }
  }

  getToken(): string | null { 
    return this.token; 
  }

  getUserInfo(): UserInfo | null { 
    return this.userInfo; 
  }

  isAuthenticated(): boolean { 
    return this.token !== null && this.userInfo !== null; 
  }

  /**
   * Clear authentication state and redirect to login
   */
  logout(): void {
    this.token = null;
    this.userInfo = null;
    // Clear cookie by setting it to expire
    document.cookie = 'token=; expires=Thu, 01 Jan 1970 00:00:00 UTC; path=/;';
    window.location.href = '/users/logout';
  }

  /**
   * Initialize authentication from existing token
   */
  async initialize(): Promise<boolean> {
    console.log(' Starting authentication initialization...');
    const token = await this.extractToken();
    
    if (!token) {
      console.log(' No token found, authentication failed');
      return false;
    }

    console.log(' Token found and user info already extracted');
    console.log(' Current user info:', this.userInfo);
    return true;
  }
}

export const authService = new AuthService();

/**
 * Enhanced Authentication Service
 * Production-ready authentication with JWT refresh tokens, role-based access control,
 * OAuth integration, session management, and comprehensive security features
 */

import React from 'react';

export interface User {
  id: number;
  username: string;
  email?: string;
  fullName?: string;
  role: UserRole;
  permissions: Permission[];
  isEmailVerified: boolean;
  lastLogin?: string;
  createdAt: string;
  updatedAt: string;
  avatar?: string;
  preferences: UserPreferences;
}

export interface UserPreferences {
  theme: 'light' | 'dark' | 'auto';
  language: string;
  timezone: string;
  notifications: NotificationSettings;
}

export interface NotificationSettings {
  email: boolean;
  push: boolean;
  gameInvites: boolean;
  systemUpdates: boolean;
}

export type UserRole = 'admin' | 'gm' | 'player' | 'guest';

export type Permission = 
  | 'user.read'
  | 'user.write'
  | 'user.delete'
  | 'game.create'
  | 'game.read'
  | 'game.write'
  | 'game.delete'
  | 'game.manage'
  | 'character.create'
  | 'character.read'
  | 'character.write'
  | 'character.delete'
  | 'system.admin'
  | 'system.moderate';

export interface AuthTokens {
  accessToken: string;
  refreshToken: string;
  expiresAt: number;
  tokenType: 'Bearer';
}

export interface LoginCredentials {
  username: string;
  password: string;
  rememberMe?: boolean;
}

export interface RegisterCredentials {
  username: string;
  email: string;
  password: string;
  fullName?: string;
  acceptTerms: boolean;
}

export interface PasswordResetRequest {
  email: string;
}

export interface PasswordResetConfirm {
  token: string;
  newPassword: string;
}

export interface ChangePasswordRequest {
  currentPassword: string;
  newPassword: string;
}

export interface SessionInfo {
  id: string;
  userId: number;
  deviceInfo: DeviceInfo;
  location?: LocationInfo;
  createdAt: string;
  lastActivity: string;
  isCurrentSession: boolean;
}

export interface DeviceInfo {
  userAgent: string;
  browser: string;
  os: string;
  device: string;
  isMobile: boolean;
}

export interface LocationInfo {
  country: string;
  region: string;
  city: string;
  ip: string;
}

export interface OAuthProvider {
  id: string;
  name: string;
  icon: string;
  isEnabled: boolean;
}

export interface AuthError {
  code: string;
  message: string;
  details?: Record<string, any>;
}

export interface AuthState {
  isAuthenticated: boolean;
  isLoading: boolean;
  user: User | null;
  tokens: AuthTokens | null;
  lastError: AuthError | null;
}

/**
 * Password validation configuration
 */
interface PasswordPolicy {
  minLength: number;
  requireUppercase: boolean;
  requireLowercase: boolean;
  requireNumbers: boolean;
  requireSpecialChars: boolean;
  maxLength: number;
  preventCommonPasswords: boolean;
  preventPersonalInfo: boolean;
}

class EnhancedAuthService {
  private static instance: EnhancedAuthService;
  private authState: AuthState = {
    isAuthenticated: false,
    isLoading: true,
    user: null,
    tokens: null,
    lastError: null
  };
  
  private listeners: ((state: AuthState) => void)[] = [];
  private refreshTimer: number | null = null;
  private sessionCheckInterval: number | null = null;
  private rateLimitMap = new Map<string, { count: number; resetTime: number }>();
  
  // Security configuration
  private readonly REFRESH_BUFFER_TIME = 5 * 60 * 1000; // 5 minutes before expiry
  private readonly SESSION_CHECK_INTERVAL = 5 * 60 * 1000; // 5 minutes
  private readonly RATE_LIMIT_WINDOW = 15 * 60 * 1000; // 15 minutes
  private readonly RATE_LIMIT_ATTEMPTS = 5;
  
  // Password policy configuration
  private readonly PASSWORD_POLICY: PasswordPolicy = {
    minLength: 8,
    maxLength: 128,
    requireUppercase: true,
    requireLowercase: true,
    requireNumbers: true,
    requireSpecialChars: true,
    preventCommonPasswords: true,
    preventPersonalInfo: true
  };

  private constructor() {
    this.initializeAuth();
    this.setupSecurityFeatures();
  }

  public static getInstance(): EnhancedAuthService {
    if (!EnhancedAuthService.instance) {
      EnhancedAuthService.instance = new EnhancedAuthService();
    }
    return EnhancedAuthService.instance;
  }

  /**
   * Initialize authentication on service startup
   */
  private async initializeAuth(): Promise<void> {
    try {
      this.updateAuthState({ isLoading: true });
      
      // Try to restore session from stored refresh token
      const refreshToken = this.getStoredRefreshToken();
      if (refreshToken) {
        await this.refreshAuthTokens();
      } else {
        // Check for authentication via HTTP-only cookies
        await this.validateCookieAuth();
      }
    } catch (error) {
      console.error('Auth initialization error:', error);
      this.updateAuthState({ 
        isLoading: false, 
        lastError: this.formatError(error) 
      });
    }
  }

  /**
   * Setup security features like automatic token refresh and session monitoring
   */
  private setupSecurityFeatures(): void {
    // Setup automatic token refresh
    this.scheduleTokenRefresh();
    
    // Setup session monitoring
    this.sessionCheckInterval = window.setInterval(() => {
      this.checkSessionValidity();
    }, this.SESSION_CHECK_INTERVAL) as unknown as number;
    
    // Listen for browser visibility changes to refresh tokens when tab becomes active
    document.addEventListener('visibilitychange', () => {
      if (!document.hidden && this.authState.isAuthenticated) {
        this.refreshAuthTokens().catch(console.error);
      }
    });
    
    // Listen for network status changes
    window.addEventListener('online', () => {
      if (this.authState.isAuthenticated) {
        this.refreshAuthTokens().catch(console.error);
      }
    });
  }

  /**
   * Authenticate user with username and password
   */
  public async login(credentials: LoginCredentials): Promise<{ success: boolean; error?: AuthError }> {
    try {
      // Check rate limiting
      if (!this.checkRateLimit('login', credentials.username)) {
        throw new Error('Too many login attempts. Please try again later.');
      }

      this.updateAuthState({ isLoading: true, lastError: null });

      const response = await this.makeAuthRequest('/auth/login', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(credentials)
      });

      if (!response.ok) {
        const errorData = await response.json();
        throw new Error(errorData.detail || 'Login failed');
      }

      const authData = await response.json();
      
      // Store tokens and user data
      this.setAuthTokens(authData.tokens);
      this.updateAuthState({
        isAuthenticated: true,
        isLoading: false,
        user: authData.user,
        tokens: authData.tokens,
        lastError: null
      });

      // Store refresh token if rememberMe is enabled
      if (credentials.rememberMe) {
        this.storeRefreshToken(authData.tokens.refreshToken);
      }

      // Schedule token refresh
      this.scheduleTokenRefresh();

      // Reset rate limiting on successful login
      this.rateLimitMap.delete(`login:${credentials.username}`);

      return { success: true };
    } catch (error) {
      const authError = this.formatError(error);
      this.updateAuthState({ 
        isLoading: false, 
        lastError: authError 
      });
      return { success: false, error: authError };
    }
  }

  /**
   * Register new user account
   */
  public async register(credentials: RegisterCredentials): Promise<{ success: boolean; error?: AuthError }> {
    try {
      // Validate password policy
      const passwordValidation = this.validatePassword(credentials.password, credentials);
      if (!passwordValidation.isValid) {
        throw new Error(passwordValidation.errors.join(', '));
      }

      this.updateAuthState({ isLoading: true, lastError: null });

      const response = await this.makeAuthRequest('/auth/register', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(credentials)
      });

      if (!response.ok) {
        const errorData = await response.json();
        throw new Error(errorData.detail || 'Registration failed');
      }

      this.updateAuthState({ isLoading: false });
      return { success: true };
    } catch (error) {
      const authError = this.formatError(error);
      this.updateAuthState({ 
        isLoading: false, 
        lastError: authError 
      });
      return { success: false, error: authError };
    }
  }

  /**
   * OAuth login with external provider
   */
  public async oauthLogin(provider: string): Promise<void> {
    const oauthUrl = `/auth/oauth/${provider}`;
    
    // Open OAuth popup window
    const popup = window.open(
      oauthUrl,
      `oauth_${provider}`,
      'width=500,height=600,scrollbars=yes,resizable=yes'
    );

    return new Promise((resolve, reject) => {
      const checkClosed = setInterval(() => {
        if (popup?.closed) {
          clearInterval(checkClosed);
          // Check if authentication was successful
          this.validateCookieAuth().then(success => {
            if (success) {
              resolve();
            } else {
              reject(new Error('OAuth authentication failed'));
            }
          });
        }
      }, 1000);

      // Timeout after 5 minutes
      setTimeout(() => {
        clearInterval(checkClosed);
        popup?.close();
        reject(new Error('OAuth authentication timed out'));
      }, 5 * 60 * 1000);
    });
  }

  /**
   * Logout user and cleanup session
   */
  public async logout(): Promise<void> {
    try {
      // Call server logout endpoint
      if (this.authState.tokens?.refreshToken) {
        await this.makeAuthRequest('/auth/logout', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ 
            refreshToken: this.authState.tokens.refreshToken 
          })
        });
      }
    } catch (error) {
      console.warn('Logout request failed:', error);
    }

    this.clearAuthState();
  }

  /**
   * Request password reset email
   */
  public async requestPasswordReset(request: PasswordResetRequest): Promise<{ success: boolean; error?: AuthError }> {
    try {
      const response = await this.makeAuthRequest('/auth/password-reset', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(request)
      });

      if (!response.ok) {
        const errorData = await response.json();
        throw new Error(errorData.detail || 'Password reset request failed');
      }

      return { success: true };
    } catch (error) {
      return { success: false, error: this.formatError(error) };
    }
  }

  /**
   * Confirm password reset with token
   */
  public async confirmPasswordReset(request: PasswordResetConfirm): Promise<{ success: boolean; error?: AuthError }> {
    try {
      // Validate new password
      const passwordValidation = this.validatePassword(request.newPassword);
      if (!passwordValidation.isValid) {
        throw new Error(passwordValidation.errors.join(', '));
      }

      const response = await this.makeAuthRequest('/auth/password-reset/confirm', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(request)
      });

      if (!response.ok) {
        const errorData = await response.json();
        throw new Error(errorData.detail || 'Password reset confirmation failed');
      }

      return { success: true };
    } catch (error) {
      return { success: false, error: this.formatError(error) };
    }
  }

  /**
   * Change user password
   */
  public async changePassword(request: ChangePasswordRequest): Promise<{ success: boolean; error?: AuthError }> {
    try {
      // Validate new password
      const passwordValidation = this.validatePassword(request.newPassword);
      if (!passwordValidation.isValid) {
        throw new Error(passwordValidation.errors.join(', '));
      }

      const response = await this.makeAuthRequest('/auth/password/change', {
        method: 'POST',
        headers: this.getAuthHeaders(),
        body: JSON.stringify(request)
      });

      if (!response.ok) {
        const errorData = await response.json();
        throw new Error(errorData.detail || 'Password change failed');
      }

      return { success: true };
    } catch (error) {
      return { success: false, error: this.formatError(error) };
    }
  }

  /**
   * Get user's active sessions
   */
  public async getSessions(): Promise<SessionInfo[]> {
    try {
      const response = await this.makeAuthRequest('/auth/sessions', {
        headers: this.getAuthHeaders()
      });

      if (!response.ok) {
        throw new Error('Failed to fetch sessions');
      }

      return await response.json();
    } catch (error) {
      console.error('Get sessions error:', error);
      return [];
    }
  }

  /**
   * Revoke a specific session
   */
  public async revokeSession(sessionId: string): Promise<{ success: boolean; error?: AuthError }> {
    try {
      const response = await this.makeAuthRequest(`/auth/sessions/${sessionId}`, {
        method: 'DELETE',
        headers: this.getAuthHeaders()
      });

      if (!response.ok) {
        const errorData = await response.json();
        throw new Error(errorData.detail || 'Session revocation failed');
      }

      return { success: true };
    } catch (error) {
      return { success: false, error: this.formatError(error) };
    }
  }

  /**
   * Get available OAuth providers
   */
  public async getOAuthProviders(): Promise<OAuthProvider[]> {
    try {
      const response = await this.makeAuthRequest('/auth/oauth/providers');
      
      if (!response.ok) {
        throw new Error('Failed to fetch OAuth providers');
      }

      return await response.json();
    } catch (error) {
      console.error('Get OAuth providers error:', error);
      return [];
    }
  }

  // Utility methods for authentication state management
  private async refreshAuthTokens(): Promise<boolean> {
    try {
      const refreshToken = this.authState.tokens?.refreshToken || this.getStoredRefreshToken();
      if (!refreshToken) {
        return false;
      }

      const response = await this.makeAuthRequest('/auth/refresh', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ refreshToken })
      });

      if (!response.ok) {
        if (response.status === 401) {
          // Refresh token is invalid, clear auth state
          this.clearAuthState();
          return false;
        }
        throw new Error('Token refresh failed');
      }

      const authData = await response.json();
      this.setAuthTokens(authData.tokens);
      this.updateAuthState({
        isAuthenticated: true,
        isLoading: false,
        user: authData.user,
        tokens: authData.tokens,
        lastError: null
      });

      this.scheduleTokenRefresh();
      return true;
    } catch (error) {
      console.error('Token refresh error:', error);
      this.clearAuthState();
      return false;
    }
  }

  private async validateCookieAuth(): Promise<boolean> {
    try {
      const response = await this.makeAuthRequest('/users/me', {
        credentials: 'include'
      });

      if (!response.ok) {
        return false;
      }

      const userData = await response.json();
      this.updateAuthState({
        isAuthenticated: true,
        isLoading: false,
        user: userData,
        tokens: null, // Using cookie-based auth
        lastError: null
      });

      return true;
    } catch (error) {
      console.error('Cookie auth validation error:', error);
      return false;
    }
  }

  private scheduleTokenRefresh(): void {
    if (this.refreshTimer) {
      window.clearTimeout(this.refreshTimer);
    }

    if (!this.authState.tokens) {
      return;
    }

    const timeUntilRefresh = this.authState.tokens.expiresAt - Date.now() - this.REFRESH_BUFFER_TIME;
    
    if (timeUntilRefresh > 0) {
      this.refreshTimer = window.setTimeout(() => {
        this.refreshAuthTokens().catch(console.error);
      }, timeUntilRefresh) as unknown as number;
    } else {
      // Token expires soon, refresh immediately
      this.refreshAuthTokens().catch(console.error);
    }
  }

  private async checkSessionValidity(): Promise<void> {
    if (!this.authState.isAuthenticated) {
      return;
    }

    try {
      const response = await this.makeAuthRequest('/auth/session/validate', {
        headers: this.getAuthHeaders()
      });

      if (!response.ok) {
        // Session is invalid, logout user
        this.clearAuthState();
      }
    } catch (error) {
      console.error('Session validation error:', error);
    }
  }

  private checkRateLimit(action: string, identifier: string): boolean {
    const key = `${action}:${identifier}`;
    const now = Date.now();
    const limit = this.rateLimitMap.get(key);

    if (!limit) {
      this.rateLimitMap.set(key, { count: 1, resetTime: now + this.RATE_LIMIT_WINDOW });
      return true;
    }

    if (now > limit.resetTime) {
      // Reset the limit
      this.rateLimitMap.set(key, { count: 1, resetTime: now + this.RATE_LIMIT_WINDOW });
      return true;
    }

    if (limit.count >= this.RATE_LIMIT_ATTEMPTS) {
      return false;
    }

    limit.count++;
    return true;
  }

  private validatePassword(password: string, userData?: Partial<RegisterCredentials>): { isValid: boolean; errors: string[] } {
    const errors: string[] = [];
    const policy = this.PASSWORD_POLICY;

    if (password.length < policy.minLength) {
      errors.push(`Password must be at least ${policy.minLength} characters long`);
    }

    if (password.length > policy.maxLength) {
      errors.push(`Password must be no more than ${policy.maxLength} characters long`);
    }

    if (policy.requireUppercase && !/[A-Z]/.test(password)) {
      errors.push('Password must contain at least one uppercase letter');
    }

    if (policy.requireLowercase && !/[a-z]/.test(password)) {
      errors.push('Password must contain at least one lowercase letter');
    }

    if (policy.requireNumbers && !/\d/.test(password)) {
      errors.push('Password must contain at least one number');
    }

    if (policy.requireSpecialChars && !/[!@#$%^&*()_+\-=\[\]{};':"\\|,.<>\/?]/.test(password)) {
      errors.push('Password must contain at least one special character');
    }

    if (policy.preventCommonPasswords && this.isCommonPassword(password)) {
      errors.push('This password is too common. Please choose a more unique password');
    }

    if (policy.preventPersonalInfo && userData) {
      const personalInfo = [userData.username, userData.email, userData.fullName].filter(Boolean);
      for (const info of personalInfo) {
        if (info && password.toLowerCase().includes(info.toLowerCase())) {
          errors.push('Password should not contain personal information');
          break;
        }
      }
    }

    return { isValid: errors.length === 0, errors };
  }

  private isCommonPassword(password: string): boolean {
    // List of common passwords - in production, this should be a more comprehensive list
    const commonPasswords = [
      'password', '123456', '123456789', 'qwerty', 'abc123', 'password123',
      'admin', 'letmein', 'welcome', 'monkey', '1234567890', 'password1'
    ];
    
    return commonPasswords.includes(password.toLowerCase());
  }

  private setAuthTokens(tokens: AuthTokens): void {
    // Set authorization header for future requests
    if (tokens.accessToken) {
      localStorage.setItem('auth_access_token', tokens.accessToken);
    }
  }

  private getStoredRefreshToken(): string | null {
    return localStorage.getItem('auth_refresh_token');
  }

  private storeRefreshToken(refreshToken: string): void {
    localStorage.setItem('auth_refresh_token', refreshToken);
  }

  private clearAuthState(): void {
    // Clear timers
    if (this.refreshTimer) {
      window.clearTimeout(this.refreshTimer);
      this.refreshTimer = null;
    }

    // Clear stored tokens
    localStorage.removeItem('auth_access_token');
    localStorage.removeItem('auth_refresh_token');

    // Update auth state
    this.updateAuthState({
      isAuthenticated: false,
      isLoading: false,
      user: null,
      tokens: null,
      lastError: null
    });

    // Clear cookies
    document.cookie = 'token=; expires=Thu, 01 Jan 1970 00:00:00 UTC; path=/; SameSite=Strict; Secure';
  }

  private updateAuthState(updates: Partial<AuthState>): void {
    this.authState = { ...this.authState, ...updates };
    this.notifyListeners();
  }

  private notifyListeners(): void {
    this.listeners.forEach(listener => {
      try {
        listener(this.authState);
      } catch (error) {
        console.error('Auth state listener error:', error);
      }
    });
  }

  private getAuthHeaders(): Record<string, string> {
    const headers: Record<string, string> = {
      'Content-Type': 'application/json'
    };

    if (this.authState.tokens?.accessToken) {
      headers.Authorization = `Bearer ${this.authState.tokens.accessToken}`;
    }

    return headers;
  }

  private async makeAuthRequest(url: string, options: RequestInit = {}): Promise<Response> {
    const defaultOptions: RequestInit = {
      credentials: 'include',
      headers: {
        'Content-Type': 'application/json',
        'X-Requested-With': 'XMLHttpRequest' // CSRF protection
      }
    };

    const mergedOptions = {
      ...defaultOptions,
      ...options,
      headers: {
        ...defaultOptions.headers,
        ...options.headers
      }
    };

    // Ensure absolute URL for test environments (Node.js fetch doesn't handle relative URLs)
    const absoluteUrl = url.startsWith('http') 
      ? url 
      : typeof window !== 'undefined'
        ? `${window.location.protocol}//${window.location.hostname}:${window.location.port}${url}`
        : `http://localhost:12345${url}`;

    return fetch(absoluteUrl, mergedOptions);
  }

  private formatError(error: any): AuthError {
    if (error instanceof Error) {
      return {
        code: 'AUTH_ERROR',
        message: error.message
      };
    }

    if (typeof error === 'string') {
      return {
        code: 'AUTH_ERROR',
        message: error
      };
    }

    return {
      code: 'UNKNOWN_ERROR',
      message: 'An unexpected error occurred'
    };
  }

  // Public getters and utility methods
  public getAuthState(): AuthState {
    return { ...this.authState };
  }

  public getCurrentUser(): User | null {
    return this.authState.user;
  }

  public isAuthenticated(): boolean {
    return this.authState.isAuthenticated;
  }

  public hasPermission(permission: Permission): boolean {
    return this.authState.user?.permissions.includes(permission) || false;
  }

  public hasRole(role: UserRole): boolean {
    return this.authState.user?.role === role;
  }

  public hasAnyRole(roles: UserRole[]): boolean {
    return roles.includes(this.authState.user?.role as UserRole);
  }

  public subscribe(listener: (state: AuthState) => void): () => void {
    this.listeners.push(listener);
    
    // Return unsubscribe function
    return () => {
      const index = this.listeners.indexOf(listener);
      if (index > -1) {
        this.listeners.splice(index, 1);
      }
    };
  }

  public cleanup(): void {
    if (this.refreshTimer) {
      window.clearTimeout(this.refreshTimer);
    }
    
    if (this.sessionCheckInterval) {
      window.clearInterval(this.sessionCheckInterval);
    }
    
    this.listeners.length = 0;
  }
}

// Export singleton instance
export const enhancedAuthService = EnhancedAuthService.getInstance();

// Export utility functions for role and permission checking
export const withAuth = <T extends {}>(
  component: React.ComponentType<T>
): React.ComponentType<T> => {
  return (props: T) => {
    const authState = enhancedAuthService.getAuthState();
    
    if (!authState.isAuthenticated) {
      // Redirect to login or show auth required message
      return null;
    }
    
    return React.createElement(component, props);
  };
};

export const withRole = <T extends {}>(
  component: React.ComponentType<T>,
  requiredRole: UserRole
): React.ComponentType<T> => {
  return (props: T) => {
    const authState = enhancedAuthService.getAuthState();
    
    if (!authState.isAuthenticated || authState.user?.role !== requiredRole) {
      return null; // Or show access denied message
    }
    
    return React.createElement(component, props);
  };
};

export const withPermission = <T extends {}>(
  component: React.ComponentType<T>,
  requiredPermission: Permission
): React.ComponentType<T> => {
  return (props: T) => {
    const authState = enhancedAuthService.getAuthState();
    
    if (!authState.isAuthenticated || !authState.user?.permissions.includes(requiredPermission)) {
      return null; // Or show access denied message
    }
    
    return React.createElement(component, props);
  };
};

import { useGameStore } from '@/store';
import { useRenderEngine } from '@features/canvas';
import { isDM } from '@features/session/types/roles';
import { AlertTriangle, Check } from 'lucide-react';
import { useEffect, useState } from 'react';

interface SyncState {
  status: 'idle' | 'syncing' | 'error' | 'success';
  error?: string;
  lastSync?: Date;
  progress?: number;
}

export function EntitiesPanel() {
  const { sprites, selectedSprites, selectSprite, addSprite, removeSprite, updateSprite } = useGameStore()
  const sessionRole = useGameStore(s => s.sessionRole);
  const visibleLayers = useGameStore(s => s.visibleLayers);
  const renderEngine = useRenderEngine();
  const [syncState, setSyncState] = useState<SyncState>({ status: 'idle' })

  // Validate and transform sprite data from WASM
  const validateAndTransformSprite = (rustSprite: any) => {
    if (!rustSprite || typeof rustSprite !== 'object') {
      throw new Error('Invalid sprite data object');
    }

    const spriteId = rustSprite.id || rustSprite.sprite_id;
    if (!spriteId) {
      throw new Error('Missing sprite ID');
    }

    return {
      id: String(spriteId),
      name: rustSprite.name || rustSprite.sprite_name || `Sprite ${spriteId}`,
      x: Number(rustSprite.x || rustSprite.world_x || 0),
      y: Number(rustSprite.y || rustSprite.world_y || 0),
      width: Number(rustSprite.width || rustSprite.size_x || 50),
      height: Number(rustSprite.height || rustSprite.size_y || 50),
      layer: String(rustSprite.layer || 'tokens'),
      isSelected: Boolean(rustSprite.isSelected || false),
      isVisible: rustSprite.visible !== false,
    };
  };

  // Function to manually sync sprites from Rust backend with comprehensive error handling
  const syncSpritesFromRust = async () => {
    setSyncState({ status: 'syncing', progress: 0 });
    
    try {
      // Validate WASM availability
      const engine = renderEngine || (window as any).rustRenderManager;
      if (!engine) {
        throw new Error('WASM render manager not available');
      }

      setSyncState(prev => ({ ...prev, progress: 25 }));

      // Get sprites with error handling
      const rustSprites = engine.get_all_sprites_network_data();
      
      if (!Array.isArray(rustSprites)) {
        throw new Error('Invalid sprite data format from WASM');
      }
      
      setSyncState(prev => ({ ...prev, progress: 50 }));
      
      // Process sprites with validation
      const processedSprites: any[] = [];
      const errors: string[] = [];
      
      for (const rustSprite of rustSprites) {
        try {
          const sprite = validateAndTransformSprite(rustSprite);
          processedSprites.push(sprite);
        } catch (error) {
          errors.push(`Sprite ${rustSprite.id}: ${error instanceof Error ? error.message : 'Invalid data'}`);
        }
      }
      
      setSyncState(prev => ({ ...prev, progress: 75 }));
      
      // Create a map of existing sprites for efficient lookup
      const existingSprites = new Map(sprites.map(s => [s.id, s]))
      const rustSpriteIds = new Set()
      
      // Process each validated sprite
      processedSprites.forEach((sprite) => {
        rustSpriteIds.add(sprite.id)
        
        if (existingSprites.has(sprite.id)) {
          // Update existing sprite
          updateSprite(sprite.id, sprite)
        } else {
          // Add new sprite
          addSprite(sprite)
        }
      })
      
      // Remove sprites that no longer exist in Rust
      sprites.forEach(sprite => {
        if (!rustSpriteIds.has(sprite.id)) {
          removeSprite(sprite.id)
        }
      })

      setSyncState({
        status: 'success',
        lastSync: new Date(),
        progress: 100
      });
      
      if (errors.length > 0) {
        console.warn('Sprite sync completed with warnings:', errors);
      }
      
      console.log(`[EntitiesPanel] Successfully synced ${processedSprites.length} sprites from Rust`)
      
    } catch (error) {
      setSyncState({
        status: 'error',
        error: error instanceof Error ? error.message : 'Unknown sync error',
        progress: 0
      });
      console.error('[EntitiesPanel] Error syncing sprites:', error)
    }
  }

  // Auto-sync on mount and when sprite events occur
  useEffect(() => {
    syncSpritesFromRust()
    
    // Listen for custom sprite addition events
    const handleSpriteAdded = () => {
      setTimeout(syncSpritesFromRust, 500) // Small delay to ensure sprite is processed
    }
    
    window.addEventListener('spriteAdded', handleSpriteAdded)
    
    return () => {
      window.removeEventListener('spriteAdded', handleSpriteAdded)
    }
  }, []) // Remove dependencies to avoid constant re-syncing

  return (
    <div className="entities-section" style={{ background: 'transparent' }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <h2>Entities ({sprites.length})</h2>
        <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
          {syncState.status === 'error' && (
            <span style={{ color: 'red', fontSize: '12px', display: 'inline-flex', alignItems: 'center', gap: '4px' }} title={syncState.error}>
              <AlertTriangle size={12} aria-hidden /> Sync Error
            </span>
          )}
          {syncState.status === 'success' && syncState.lastSync && (
            <span style={{ color: 'green', fontSize: '12px', display: 'inline-flex', alignItems: 'center', gap: '4px' }}>
              <Check size={12} aria-hidden /> {new Date(syncState.lastSync).toLocaleTimeString()}
            </span>
          )}
          <button 
            onClick={syncSpritesFromRust}
            disabled={syncState.status === 'syncing'}
            style={{ 
              padding: '4px 8px', 
              fontSize: '12px',
              opacity: syncState.status === 'syncing' ? 0.6 : 1,
              cursor: syncState.status === 'syncing' ? 'wait' : 'pointer'
            }}
          >
            {syncState.status === 'syncing' ? (
              syncState.progress ? `Syncing... ${syncState.progress}%` : 'Syncing...'
            ) : 'Refresh'}
          </button>
        </div>
      </div>
      
      <div className="sprite-list">
        {(() => {
          const visibleSprites = isDM(sessionRole)
            ? sprites
            : sprites.filter(s => {
                if (visibleLayers.length > 0 && !visibleLayers.includes(s.layer)) return false;
                return s.isVisible !== false;
              });
          return visibleSprites.length === 0 ? (
          <div style={{ color: 'var(--text-muted)', textAlign: 'center', padding: '2rem' }}>
            {syncState.status === 'syncing' ? (
              <div>
                <div>Syncing sprites...</div>
                {syncState.progress && (
                  <div style={{ 
                    width: '100%', 
                    height: '4px', 
                    backgroundColor: 'var(--bg-tertiary)', 
                    borderRadius: '2px',
                    marginTop: '8px',
                    overflow: 'hidden'
                  }}>
                    <div style={{
                      width: `${syncState.progress}%`,
                      height: '100%',
                      backgroundColor: 'var(--color-primary)',
                      transition: 'width 0.3s ease'
                    }} />
                  </div>
                )}
              </div>
            ) : (
              <p>No sprites on the map</p>
            )}
          </div>
        ) : (
          visibleSprites.map((sprite) => {
            // Provide fallback for scale if missing
            const scale = sprite.scale && typeof sprite.scale.x === 'number' && typeof sprite.scale.y === 'number'
              ? sprite.scale
              : { x: 1, y: 1 };
            return (
              <div
                key={sprite.id}
                className={`sprite-item ${selectedSprites.includes(sprite.id) ? 'selected' : ''}`}
                onClick={() => selectSprite(sprite.id)}
              >
                <h3>{sprite.name} ({sprite.id})</h3>
                <p>Position: ({sprite.x}, {sprite.y})</p>
                <p>Layer: {sprite.layer}</p>
                <p>Scale: {scale.x.toFixed(2)} x {scale.y.toFixed(2)}</p>
              </div>
            );
          })
        );
        })()}
      </div>
    </div>
  )
}

import { useGameStore } from '@/store';
import { isDM } from '@features/session/types/roles';
import { BrickWall, CloudFog, Crown, Lightbulb, Map, Mountain, Users } from 'lucide-react';
import { useEffect, useState } from 'react';
import styles from './FloatingLayerPicker.module.css';

const LAYERS = [
  { id: 'map',            label: 'Map',     Icon: Map,       hotkey: '1' },
  { id: 'tokens',         label: 'Tokens',  Icon: Users,     hotkey: '2' },
  { id: 'dungeon_master', label: 'DM',      Icon: Crown,     hotkey: '3' },
  { id: 'light',          label: 'Light',   Icon: Lightbulb, hotkey: '4' },
  { id: 'height',         label: 'Height',  Icon: Mountain,  hotkey: '5' },
  { id: 'obstacles',      label: 'Walls',   Icon: BrickWall, hotkey: '6' },
  { id: 'fog_of_war',     label: 'Fog',     Icon: CloudFog,  hotkey: '7' },
] as const;

export function FloatingLayerPicker() {
  const sessionRole = useGameStore(s => s.sessionRole);
  const activeLayer = useGameStore(s => s.activeLayer);
  const setActiveLayer = useGameStore(s => s.setActiveLayer);
  // Track DM status in local state so we re-render after WS role arrives
  const [dmConfirmed, setDmConfirmed] = useState(false);

  useEffect(() => {
    // Check on mount using injected initial data (before WS welcome)
    const initial = (window as any).__INITIAL_DATA__?.userRole ?? null;
    if (isDM(initial)) setDmConfirmed(true);
  }, []);

  useEffect(() => {
    if (isDM(sessionRole)) setDmConfirmed(true);
  }, [sessionRole]);

  if (!dmConfirmed) return null;

  const switchLayer = (id: string) => {
    setActiveLayer(id);
    const rm = (window as any).rustRenderManager;
    if (rm?.set_active_layer) rm.set_active_layer(id);
  };

  const active = LAYERS.find(l => l.id === activeLayer);

  return (
    <div className={styles.picker} role="toolbar" aria-label="Layer switcher">
      {LAYERS.map(({ id, label, Icon, hotkey }) => (
        <button
          key={id}
          className={`${styles.btn} ${activeLayer === id ? styles.active : ''}`}
          onClick={() => switchLayer(id)}
          title={`${label} [${hotkey}]`}
          aria-pressed={activeLayer === id}
          aria-label={`Switch to ${label} layer`}
        >
          <Icon size={14} aria-hidden />
        </button>
      ))}
      {active && <span className={styles.label}>{active.label}</span>}
    </div>
  );
}

