        >
          <div>
            <b>FPS:</b> <span style={{ color: fps > 30 ? '#0f0' : fps > 15 ? '#ff0' : '#f00' }}>{fps}</span>
          </div>
          <div>
            <b>Canvas CSS:</b> {debugPanel.cssWidth} x {debugPanel.cssHeight}
          </div>
          <div>
            <b>Canvas Device:</b> {debugPanel.deviceWidth} x {debugPanel.deviceHeight}
          </div>
          <div>
