export interface TextSpriteConfig {
  text: string;
  fontSize: number;
  fontFamily: string;
  fontWeight: string;
  color: string;
  backgroundColor: string;
  hasBackground: boolean;
  textAlign: 'left' | 'center' | 'right';
  opacity: number;
  rotation: number;
  borderWidth: number;
  borderColor: string;
  hasBorder: boolean;
  padding: number;
  lineHeight: number;
  letterSpacing: number;
  textShadow: boolean;
  shadowColor: string;
  shadowBlur: number;
  shadowOffsetX: number;
  shadowOffsetY: number;
}

interface TextSpriteCreatorProps {
  isOpen: boolean;
  onClose: () => void;
  onCreateSprite: (config: TextSpriteConfig, position: { x: number; y: number }) => void;
  activeLayer: string;
  initialPosition?: { x: number; y: number };
  initialConfig?: TextSpriteConfig;
  title?: string;
  createButtonText?: string;
  showDeleteButton?: boolean;
  onDelete?: () => void;
  isDeleting?: boolean;
}

export function TextSpriteCreator({ 
  isOpen, 
  onClose, 
  onCreateSprite, 
  activeLayer,
  initialPosition = { x: 100, y: 100 },
  initialConfig,
  title = "Create Text Sprite",
  createButtonText = "Create Text Sprite",
  showDeleteButton = false,
  onDelete,
  isDeleting = false
}: TextSpriteCreatorProps) {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  
  const [config, setConfig] = useState<TextSpriteConfig>(initialConfig || {
    text: 'Sample Text',
    fontSize: 24,
    fontFamily: 'Arial',
    fontWeight: 'normal',
    color: '#000000',
    backgroundColor: '#ffffff',
    hasBackground: false,
    textAlign: 'left',
    opacity: 1.0,
    rotation: 0,
    borderWidth: 1,
    borderColor: '#000000',
    hasBorder: false,
    padding: 8,
    lineHeight: 1.2,
    letterSpacing: 0,
    textShadow: false,
    shadowColor: '#000000',
    shadowBlur: 2,
    shadowOffsetX: 1,
    shadowOffsetY: 1,
  });

  const [position, setPosition] = useState(initialPosition);

  // Update preview when config changes
  useEffect(() => {
    updatePreview();
  }, [config]);

  const updatePreview = useCallback(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    // Calculate text metrics
    const font = `${config.fontWeight} ${config.fontSize}px ${config.fontFamily}`;
    ctx.font = font;
    
    const lines = config.text.split('\n');
    const lineHeight = config.fontSize * config.lineHeight;
    const textMetrics = lines.map(line => ctx.measureText(line));
    const maxWidth = Math.max(...textMetrics.map(m => m.width));
    const textHeight = lines.length * lineHeight;

    // Calculate canvas dimensions with padding
    const totalPadding = config.padding * 2;
    const canvasWidth = Math.max(50, maxWidth + totalPadding + (config.hasBorder ? config.borderWidth * 2 : 0));
    const canvasHeight = Math.max(30, textHeight + totalPadding + (config.hasBorder ? config.borderWidth * 2 : 0));

    // Set canvas size
    canvas.width = canvasWidth;
    canvas.height = canvasHeight;

    // Clear canvas
    ctx.clearRect(0, 0, canvasWidth, canvasHeight);

    // Apply rotation transform
    if (config.rotation !== 0) {
      ctx.save();
      ctx.translate(canvasWidth / 2, canvasHeight / 2);
      ctx.rotate((config.rotation * Math.PI) / 180);
      ctx.translate(-canvasWidth / 2, -canvasHeight / 2);
    }

    // Draw background
    if (config.hasBackground) {
      ctx.fillStyle = config.backgroundColor;
      ctx.globalAlpha = config.opacity;
      const bgX = config.hasBorder ? config.borderWidth : 0;
      const bgY = config.hasBorder ? config.borderWidth : 0;
      const bgWidth = canvasWidth - (config.hasBorder ? config.borderWidth * 2 : 0);
      const bgHeight = canvasHeight - (config.hasBorder ? config.borderWidth * 2 : 0);
      ctx.fillRect(bgX, bgY, bgWidth, bgHeight);
    }

    // Draw border
    if (config.hasBorder) {
      ctx.strokeStyle = config.borderColor;
      ctx.lineWidth = config.borderWidth;
      ctx.globalAlpha = config.opacity;
      ctx.strokeRect(config.borderWidth / 2, config.borderWidth / 2, 
                    canvasWidth - config.borderWidth, canvasHeight - config.borderWidth);
    }

    // Configure text rendering
    ctx.font = font;
    ctx.fillStyle = config.color;
    ctx.globalAlpha = config.opacity;
    ctx.textBaseline = 'top';

    // Apply text shadow
    if (config.textShadow) {
      ctx.shadowColor = config.shadowColor;
      ctx.shadowBlur = config.shadowBlur;
      ctx.shadowOffsetX = config.shadowOffsetX;
      ctx.shadowOffsetY = config.shadowOffsetY;
    } else {
      ctx.shadowColor = 'transparent';
      ctx.shadowBlur = 0;
      ctx.shadowOffsetX = 0;
      ctx.shadowOffsetY = 0;
    }

    // Apply letter spacing (if supported)
    if (config.letterSpacing !== 0) {
      ctx.letterSpacing = `${config.letterSpacing}px`;
    }

    // Draw text lines
    const startX = config.padding + (config.hasBorder ? config.borderWidth : 0);
    const startY = config.padding + (config.hasBorder ? config.borderWidth : 0);

    lines.forEach((line, index) => {
      let x = startX;
      const y = startY + (index * lineHeight);

      // Apply text alignment
      if (config.textAlign === 'center') {
        x = (canvasWidth - ctx.measureText(line).width) / 2;
      } else if (config.textAlign === 'right') {
        x = canvasWidth - startX - ctx.measureText(line).width;
      }

      ctx.fillText(line, x, y);
    });

    // Restore transformation if rotation was applied
    if (config.rotation !== 0) {
      ctx.restore();
    }
  }, [config]);

  const handleCreate = useCallback(() => {
    onCreateSprite(config, position);
    onClose();
  }, [config, position, onCreateSprite, onClose]);

  const updateConfig = <K extends keyof TextSpriteConfig>(
    key: K, 
    value: TextSpriteConfig[K]
  ) => {
    setConfig(prev => ({ ...prev, [key]: value }));
  };

  return (
    <Modal
      isOpen={isOpen}
      onClose={onClose}
      title={title}
      size="large"
      closeOnEscape={true}
    >
      <ErrorBoundary>
        <div className={styles.textSpriteCreator}>
          <div className="creator-layout">
            {/* Left panel - Controls */}
            <div className="controls-panel">
              <div className="control-section">
                <h3 className={styles['control-section-title']}>Text Content</h3>
                <div className="control-group">
                  <label htmlFor="text-content">Text:</label>
                  <textarea
                    id="text-content"
                    value={config.text}
                    onChange={(e) => updateConfig('text', e.target.value)}
                    placeholder="Enter your text..."
                    rows={3}
                    className="text-input"
                  />
                </div>
              </div>

              <div className="control-section">
                <h3 className={styles['control-section-title']}>Typography</h3>
                <div className="control-row">
                  <div className="control-group">
                    <label htmlFor="font-family">Font:</label>
                    <select
                      id="font-family"
                      value={config.fontFamily}
                      onChange={(e) => updateConfig('fontFamily', e.target.value)}
                    >
                      {FONT_FAMILIES.map(font => (
                        <option key={font} value={font}>{font}</option>
                      ))}
                    </select>
                  </div>
                  <div className="control-group">
                    <label htmlFor="font-weight">Weight:</label>
                    <select
                      id="font-weight"
                      value={config.fontWeight}
                      onChange={(e) => updateConfig('fontWeight', e.target.value)}
                    >
                      {FONT_WEIGHTS.map(weight => (
                        <option key={weight.value} value={weight.value}>
                          {weight.label}
                        </option>
                      ))}
                    </select>
                  </div>
                </div>
                
                <div className="control-row">
                  <div className="control-group">
                    <label htmlFor="font-size">Size: {config.fontSize}px</label>
                    <input
                      id="font-size"
                      type="range"
                      min="8"
                      max="128"
                      step="1"
                      value={config.fontSize}
                      onChange={(e) => updateConfig('fontSize', parseInt(e.target.value))}
                    />
                  </div>
                  <div className="control-group">
                    <label htmlFor="line-height">Line Height: {config.lineHeight}x</label>
                    <input
                      id="line-height"
                      type="range"
                      min="0.5"
                      max="3"
                      step="0.1"
                      value={config.lineHeight}
                      onChange={(e) => updateConfig('lineHeight', parseFloat(e.target.value))}
                    />
                  </div>
                </div>

                <div className="control-group">
                  <label>Alignment:</label>
                  <div className="alignment-buttons">
                    {TEXT_ALIGNMENTS.map(align => (
                      <button
                        key={align.value}
                        type="button"
                        className={`align-btn ${config.textAlign === align.value ? 'active' : ''}`}
                        onClick={() => updateConfig('textAlign', align.value)}
                        title={align.label}
                      >
                        {ALIGN_ICONS[align.value]}
                      </button>
                    ))}
                  </div>
                </div>
              </div>

              <div className="control-section">
                <h3 className={styles['control-section-title']}>Colors & Effects</h3>
                <div className="control-row">
                  <div className="control-group">
                    <label htmlFor="text-color">Text Color:</label>
                    <input
                      id="text-color"
                      type="color"
                      value={config.color}
                      onChange={(e) => updateConfig('color', e.target.value)}
                    />
                  </div>
                  <div className="control-group">
                    <label htmlFor="opacity">Opacity: {Math.round(config.opacity * 100)}%</label>
                    <input
                      id="opacity"
                      type="range"
                      min="0"
                      max="1"
                      step="0.05"
                      value={config.opacity}
                      onChange={(e) => updateConfig('opacity', parseFloat(e.target.value))}
                    />
                  </div>
                </div>

                <div className="control-group">
                  <label>
                    <input
                      type="checkbox"
                      checked={config.hasBackground}
                      onChange={(e) => updateConfig('hasBackground', e.target.checked)}
                    />
                    Background
                  </label>
                  {config.hasBackground && (
                    <input
                      type="color"
                      value={config.backgroundColor}
                      onChange={(e) => updateConfig('backgroundColor', e.target.value)}
                      className="color-input"
                    />
                  )}
                </div>

                <div className="control-group">
                  <label>
                    <input
                      type="checkbox"
                      checked={config.hasBorder}
                      onChange={(e) => updateConfig('hasBorder', e.target.checked)}
                    />
                    Border
                  </label>
                  {config.hasBorder && (
                    <div className="control-row">
                      <input
                        type="color"
                        value={config.borderColor}
                        onChange={(e) => updateConfig('borderColor', e.target.value)}
                        className="color-input"
                      />
                      <input
                        type="range"
                        min="1"
                        max="10"
                        value={config.borderWidth}
                        onChange={(e) => updateConfig('borderWidth', parseInt(e.target.value))}
                        title={`Width: ${config.borderWidth}px`}
                      />
                    </div>
                  )}
                </div>

                <div className="control-group">
                  <label>
                    <input
                      type="checkbox"
                      checked={config.textShadow}
                      onChange={(e) => updateConfig('textShadow', e.target.checked)}
                    />
                    Text Shadow
                  </label>
                  {config.textShadow && (
                    <div className="shadow-controls">
                      <input
                        type="color"
                        value={config.shadowColor}
                        onChange={(e) => updateConfig('shadowColor', e.target.value)}
                        title="Shadow Color"
                      />
                      <input
                        type="range"
                        min="0"
                        max="10"
                        value={config.shadowBlur}
                        onChange={(e) => updateConfig('shadowBlur', parseInt(e.target.value))}
                        title={`Blur: ${config.shadowBlur}px`}
                      />
                    </div>
                  )}
                </div>
              </div>

              <div className="control-section">
                <h3 className={styles['control-section-title']}>Transform</h3>
                <div className="control-group">
                  <label htmlFor="rotation">Rotation: {config.rotation}┬░</label>
                  <input
                    id="rotation"
                    type="range"
                    min="-180"
                    max="180"
                    step="5"
                    value={config.rotation}
                    onChange={(e) => updateConfig('rotation', parseInt(e.target.value))}
                  />
                </div>
                <div className="control-group">
                  <label htmlFor="padding">Padding: {config.padding}px</label>
                  <input
                    id="padding"
                    type="range"
                    min="0"
                    max="50"
                    step="1"
                    value={config.padding}
                    onChange={(e) => updateConfig('padding', parseInt(e.target.value))}
                  />
                </div>
              </div>

              <div className="control-section">
                <h3 className={styles['control-section-title']}>Position</h3>
                <div className="control-row">
                  <div className="control-group">
                    <label htmlFor="pos-x">X:</label>
                    <input
                      id="pos-x"
                      type="number"
                      value={position.x}
                      onChange={(e) => setPosition(prev => ({ ...prev, x: parseInt(e.target.value) || 0 }))}
                    />
                  </div>
                  <div className="control-group">
                    <label htmlFor="pos-y">Y:</label>
                    <input
                      id="pos-y"
                      type="number"
                      value={position.y}
                      onChange={(e) => setPosition(prev => ({ ...prev, y: parseInt(e.target.value) || 0 }))}
                    />
                  </div>
                </div>
              </div>
            </div>

            {/* Right panel - Preview */}
            <div className="preview-panel">
              <h3 className={styles['preview-panel-title']}>Preview</h3>
              <div className="preview-container">
                <canvas
                  ref={canvasRef}
                  className="text-preview"
                  style={{
                    border: '1px solid #ddd',
                    borderRadius: '4px',
                    maxWidth: '100%',
                    maxHeight: '300px'
                  }}
                />
              </div>
              <div className="preview-info">
                <small>Layer: <strong>{activeLayer}</strong></small>
              </div>
            </div>
          </div>

          {/* Action buttons */}
          <div className="creator-actions">
            {showDeleteButton && onDelete && (
              <button
                type="button"
                onClick={onDelete}
                className="btn-delete"
                disabled={isDeleting}
                style={{
                  background: '#dc3545',
                  color: 'white',
                  padding: '0.75rem 1.5rem',
                  border: 'none',
                  borderRadius: '6px',
                  fontSize: '0.875rem',
                  fontWeight: '500',
                  cursor: isDeleting ? 'wait' : 'pointer',
                  opacity: isDeleting ? 0.6 : 1
                }}
              >
                {isDeleting ? 'Deleting...' : 'Delete Sprite'}
              </button>
            )}
            <div style={{ flex: 1 }} />
            <button
              type="button"
              onClick={onClose}
              className="btn-cancel"
            >
              Cancel
            </button>
            <button
              type="button"
              onClick={handleCreate}
              className="btn-create"
              disabled={!config.text.trim()}
            >
              {createButtonText}
            </button>
          </div>
        </div>
      </ErrorBoundary>
    </Modal>
  );
}

import clsx from 'clsx';
import { Check, X } from 'lucide-react';
import { useEffect, useRef, useState } from 'react';
import styles from './TextSpriteEditor.module.css';

interface TextSpriteEditorProps {
  position: { x: number; y: number } | null;
  onComplete: (config: TextSpriteConfig) => void;
  onCancel: () => void;
}

export interface TextSpriteConfig {
  text: string;
  fontSize: number;
  color: string;
  bold: boolean;
}

export function TextSpriteEditor({ position, onComplete, onCancel }: TextSpriteEditorProps) {
  const [text, setText] = useState('');
  const [fontSize, setFontSize] = useState(24);
  const [color, setColor] = useState('#ffffff');
  const [bold, setBold] = useState(false);
  const [screenPos, setScreenPos] = useState<{ x: number; y: number } | null>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  // Convert world coordinates to screen coordinates
  useEffect(() => {
    console.log('[TextSpriteEditor] useEffect triggered, position:', position);
    
    if (!position) {
      console.log('[TextSpriteEditor] No position, setting screenPos to null');
      setScreenPos(null);
      return;
    }

    const rustManager = (window as any).rustRenderManager;
    if (!rustManager) {
      console.error('[TextSpriteEditor] Rust render manager not available');
      return;
    }

    console.log('[TextSpriteEditor] rustManager available, converting coords');

    try {
      const canvas = document.querySelector('.game-canvas') as HTMLCanvasElement;
      if (!canvas) {
        console.error('[TextSpriteEditor] Canvas not found!');
        return;
      }

      console.log('[TextSpriteEditor] Canvas found, getting bounds');
      const rect = canvas.getBoundingClientRect();
      console.log('[TextSpriteEditor] Canvas rect:', rect);
      
      const screenCoords = rustManager.world_to_screen(position.x, position.y);
      console.log('[TextSpriteEditor] Screen coords from Rust:', screenCoords);
      
      const finalPos = {
        x: rect.left + screenCoords.x,
        y: rect.top + screenCoords.y
      };
      console.log('[TextSpriteEditor] Final screen position:', finalPos);
      
      setScreenPos(finalPos);
    } catch (error) {
      console.error('[TextSpriteEditor] Error converting world to screen coords:', error);
    }
  }, [position]);

  // Auto-focus input when editor appears
  useEffect(() => {
    if (screenPos && inputRef.current) {
      inputRef.current.focus();
    }
  }, [screenPos]);

  // Handle keyboard shortcuts
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'Escape') {
        handleCancel();
      } else if (e.key === 'Enter' && (e.ctrlKey || e.metaKey)) {
        handleFinish();
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [text]);

  const handleFinish = () => {
    if (text.trim()) {
      onComplete({ text: text.trim(), fontSize, color, bold });
    }
  };

  const handleCancel = () => {
    setText('');
    onCancel();
  };

  console.log('[TextSpriteEditor] Render check - screenPos:', screenPos, 'position:', position);

  if (!screenPos) {
    console.log('[TextSpriteEditor] Returning null - no screenPos');
    return null;
  }

  console.log('[TextSpriteEditor] Rendering editor at:', screenPos);

  return (
    <>
      {/* Text input cursor on canvas */}
      <div
        className={styles.textSpriteInput}
        style={{
          position: 'fixed',
          left: `${screenPos.x}px`,
          top: `${screenPos.y}px`,
          zIndex: 9999,
        }}
      >
        <input
          ref={inputRef}
          type="text"
          value={text}
          onChange={(e) => setText(e.target.value)}
          placeholder="Type text..."
          style={{
            fontSize: `${fontSize}px`,
            color: color,
            fontWeight: bold ? 'bold' : 'normal',
            fontFamily: 'Consolas, monospace',
            background: 'rgba(0, 0, 0, 0.8)',
            border: '2px solid #4299e1',
            padding: '4px 8px',
            borderRadius: '4px',
            outline: 'none',
            minWidth: '200px',
          }}
        />
      </div>

      {/* Floating toolbar above text */}
      <div
        className={styles.textSpriteToolbar}
        style={{
          position: 'fixed',
          left: `${screenPos.x}px`,
          top: `${screenPos.y - 60}px`,
          zIndex: 10000,
        }}
      >
        <div className={styles.toolbarContainer}>
          {/* Font size */}
          <div className={styles.toolbarGroup}>
            <label>Size</label>
            <select 
              value={fontSize} 
              onChange={(e) => setFontSize(Number(e.target.value))}
              className={styles.toolbarSelect}
            >
              <option value={12}>12</option>
              <option value={16}>16</option>
              <option value={20}>20</option>
              <option value={24}>24</option>
              <option value={32}>32</option>
              <option value={48}>48</option>
              <option value={64}>64</option>
            </select>
          </div>

          {/* Color picker */}
          <div className={styles.toolbarGroup}>
            <label>Color</label>
            <input
              type="color"
              value={color}
              onChange={(e) => setColor(e.target.value)}
              className={styles.toolbarColor}
            />
          </div>

          {/* Bold toggle */}
          <button
            className={clsx(styles.toolbarButton, {[styles.active]: bold})}
            onClick={() => setBold(!bold)}
            title="Bold (Ctrl+B)"
          >
            <strong>B</strong>
          </button>

          {/* Divider */}
          <div className={styles.toolbarDivider}></div>

          {/* Finish button */}
          <button
            className={clsx(styles.toolbarButton, styles.finish)}
            onClick={handleFinish}
            disabled={!text.trim()}
            title="Finish (Ctrl+Enter)"
          >
            <Check size={16} aria-hidden />
          </button>

          {/* Cancel button */}
          <button
            className={clsx(styles.toolbarButton, styles.cancel)}
            onClick={handleCancel}
            title="Cancel (Esc)"
          >
            <X size={16} aria-hidden />
          </button>
        </div>

        {/* Hint text */}
        <div className={styles.toolbarHint}>
          Press Enter to add line ┬╖ Ctrl+Enter to finish ┬╖ Esc to cancel
        </div>
      </div>
    </>
  );
}

export default TextSpriteEditor;

import { useGameStore } from '@/store';
import { Check, X } from 'lucide-react';
import { useEffect, useRef, useState } from 'react';

interface TextSpriteToolProps {
  activeLayer: string;
  activeTool: string | null;
  onSpriteCreated?: (spriteId: string) => void;
  onError?: (error: Error) => void;
}

interface InlineTextEditorProps {
  worldPosition: { x: number; y: number };
  onComplete: (text: string, fontSize: number, color: string) => void;
  onCancel: () => void;
}

function InlineTextEditor({ worldPosition, onComplete, onCancel }: InlineTextEditorProps) {
  const [text, setText] = useState('');
  const [fontSize, setFontSize] = useState(16);  // Default 16px (0.5 multiplier)
  const [color, setColor] = useState('#ffffff');
  const [screenPos, setScreenPos] = useState<{ x: number; y: number } | null>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  // Convert world coords to screen coords тАФ retry until rustRenderManager is ready
  useEffect(() => {
    let cancelled = false;
    let retryId: ReturnType<typeof setTimeout> | null = null;

    const tryConvert = () => {
      const rustManager = (window as any).rustRenderManager;
      const canvas = document.querySelector('.game-canvas') as HTMLCanvasElement;

      if (!rustManager || !canvas) {
        if (!cancelled) retryId = setTimeout(tryConvert, 100);
        return;
      }

      try {
        const rect = canvas.getBoundingClientRect();
        const screenCoords = rustManager.world_to_screen(worldPosition.x, worldPosition.y);

        console.log('[InlineTextEditor] Converting coords:', {
          world: worldPosition,
          screen: screenCoords,
          canvasRect: { left: rect.left, top: rect.top, width: rect.width, height: rect.height }
        });

        // Validate screen coordinates
        if (screenCoords && screenCoords.length >= 2 &&
            !isNaN(screenCoords[0]) && !isNaN(screenCoords[1])) {
          const finalX = rect.left + screenCoords[0];
          const finalY = rect.top + screenCoords[1];

          console.log('[InlineTextEditor] Final screen position:', { x: finalX, y: finalY });

          if (!cancelled) setScreenPos({ x: finalX, y: finalY });
        } else {
          console.error('[InlineTextEditor] Invalid screen coords:', screenCoords);
        }
      } catch (error) {
        console.error('[InlineTextEditor] Error converting coords:', error);
      }
    };

    tryConvert();
    return () => {
      cancelled = true;
      if (retryId !== null) clearTimeout(retryId);
    };
  }, [worldPosition]);

  // Auto-focus input
  useEffect(() => {
    if (screenPos && inputRef.current) {
      inputRef.current.focus();
    }
  }, [screenPos]);

  // Keyboard shortcuts
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'Escape') {
        onCancel();
      } else if (e.key === 'Enter' && !e.shiftKey) {
        e.preventDefault();
        if (text.trim()) {
          onComplete(text.trim(), fontSize, color);
        }
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [text, fontSize, color, onComplete, onCancel]);

  if (!screenPos) return null;

  return (
    <>
      {/* Floating toolbar above input - centered */}
      <div
        style={{
          position: 'fixed',
          left: `${screenPos.x}px`,
          top: `${screenPos.y - 50}px`,
          transform: 'translateX(-50%)',  // Center toolbar horizontally
          display: 'flex',
          gap: '8px',
          alignItems: 'center',
          background: 'rgba(30, 30, 30, 0.95)',
          padding: '6px 12px',
          borderRadius: '6px',
          border: '1px solid #4299e1',
          zIndex: 10000,
          fontSize: '12px',
          color: 'var(--text-secondary)',
        }}
      >
        <label style={{ display: 'flex', alignItems: 'center', gap: '4px' }}>
          Size:
          <input
            type="range"
            min="12"
            max="48"
            value={fontSize}
            onChange={(e) => setFontSize(Number(e.target.value))}
            style={{ width: '80px' }}
          />
          <span style={{ minWidth: '30px', color: 'var(--text-primary)' }}>{fontSize}px</span>
        </label>
        
        <label style={{ display: 'flex', alignItems: 'center', gap: '4px' }}>
          Color:
          <input
            type="color"
            value={color}
            onChange={(e) => setColor(e.target.value)}
            style={{ width: '30px', height: '20px', border: 'none', cursor: 'pointer' }}
          />
        </label>
        
        <button
          onClick={() => text.trim() && onComplete(text.trim(), fontSize, color)}
          aria-label="Confirm"
          style={{
            padding: '4px 12px',
            background: 'var(--color-primary)',
            color: 'var(--text-inverse-primary)',
            border: 'none',
            borderRadius: '4px',
            cursor: 'pointer',
            fontSize: '12px',
          }}
        >
          <Check size={14} aria-hidden />
        </button>
        <button
          onClick={onCancel}
          style={{
            padding: '4px 12px',
            background: 'var(--bg-elevated)',
            color: 'var(--text-primary)',
            border: 'none',
            borderRadius: '4px',
            cursor: 'pointer',
            fontSize: '12px',
          }}
        >
          <X size={14} aria-hidden />
        </button>
      </div>

      {/* Inline text input - centered to match Rust text rendering */}
      <input
        ref={inputRef}
        type="text"
        value={text}
        onChange={(e) => setText(e.target.value)}
        placeholder="Type text..."
        style={{
          position: 'fixed',
          left: `${screenPos.x}px`,
          top: `${screenPos.y}px`,
          transform: 'translateX(-50%)',  // Center horizontally at the x position
          fontSize: `${fontSize}px`,
          color: color,
          fontFamily: 'Consolas, monospace',
          background: 'transparent',
          border: 'none',
          outline: '2px solid #4299e1',
          padding: '2px 4px',
          zIndex: 9999,
          minWidth: '100px',
        }}
      />
    </>
  );
}

export function TextSpriteTool({ 
  activeLayer,
  activeTool,
  onSpriteCreated,
  onError 
}: TextSpriteToolProps) {
  const [showDialog, setShowDialog] = useState(false);
  const [clickPosition, setClickPosition] = useState<{ x: number; y: number } | null>(null);
  const { setActiveTool } = useGameStore();

  // Listen for map clicks when text tool is active
  useEffect(() => {
    if (activeTool !== 'text') {
      setShowDialog(false);
      setClickPosition(null);
      return;
    }

    const handleMapClick = (event: CustomEvent) => {
      const { x, y } = event.detail;
      console.log('[TextSpriteTool] Received textSpriteClick event at:', x, y);
      setClickPosition({ x, y });
      setShowDialog(true);
    };

    console.log('[TextSpriteTool] Registering textSpriteClick event listener');
    window.addEventListener('textSpriteClick' as any, handleMapClick);

    return () => {
      console.log('[TextSpriteTool] Removing textSpriteClick event listener');
      window.removeEventListener('textSpriteClick' as any, handleMapClick);
    };
  }, [activeTool]);

  const handleComplete = (text: string, fontSize: number, color: string) => {
    if (!clickPosition) {
      console.error('[TextSpriteTool] No click position available');
      return;
    }

    try {
      const rustManager = (window as any).rustRenderManager;
      if (!rustManager) {
        throw new Error('Rust render manager not available');
      }

      // Convert font size from pixels to multiplier for Rust renderer
      // The bitmap font atlas has 32px base size, so:
      // 16px = 0.5, 24px = 0.75, 32px = 1.0, 48px = 1.5
      const sizeMultiplier = fontSize / 32.0;

      console.log('[TextSpriteTool] Creating text sprite:', {
        text,
        position: clickPosition,
        fontSize,
        sizeMultiplier,
        color,
        layer: activeLayer
      });

      // Call Rust function to create text sprite directly in WebGL
      const spriteId = rustManager.create_text_sprite(
        text,
        clickPosition.x,
        clickPosition.y,
        sizeMultiplier,  // Use multiplier, not pixel size
        color,
        activeLayer || 'tokens'
      );

      console.log('[TextSpriteTool] Successfully created text sprite:', spriteId);
      onSpriteCreated?.(spriteId);
      
      // Auto-switch to select tool after creating text
      setActiveTool('select');
      
      setShowDialog(false);
      setClickPosition(null);
    } catch (error) {
      console.error('[TextSpriteTool] Error creating text sprite:', error);
      const err = error instanceof Error ? error : new Error('Unknown error');
      onError?.(err);
    }
  };

  const handleCancel = () => {
    setShowDialog(false);
    setClickPosition(null);
  };

  return showDialog && clickPosition ? (
    <InlineTextEditor
      worldPosition={clickPosition}
      onComplete={handleComplete}
      onCancel={handleCancel}
    />
  ) : null;
}

