                    )}
                    <button className={`${styles.toolButton} ${styles.wallDangerBtn}`} onClick={() => {
                      removeWall(w.wall_id);
                      if (ProtocolService.hasProtocol()) ProtocolService.getProtocol().removeWall(w.wall_id);
                    }}>╨▓╤ЪтАв</button>
                  </div>
                ))}
              </div>
            );
          })()}

