  const [tokenImagePreview, setTokenImagePreview] = useState<string>('');
  const [hpAmount, setHpAmount] = useState<number>(0);
  const imageInputRef = useRef<HTMLInputElement>(null);

  const { isConnected } = useProtocol();
  const { sprites, activeTableId, getSpritesForCharacter, linkSpriteToCharacter } = useGameStore();

  if (!character) {
    return <div className={styles.characterSheetEmpty}>No character data</div>;
  }

  const data = character.data || {};
  const abilities = data.abilityScores || { str: 10, dex: 10, con: 10, int: 10, wis: 10, cha: 10 };
  const stats = data.stats || { hp: 0, maxHp: 10, ac: 10, speed: 30, initiative: 0 };
  const profBonus = data.proficiencyBonus || Math.ceil((data.level || 1) / 4) + 1;
  const skills = data.skills || {};
  const savingThrows = data.savingThrows || { str: false, dex: false, con: false, int: false, wis: false, cha: false };

  const getModifier = (score: number) => Math.floor((score - 10) / 2);
  const modStr = (mod: number) => mod >= 0 ? `+${mod}` : `${mod}`;
  const hpPct = Math.min(1, (stats.hp || 0) / Math.max(1, stats.maxHp || 10));
  const hpBarColor = hpPct > 0.5 ? 'var(--green-600)' : hpPct > 0.25 ? '#eab308' : 'var(--red-600, #dc2626)';

  const handleHPChange = (delta: number) => {
    const currentTempHp = stats.tempHp || 0;
    let remaining = delta;
    let newTempHp = currentTempHp;
    if (delta < 0 && currentTempHp > 0) {
      const absorbed = Math.min(currentTempHp, -delta);
      newTempHp = currentTempHp - absorbed;
      remaining = delta + absorbed;
    }
    const newHP = Math.max(0, Math.min((stats.hp || 0) + remaining, stats.maxHp || 10));
    // Reset death saves when healed from 0
    const deathSaves = newHP > 0 ? { successes: 0, failures: 0 } : (stats.deathSaves || { successes: 0, failures: 0 });
    onSave({ data: { ...data, stats: { ...stats, hp: newHP, tempHp: newTempHp, deathSaves } } });
  };



  const handleTempHpChange = (value: number) => {
    onSave({ data: { ...data, stats: { ...stats, tempHp: Math.max(0, value) } } });
  };

  const handleSkillRoll = (skillName: string, modifier: number) => {
    if (isConnected && ProtocolService.hasProtocol() && character) {
      ProtocolService.getProtocol().rollSkill(character.id, skillName, modifier);
      showToast.success(`Rolling ${skillName}тАж`);
    }
  };

  const handleAbilitySaveRoll = (ability: string, modifier: number) => {
    if (isConnected && ProtocolService.hasProtocol() && character) {
      ProtocolService.getProtocol().rollAbilitySave(character.id, ability, modifier);
      showToast.success(`Rolling ${ABILITY_SHORT[ability]} saveтАж`);
    }
  };

  const handleAbilityCheckRoll = (ability: string, modifier: number) => {
    if (isConnected && ProtocolService.hasProtocol() && character) {
      ProtocolService.getProtocol().rollAbilityCheck(character.id, ability, modifier);
      showToast.success(`Rolling ${ABILITY_SHORT[ability]} checkтАж`);
    }
  };

  const handleAttackRoll = (attackType: string, modifier: number) => {
    if (isConnected && ProtocolService.hasProtocol() && character) {
      ProtocolService.getProtocol().rollAttack(character.id, attackType, modifier);
      showToast.success(`Rolling ${attackType} attackтАж`);
    }
  };

  const handleDeathSaveRoll = () => {
    if (isConnected && ProtocolService.hasProtocol() && character) {
      ProtocolService.getProtocol().rollDeathSave(character.id);
      showToast.info('Rolling death saveтАж');
    }
  };

  const handleLongRest = () => {
    if (!character) return;
    const totalHitDice = data.level || 1;
    const usedHitDice = data.hitDiceUsed || 0;
    const recoveredDice = Math.max(1, Math.floor(totalHitDice / 2));
    const newUsedHitDice = Math.max(0, usedHitDice - recoveredDice);
    onSave({
      data: {
        ...data,
        stats: { ...stats, hp: stats.maxHp || 10, deathSaves: { successes: 0, failures: 0 } },
        spellSlotsUsed: {},
        hitDiceUsed: newUsedHitDice,
      }
    });
    showToast.success('Long Rest тАФ HP and spell slots restored');
  };

  const handleShortRest = () => {
    showToast.info('Short Rest тАФ use Hit Dice roll to recover HP');
  };

  const handleStatUpdate = (field: string, value: number) => {
    onSave({
      data: {
        ...data,
        stats: { ...stats, [field]: value }
      }
    });
  };

  const handleAbilityUpdate = (ability: string, value: number) => {
    onSave({
      data: {
        ...data,
        abilityScores: { ...abilities, [ability]: value }
      }
    });
  };

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (!file.type.startsWith('image/')) {
      showToast.error('Please select an image file');
      return;
    }

    const reader = new FileReader();
    reader.onload = (ev) => {
      const result = ev.target?.result as string;
      setTokenImagePreview(result);
    };
    reader.readAsDataURL(file);
  };

  const handleLinkExistingToken = () => {
    if (!selectedTokenSpriteId) {
      showToast.error('Please select a token to link');
      return;
    }

    linkSpriteToCharacter(selectedTokenSpriteId, character.id);
    showToast.success(`Token linked to ${character.name}`);
    setSelectedTokenSpriteId('');
  };

  const handleCreateTokenFromImage = () => {
    if (!tokenImagePreview) {
      showToast.error('Please upload an image first');
      return;
    }

    if (!activeTableId) {
      showToast.error('No active table. Please create or join a table first');
      return;
    }

    if (!isConnected || !ProtocolService.hasProtocol()) {
      showToast.error('Not connected to server');
      return;
    }

    const spriteId = `sprite_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
    const spriteData = {
      sprite_id: spriteId,
      table_id: activeTableId,
      character_id: character.id,
      texture_path: tokenImagePreview,
      coord_x: 100,
      coord_y: 100,
      scale_x: 1.0,
      scale_y: 1.0,
      rotation: 0,
      layer: 'tokens',
      moving: false,
      collidable: true,
      hp: character.data?.stats?.hp,
      max_hp: character.data?.stats?.maxHp,
      ac: character.data?.stats?.ac
    };

    try {
      ProtocolService.getProtocol().createSprite(spriteData);
      showToast.success(`Token created for ${character.name}`);
      setTokenImagePreview('');
      if (imageInputRef.current) {
        imageInputRef.current.value = '';
      }
    } catch (error) {
      showToast.error('Failed to create token');
    }
  };

  const linkedTokens = getSpritesForCharacter(character.id);
  const availableSprites = sprites.filter(s => s.tableId === activeTableId && !s.characterId);

  return (
    <div className={styles.characterSheetRedesigned}>
      {/* Header */}
      <div className={styles.sheetHeader}>
        <div className={styles.headerLeft}>
          <h1 className={styles.charName}>{character.name}</h1>
          <div className={styles.charSubtitle}>
            <span>{data.class || 'Class'}</span>
            <span className={styles.charDivider}>&middot;</span>
            <span>Level {data.level || 1}</span>
            <span className={styles.charDivider}>&middot;</span>
            <span>{data.race || 'Race'}</span>
          </div>
        </div>
        <div className={styles.headerRight}>
          <div className={styles.profBonusDisplay}>
            <div className={styles.profLabel}>Proficiency</div>
            <div className={styles.profValue}>+{profBonus}</div>
          </div>
        </div>
      </div>

      {/* Main layout: sidebar + content */}
      <div className={styles.sheetLayout}>
        {/* Left sidebar тАФ always visible */}
        <aside className={styles.sidebar}>
          <div className={styles.abilitiesColumn}>
            {Object.entries(abilities).map(([key, rawVal]) => {
              const score = Number(rawVal);
              const mod = getModifier(score);
              const isProfSave = savingThrows[key as keyof typeof savingThrows];
              const saveBonus = mod + (isProfSave ? profBonus : 0);
              return (
                <div key={key} className={styles.abilityBlock}>
                  <div className={styles.abilityLabel}>{ABILITY_SHORT[key]}</div>
                  <button
                    type="button"
                    className={styles.abilityMod}
                    onClick={() => handleAbilityCheckRoll(key, mod)}
                    title={`Roll ${ABILITY_SHORT[key]} check`}
                  >
                    {modStr(mod)}
                  </button>
                  <input
                    type="number"
                    className={styles.abilityScore}
                    value={score}
                    onChange={e => handleAbilityUpdate(key, Number(e.target.value))}
                    min={1} max={30}
                  />
                  <div className={styles.abilitySaveRow}>
                    <span
                      className={clsx(styles.saveDot, isProfSave && styles.saveProficient)}
                      title="Toggle saving throw proficiency"
                      onClick={() => onSave({ data: { ...data, savingThrows: { ...savingThrows, [key]: !isProfSave } } })}
                    />
                    <button
                      type="button"
                      className={styles.saveBonus}
                      onClick={() => handleAbilitySaveRoll(key, saveBonus)}
                      title={`Roll ${ABILITY_SHORT[key]} saving throw`}
                    >
                      {modStr(saveBonus)}
                    </button>
                    <span className={styles.saveLabel}>Save</span>
                  </div>
                </div>
              );
            })}
          </div>

          <div className={styles.sidebarExtras}>
            <div className={styles.passiveRow}>
              <span className={styles.passiveLabel}>Passive Perception</span>
              <strong className={styles.passiveValue}>
                {10 + getModifier(abilities.wis) + (skills['Perception'] ? profBonus : 0)}
              </strong>
            </div>
            <label className={styles.inspirationRow}>
              <input
                type="checkbox"
                checked={data.inspiration || false}
                onChange={e => onSave({ data: { ...data, inspiration: e.target.checked } })}
              />
              <span>Inspiration</span>
            </label>
          </div>
        </aside>

        {/* Right main area */}
        <div className={styles.mainArea}>
          {/* Tabs */}
          <div className={styles.sheetTabs}>
            {(['core', 'spells', 'inventory', 'bio', 'activity'] as const).map(tab => (
              <button
                key={tab}
                type="button"
                className={clsx(styles.sheetTab, activeTab === tab && styles.active)}
                onClick={() => setActiveTab(tab)}
              >
                {tab === 'core' ? 'Core' : tab === 'spells' ? 'Spells' : tab === 'inventory' ? 'Inventory' : tab === 'bio' ? 'Notes' : 'Activity'}
              </button>
            ))}
          </div>

          <div className={styles.sheetBody}>
            {activeTab === 'core' && (
              <div className={styles.coreLayout}>
                {/* Combat row */}
                <div className={styles.combatRow}>
                  <div className={styles.combatStat}>
                    <div className={styles.combatIcon}><Shield size={16} aria-hidden /></div>
                    <input type="number" className={styles.combatInput} value={stats.ac || 10}
                      onChange={e => handleStatUpdate('ac', Number(e.target.value))} />
                    <div className={styles.combatLabel}>Armor Class</div>
                  </div>
                  <div className={styles.combatStat}>
                    <div className={styles.combatIcon}><Zap size={16} aria-hidden /></div>
                    <div className={styles.combatValue}>{modStr(getModifier(abilities.dex))}</div>
                    <div className={styles.combatLabel}>Initiative</div>
                  </div>
                  <div className={styles.combatStat}>
                    <div className={styles.combatIcon}><Footprints size={16} aria-hidden /></div>
                    <input type="number" className={styles.combatInput} value={stats.speed || 30}
                      onChange={e => handleStatUpdate('speed', Number(e.target.value))} />
                    <div className={styles.combatLabel}>Speed (ft)</div>
                  </div>
                  <div className={styles.combatStat}>
                    <div className={styles.combatIcon}><Dices size={16} aria-hidden /></div>
                    <div className={styles.combatValue}>{data.level || 1}d{data.hitDie || 8}</div>
                    <button type="button" className={styles.hitDieBtn}
                      onClick={() => handleHPChange(Math.floor(Math.random() * (data.hitDie || 8)) + 1 + getModifier(abilities.con))}>
                      Roll
                    </button>
                    <div className={styles.combatLabel}>Hit Dice</div>
                  </div>
                </div>

                {/* HP block */}
                <div className={styles.hpBlock}>
                  <div className={styles.hpBarWrap}>
                    <div className={styles.hpBarFill} style={{ width: `${hpPct * 100}%`, background: hpBarColor }} />
                  </div>
                  <div className={styles.hpNums}>
                    <input type="number" className={styles.hpCurrent} value={stats.hp || 0}
                      onChange={e => handleStatUpdate('hp', Number(e.target.value))} min={0} max={stats.maxHp || 999} />
                    <span className={styles.hpSlash}>/</span>
                    <input type="number" className={styles.hpMax} value={stats.maxHp || 10}
                      onChange={e => handleStatUpdate('maxHp', Number(e.target.value))} min={1} />
                    {(stats.tempHp || 0) > 0 && (
                      <span className={styles.tempHpBadge}>+{stats.tempHp} tmp</span>
                    )}
                  </div>
                  <div className={styles.hpControls}>
                    <input type="number" className={styles.hpAmountInput} value={hpAmount} min={0}
                      onChange={e => setHpAmount(Math.max(0, Number(e.target.value)))} placeholder="Amt" />
                    <button type="button" className={styles.damageBtn}
                      onClick={() => { handleHPChange(-hpAmount); setHpAmount(0); }} disabled={hpAmount === 0}>Damage</button>
                    <button type="button" className={styles.healBtn}
                      onClick={() => { handleHPChange(hpAmount); setHpAmount(0); }} disabled={hpAmount === 0}>Heal</button>
                    <label className={styles.tempHpLabel}>
                      Temp:
                      <input type="number" value={stats.tempHp || 0} min={0}
                        onChange={e => handleTempHpChange(Number(e.target.value))} />
                    </label>
                  </div>
                </div>

                {/* Death saves ╨▓╨ВтАЭ only at 0 HP */}
                {/* Death saves тАФ only at 0 HP */}
                {(stats.hp || 0) === 0 && (
                  <div className={styles.deathSavesBlock}>
                    <span className={styles.deathTitle}>Death Saves</span>
                    <div className={styles.deathRow}>
                      <span className={styles.deathLabel}><Check size={14} aria-hidden /></span>
                      {[0, 1, 2].map(i => (
                        <span key={i} className={clsx(styles.deathPip, i < (stats.deathSaves?.successes || 0) && styles.deathSuccess)} />
                      ))}
                    </div>
                    <div className={styles.deathRow}>
                      <span className={clsx(styles.deathLabel, styles.deathFailLabel)}><X size={14} aria-hidden /></span>
                      {[0, 1, 2].map(i => (
                        <span key={i} className={clsx(styles.deathPip, i < (stats.deathSaves?.failures || 0) && styles.deathFailure)} />
                      ))}
                    </div>
                    <button type="button" className={styles.deathRollBtn} onClick={handleDeathSaveRoll}>
                      Roll Death Save
                    </button>
                  </div>
                )}

                {/* Rest Actions */}
                <div className={styles.restActionsBlock}>
                  <button type="button" className={styles.shortRestBtn} onClick={handleShortRest}>Short Rest</button>
                  <button type="button" className={styles.longRestBtn} onClick={handleLongRest}>Long Rest</button>
                </div>

                {/* Conditions */}
                {data.conditions && data.conditions.length > 0 && (
                  <div className={styles.conditionsRow}>
                    {data.conditions.map((c: string) => (
                      <span key={c} className={styles.conditionBadge}>{c}</span>
                    ))}
                  </div>
                )}

                {/* Skills 2-column */}
                <div className={styles.skillsSection}>
                  <div className={styles.skillsTitle}>Skills</div>
                  <div className={styles.skillsGrid}>
                    {SKILLS.map(skill => {
                      const mod = getModifier(abilities[skill.ability as keyof typeof abilities]);
                      const isProficient = skills[skill.name] || false;
                      const bonus = mod + (isProficient ? profBonus : 0);
                      return (
                        <div key={skill.name} className={styles.skillRow}>
                          <span
                            className={clsx(styles.profDot, isProficient && styles.proficient)}
                            onClick={() => onSave({ data: { ...data, skills: { ...skills, [skill.name]: !isProficient } } })}
                          />
                          <button type="button" className={styles.skillRollBtn}
                            onClick={() => handleSkillRoll(skill.name, bonus)}
                            title={`Roll ${skill.name}`}>
                            {modStr(bonus)}
                          </button>
                          <span className={styles.skillName}>{skill.name}</span>
                          <span className={styles.skillAbility}>{ABILITY_SHORT[skill.ability].slice(0, 3)}</span>
                        </div>
                      );
                    })}
                  </div>
                </div>

                {/* Attacks summary */}
                <div className={styles.attacksBlock}>
                  <div className={styles.attacksTitle}>Attacks</div>
                  <button type="button" className={styles.attackRollBtn}
                    onClick={() => handleAttackRoll('melee', getModifier(abilities.str) + profBonus)}>
                    <span>Melee</span>
                    <span className={styles.attackBonus}>{modStr(getModifier(abilities.str) + profBonus)}</span>
                  </button>
                  <button type="button" className={styles.attackRollBtn}
                    onClick={() => handleAttackRoll('ranged', getModifier(abilities.dex) + profBonus)}>
                    <span>Ranged</span>
                    <span className={styles.attackBonus}>{modStr(getModifier(abilities.dex) + profBonus)}</span>
                  </button>
                  <div className={styles.attackRow}>
                    <span>Spell DC</span>
                    <span>{8 + profBonus + Math.max(getModifier(abilities.wis), getModifier(abilities.int), getModifier(abilities.cha))}</span>
                  </div>
                </div>

                {/* Features */}
                {data.features && data.features.length > 0 && (
                  <div className={styles.featuresBlock}>
                    <div className={styles.featuresTitle}>Features & Traits</div>
                    {data.features.map((f: string, i: number) => (
                      <div key={i} className={styles.featureItem}>{f}</div>
                    ))}
                  </div>
                )}
              </div>
            )}

            {activeTab === 'spells' && (
              <SpellsTab data={data} onSave={newData => onSave({ data: newData })} />
            )}

            {activeTab === 'inventory' && (
              <InventoryTab data={data} onSave={newData => onSave({ data: newData })} />
            )}

            {activeTab === 'bio' && (
              <div className={styles.bioTabContent}>
                <div className={styles.bioSection}>
                  <h4>Biography</h4>
                  <textarea
                    value={character.data?.bio || ''}
                    onChange={e => onSave({ data: { ...data, bio: e.target.value } })}
                    placeholder="Backstory, personality, goalsтАж"
                    rows={6}
                    className={styles.bioTextarea}
                  />
                </div>

                <div className={styles.linkedTokensSection}>
                  <h4>Linked Tokens</h4>
                  {linkedTokens.length > 0 ? (
                    <div className={styles.tokenList}>
                      {linkedTokens.map(token => (
                        <div key={token.id} className={styles.tokenBadge}>
                          <CircleUser size={14} aria-hidden />
                          <span>{token.name || token.id.substring(0, 8)}</span>
                        </div>
                      ))}
                    </div>
                  ) : (
                    <p className={styles.noTokens}>No tokens linked</p>
                  )}
                </div>

                <div className={styles.linkTokenSection}>
                  <h4>Link Existing Token</h4>
                  <div className={styles.linkTokenRow}>
                    <select value={selectedTokenSpriteId} onChange={e => setSelectedTokenSpriteId(e.target.value)} className={styles.tokenSelect}>
                      <option value="">-- Select a token --</option>
                      {availableSprites.map(sprite => (
                        <option key={sprite.id} value={sprite.id}>
                          {sprite.name || `Token ${sprite.id.substring(0, 8)}`}
                        </option>
                      ))}
                    </select>
                    <button onClick={handleLinkExistingToken} disabled={!selectedTokenSpriteId} className={styles.linkBtn}>Link</button>
                  </div>
                </div>

                <div className={styles.createTokenSection}>
                  <h4>Create Token from Image</h4>
                  <input ref={imageInputRef} type="file" accept="image/*" onChange={handleImageChange} className={styles.tokenImageInput} />
                  {tokenImagePreview && (
                    <div className={styles.imagePreview}>
                      <img src={tokenImagePreview} alt="Token preview" className={styles.previewImg} />
                    </div>
                  )}
                  <button
                    onClick={handleCreateTokenFromImage}
                    disabled={!tokenImagePreview || !isConnected}
                    className={clsx(styles.createTokenBtn, tokenImagePreview && isConnected && styles.ready)}
                  >
                    {!isConnected ? 'Not Connected' : !tokenImagePreview ? 'Upload Image First' : 'Add Token to Table'}
                  </button>
                  {!activeTableId && <p className={styles.noTableWarning}>No active table</p>}
                </div>
              </div>
            )}

            {activeTab === 'activity' && (
              <ActivityTab characterId={character.id} />
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

import { useChatStore } from '@features/chat';
import { useRacesForCharacterWizard } from '@features/compendium';
import { Controller, useFormContext } from 'react-hook-form';
import styles from './AbilitiesStep.module.css';
import { calculateRacialASI } from './raceData';
import type { AbilitiesStepData } from './schemas';
import type { WizardFormData } from './WizardFormData';

type AbilityName = keyof AbilitiesStepData;
type Method = 'standard' | 'pointbuy' | 'roll' | 'manual';

const ABILITIES: AbilityName[] = ['strength', 'dexterity', 'constitution', 'intelligence', 'wisdom', 'charisma'];
const ABILITY_LABELS = ['Strength', 'Dexterity', 'Constitution', 'Intelligence', 'Wisdom', 'Charisma'] as const;
const STANDARD_ARRAY = [15, 14, 13, 12, 10, 8];

export function AbilitiesStep({ onNext: _onNext, onBack: _onBack }: { onNext?: () => void; onBack?: () => void } = {}) {
  const { control, setValue, getValues, watch, formState: { errors } } = useFormContext<WizardFormData>();
  const addMessage = useChatStore(s => s.addMessage);

  // Persist method + rolls in form state so they survive step navigation
  const method: Method = (watch('_abilityMethod') as Method) ?? 'standard';
  const rolls: number[] = watch('_abilityRolls') ?? [];
  const rollAssignments: Partial<Record<string, number>> = watch('_rollAssignments') ?? {};

  const setMethod = (m: Method) => {
    setValue('_abilityMethod', m);
    if (m !== 'roll') {
      setValue('_abilityRolls', []);
      setValue('_rollAssignments', {});
    }
    const resetValue = m === 'pointbuy' ? 8 : 10;
    ABILITIES.forEach(ability => setValue(ability, resetValue, { shouldValidate: true }));
  };

  const selectedRace = watch('race') ?? '';
  const selectedSubrace = watch('subrace' as any) as string ?? '';
  const characterName = watch('name') ?? '';
  const characterClass = watch('class') ?? '';
  const characterBackground = watch('background') ?? '';
  const { data: races } = useRacesForCharacterWizard();
  const racialASI = races ? calculateRacialASI(selectedRace, selectedSubrace, races) : {};

  const getRacialBonus = (ability: string): number => (racialASI as Record<string, number>)[ability] ?? 0;

  const rollAbilities = () => {
    const newRolls = Array.from({ length: 6 }, () => 
      Array.from({ length: 4 }, () => Math.floor(Math.random() * 6) + 1)
        .sort((a, b) => b - a)
        .slice(0, 3)
        .reduce((sum, roll) => sum + roll, 0)
    ).sort((a, b) => b - a);
    setValue('_abilityRolls', newRolls);
    setValue('_rollAssignments', {});
    // Reset ability scores since assignments cleared
    ABILITIES.forEach(ability => setValue(ability, 0, { shouldValidate: true }));

    addMessage({
      id: Date.now().toString(),
      user: 'System',
      text: `Ability roll (4d6 drop lowest): [${newRolls.join(', ')}]`,
      timestamp: Date.now(),
    });
  };

  // Assign a specific roll index to an ability (null = unassign)
  const assignRoll = (ability: AbilityName, rollIndex: number | null) => {
    const current = getValues('_rollAssignments') ?? {};
    // Unassign any other ability that had this roll index
    const cleared: Partial<Record<string, number>> = {};
    for (const [k, v] of Object.entries(current)) {
      if (v !== rollIndex) cleared[k] = v;
    }
    if (rollIndex !== null) {
      cleared[ability] = rollIndex;
      setValue(ability, rolls[rollIndex], { shouldValidate: true });
    } else {
      setValue(ability, 0, { shouldValidate: true });
    }
    setValue('_rollAssignments', cleared);
  };

  // Point buy calculation
  const getPointCost = (score: number): number => {
    if (score <= 8) return 0;
    if (score <= 13) return score - 8;
    if (score === 14) return 7;
    if (score === 15) return 9;
    return 999;
  };

  // Watch ability scores reactively for display
  const abilityValues = watch(ABILITIES as any) as number[];
  const scores: Record<AbilityName, number> = Object.fromEntries(
    ABILITIES.map((a, i) => [a, abilityValues[i] || (method === 'pointbuy' ? 8 : 0)])
  ) as Record<AbilityName, number>;

  const totalPointsUsed = ABILITIES.reduce((t, a) => t + getPointCost(scores[a] ?? 8), 0);

  // Standard array - track which values are already used
  const usedStandardValues = new Set(ABILITIES.map(a => scores[a]).filter(Boolean));

  // Roll mode - show which roll indices are available vs assigned
  const assignedIndices = new Set(Object.values(rollAssignments).filter(v => v !== undefined) as number[]);

  return (
    <div className={styles.container}>
      {/* Character summary bar */}
      {(characterName || characterClass || characterBackground) && (
        <div className={styles.summaryBar}>
          {characterName && <span className={styles.summaryItem}><strong>{characterName}</strong></span>}
          {characterClass && <span className={styles.summaryItem}>{characterClass.charAt(0).toUpperCase() + characterClass.slice(1)}</span>}
          {characterBackground && <span className={styles.summaryItem}>{characterBackground.charAt(0).toUpperCase() + characterBackground.slice(1)}</span>}
          {Object.keys(racialASI).length > 0 && (
            <span className={styles.summaryItem}>
              Racial bonuses: {Object.entries(racialASI).map(([k, v]) => `+${v} ${k}`).join(', ')}
            </span>
          )}
        </div>
      )}

      <h2>Assign ability scores</h2>

      <div className={styles.methodRow}>
        {[
          { value: 'standard', label: 'Standard Array' },
          { value: 'pointbuy', label: 'Point Buy (27 pts)' },
          { value: 'roll', label: 'Roll 4d6' },
          { value: 'manual', label: 'Manual' },
        ].map(({ value, label }) => (
          <button
            key={value}
            type="button"
            className={method === value ? styles.methodBtnActive : styles.methodBtnInactive}
            onClick={() => setMethod(value as Method)}
          >
            {label}
          </button>
        ))}
      </div>

      {method === 'roll' && (
        <div className={styles.rollSection}>
          <button type="button" className={styles.rollBtn} onClick={rollAbilities}>
            {rolls.length > 0 ? 'Re-roll' : 'Roll Abilities'}
          </button>
          {rolls.length > 0 && (
            <div className={styles.rollResults}>
              {rolls.map((r, i) => (
                <span
                  key={i}
                  className={assignedIndices.has(i) ? styles.rollChipUsed : styles.rollChipAvail}
                >
                  {r}
                </span>
              ))}
            </div>
          )}
        </div>
      )}

      {method === 'pointbuy' && (
        <div className={styles.pointBuyInfo}>
          <span>
            Point Buy: <strong data-testid="points-remaining">{27 - totalPointsUsed}</strong> / 27 pts remaining
          </span>
          <small className={styles.infoNote}>8тАУ13: cost = scoreтИТ8 &nbsp;|&nbsp; 14 = 7 pts &nbsp;|&nbsp; 15 = 9 pts</small>
        </div>
      )}

      <div className={styles.abilityGrid}>
        {ABILITIES.map((ability, index) => {
          const score = scores[ability] ?? (method === 'pointbuy' ? 8 : 0);
          const racial = getRacialBonus(ability);
          const thisRollIdx = rollAssignments[ability] ?? null;

          return (
            <div key={ability} className={styles.abilityRow}>
              <label className={styles.abilityLabel}>{ABILITY_LABELS[index]}</label>

              {method === 'standard' ? (
                <select
                  className={styles.select}
                  value={score || ''}
                  onChange={(e) => setValue(ability, Number(e.target.value), { shouldValidate: true })}
                >
                  <option value="">тАФ</option>
                  {STANDARD_ARRAY.map(s => (
                    <option key={s} value={s} disabled={s !== score && usedStandardValues.has(s)}>
                      {s}{s !== score && usedStandardValues.has(s) ? ' (used)' : ''}
                    </option>
                  ))}
                </select>
              ) : method === 'roll' && rolls.length > 0 ? (
                <select
                  className={styles.select}
                  value={thisRollIdx ?? ''}
                  onChange={(e) => {
                    const val = e.target.value;
                    assignRoll(ability, val === '' ? null : Number(val));
                  }}
                >
                  <option value="">тАФ</option>
                  {rolls.map((r, i) => {
                    const takenByOther = assignedIndices.has(i) && thisRollIdx !== i;
                    return (
                      <option key={i} value={i} disabled={takenByOther}>
                        {r}{takenByOther ? ' (used)' : ''}
                      </option>
                    );
                  })}
                </select>
              ) : method === 'pointbuy' ? (
                <div className={styles.pbRow}>
                  <button
                    type="button"
                    className={score > 8 ? styles.decBtnActive : styles.decBtnDisabled}
                    onClick={() => { if (score > 8) setValue(ability, score - 1, { shouldValidate: true }); }}
                    disabled={score <= 8}
                  >тИТ</button>
                  <span className={styles.scoreDisplay}>{score}</span>
                  <button
                    type="button"
                    className={score < 15 && totalPointsUsed < 27 ? styles.incBtnActive : styles.incBtnDisabled}
                    onClick={() => {
                      const next = score + 1;
                      const extra = getPointCost(next) - getPointCost(score);
                      if (next <= 15 && totalPointsUsed + extra <= 27) setValue(ability, next, { shouldValidate: true });
                    }}
                    disabled={score >= 15 || totalPointsUsed >= 27}
                  >+</button>
                  <span className={styles.costNote}>{getPointCost(score)} pts</span>
                </div>
              ) : (
                <Controller
                  name={ability as any}
                  control={control}
                  render={({ field }) => (
                    <input
                      {...field}
                      type="number"
                      min={3}
                      max={20}
                      className={styles.input}
                      onChange={(e) => field.onChange(Number(e.target.value))}
                    />
                  )}
                />
              )}

              {(method !== 'pointbuy') && (
                <span data-testid={`${ability}-final`} className={styles.finalScore}>
                  {score ? `= ${score + racial}${racial > 0 ? ` (+${racial} racial)` : ''}` : ''}
                </span>
              )}
              {method === 'pointbuy' && (
                <span data-testid={`${ability}-final`} className={styles.finalScore}>
                  Final: {score + racial}
                </span>
              )}

              {errors[ability as keyof typeof errors] && (
                <span className={styles.errorText}>{(errors[ability as keyof typeof errors] as any)?.message}</span>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
}

import { useBackgrounds, useClasses, useRacesForCharacterWizard } from '@features/compendium';
import { useEffect, useMemo, useState } from 'react';
import { useFormContext } from 'react-hook-form';
import type { BackgroundStepData } from './schemas';
import styles from './BackgroundStep.module.css';

export function BackgroundStep({ onNext: _onNext, onBack: _onBack }: { onNext?: () => void; onBack?: () => void } = {}) {
  const { register, formState, watch, setValue, getValues } = useFormContext<BackgroundStepData>();
  const selectedBackground = watch('background');
  const { data: backgrounds, loading: bgLoading, error: bgError } = useBackgrounds();
  const { data: classes } = useClasses();
  const { data: races } = useRacesForCharacterWizard();

  const characterClass: string = (watch as any)('class') ?? '';
  const characterRace: string = (watch as any)('race') ?? '';

  // Derive class skill data from compendium
  const classData = classes?.find(c => c.name.toLowerCase() === characterClass.toLowerCase());
  const classSkills: string[] = classData?.skill_proficiencies ?? [];
  const classChoices: number = classData?.num_skills ?? 2;

  // Derive race bonus skills from compendium
  const raceEntry = races?.[characterRace];
  const raceSkills: string[] = raceEntry?.proficiencies?.skills ?? [];

  // Find selected background skills from compendium data
  const selectedBackgroundData = backgrounds?.find(bg => bg.name === selectedBackground);
  const backgroundSkills: string[] = selectedBackgroundData?.skill_proficiencies ?? [];

  const alreadyGranted = useMemo(() => [...backgroundSkills, ...raceSkills], [backgroundSkills, raceSkills]);
  const availableClassSkills = classSkills.filter(s => !alreadyGranted.includes(s));

  const [selectedClassSkills, setSelectedClassSkills] = useState<string[]>(() => {
    const existing = (getValues as any)().skills;
    if (Array.isArray(existing) && existing.length > 0) return existing.filter((s: string) => classSkills.includes(s));
    return [];
  });

  useEffect(() => {
    const allSkills = [...new Set([...alreadyGranted, ...selectedClassSkills])];
    (setValue as any)('skills', allSkills, { shouldValidate: false });
  }, [alreadyGranted, selectedClassSkills, setValue]);

  function toggleClassSkill(skill: string) {
    setSelectedClassSkills(prev => {
      if (prev.includes(skill)) return prev.filter(s => s !== skill);
      if (prev.length >= classChoices) return prev;
      return [...prev, skill];
    });
  }

  if (bgLoading) {
    return <div className={styles.centered}>Loading backgrounds...</div>;
  }

  if (bgError) {
    return <div className={styles.error}>Error loading backgrounds: {bgError}</div>;
  }

  // Show if no backgrounds available
  if (!backgrounds || backgrounds.length === 0) {
    return <div className={styles.centered}>No backgrounds available</div>;
  }

  return (
    <div className={styles.step}>
      <div className={styles.title}>Choose background</div>

      <label className={styles['select-label']}>
        Background:
        <select
          {...register('background', { required: 'Select a background' })}
          className={styles.select}
        >
          <option value="">Select...</option>
          {backgrounds.map((bg) => (
            <option key={bg.name} value={bg.name}>{bg.name}</option>
          ))}
        </select>
      </label>

      {formState.errors.background && typeof formState.errors.background === 'object' && 'message' in formState.errors.background && (
        <span className={styles['field-error']}>{formState.errors.background.message as string}</span>
      )}

      {selectedBackgroundData && (
        <div className={styles['details-card']}>
          <h3>{selectedBackgroundData.name} Benefits</h3>

          {backgroundSkills.length > 0 && (
            <div className={styles['detail-row']}>
              <strong>Skill Proficiencies:</strong>{' '}
              <span className={styles['skill-text']}>{backgroundSkills.join(', ')}</span>
            </div>
          )}

          {selectedBackgroundData.tool_proficiencies && selectedBackgroundData.tool_proficiencies.length > 0 && (
            <div className={styles['detail-row']}>
              <strong>Tool Proficiencies:</strong>{' '}
              <span className={styles['tool-text']}>{selectedBackgroundData.tool_proficiencies.join(', ')}</span>
            </div>
          )}

          {selectedBackgroundData.language_proficiencies && selectedBackgroundData.language_proficiencies.length > 0 && (
            <div className={styles['detail-row']}>
              <strong>Languages:</strong>{' '}
              <span className={styles['language-text']}>{selectedBackgroundData.language_proficiencies.join(', ')}</span>
            </div>
          )}

          {selectedBackgroundData.features && selectedBackgroundData.features.length > 0 && (
            <div>
              {selectedBackgroundData.features.map((feature, index) => (
                <div key={index} className={styles['feature-item']}>
                  <h4 className={styles['feature-title']}>{feature.name}</h4>
                  <p className={styles['feature-desc']}>{feature.description}</p>
                </div>
              ))}
            </div>
          )}
        </div>
      )}

      {availableClassSkills.length > 0 && (
        <div className={styles['skills-section']}>
          <h4 className={styles['skills-title']}>
            Class Skill Proficiencies
            <span className={styles['skills-count']}>
              {selectedClassSkills.length} / {classChoices} chosen
            </span>
          </h4>
          <div className={styles['skills-grid']}>
            {availableClassSkills.map(skill => {
              const checked = selectedClassSkills.includes(skill);
              const maxed = selectedClassSkills.length >= classChoices;
              return (
                <label
                  key={skill}
                  className={styles['skill-item']}
                  data-disabled={!checked && maxed ? true : undefined}
                >
                  <input
                    type="checkbox"
                    checked={checked}
                    disabled={!checked && maxed}
                    onChange={() => toggleClassSkill(skill)}
                  />
                  {skill}
                </label>
              );
            })}
          </div>
        </div>
      )}
    </div>
  );
}

import { AdvancementSystemService } from '@features/character/services/advancementSystem.service';
import React from 'react';
import { useFormContext } from 'react-hook-form';
import { LevelUpWizard } from './LevelUpWizard';
import type { WizardFormData } from './WizardFormData';
import { XPTracker } from './XPTracker';

interface CharacterAdvancementStepProps {
  onNext?: () => void;
  onPrevious?: () => void;
  onBack?: () => void;
  // Legacy props for backwards compatibility
  data?: WizardFormData;
  onChange?: (field: keyof WizardFormData, value: any) => void;
  onComplete?: () => void;
}

export const CharacterAdvancementStep: React.FC<CharacterAdvancementStepProps> = ({
  onNext,
  onPrevious: _onPrevious,
  onBack: _onBack,
  data: legacyData,
  onChange: legacyOnChange,
  onComplete
}) => {
  const formContext = useFormContext<WizardFormData>();
  const isUsingFormContext = formContext !== undefined;
  
  // Use form context if available, otherwise use legacy props
  const data = isUsingFormContext ? formContext.watch() : (legacyData || {} as WizardFormData);
  
  const onChange = legacyOnChange || ((field: keyof WizardFormData, value: any) => {
    if (isUsingFormContext) {
      formContext.setValue(field, value, { shouldValidate: true });
    }
  });
  
  const [showLevelUpWizard, setShowLevelUpWizard] = React.useState(false);
  const [currentXP, setCurrentXP] = React.useState(data.advancement?.experiencePoints || 0);
  const [targetLevel, setTargetLevel] = React.useState<number | null>(null);

  // Calculate current level from XP
  const calculateLevelFromXP = (xp: number): number => {
    const xpThresholds = [0, 300, 900, 2700, 6500, 14000, 23000, 34000, 48000, 64000, 85000, 100000, 120000, 140000, 165000, 195000, 225000, 265000, 305000, 355000];
    
    for (let i = xpThresholds.length - 1; i >= 0; i--) {
      if (xp >= xpThresholds[i]) {
        return i + 1;
      }
    }
    return 1;
  };

  // Calculate XP needed for next level
  const getXPForLevel = (level: number): number => {
    const xpThresholds = [0, 300, 900, 2700, 6500, 14000, 23000, 34000, 48000, 64000, 85000, 100000, 120000, 140000, 165000, 195000, 225000, 265000, 305000, 355000];
    return level <= 20 ? xpThresholds[level - 1] : xpThresholds[19];
  };

  const currentLevel = calculateLevelFromXP(currentXP);
  const nextLevel = Math.min(currentLevel + 1, 20);
  const xpForNextLevel = getXPForLevel(nextLevel);
  const xpNeeded = Math.max(0, xpForNextLevel - currentXP);
  const canLevelUp = currentLevel < 20 && currentXP >= xpForNextLevel;

  const handleXPChange = (newXP: number) => {
    setCurrentXP(newXP);
    const newLevel = calculateLevelFromXP(newXP);
    
    // Update advancement data
    const updatedAdvancement = {
      ...data.advancement,
      experiencePoints: newXP,
      currentLevel: newLevel,
      levelHistory: data.advancement?.levelHistory || []
    };
    
    onChange('advancement', updatedAdvancement);
    
    // Check if we can level up to multiple levels
    if (newLevel > currentLevel) {
      const levelsToGain = newLevel - currentLevel;
      if (levelsToGain > 0) {
        setTargetLevel(newLevel);
      }
    }
  };

  const handleLevelUp = () => {
    if (canLevelUp || targetLevel) {
      setShowLevelUpWizard(true);
    }
  };

  const handleLevelUpComplete = (levelUpData: any) => {
    // Update character with level up data
    const updatedData = {
      ...data,
      ...levelUpData,
      advancement: {
        ...data.advancement,
        ...levelUpData.advancement,
        experiencePoints: currentXP,
        currentLevel: targetLevel || calculateLevelFromXP(currentXP)
      }
    };
    
    // Update each field that might have changed
    Object.keys(levelUpData).forEach(key => {
      if (key !== 'advancement') {
        onChange(key as keyof WizardFormData, levelUpData[key]);
      }
    });
    
    onChange('advancement', updatedData.advancement);
    
    setShowLevelUpWizard(false);
    setTargetLevel(null);
    
    // Call completion handlers if available
    if (onComplete) {
      onComplete();
    }
    if (onNext) {
      onNext();
    }
  };

  const handleManualLevelUp = () => {
    // Allow manual level up even without XP requirements
    setTargetLevel(Math.min(currentLevel + 1, 20));
    setShowLevelUpWizard(true);
  };

  if (showLevelUpWizard) {
    // AdvancedCharacter extends WizardFormData, so abilities should be top-level (not nested)
    // Just add the missing required AdvancedCharacter properties
    
    const characterData: any = {
      ...data,
      // Ensure ability scores have defaults if not set
      strength: data.strength || 10,
      dexterity: data.dexterity || 10,
      constitution: data.constitution || 10,
      intelligence: data.intelligence || 10,
      wisdom: data.wisdom || 10,
      charisma: data.charisma || 10,
      // Add required AdvancedCharacter properties
      totalLevel: currentLevel,
      classLevels: data.class ? [{ name: data.class, level: currentLevel }] : [],
      experiencePoints: {
        current: currentXP,
        required: AdvancementSystemService.calculateXPForLevel(currentLevel + 1)
      },
      hitPoints: { 
        current: 10, 
        maximum: 10,
        temporary: 0 
      },
      features: [],
      feats: [],
      inspiration: false
    };
    
    return (
      <LevelUpWizard
        character={characterData}
        onComplete={handleLevelUpComplete}
        onCancel={() => {
          setShowLevelUpWizard(false);
          setTargetLevel(null);
        }}
      />
    );
  }

  return (
    <div className="character-advancement-step">
      <div className="advancement-header">
        <h2>Character Advancement</h2>
        <p>Manage your character's experience points and level progression.</p>
      </div>

      <div className="advancement-content">
        {/* Current Status */}
        <div className="advancement-section">
          <h3>Current Status</h3>
          <div className="status-grid">
            <div className="status-item">
              <label>Current Level</label>
              <div className="status-value level">{currentLevel}</div>
            </div>
            <div className="status-item">
              <label>Experience Points</label>
              <div className="status-value xp">{currentXP.toLocaleString()} XP</div>
            </div>
            <div className="status-item">
              <label>Next Level</label>
              <div className="status-value next-level">
                {currentLevel < 20 ? `Level ${nextLevel}` : 'Max Level'}
              </div>
            </div>
            <div className="status-item">
              <label>XP Needed</label>
              <div className="status-value xp-needed">
                {currentLevel < 20 ? `${xpNeeded.toLocaleString()} XP` : 'N/A'}
              </div>
            </div>
          </div>
        </div>

        {/* XP Management */}
        <div className="advancement-section">
          <XPTracker
            currentXP={currentXP}
            currentLevel={currentLevel}
            onXPChange={handleXPChange}
          />
        </div>

        {/* Level Up Actions */}
        <div className="advancement-section">
          <h3>Level Up</h3>
          <div className="level-up-controls">
            {canLevelUp || targetLevel ? (
              <div className="level-up-ready">
                <div className="level-up-notice">
                  <h4>Level Up Available!</h4>
                  <p>
                    You have enough experience to advance to level {targetLevel || nextLevel}!
                  </p>
                </div>
                <button
                  type="button"
                  onClick={handleLevelUp}
                  className="level-up-btn primary"
                >
                  Level Up to {targetLevel || nextLevel}
                </button>
              </div>
            ) : (
              <div className="level-up-waiting">
                <p>
                  {currentLevel < 20
                    ? `You need ${xpNeeded.toLocaleString()} more XP to reach level ${nextLevel}.`
                    : 'Your character has reached the maximum level of 20!'
                  }
                </p>
                {currentLevel < 20 && (
                  <button
                    type="button"
                    onClick={handleManualLevelUp}
                    className="level-up-btn secondary"
                  >
                    Manual Level Up
                  </button>
                )}
              </div>
            )}
          </div>
        </div>

        {/* Level History */}
        {data.advancement?.levelHistory && data.advancement.levelHistory.length > 0 && (
          <div className="advancement-section">
            <h3>Level History</h3>
            <div className="level-history">
              {data.advancement.levelHistory.map((entry: any, index: number) => (
                <div key={index} className="history-entry">
                  <div className="history-level">Level {entry.level}</div>
                  <div className="history-class">
                    {entry.className}
                    {entry.subclassName && ` (${entry.subclassName})`}
                  </div>
                  <div className="history-details">
                    <span>HP: +{entry.hitPointIncrease}</span>
                    {entry.abilityScoreImprovements && (
                      <span>ASI: {entry.abilityScoreImprovements.map((asi: any) => `${asi.ability} +${asi.increase}`).join(', ')}</span>
                    )}
                    {entry.featGained && <span>Feat: {entry.featGained}</span>}
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* Multiclassing Info */}
        {data.classes && data.classes.length > 1 && (
          <div className="advancement-section">
            <h3>Multiclassing</h3>
            <div className="multiclass-info">
              <p>Your character is multiclassed across the following classes:</p>
              <div className="multiclass-breakdown">
                {data.classes.map((cls: any, index: number) => (
                  <div key={index} className="multiclass-entry">
                    <strong>{cls.name}</strong>
                    <span>Level {cls.level}</span>
                    {cls.subclass && <span>({cls.subclass})</span>}
                  </div>
                ))}
              </div>
              <div className="total-level">
                <strong>Total Character Level: {data.classes.reduce((sum: number, cls: any) => sum + cls.level, 0)}</strong>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

/**
 * Enhanced Character Creation Wizard with production-ready features
 * - React Portal-based modal management
 * - Comprehensive form validation with Zod schemas
 * - Error boundaries for each step
 * - Loading states and skeleton UI
 * - LocalStorage persistence
 * - Accessibility (ARIA) support
 */

import { zodResolver } from '@hookform/resolvers/zod';
import { ErrorBoundary, LoadingSpinner } from '@shared/components';
import clsx from 'clsx';
import { AlertTriangle, Check, Save, X } from 'lucide-react';
import React, { useCallback, useEffect, useMemo, useState } from 'react';
import { createPortal } from 'react-dom';
import { FormProvider, useForm } from 'react-hook-form';
import { z } from 'zod';
import { AbilitiesStep } from './AbilitiesStep';
import { BackgroundStep } from './BackgroundStep';
import { ClassStep } from './ClassStep';
import styles from './EnhancedCharacterWizard.module.css';
import { EquipmentSelectionStep } from './EquipmentSelectionStep';
