      totalWeight: weight,
      isEncumbered: weight >= capacity.encumbered_at,
      isHeavilyEncumbered: weight >= capacity.heavily_encumbered_at
    };
  }, [selectedItems, calculateCarryingCapacity]);

  if (loading) {
    return (
      <div className="equipment-selection-step loading">
        <div className="loading-spinner">Loading equipment...</div>
      </div>
    );
  }

  return (
    <ErrorBoundary>
      <div className={styles['equipment-selection-step']}>
        <h2>Select Starting Equipment</h2>
        
        {error && (
          <div className={styles['error-message']}>
            <span className={styles['error-icon']}>!</span>
            {error}
          </div>
        )}

        {/* Equipment Summary */}
        <div className={styles['equipment-summary']}>
          <div className={styles['summary-item']}>
            <span className={styles.label}>Starting Gold:</span>
            <span className={styles.value}>{startingGold} gp</span>
          </div>
          <div className={styles['summary-item']}>
            <span className={styles.label}>Remaining Gold:</span>
            <span className={styles.value}>{currentGold} gp</span>
          </div>
          <div className={styles['summary-item']}>
            <span className={styles.label}>Total Weight:</span>
            <span className={`${styles.value} ${isHeavilyEncumbered ? styles['heavily-encumbered'] : isEncumbered ? styles.encumbered : ''}`}>
              {totalWeight.toFixed(1)} lbs
              {isHeavilyEncumbered && ' (Heavily Encumbered)'}
              {isEncumbered && !isHeavilyEncumbered && ' (Encumbered)'}
            </span>
          </div>
        </div>

        {/* Currency Reference */}
        <div className={styles['currency-reference']}>
          <span className={styles['currency-label']}>Currency:</span>
          <span className={styles['currency-rate']}>10 cp = 1 sp</span>
          <span className={styles['currency-sep']}>┬╖</span>
          <span className={styles['currency-rate']}>10 sp = 1 gp</span>
          <span className={styles['currency-sep']}>┬╖</span>
          <span className={styles['currency-rate']}>2 ep = 1 gp</span>
          <span className={styles['currency-sep']}>┬╖</span>
          <span className={styles['currency-rate']}>10 gp = 1 pp</span>
        </div>

        {/* Standard Starting Equipment (Free) */}
        {(() => {
          const startingPack = equipmentManagementService.getStartingEquipment(characterClass);
          const classItems = startingPack.equipment.filter(Boolean);
          const bgItemNames = bgData?.equipment ?? [];
          const bgItems = bgItemNames.map(name => availableEquipment.find(e => e.name === name)).filter(Boolean) as Equipment[];
          const hasAny = classItems.length > 0 || bgItems.length > 0;
          if (!hasAny) return null;
          return (
            <div className={styles['starting-equipment']}>
              <div className={styles['starting-equipment-header']}>
                <span>Starting Equipment тАФ Free Grant</span>
                <button
                  className={styles['take-standard-button']}
                  onClick={() => {
                    const allItems = [
                      ...classItems.map(eq => equipmentToWizardItem(eq, 1)),
                      ...bgItems.map(eq => equipmentToWizardItem(eq, 1))
                    ];
                    setSelectedItems(allItems);
                    // No gold consumption тАФ starting gear is free in D&D 5e
                  }}
                >
                  Take Standard Pack
                </button>
              </div>
              {classItems.length > 0 && (
                <div className={styles['starting-items-list']}>
                  <span className={styles['starting-items-label']}>Class ({characterClass.charAt(0).toUpperCase() + characterClass.slice(1)}):</span>
                  {classItems.map((eq, i) => (
                    <span key={i} className={styles['starting-item-tag']}>{eq.name}</span>
                  ))}
                </div>
              )}
              {bgItems.length > 0 && (
                <div className={styles['starting-items-list']}>
                  <span className={styles['starting-items-label']}>Background ({characterBackground}):</span>
                  {bgItems.map((eq, i) => (
                    <span key={i} className={styles['starting-item-tag']}>{eq.name}</span>
                  ))}
                </div>
              )}
            </div>
          );
        })()}

        {/* Equipment Filters - Spans both columns */}
        <div className={styles['equipment-filters']}>
          <input
            type="text"
            placeholder="Search equipment..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className={styles['search-input']}
          />
          
          <div className={styles['category-filters']}>
            {equipmentCategories.map(category => (
              <button
                key={category}
                className={`${styles['category-button']} ${selectedCategory === category ? styles['active'] : ''}`}
                onClick={() => setSelectedCategory(category)}
              >
                {category.replace('-', ' ').replace(/\b\w/g, l => l.toUpperCase())}
              </button>
            ))}
          </div>
        </div>

        <div className={styles['equipment-content']}>
          {/* Available Equipment - Left side */}
          <div className={styles['available-equipment']}>
            <h3>Available Equipment ({filteredEquipment.length})</h3>
            <div className={styles.equipmentGrid}>
              {filteredEquipment.map((equipment) => {
                const isExpanded = expandedCards.has(equipment.name);
                const canAfford = currentGold >= costToGold(equipment.cost);
                return (
                  <div
                    key={equipment.name}
                    className={`${styles['equipment-card']} ${isExpanded ? styles['equipment-card-expanded'] : ''}`}
                    onClick={() => setExpandedCards(prev => {
                      const next = new Set(prev);
                      next.has(equipment.name) ? next.delete(equipment.name) : next.add(equipment.name);
                      return next;
                    })}
                  >
                    <div className={styles['equipment-compact-row']}>
                      <span className={styles['equipment-name']}>{equipment.name}</span>
                      <span className={styles['equipment-cost']}>{formatCost(equipment.cost)}</span>
                      {equipment.weight != null && <span className={styles['equipment-weight']}>{equipment.weight}lb</span>}
                      <button
                        className={styles['add-equipment-button']}
                        onClick={e => { e.stopPropagation(); addItem(equipment); }}
                        disabled={!canAfford}
                        title={canAfford ? 'Add to inventory' : 'Not enough gold'}
                      >
                        +
                      </button>
                    </div>
                    {isExpanded && (
                      <div className={styles['equipment-expanded-details']}>
                        {equipment.description && <p className={styles['equipment-description']}>{equipment.description}</p>}
                        {equipment.category && <span className={styles['equipment-category']}>{equipment.category}</span>}
                        <span className={styles['equipment-stats']}>{equipment.weight || 0} lbs</span>
                      </div>
                    )}
                  </div>
                );
              })}
              
              {filteredEquipment.length === 0 && (
                <div className={styles['no-equipment']}>
                  No equipment found matching your criteria.
                </div>
              )}
            </div>
          </div>

          {/* Selected Equipment */}
          <div className={styles['selected-equipment']}>
            <h3>Selected Equipment ({selectedItems.length})</h3>
            {selectedItems.length > 0 ? (
              <div className={styles['selected-items']}>
                {selectedItems.map((item, index) => (
                  <div key={`${item?.equipment?.name || 'item'}-${index}`} className={styles['selected-item']}>
                    <div className={styles['item-info']}>
                      <span className={styles['item-name']}>{item?.equipment?.name || 'Unknown Item'}</span>
                      <span className={styles['item-quantity']}>├Ч{item?.quantity || 1}</span>
                      <span className={styles['item-weight']}>{((item?.equipment?.weight ?? 0) * (item?.quantity ?? 1)).toFixed(1)} lbs</span>
                    </div>
                    <button
                      className={styles['remove-button']}
                      onClick={() => removeItem(index)}
                      title="Remove one"
                    >
                      тИТ
                    </button>
                  </div>
                ))}
              </div>
            ) : (
              <div className={styles['no-selected']}>
                No equipment selected yet.
              </div>
            )}
          </div>
        </div>

      </div>
    </ErrorBoundary>
  );
};

import React, { useEffect, useState } from 'react';
import { useFormContext } from 'react-hook-form';
import type { Feat, FeatChoice } from '../../services/featSelection.service';
import { featSelectionService } from '../../services/featSelection.service';
import styles from './FeatSelectionStep.module.css';

// Character form data interface
interface CharacterFormData {
  character_class: string;
  subclass: string;
  level: number;
  race: string;
  ability_scores: Record<string, number>;
  feats: string[];
  feat_choices: FeatChoice[];
}

interface FeatSelectionStepProps {
  onNext: () => void;
  onBack: () => void;
}

interface FeatDisplayProps {
  feat: Feat;
  isSelected: boolean;
  onSelect: () => void;
  characterAbilityScores: Record<string, number>;
  characterClass: string;
}

const FeatDisplay: React.FC<FeatDisplayProps> = ({ 
  feat, 
  isSelected, 
  onSelect, 
  characterAbilityScores, 
  characterClass 
}) => {
  const [showDetails, setShowDetails] = useState(false);
  const [showAnalysis, setShowAnalysis] = useState(false);

  const analysis = featSelectionService.analyzeFeatVsASI(feat, characterAbilityScores, characterClass);

  return (
    <div className={`feat-card ${isSelected ? 'selected' : ''}`}>
      <div className="feat-header" onClick={onSelect}>
        <div className="feat-info">
          <h4 className={styles.featName}>{feat.name}</h4>
          <div className="feat-tags">
            {feat.tags.map((tag, index) => (
              <span key={index} className={`feat-tag feat-tag-${tag.toLowerCase()}`}>
                {tag}
              </span>
            ))}
            {feat.is_half_feat && (
              <span className="feat-tag feat-tag-half">Half Feat</span>
            )}
          </div>
          <span className="feat-source">Source: {feat.source}</span>
        </div>
        <div className="feat-controls">
          <button
            type="button"
            className="details-toggle"
            onClick={(e) => {
              e.stopPropagation();
              setShowDetails(!showDetails);
            }}
          >
            {showDetails ? 'Hide' : 'Show'} Details
          </button>
        </div>
      </div>

      <p className={styles.featDescription}>{feat.description}</p>

      {feat.prerequisites.length > 0 && (
        <div className={styles.featPrerequisites}>
          <h5>Prerequisites:</h5>
          <ul>
            {feat.prerequisites.map((prereq, index) => (
              <li key={index}>{prereq.description}</li>
            ))}
          </ul>
        </div>
      )}

      {showDetails && (
        <div className="feat-details">
          <div className="feat-benefits">
            <h5>Benefits:</h5>
            <ul>
              {feat.benefits.map((benefit, index) => (
                <li key={index} className={`benefit-${benefit.type}`}>
                  <strong>{benefit.type.replace('_', ' ').toUpperCase()}:</strong> {benefit.description}
                  {benefit.choices && (
                    <div className="benefit-choices">
                      Choose from: {benefit.choices.join(', ')}
                    </div>
                  )}
                </li>
              ))}
            </ul>
          </div>

          <div className="feat-analysis">
            <button
              type="button"
              className="analysis-toggle"
              onClick={() => setShowAnalysis(!showAnalysis)}
            >
              {showAnalysis ? 'Hide' : 'Show'} Feat vs ASI Analysis
            </button>

            {showAnalysis && (
              <div className="analysis-content">
                <div className="recommendation">
                  <h6>Recommendation: <span className={`rec-${analysis.recommendation}`}>
                    {analysis.recommendation === 'feat' ? 'Take This Feat' : 
                     analysis.recommendation === 'asi' ? 'Take ASI Instead' : 'Either Option'}
                  </span></h6>
                  <p className="reasoning">{analysis.reasoning}</p>
                </div>
                
                <div className="comparison">
                  <div className="comparison-column">
                    <h6>Feat Benefits:</h6>
                    <ul>
                      {analysis.featBenefits.map((benefit, index) => (
                        <li key={index}>{benefit}</li>
                      ))}
                    </ul>
                  </div>
                  
                  <div className="comparison-column">
                    <h6>ASI Benefits:</h6>
                    <ul>
                      {analysis.asiBenefits.map((benefit, index) => (
                        <li key={index}>{benefit}</li>
                      ))}
                    </ul>
                  </div>
                </div>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

interface ASISelectionProps {
  currentScores: Record<string, number>;
  onASIChange: (improvements: Record<string, number>) => void;
  availablePoints: number;
}

const ASISelection: React.FC<ASISelectionProps> = ({ currentScores, onASIChange, availablePoints }) => {
  const [improvements, setImprovements] = useState<Record<string, number>>({});
  const abilities = ['Strength', 'Dexterity', 'Constitution', 'Intelligence', 'Wisdom', 'Charisma'];

  useEffect(() => {
    onASIChange(improvements);
  }, [improvements, onASIChange]);

  const handleImprovement = (ability: string, change: number) => {
    const newImprovements = { ...improvements };
    const current = newImprovements[ability] || 0;
    const newValue = Math.max(0, current + change);
    
    // Check if we have enough points
    const totalUsed = Object.values(newImprovements).reduce((sum, val) => sum + val, 0) - current + newValue;
    if (totalUsed <= availablePoints && newValue <= 1 && (currentScores[ability] || 10) + newValue <= 20) {
      newImprovements[ability] = newValue;
      if (newValue === 0) {
        delete newImprovements[ability];
      }
      setImprovements(newImprovements);
    }
  };

  const usedPoints = Object.values(improvements).reduce((sum, val) => sum + val, 0);

  return (
    <div className="asi-selection">
      <h3>Ability Score Improvement</h3>
      <p className="asi-description">
        You can increase your ability scores. You have {availablePoints} points to distribute, 
        with a maximum of 1 point per ability score.
      </p>
      
      <div className="points-display">
        <span className="points-used">{usedPoints}</span> / <span className="points-total">{availablePoints}</span> points used
      </div>

      <div className="abilities-grid">
        {abilities.map(ability => {
          const currentScore = currentScores[ability] || 10;
          const improvement = improvements[ability] || 0;
          const newScore = currentScore + improvement;
          const currentModifier = Math.floor((currentScore - 10) / 2);
          const newModifier = Math.floor((newScore - 10) / 2);
          const modifierChange = newModifier - currentModifier;

          return (
            <div key={ability} className="ability-improvement">
              <h4 className="ability-name">{ability}</h4>
              <div className="ability-scores">
                <div className="current-score">
                  Current: {currentScore} ({currentModifier >= 0 ? '+' : ''}{currentModifier})
                </div>
                {improvement > 0 && (
                  <div className="new-score">
                    New: {newScore} ({newModifier >= 0 ? '+' : ''}{newModifier})
                    {modifierChange > 0 && (
                      <span className="modifier-increase"> (+{modifierChange} modifier!)</span>
                    )}
                  </div>
                )}
              </div>
              
              <div className="improvement-controls">
                <button
                  type="button"
                  className="improvement-btn"
                  onClick={() => handleImprovement(ability, -1)}
                  disabled={improvement === 0}
                >
                  -
                </button>
                <span className="improvement-value">{improvement}</span>
                <button
                  type="button"
                  className="improvement-btn"
                  onClick={() => handleImprovement(ability, 1)}
                  disabled={
                    usedPoints >= availablePoints || 
                    improvement >= 1 || 
                    newScore >= 20
                  }
                >
                  +
                </button>
              </div>

              {newScore >= 20 && (
                <div className="ability-warning">Maximum ability score reached</div>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
};

const FeatSelectionStep: React.FC<FeatSelectionStepProps> = ({ onNext, onBack }) => {
  const { watch, setValue, formState: { errors } } = useFormContext<CharacterFormData>();
  
  const characterClass = watch('character_class') || '';
  const characterLevel = watch('level') || 1;
  const race = watch('race') || '';
  const abilityScores = watch('ability_scores') || {};
  const existingFeats = watch('feats') || [];
  const featChoices = watch('feat_choices') || [];

  const [selectionType, setSelectionType] = useState<'asi' | 'feat' | null>(null);
  const [selectedFeat, setSelectedFeat] = useState<string | null>(null);
  const [asiImprovements, setASIImprovements] = useState<Record<string, number>>({});
  const [featFilter, setFeatFilter] = useState<string>('all');
  const [searchTerm, setSearchTerm] = useState<string>('');

  // Check if character gets ASI/feat at current level
  const hasASIChoice = featSelectionService.hasASIChoiceAtLevel(characterClass, characterLevel);
  const availableFeats = featSelectionService.getAvailableFeats(
    characterLevel,
    characterClass,
    race,
    abilityScores,
    existingFeats,
    ['Wizard', 'Sorcerer', 'Cleric', 'Bard', 'Druid', 'Warlock'].includes(characterClass)
  );

  // Filter feats based on search and filter
  const filteredFeats = availableFeats.filter(feat => {
    const matchesSearch = searchTerm === '' || 
      feat.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      feat.description.toLowerCase().includes(searchTerm.toLowerCase());
    
    const matchesFilter = featFilter === 'all' || feat.tags.includes(featFilter);
    
    return matchesSearch && matchesFilter;
  });

  // Get feat recommendations
  const recommendations = featSelectionService.getFeatRecommendations(
    characterClass,
    abilityScores,
    race,
    featFilter === 'all' ? 'combat' : featFilter as any
  );

  useEffect(() => {
    // Load existing choice if any
    const existingChoice = featChoices.find(choice => 
      choice.level === characterLevel && choice.character_class === characterClass
    );
    
    if (existingChoice) {
      setSelectionType(existingChoice.selected_type || null);
      if (existingChoice.selected_feat) {
        setSelectedFeat(existingChoice.selected_feat);
      }
      if (existingChoice.asi_improvements) {
        setASIImprovements(existingChoice.asi_improvements);
      }
    }
  }, [characterLevel, characterClass, featChoices]);

  const handleSelectionTypeChange = (type: 'asi' | 'feat') => {
    setSelectionType(type);
    if (type === 'asi') {
      setSelectedFeat(null);
    } else {
      setASIImprovements({});
    }
  };

  const handleFeatSelect = (featName: string) => {
    setSelectedFeat(selectedFeat === featName ? null : featName);
  };

  const handleASIChange = (improvements: Record<string, number>) => {
    setASIImprovements(improvements);
  };

  const canProceed = (): boolean => {
    if (!hasASIChoice) return true; // No choice needed at this level
    
    if (selectionType === 'feat') {
      return selectedFeat !== null;
    }
    
    if (selectionType === 'asi') {
      const totalPoints = Object.values(asiImprovements).reduce((sum, val) => sum + val, 0);
      return totalPoints === 2; // Must use all ASI points
    }
    
    return false;
  };

  const handleNext = () => {
    if (hasASIChoice) {
      const newFeatChoice: FeatChoice = {
        level: characterLevel,
        character_class: characterClass,
        choice_type: 'both',
        selected_type: selectionType!,
        selected_feat: selectedFeat || undefined,
        asi_improvements: Object.keys(asiImprovements).length > 0 ? asiImprovements : undefined
      };

      // Update feat choices
      const updatedFeatChoices = featChoices.filter(choice => 
        !(choice.level === characterLevel && choice.character_class === characterClass)
      );
      updatedFeatChoices.push(newFeatChoice);
      setValue('feat_choices', updatedFeatChoices);

      // Update feats list if feat was selected
      if (selectedFeat) {
        const updatedFeats = [...existingFeats];
        if (!updatedFeats.includes(selectedFeat)) {
          updatedFeats.push(selectedFeat);
        }
        setValue('feats', updatedFeats);
      }

      // Update ability scores if ASI was selected
      if (selectionType === 'asi') {
        const updatedScores = { ...abilityScores };
        for (const [ability, improvement] of Object.entries(asiImprovements)) {
          updatedScores[ability] = (updatedScores[ability] || 10) + improvement;
        }
        setValue('ability_scores', updatedScores);
      }
    }

    onNext();
  };

  if (!hasASIChoice) {
    return (
      <div className="feat-selection-step">
        <div className="step-header">
          <h2>Feat Selection</h2>
          <p>Your character doesn't receive an Ability Score Improvement or feat at level {characterLevel}.</p>
        </div>

        <div className="step-navigation">
          <button type="button" onClick={onBack} className="btn btn-secondary">
            Back
          </button>
          <button type="button" onClick={onNext} className="btn btn-primary">
            Next: Continue
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="feat-selection-step">
      <div className="step-header">
        <h2>Ability Score Improvement or Feat</h2>
        <p>At level {characterLevel}, you can choose to either increase your ability scores or take a feat.</p>
      </div>

      <div className="choice-selector">
        <button
          type="button"
          className={`choice-btn ${selectionType === 'asi' ? 'selected' : ''}`}
          onClick={() => handleSelectionTypeChange('asi')}
        >
          Ability Score Improvement
        </button>
        <button
          type="button"
          className={`choice-btn ${selectionType === 'feat' ? 'selected' : ''}`}
          onClick={() => handleSelectionTypeChange('feat')}
        >
          Take a Feat
        </button>
      </div>

      {selectionType === 'asi' && (
        <ASISelection
          currentScores={abilityScores}
          onASIChange={handleASIChange}
          availablePoints={2}
        />
      )}

      {selectionType === 'feat' && (
        <div className={styles.featSelection}>
          <div className="feat-filters">
            <div className="search-container">
              <input
                type="text"
                placeholder="Search feats..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="feat-search"
              />
            </div>
            
            <select
              value={featFilter}
              onChange={(e) => setFeatFilter(e.target.value)}
              className="feat-filter"
            >
              <option value="all">All Feats</option>
              <option value="Combat">Combat</option>
              <option value="Magic">Magic</option>
              <option value="Utility">Utility</option>
              <option value="Social">Social</option>
            </select>
          </div>

          {recommendations.length > 0 && (
            <div className="feat-recommendations">
              <h3>Recommended Feats</h3>
              <div className="feats-grid">
                {recommendations.slice(0, 3).map((feat, index) => (
                  <FeatDisplay
                    key={index}
                    feat={feat}
                    isSelected={selectedFeat === feat.name}
                    onSelect={() => handleFeatSelect(feat.name)}
                    characterAbilityScores={abilityScores}
                    characterClass={characterClass}
                  />
                ))}
              </div>
            </div>
          )}

          <div className="all-feats">
            <h3>All Available Feats ({filteredFeats.length})</h3>
            <div className="feats-grid">
              {filteredFeats.map((feat, index) => (
                <FeatDisplay
                  key={index}
                  feat={feat}
                  isSelected={selectedFeat === feat.name}
                  onSelect={() => handleFeatSelect(feat.name)}
                  characterAbilityScores={abilityScores}
                  characterClass={characterClass}
                />
              ))}
            </div>
          </div>
        </div>
      )}

      {errors.feat_choices && (
        <div className="error-message">
          Please make a selection before proceeding.
        </div>
      )}

      <div className="step-navigation">
        <button type="button" onClick={onBack} className="btn btn-secondary">
          Back
        </button>
        <button 
          type="button" 
          onClick={handleNext}
          disabled={!canProceed()}
          className="btn btn-primary"
        >
          Next: Continue
        </button>
      </div>
    </div>
  );
};

export default FeatSelectionStep;

import type { CharacterTemplate } from '@features/character';
import { ALL_TEMPLATES } from '@features/character';
import { useRef } from 'react';
import { useFormContext } from 'react-hook-form';
import styles from './IdentityStep.module.css';

const ALIGNMENTS = [
  'Lawful Good', 'Neutral Good', 'Chaotic Good',
  'Lawful Neutral', 'True Neutral', 'Chaotic Neutral',
  'Lawful Evil', 'Neutral Evil', 'Chaotic Evil',
] as const;

interface IdentityStepData {
  name: string;
  bio?: string;
  image?: string;
  alignment?: string;
}

export function IdentityStep({ onNext, onBack: _onBack }: { onNext?: () => void; onBack?: () => void } = {}) {
  const { register, setValue, getValues, formState, watch } = useFormContext<IdentityStepData>();
  const imageInputRef = useRef<HTMLInputElement>(null);
  const imageUrl = watch('image');

  function handleTemplateSelect(templateId: string) {
    if (!templateId) return;
    const template = ALL_TEMPLATES.find((t: CharacterTemplate) => t.id === templateId);
    if (!template) return;
    Object.entries(template.data).forEach(([key, value]) => {
      setValue(key as any, value, { shouldValidate: true });
    });
  }

  function handleImageChange(e: React.ChangeEvent<HTMLInputElement>) {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (ev) => {
        setValue('image', ev.target?.result as string, { shouldValidate: true });
      };
      reader.readAsDataURL(file);
    }
  }

  function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    if (!getValues('name')) {
      formState.errors.name = { type: 'manual', message: 'Name is required' };
      return;
    }
    onNext?.();
  }

  return (
    <form onSubmit={handleSubmit} className={styles.step}>
      <div className={styles.header}>
        <h3 className={styles.title}>Character Identity</h3>
        <p className={styles.subtitle}>Choose your character's name and background</p>
      </div>

      <div className={styles.field}>
        <label className={styles.label}>
          <span className={styles['label-text']}>Start with a template (optional)</span>
          <select
            className={styles.select}
            defaultValue=""
            onChange={(e) => handleTemplateSelect(e.target.value)}
          >
            <option value="">None тАФ start from scratch</option>
            <optgroup label="Player Characters">
              {ALL_TEMPLATES.filter((t: CharacterTemplate) => t.type === 'pc').map((t: CharacterTemplate) => (
                <option key={t.id} value={t.id}>{t.name}</option>
              ))}
            </optgroup>
            <optgroup label="NPCs / Monsters">
              {ALL_TEMPLATES.filter((t: CharacterTemplate) => t.type === 'npc').map((t: CharacterTemplate) => (
                <option key={t.id} value={t.id}>{t.name}</option>
              ))}
            </optgroup>
          </select>
        </label>
      </div>

      <div className={styles.field}>
        <label className={styles.label}>
          <span className={styles['label-text']}>Character Name <span className={styles.required}>*</span></span>
          <input
            {...register('name', { required: true })}
            placeholder="Enter character name..."
            className={styles.input}
          />
        </label>
        {formState.errors.name && (
          <span className={styles.error}>{formState.errors.name.message as string}</span>
        )}
      </div>

      <div className={styles.field}>
        <label className={styles.label}>
          <span className={styles['label-text']}>Character Bio</span>
          <textarea
            {...register('bio')}
            placeholder="Describe your character's backstory..."
            rows={4}
            className={styles.textarea}
          />
        </label>
      </div>

      <div className={styles.field}>
        <span className={styles['label-text']}>Alignment</span>
        <select {...register('alignment')} className={styles.select}>
          <option value="">тАФ Choose alignment тАФ</option>
          {ALIGNMENTS.map((a) => (
            <option key={a} value={a}>{a}</option>
          ))}
        </select>
      </div>

      <div className={styles.field}>
        <span className={styles['label-text']}>Character Portrait / Token Image</span>
        <div className={styles.portraitSection}>
          {imageUrl ? (
            <img src={imageUrl} alt="Character portrait" className={styles.portrait} />
          ) : (
            <div className={styles.portraitPlaceholder}>
              <span>No image</span>
            </div>
          )}
          <div className={styles.portraitActions}>
            <button
              type="button"
              className={styles.uploadBtn}
              onClick={() => imageInputRef.current?.click()}
            >
              {imageUrl ? 'Change Image' : 'Upload Image'}
            </button>
            {imageUrl && (
              <button
                type="button"
                className={styles.removeBtn}
                onClick={() => setValue('image', '', { shouldValidate: true })}
              >
                Remove
              </button>
            )}
            <span className={styles.hint}>PNG, JPG, WebP тАФ used as token on the table</span>
          </div>
        </div>
        <input
          type="file"
          accept="image/png,image/jpeg,image/webp,image/gif"
          ref={imageInputRef}
          onChange={handleImageChange}
          className={styles['file-input-hidden']}
        />
      </div>
    </form>
  );
}

export default IdentityStep;

/**
 * Level Up Wizard Component
 * Handles character level progression with automatic feature/spell advancement
 */

import { useEffect, useState } from 'react';
import { AdvancementSystemService, type AdvancedCharacter, type LevelProgression, type MulticlassRequirements } from '../../services/advancementSystem.service';

interface LevelUpWizardProps {
  character: AdvancedCharacter;
  onComplete: (updatedCharacter: AdvancedCharacter) => void;
  onCancel: () => void;
}

type LevelUpStep = 'class-choice' | 'hit-points' | 'asi-feat' | 'features' | 'spells' | 'review';

interface LevelUpChoices {
  class: string;
  hitPointMethod: 'average' | 'roll';
  hitPointRoll?: number;
  hitPointIncrease: number;
  asiOrFeat: 'asi' | 'feat';
  asiChoices?: Record<string, number>;
  featChoice?: string;
  featureChoices: Record<string, string>;
  newSpells: string[];
  newCantrips: string[];
}

export function LevelUpWizard({ character, onComplete, onCancel }: LevelUpWizardProps) {
  if (!character) {
    return (
      <div className="level-up-wizard">
        <div className="wizard-header">
          <h2>Error</h2>
          <p>Character data is missing. Please go back and complete the previous steps.</p>
        </div>
        <div className="wizard-actions">
          <button onClick={onCancel} className="btn-secondary">Back</button>
        </div>
      </div>
    );
  }
  
  if (!character.totalLevel || !character.experiencePoints) {
    return (
      <div className="level-up-wizard">
        <div className="wizard-header">
          <h2>Error</h2>
          <p>Character data is incomplete. Missing level or experience points.</p>
        </div>
        <div className="wizard-actions">
          <button onClick={onCancel} className="btn-secondary">Back</button>
        </div>
      </div>
    );
  }
  
  const [currentStep, setCurrentStep] = useState<LevelUpStep>('class-choice');
  const [levelProgression, setLevelProgression] = useState<LevelProgression | null>(null);
  const [multiclassOptions, setMulticlassOptions] = useState<MulticlassRequirements[]>([]);
  const [choices, setChoices] = useState<LevelUpChoices>({
    class: character.classLevels[0]?.class || character.class,
    hitPointMethod: 'average',
    hitPointIncrease: 0,
    asiOrFeat: 'asi',
    featureChoices: {},
    newSpells: [],
    newCantrips: []
  });
  
  const nextLevel = character.totalLevel + 1;
  const currentXP = character.experiencePoints.current;
  const requiredXP = AdvancementSystemService.calculateXPForLevel(nextLevel);
  const canLevelUp = currentXP >= requiredXP;
  
  useEffect(() => {
    if (!canLevelUp) return;
    
    // Check multiclass options
    const abilities = {
      strength: character.strength,
      dexterity: character.dexterity,
      constitution: character.constitution,
      intelligence: character.intelligence,
      wisdom: character.wisdom,
      charisma: character.charisma
    };
    
    const allClasses = ['Fighter', 'Wizard', 'Rogue', 'Cleric', 'Barbarian', 'Bard', 'Druid', 'Monk', 'Paladin', 'Ranger', 'Sorcerer', 'Warlock'];
    const multiclassChecks = allClasses
      .filter(cls => !character.classLevels.some(cl => cl.class.toLowerCase() === cls.toLowerCase()))
      .map(cls => AdvancementSystemService.checkMulticlassRequirements(cls, abilities));
    
    setMulticlassOptions(multiclassChecks);
  }, [character, canLevelUp]);
  
  useEffect(() => {
    if (choices.class) {
      const classLevels = character.classLevels.find(cl => cl.class.toLowerCase() === choices.class.toLowerCase());
      const classLevel = (classLevels?.level || 0) + 1;
      
      const progression: LevelProgression = {
        level: nextLevel,
        totalXP: AdvancementSystemService.calculateXPForLevel(nextLevel),
        proficiencyBonus: AdvancementSystemService.getProficiencyBonus(nextLevel),
        newFeatures: AdvancementSystemService.getClassFeaturesForLevel(choices.class, classLevel),
        newSpells: AdvancementSystemService.getSpellProgression(choices.class, classLevel) || undefined,
        hitPointIncrease: AdvancementSystemService.calculateHitPointIncrease(
          choices.class, 
          Math.floor((character.constitution - 10) / 2)
        ),
        asiOrFeatAvailable: AdvancementSystemService.isASILevel(choices.class, classLevel)
      };
      
      setLevelProgression(progression);
      setChoices(prev => ({ ...prev, hitPointIncrease: progression.hitPointIncrease }));
    }
  }, [choices.class, character, nextLevel]);
  
  if (!canLevelUp) {
    return (
      <div className="level-up-wizard">
        <div className="wizard-header">
          <h2>Level Up Not Available</h2>
          <p>Your character does not have enough experience to level up.</p>
        </div>
        <div className="wizard-navigation">
          <button 
            type="button" 
            onClick={onCancel}
            className="nav-button secondary"
          >
            Close
          </button>
        </div>
      </div>
    );
  }
  
  const handleStepNavigation = (direction: 'next' | 'back') => {
    const steps: LevelUpStep[] = ['class-choice', 'hit-points', 'asi-feat', 'features', 'spells', 'review'];
    const currentIndex = steps.indexOf(currentStep);
    
    if (direction === 'next' && currentIndex < steps.length - 1) {
      // Skip steps that don't apply
      let nextStep = steps[currentIndex + 1];
      
      if (nextStep === 'asi-feat' && !levelProgression?.asiOrFeatAvailable) {
        nextStep = steps[currentIndex + 2] || 'review';
      }
      if (nextStep === 'features' && (!levelProgression?.newFeatures.length || !levelProgression.newFeatures.some(f => f.choices))) {
        nextStep = steps[currentIndex + 3] || 'review';
      }
      if (nextStep === 'spells' && !levelProgression?.newSpells) {
        nextStep = 'review';
      }
      
      setCurrentStep(nextStep);
    } else if (direction === 'back' && currentIndex > 0) {
      setCurrentStep(steps[currentIndex - 1]);
    }
  };
  
  const handleFinishLevelUp = () => {
    const updatedCharacter = AdvancementSystemService.applyLevelUp(character, {
      class: choices.class,
      hitPointIncrease: choices.hitPointIncrease,
      asiChoices: choices.asiChoices,
      featChoice: choices.featChoice,
      featureChoices: choices.featureChoices,
      newSpells: choices.newSpells,
      newCantrips: choices.newCantrips
    });
    
    onComplete(updatedCharacter);
  };
  
  const renderClassChoice = () => (
    <div className="level-up-step">
      <h3>Choose Class for Level {nextLevel}</h3>
      <div className="class-options">
        {/* Current class option */}
        <div className="class-option primary">
          <label>
            <input
              type="radio"
              value={character.classLevels[0]?.class || character.class}
              checked={choices.class === (character.classLevels[0]?.class || character.class)}
              onChange={(e) => setChoices(prev => ({ ...prev, class: e.target.value }))}
            />
            <div className="class-info">
              <strong>Continue as {character.classLevels[0]?.class || character.class}</strong>
              <span>Level {(character.classLevels[0]?.level || 0) + 1}</span>
            </div>
          </label>
        </div>
        
        {/* Multiclass options */}
        {multiclassOptions.filter(opt => opt.met).map(option => (
          <div key={option.class} className="class-option multiclass">
            <label>
              <input
                type="radio"
                value={option.class}
                checked={choices.class === option.class}
                onChange={(e) => setChoices(prev => ({ ...prev, class: e.target.value }))}
              />
              <div className="class-info">
                <strong>Multiclass into {option.class}</strong>
                <span>Level 1 {option.class}</span>
              </div>
            </label>
          </div>
        ))}
        
        {/* Unavailable multiclass options */}
        {multiclassOptions.filter(opt => !opt.met).map(option => (
          <div key={option.class} className="class-option disabled">
            <div className="class-info">
              <strong>{option.class}</strong>
              <span className="requirements-not-met">
                Requires: {option.missing.join(', ')}
              </span>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
  
  const renderHitPointChoice = () => (
    <div className="level-up-step">
      <h3>Hit Point Increase</h3>
      <div className="hit-point-options">
        <div className="hp-method">
          <label>
            <input
              type="radio"
              value="average"
              checked={choices.hitPointMethod === 'average'}
              onChange={(e) => setChoices(prev => ({
                ...prev,
                hitPointMethod: e.target.value as 'average' | 'roll',
                hitPointIncrease: levelProgression?.hitPointIncrease || 0
              }))}
            />
            <div className="method-info">
              <strong>Take Average</strong>
              <span>Gain {levelProgression?.hitPointIncrease} hit points (recommended)</span>
            </div>
          </label>
        </div>
        
        <div className="hp-method">
          <label>
            <input
              type="radio"
              value="roll"
              checked={choices.hitPointMethod === 'roll'}
              onChange={(e) => setChoices(prev => ({ ...prev, hitPointMethod: e.target.value as 'average' | 'roll' }))}
            />
            <div className="method-info">
              <strong>Roll Hit Die</strong>
              <span>Roll for hit points (minimum 1 + CON modifier)</span>
            </div>
          </label>
        </div>
        
        {choices.hitPointMethod === 'roll' && (
          <div className="hp-roll-section">
            <button 
              type="button" 
              className="roll-button"
              onClick={() => {
                // In a real implementation, this would be a proper dice roll
                const hitDie = choices.class === 'Wizard' ? 6 : choices.class === 'Fighter' ? 10 : 8;
                const roll = Math.floor(Math.random() * hitDie) + 1;
                const conModifier = Math.floor((character.constitution - 10) / 2);
                const increase = Math.max(1, roll + conModifier);
                setChoices(prev => ({ ...prev, hitPointRoll: roll, hitPointIncrease: increase }));
              }}
            >
              Roll Hit Die
            </button>
            {choices.hitPointRoll && (
              <div className="roll-result">
                <span>Rolled: {choices.hitPointRoll}</span>
                <span>+ {Math.floor((character.constitution - 10) / 2)} (CON)</span>
                <span>= {choices.hitPointIncrease} HP gained</span>
              </div>
            )}
          </div>
        )}
      </div>
      
      <div className="hp-preview">
        <div className="hp-current">
          Current HP: {character.hitPoints.maximum}
        </div>
        <div className="hp-new">
          New HP: {character.hitPoints.maximum + choices.hitPointIncrease}
        </div>
      </div>
    </div>
  );
  
  const renderASIFeatChoice = () => {
    if (!levelProgression?.asiOrFeatAvailable) return null;
    
    return (
      <div className="level-up-step">
        <h3>Ability Score Improvement or Feat</h3>
        <div className="asi-feat-options">
          <div className="option-type">
            <label>
              <input
                type="radio"
                value="asi"
                checked={choices.asiOrFeat === 'asi'}
                onChange={(e) => setChoices(prev => ({ ...prev, asiOrFeat: e.target.value as 'asi' | 'feat' }))}
              />
              <div className="choice-info">
                <strong>Ability Score Improvement</strong>
                <span>Increase your ability scores by 2 points total</span>
              </div>
            </label>
          </div>
          
          <div className="option-type">
            <label>
              <input
                type="radio"
                value="feat"
                checked={choices.asiOrFeat === 'feat'}
                onChange={(e) => setChoices(prev => ({ ...prev, asiOrFeat: e.target.value as 'asi' | 'feat' }))}
              />
              <div className="choice-info">
                <strong>Choose a Feat</strong>
                <span>Gain a special ability or training</span>
              </div>
            </label>
          </div>
        </div>
        
        {choices.asiOrFeat === 'asi' && (
          <div className="asi-selection">
            <h4>Allocate 2 points among your abilities:</h4>
            <div className="ability-increases">
              {['strength', 'dexterity', 'constitution', 'intelligence', 'wisdom', 'charisma'].map(ability => {
                const currentScore = (character as any)[ability];
                const increase = choices.asiChoices?.[ability] || 0;
                const maxIncrease = Math.min(2, 20 - currentScore);
                
                return (
                  <div key={ability} className="ability-increase">
                    <label>{ability.charAt(0).toUpperCase() + ability.slice(1)}</label>
                    <div className="ability-control">
                      <span className="current-score">{currentScore}</span>
                      <button
                        type="button"
                        onClick={() => {
                          const newChoices = { ...choices.asiChoices };
                          const currentIncrease = newChoices[ability] || 0;
                          if (currentIncrease > 0) {
                            newChoices[ability] = currentIncrease - 1;
                            if (newChoices[ability] === 0) delete newChoices[ability];
                            setChoices(prev => ({ ...prev, asiChoices: newChoices }));
                          }
                        }}
                        disabled={increase === 0}
                      >
                        -
                      </button>
                      <span className="increase-amount">+{increase}</span>
                      <button
                        type="button"
                        onClick={() => {
                          const totalIncreases = Object.values(choices.asiChoices || {}).reduce((sum, val) => sum + val, 0);
                          if (totalIncreases < 2 && increase < maxIncrease) {
                            const newChoices = { ...choices.asiChoices, [ability]: increase + 1 };
                            setChoices(prev => ({ ...prev, asiChoices: newChoices }));
                          }
                        }}
                        disabled={increase >= maxIncrease || Object.values(choices.asiChoices || {}).reduce((sum, val) => sum + val, 0) >= 2}
                      >
                        +
                      </button>
                      <span className="new-score">тЖТ {currentScore + increase}</span>
                    </div>
                  </div>
                );
              })}
            </div>
            <div className="asi-summary">
              Points remaining: {2 - Object.values(choices.asiChoices || {}).reduce((sum, val) => sum + val, 0)}
            </div>
          </div>
        )}
        
        {choices.asiOrFeat === 'feat' && (
          <div className="feat-selection">
            <h4>Choose a Feat:</h4>
            <select
              value={choices.featChoice || ''}
              onChange={(e) => setChoices(prev => ({ ...prev, featChoice: e.target.value }))}
            >
              <option value="">Select a feat...</option>
              <option value="Alert">Alert</option>
              <option value="Athlete">Athlete</option>
              <option value="Great Weapon Master">Great Weapon Master</option>
              <option value="Lucky">Lucky</option>
              <option value="Magic Initiate">Magic Initiate</option>
              <option value="Sharpshooter">Sharpshooter</option>
              <option value="War Caster">War Caster</option>
            </select>
          </div>
        )}
      </div>
    );
  };
  
  const renderFeatureChoices = () => {
    const featuresWithChoices = levelProgression?.newFeatures.filter(f => f.choices && f.choices.length > 0) || [];
    
    if (featuresWithChoices.length === 0) return null;
    
    return (
      <div className="level-up-step">
        <h3>Feature Choices</h3>
        <div className="feature-choices">
          {featuresWithChoices.map((feature, index) => (
            <div key={index} className="feature-choice">
              <h4>{feature.name}</h4>
              <p>{feature.description}</p>
              {feature.choices?.map((choice, choiceIndex) => (
                <div key={choiceIndex} className="choice-selection">
                  <label>{choice.name}:</label>
                  <select
                    value={choices.featureChoices[`${feature.name}-${choice.name}`] || ''}
                    onChange={(e) => setChoices(prev => ({
                      ...prev,
                      featureChoices: {
                        ...prev.featureChoices,
                        [`${feature.name}-${choice.name}`]: e.target.value
                      }
                    }))}
                  >
                    <option value="">Select...</option>
                    {choice.options.map(option => (
                      <option key={option} value={option}>{option}</option>
                    ))}
                  </select>
                </div>
              ))}
            </div>
          ))}
        </div>
      </div>
    );
  };
  
  const renderSpellChoices = () => {
    if (!levelProgression?.newSpells) return null;
    
    return (
      <div className="level-up-step">
        <h3>New Spells</h3>
        <div className="spell-selection">
          {levelProgression.newSpells.newCantrips > 0 && (
            <div className="cantrip-selection">
              <h4>Choose {levelProgression.newSpells.newCantrips} Cantrips:</h4>
              {/* Cantrip selection would go here - simplified for now */}
              <div className="spell-grid">
                {['Mage Hand', 'Prestidigitation', 'Fire Bolt', 'Minor Illusion'].map(cantrip => (
                  <label key={cantrip}>
                    <input
                      type="checkbox"
                      checked={choices.newCantrips.includes(cantrip)}
                      onChange={(e) => {
                        if (e.target.checked && choices.newCantrips.length < levelProgression.newSpells!.newCantrips) {
                          setChoices(prev => ({ ...prev, newCantrips: [...prev.newCantrips, cantrip] }));
                        } else if (!e.target.checked) {
                          setChoices(prev => ({ ...prev, newCantrips: prev.newCantrips.filter(c => c !== cantrip) }));
                        }
                      }}
                    />
                    {cantrip}
                  </label>
                ))}
              </div>
            </div>
          )}
          
          {levelProgression.newSpells.newSpells > 0 && (
            <div className="spell-selection">
              <h4>Choose {levelProgression.newSpells.newSpells} Spells:</h4>
              {/* Spell selection would go here - simplified for now */}
              <div className="spell-grid">
                {['Magic Missile', 'Shield', 'Burning Hands', 'Identify'].map(spell => (
                  <label key={spell}>
                    <input
                      type="checkbox"
                      checked={choices.newSpells.includes(spell)}
                      onChange={(e) => {
                        if (e.target.checked && choices.newSpells.length < levelProgression.newSpells!.newSpells) {
                          setChoices(prev => ({ ...prev, newSpells: [...prev.newSpells, spell] }));
                        } else if (!e.target.checked) {
                          setChoices(prev => ({ ...prev, newSpells: prev.newSpells.filter(s => s !== spell) }));
                        }
                      }}
                    />
                    {spell}
                  </label>
                ))}
              </div>
            </div>
          )}
        </div>
      </div>
    );
  };
  
  const renderReview = () => (
    <div className="level-up-step">
      <h3>Review Level Up</h3>
      <div className="level-up-summary">
        <div className="summary-section">
          <h4>Level Progression</h4>
          <p>Advancing to Level {nextLevel} {choices.class}</p>
          <p>Hit Points: +{choices.hitPointIncrease} ({character.hitPoints.maximum} тЖТ {character.hitPoints.maximum + choices.hitPointIncrease})</p>
          <p>Proficiency Bonus: +{levelProgression?.proficiencyBonus}</p>
        </div>
        
        {levelProgression?.asiOrFeatAvailable && (
          <div className="summary-section">
            <h4>Ability Improvement</h4>
            {choices.asiOrFeat === 'asi' && choices.asiChoices && (
              <div>
                <p>Ability Score Increases:</p>
                <ul>
                  {Object.entries(choices.asiChoices).map(([ability, increase]) => (
                    <li key={ability}>
                      {ability.charAt(0).toUpperCase() + ability.slice(1)}: +{increase}
                    </li>
                  ))}
                </ul>
              </div>
            )}
            {choices.asiOrFeat === 'feat' && choices.featChoice && (
              <p>Feat: {choices.featChoice}</p>
            )}
          </div>
        )}
        
        {levelProgression?.newFeatures && levelProgression.newFeatures.length > 0 && (
          <div className="summary-section">
            <h4>New Features</h4>
            <ul>
              {levelProgression.newFeatures.map((feature, index) => (
                <li key={index}>{feature.name}</li>
              ))}
            </ul>
          </div>
        )}
        
        {(choices.newSpells.length > 0 || choices.newCantrips.length > 0) && (
          <div className="summary-section">
            <h4>New Spells</h4>
            {choices.newCantrips.length > 0 && (
              <p>Cantrips: {choices.newCantrips.join(', ')}</p>
            )}
            {choices.newSpells.length > 0 && (
              <p>Spells: {choices.newSpells.join(', ')}</p>
            )}
          </div>
        )}
      </div>
    </div>
  );
  
  return (
    <div className="level-up-wizard">
      <div className="wizard-header">
        <h2>Level Up to {nextLevel}</h2>
