              )}
              {selectedSpell.savingThrow && (
                <div className="spell-save"><strong>Saving Throw:</strong> {selectedSpell.savingThrow}</div>
              )}
              <div className="spell-description-detailed">{selectedSpell.description}</div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

