                                  </div>
                                  
                                  <p className={styles['spell-description']}>{spell.description}</p>
                                  
                                  {spell.higher_levels && (
                                    <p className={styles['at-higher-levels']}>
                                      <strong>At Higher Levels:</strong> {spell.higher_levels}
                                    </p>
                                  )}

                                  <button
                                    className={!canSelect && !isSelected
                                      ? styles['add-spell-button-disabled']
                                      : isSelected
                                        ? styles['add-spell-button-remove']
                                        : styles['add-spell-button-add']}
                                    onClick={(e) => {
                                      e.stopPropagation();
                                      if (canSelect || isSelected) handleSpellToggle(spell);
                                    }}
                                    disabled={!canSelect && !isSelected}
                                  >
                                    {isSelected ? 'Selected' : '+ Add to Spellbook'}
                                  </button>
                                </div>
                              )}
                            </div>
                          );
                        })}
                      </div>
                    </div>
                  );
                })}
            </div>
          </div>

          {/* Right Side: Selected Spells Panel */}
          <div className={styles['selected-spells-panel']}>
            <div className={styles['panel-sticky']}>
              <h3>Your Spellbook</h3>
              
              {/* Spell Statistics */}
              <div className={styles['spell-stats-panel']}>
                <div className={styles['stat-row']}>
                  <span className={styles['stat-label']}>Cantrips:</span>
                  <span className={currentSpells.cantrips.length >= (spellSlots.cantrips || 0) ? styles['stat-value-complete'] : styles['stat-value']}>
                    {currentSpells.cantrips.length} / {spellSlots.cantrips || 0}
                  </span>
                </div>
                
                <div className={styles['stat-row']}>
                  <span className={styles['stat-label']}>{maxSpellsKnown === Infinity ? 'Spells' : 'Known'}:</span>
                  <span className={maxSpellsKnown !== Infinity && currentSpells.knownSpells.length >= maxSpellsKnown ? styles['stat-value-complete'] : styles['stat-value']}>
                    {currentSpells.knownSpells.length} {maxSpellsKnown === Infinity ? '' : `/ ${maxSpellsKnown}`}
                  </span>
                </div>

                <div className={styles['stat-row']}>
                  <span className={styles['stat-label']}>Spell Save DC:</span>
                  <span className={styles['stat-value']}>{spellcastingStats.spellSaveDC}</span>
                </div>

                <div className={styles['stat-row']}>
                  <span className={styles['stat-label']}>Spell Attack:</span>
                  <span className={styles['stat-value']}>+{spellcastingStats.spellAttackBonus}</span>
                </div>
              </div>

              {/* Selected Cantrips */}
              <div className={styles['selected-spell-section']}>
                <h4>Cantrips ({currentSpells.cantrips.length})</h4>
                {currentSpells.cantrips.length > 0 ? (
                  <ul className={styles['selected-spell-list']}>
                    {currentSpells.cantrips.map(spellName => {
                      const spell = availableSpells[spellName];
                      return (
                        <li key={spellName} className={styles['selected-spell-item']}>
                          <span className={styles['spell-name']}>{spellName}</span>
                          <button
                            className={styles['remove-spell-btn']}
                            onClick={() => spell && handleSpellToggle(spell)}
                            title="Remove spell"
                          >
                            ├Ч
                          </button>
                        </li>
                      );
                    })}
                  </ul>
                ) : (
                  <p className={styles['empty-message']}>No cantrips selected</p>
                )}
              </div>

              {/* Selected Spells */}
              <div className={styles['selected-spell-section']}>
                <h4>{maxSpellsKnown === Infinity ? 'Spells' : 'Known Spells'} ({currentSpells.knownSpells.length})</h4>
                {currentSpells.knownSpells.length > 0 ? (
                  <ul className={styles['selected-spell-list']}>
                    {currentSpells.knownSpells.map(spellName => {
                      const spell = availableSpells[spellName];
                      return (
                        <li key={spellName} className={styles['selected-spell-item']}>
                          <span className={styles['spell-name']}>{spellName}</span>
                          {spell && <span className={styles['selected-spell-level']}>Lvl {spell.level}</span>}
                          <button
                            className={styles['remove-spell-btn']}
                            onClick={() => spell && handleSpellToggle(spell)}
                            title="Remove spell"
                          >
                            ├Ч
                          </button>
                        </li>
                      );
                    })}
                  </ul>
                ) : (
                  <p className={styles['empty-message']}>No spells selected</p>
                )}
              </div>
            </div>
          </div>
        </div>

        {errors.spells && (
          <div className={styles['validation-error']}>
            {errors.spells.message}
          </div>
        )}

      </div>
    </ErrorBoundary>
  );
};

/**
 * Template Selection Step for Character Wizard
 * Allows users to choose between PC templates, NPC templates, or start from scratch
 */

import type { CharacterTemplate } from '@features/character';
import { ALL_TEMPLATES, getTemplatesByType } from '@features/character';
import React, { useState } from 'react';
import { useFormContext } from 'react-hook-form';
import type { WizardFormData } from './WizardFormData';

export const TemplateSelectionStep: React.FC = () => {
  const { setValue } = useFormContext<WizardFormData>();
  const [selectedTemplate, setSelectedTemplate] = useState<string | null>(null);
  const [templateType, setTemplateType] = useState<'pc' | 'npc' | 'scratch'>('scratch');

  const handleTemplateTypeChange = (type: 'pc' | 'npc' | 'scratch') => {
    setTemplateType(type);
    setSelectedTemplate(null);
  };

  const handleTemplateSelect = (template: CharacterTemplate) => {
    setSelectedTemplate(template.id);
    
    // Apply template data to form
    Object.entries(template.data).forEach(([key, value]) => {
      setValue(key as any, value, { shouldValidate: true });
    });
  };

  const pcTemplates = getTemplatesByType('pc');
  const npcTemplates = getTemplatesByType('npc');

  return (
    <div className="template-selection-step">
      <div className="step-header">
        <h3>Choose a Template</h3>
        <p className="step-description">
          Start with a template or create from scratch. Templates pre-fill common character data.
        </p>
      </div>

      {/* Template Type Selector */}
      <div className="template-type-selector">
        <button
          type="button"
          className={`template-type-btn ${templateType === 'scratch' ? 'active' : ''}`}
          onClick={() => handleTemplateTypeChange('scratch')}
        >
          <div className="template-type-icon">*</div>
          <div className="template-type-info">
            <div className="template-type-title">Start from Scratch</div>
            <div className="template-type-desc">Build your character step by step</div>
          </div>
        </button>

        <button
          type="button"
          className={`template-type-btn ${templateType === 'pc' ? 'active' : ''}`}
          onClick={() => handleTemplateTypeChange('pc')}
        >
          <div className="template-type-icon">@</div>
          <div className="template-type-info">
            <div className="template-type-title">Player Character</div>
            <div className="template-type-desc">Full character sheet for PCs</div>
          </div>
        </button>

        <button
          type="button"
          className={`template-type-btn ${templateType === 'npc' ? 'active' : ''}`}
          onClick={() => handleTemplateTypeChange('npc')}
        >
          <div className="template-type-icon">#</div>
          <div className="template-type-info">
            <div className="template-type-title">NPC/Monster</div>
            <div className="template-type-desc">Simplified stat block for NPCs</div>
          </div>
        </button>
      </div>

      {/* Template List */}
      {templateType === 'pc' && (
        <div className="template-list">
          <h4>Player Character Templates</h4>
          <div className="template-grid">
            {pcTemplates.map((template: CharacterTemplate) => (
              <button
                key={template.id}
                type="button"
                className={`template-card ${selectedTemplate === template.id ? 'selected' : ''}`}
                onClick={() => handleTemplateSelect(template)}
              >
                <div className="template-icon">{template.icon}</div>
                <div className="template-name">{template.name}</div>
                <div className="template-description">{template.description}</div>
              </button>
            ))}
          </div>
        </div>
      )}

      {templateType === 'npc' && (
        <div className="template-list">
          <h4>NPC/Monster Templates</h4>
          <div className="template-grid">
            {npcTemplates.map((template: CharacterTemplate) => (
              <button
                key={template.id}
                type="button"
                className={`template-card ${selectedTemplate === template.id ? 'selected' : ''}`}
                onClick={() => handleTemplateSelect(template)}
              >
                <div className="template-icon">{template.icon}</div>
                <div className="template-name">{template.name}</div>
                <div className="template-description">{template.description}</div>
              </button>
            ))}
          </div>
        </div>
      )}

      {templateType === 'scratch' && (
        <div className="template-scratch-info">
          <div className="info-box">
            <p>
              <strong>Starting from scratch</strong> will guide you through each step of character creation
              with empty fields. This gives you complete control but takes more time.
            </p>
            <p>
              You can always switch to a template later or import character data.
            </p>
          </div>
        </div>
      )}

      {/* Selection Summary */}
      <div className="selection-summary">
        {selectedTemplate ? (
          <div className="summary-box success">
            Template selected: <strong>{ALL_TEMPLATES.find((t: CharacterTemplate) => t.id === selectedTemplate)?.name}</strong>
          </div>
        ) : templateType === 'scratch' ? (
          <div className="summary-box info">
            тД╣я╕П Starting from scratch - all fields will be empty
          </div>
        ) : (
          <div className="summary-box warning">
            Please select a template from the list above
          </div>
        )}
      </div>
    </div>
  );
};

