describe('SkillsStep Interaction Test', () => {
  it('should allow selecting available class skills', async () => {
    const user = userEvent.setup();
    render(<TestWrapper />);

    // Wait for component to load
    await waitFor(() => {
      expect(screen.getByText(/select skills/i)).toBeInTheDocument();
    });

    // Log all checkboxes to understand what's available
    const allCheckboxes = screen.getAllByRole('checkbox');
    console.log('[Test] Found', allCheckboxes.length, 'total checkboxes');
    
    allCheckboxes.forEach((checkbox, index) => {
      const inputElement = checkbox as HTMLInputElement;
      const label = checkbox.closest('label');
      const labelText = label?.textContent || '';
      console.log(`[Test] Checkbox ${index}:`, {
        labelText,
        checked: inputElement.checked,
        disabled: inputElement.disabled
      });
    });

    // Filter for available class skills
    const availableCheckboxes = allCheckboxes.filter(checkbox => {
      const inputElement = checkbox as HTMLInputElement;
      const label = checkbox.closest('label');
      const labelText = label?.textContent || '';
      return !inputElement.disabled && !inputElement.checked && !labelText.includes('(Background)') && !labelText.includes('(Unavailable)');
    });

    console.log('[Test] Available checkboxes:', availableCheckboxes.length);

    // Select first two available class skills
    if (availableCheckboxes.length >= 2) {
      console.log('[Test] Clicking first available skill');
      await user.click(availableCheckboxes[0]);
      console.log('[Test] Clicking second available skill');
      await user.click(availableCheckboxes[1]);
    } else {
      throw new Error('Not enough available checkboxes to select');
    }

    // Debug: log DOM after selection
     
    console.log('[Test] DOM after skill selection:', document.body.innerHTML);

    // Try to submit (wait for button to be enabled or present)
    let nextButton = null;
    try {
      nextButton = await screen.findByTestId('skills-next-button', {}, { timeout: 2000 });
    } catch (e) {
      // Not found, log all buttons
      const allButtons = screen.queryAllByRole('button');
      console.log('[Test] All buttons:', allButtons.map(btn => btn.outerHTML));
      throw new Error('skills-next-button not found after skill selection');
    }
    expect(nextButton).toBeEnabled();
    console.log('[Test] Clicking next button');
    await user.click(nextButton);
    // The test should complete without timing out
    expect(true).toBe(true);
  });
});

import { useSpells } from '@features/compendium';
import clsx from 'clsx';
import React, { useMemo, useState } from 'react';
import { spellManagementService } from '../services/spellManagement.service';
import styles from './SpellsTab.module.css';

interface SpellData {
  cantrips: string[];
  knownSpells: string[];
  preparedSpells: string[];
}

interface Props {
  data: Record<string, any>;
  onSave: (data: Record<string, any>) => void;
}

export const SpellsTab: React.FC<Props> = ({ data, onSave }) => {
  const characterClass: string = data.class ?? '';
  const level: number = data.level ?? 1;
  const spells: SpellData = data.spells ?? { cantrips: [], knownSpells: [], preparedSpells: [] };
  const slotsUsed: Record<number, number> = data.spellSlotsUsed ?? {};
  const [expandedSpell, setExpandedSpell] = useState<string | null>(null);

  const slots = useMemo(
    () => spellManagementService.getSpellSlots(characterClass, level),
    [characterClass, level]
  );

  // Load compendium spell details for known spells
  const { data: compendiumSpells } = useSpells({ class: characterClass });

  const slotLevels = useMemo(
    () => [1, 2, 3, 4, 5, 6, 7, 8, 9].filter(l => ((slots as any)[l] ?? 0) > 0),
    [slots]
  );

  // Group known spells by level using compendium data
  const spellsByLevel = useMemo(() => {
    const groups: Record<number, Array<{ name: string; details: any }>> = {};
    spells.knownSpells.forEach(name => {
      const details = compendiumSpells?.[name] ?? null;
      const spellLevel = details?.level ?? 1;
      if (!groups[spellLevel]) groups[spellLevel] = [];
      groups[spellLevel].push({ name, details });
    });
    return groups;
  }, [spells.knownSpells, compendiumSpells]);

  function useSlot(slotLevel: number) {
    const max = (slots as any)[slotLevel] ?? 0;
    const used = slotsUsed[slotLevel] ?? 0;
    if (used >= max) return;
    onSave({ ...data, spellSlotsUsed: { ...slotsUsed, [slotLevel]: used + 1 } });
  }

  function recoverSlot(slotLevel: number) {
    const used = slotsUsed[slotLevel] ?? 0;
    if (used <= 0) return;
    onSave({ ...data, spellSlotsUsed: { ...slotsUsed, [slotLevel]: used - 1 } });
  }

  function longRest() {
    onSave({ ...data, spellSlotsUsed: {} });
  }

  return (
    <div className={styles.tab}>
      {/* Spell Slots */}
      <section className={styles.section}>
        <div className={styles.sectionHeader}>
          <h3 className={styles.sectionTitle}>Spell Slots</h3>
          {slotLevels.length > 0 && (
            <button className={styles.restBtn} onClick={longRest} type="button">
              Long Rest
            </button>
          )}
        </div>
        {slotLevels.length === 0 ? (
          <p className={styles.empty}>No spell slots тАФ non-caster or cantrips only</p>
        ) : (
          <div className={styles.slotsGrid}>
            {slotLevels.map(slotLevel => {
              const max = (slots as any)[slotLevel];
              const used = slotsUsed[slotLevel] ?? 0;
              const remaining = max - used;
              return (
                <div key={slotLevel} className={styles.slotGroup}>
                  <span className={styles.slotLabel}>Lvl {slotLevel}</span>
                  <div className={styles.slotPips}>
                    {Array.from({ length: max }).map((_, i) => (
                      <button
                        key={i}
                        type="button"
                        className={clsx(styles.slotPip, i < remaining ? styles.pipAvailable : styles.pipUsed)}
                        onClick={() => i < remaining ? useSlot(slotLevel) : recoverSlot(slotLevel)}
                        title={i < remaining ? 'Click to use slot' : 'Click to recover slot'}
                      />
                    ))}
                  </div>
                  <span className={styles.slotCount}>{remaining}/{max}</span>
                </div>
              );
            })}
          </div>
        )}
      </section>

      {/* Cantrips */}
      {spells.cantrips.length > 0 && (
        <section className={styles.section}>
          <h3 className={styles.sectionTitle}>Cantrips</h3>
          <div className={styles.spellList}>
            {spells.cantrips.map(name => {
              const details = compendiumSpells?.[name];
              const isExpanded = expandedSpell === name;
              return (
                <div key={name} className={styles.spellRow}>
                  <button
                    type="button"
                    className={styles.spellToggle}
                    onClick={() => setExpandedSpell(isExpanded ? null : name)}
                    aria-expanded={isExpanded}
                  >
                    <span className={styles.spellName}>{name}</span>
                    <span className={styles.spellMeta}>
                      {details ? `${details.school} ┬╖ ${details.casting_time}` : 'Cantrip'}
                    </span>
                  </button>
                  {isExpanded && details && (
                    <div className={styles.spellDetails}>
                      <p className={styles.spellDesc}>{details.description}</p>
                      <div className={styles.spellStats}>
                        <span>Range: {details.range}</span>
                        <span>Duration: {details.duration}</span>
                      </div>
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        </section>
      )}

      {/* Known Spells by level */}
      {spells.knownSpells.length > 0 && (
        <section className={styles.section}>
          <h3 className={styles.sectionTitle}>Spells</h3>
          {Object.keys(spellsByLevel)
            .sort((a, b) => Number(a) - Number(b))
            .map(levelStr => {
              const lvl = Number(levelStr);
              const spellsInLevel = spellsByLevel[lvl];
              const max = (slots as any)[lvl] ?? 0;
              const used = slotsUsed[lvl] ?? 0;
              const remaining = max - used;
              return (
                <div key={lvl} className={styles.spellLevelGroup}>
                  <div className={styles.levelHeader}>
                    <span>Level {lvl}</span>
                    {max > 0 && (
                      <span className={clsx(styles.slotBadge, remaining === 0 && styles.slotBadgeEmpty)}>
                        {remaining}/{max} slots
                      </span>
                    )}
                  </div>
                  <div className={styles.spellList}>
                    {spellsInLevel.map(({ name, details }) => {
                      const isExpanded = expandedSpell === name;
                      const canCast = remaining > 0;
                      return (
                        <div key={name} className={styles.spellRow}>
                          <button
                            type="button"
                            className={styles.spellToggle}
                            onClick={() => setExpandedSpell(isExpanded ? null : name)}
                            aria-expanded={isExpanded}
                          >
                            <span className={styles.spellName}>{name}</span>
                            <span className={styles.spellMeta}>
                              {details ? `${details.school} ┬╖ ${details.casting_time}` : `Level ${lvl}`}
                            </span>
                          </button>
                          {isExpanded && (
                            <div className={styles.spellDetails}>
                              {details && (
                                <>
                                  <p className={styles.spellDesc}>{details.description}</p>
                                  <div className={styles.spellStats}>
                                    <span>Range: {details.range}</span>
                                    <span>Duration: {details.duration}</span>
                                    {details.concentration && <span className={styles.tag}>Concentration</span>}
                                    {details.ritual && <span className={styles.tag}>Ritual</span>}
                                  </div>
                                </>
                              )}
                              <button
                                type="button"
                                className={clsx(styles.castBtn, !canCast && styles.castBtnDisabled)}
                                disabled={!canCast}
                                onClick={() => { if (canCast) useSlot(lvl); }}
                              >
                                {canCast ? 'Cast (use slot)' : 'No slots remaining'}
                              </button>
                            </div>
                          )}
                        </div>
                      );
                    })}
                  </div>
                </div>
              );
            })}
        </section>
      )}

      {spells.cantrips.length === 0 && spells.knownSpells.length === 0 && (
        <p className={styles.empty}>No spells тАФ select spells during character creation or level-up</p>
      )}
    </div>
  );
};

