export class CharacterExportService {
  private static readonly EXPORT_VERSION = '1.0.0';
  
  /**
   * Calculate ability modifier from ability score
   */
  private static calculateModifier(score: number): number {
    return Math.floor((score - 10) / 2);
  }
  
  /**
   * Calculate proficiency bonus based on character level
   */
  private static calculateProficiencyBonus(level: number): number {
    return Math.ceil(level / 4) + 1;
  }
  
  /**
   * Get saving throw proficiencies for a class
   */
  private static getSavingThrowProficiencies(className: string): string[] {
    const proficiencies: Record<string, string[]> = {
      'Fighter': ['strength', 'constitution'],
      'Wizard': ['intelligence', 'wisdom'],
      'Rogue': ['dexterity', 'intelligence'],
      'Cleric': ['wisdom', 'charisma'],
      'Barbarian': ['strength', 'constitution'],
      'Bard': ['dexterity', 'charisma'],
      'Druid': ['intelligence', 'wisdom'],
      'Monk': ['strength', 'dexterity'],
      'Paladin': ['wisdom', 'charisma'],
      'Ranger': ['strength', 'dexterity'],
      'Sorcerer': ['constitution', 'charisma'],
      'Warlock': ['wisdom', 'charisma'],
    };
    
    return proficiencies[className] || [];
  }
  
  /**
   * Calculate base hit points for character
   */
  private static calculateHitPoints(className: string, level: number, constitutionModifier: number): number {
    const hitDice: Record<string, number> = {
      'Barbarian': 12,
      'Fighter': 10,
      'Paladin': 10,
      'Ranger': 10,
      'Bard': 8,
      'Cleric': 8,
      'Druid': 8,
      'Monk': 8,
      'Rogue': 8,
      'Warlock': 8,
      'Sorcerer': 6,
      'Wizard': 6,
    };
    
    const hitDie = hitDice[className] || 8;
    const baseHitPoints = hitDie + constitutionModifier;
    const additionalLevels = level - 1;
    const avgHitPointsPerLevel = Math.floor(hitDie / 2) + 1 + constitutionModifier;
    
    return baseHitPoints + (additionalLevels * avgHitPointsPerLevel);
  }
  
  /**
   * Calculate armor class (base 10 + Dex modifier without armor)
   */
  private static calculateArmorClass(dexterityModifier: number): number {
    // Base AC calculation - can be enhanced when equipment system is implemented
    return 10 + dexterityModifier;
  }
  
  /**
   * Get base speed for race
   */
  private static getBaseSpeed(race: string): number {
    const speeds: Record<string, number> = {
      'Human': 30,
      'Elf': 30,
      'Dwarf': 25,
      'Halfling': 25,
      'Dragonborn': 30,
      'Gnome': 25,
      'Half-Elf': 30,
      'Half-Orc': 30,
      'Tiefling': 30,
    };
    
    return speeds[race] || 30;
  }
  
  /**
   * Get spellcasting ability for class
   */
  private static getSpellcastingAbility(className: string): 'intelligence' | 'wisdom' | 'charisma' | undefined {
    const abilities: Record<string, 'intelligence' | 'wisdom' | 'charisma'> = {
      'Wizard': 'intelligence',
      'Cleric': 'wisdom',
      'Druid': 'wisdom',
      'Ranger': 'wisdom',
      'Monk': 'wisdom', // Ki save DC
      'Sorcerer': 'charisma',
      'Bard': 'charisma',
      'Warlock': 'charisma',
      'Paladin': 'charisma',
    };
    
    return abilities[className];
  }
  
  /**
   * Export character to comprehensive D&D 5e format
   */
  static exportToD5e(character: WizardFormData, additionalData?: any): D5eCharacterExport {
    const level = additionalData?.level || 1;
    const exportedBy = additionalData?.exportedBy;
    const notes = additionalData?.notes;
    
    // Calculate modifiers
    const abilityModifiers = {
      strength: this.calculateModifier(character.strength),
      dexterity: this.calculateModifier(character.dexterity),
      constitution: this.calculateModifier(character.constitution),
      intelligence: this.calculateModifier(character.intelligence),
      wisdom: this.calculateModifier(character.wisdom),
      charisma: this.calculateModifier(character.charisma),
    };
    
    const proficiencyBonus = this.calculateProficiencyBonus(level);
    const savingThrowProfs = this.getSavingThrowProficiencies(character.class);
    
    // Calculate saving throws
    const savingThrows = {
      strength: {
        value: abilityModifiers.strength + (savingThrowProfs.includes('strength') ? proficiencyBonus : 0),
        proficient: savingThrowProfs.includes('strength'),
      },
      dexterity: {
        value: abilityModifiers.dexterity + (savingThrowProfs.includes('dexterity') ? proficiencyBonus : 0),
        proficient: savingThrowProfs.includes('dexterity'),
      },
      constitution: {
        value: abilityModifiers.constitution + (savingThrowProfs.includes('constitution') ? proficiencyBonus : 0),
        proficient: savingThrowProfs.includes('constitution'),
      },
      intelligence: {
        value: abilityModifiers.intelligence + (savingThrowProfs.includes('intelligence') ? proficiencyBonus : 0),
        proficient: savingThrowProfs.includes('intelligence'),
      },
      wisdom: {
        value: abilityModifiers.wisdom + (savingThrowProfs.includes('wisdom') ? proficiencyBonus : 0),
        proficient: savingThrowProfs.includes('wisdom'),
      },
      charisma: {
        value: abilityModifiers.charisma + (savingThrowProfs.includes('charisma') ? proficiencyBonus : 0),
        proficient: savingThrowProfs.includes('charisma'),
      },
    };
    
    // Calculate skill modifiers
    const skillModifiers = this.calculateSkillModifiers(character.skills, abilityModifiers, proficiencyBonus);
    
    const spellcastingAbility = this.getSpellcastingAbility(character.class);
    
    return {
      version: this.EXPORT_VERSION,
      timestamp: new Date().toISOString(),
      character: {
        name: character.name,
        race: character.race,
        class: character.class,
        level,
        background: character.background,
        
        abilities: {
          strength: character.strength,
          dexterity: character.dexterity,
          constitution: character.constitution,
          intelligence: character.intelligence,
          wisdom: character.wisdom,
          charisma: character.charisma,
        },
        
        skills: character.skills,
        
        spells: character.spells ? {
          ...character.spells,
          spellcastingAbility,
        } : undefined,
        
        personality: {
          bio: character.bio,
          image: character.image || undefined, // Guard against undefined character
        },
        
        calculated: {
          hitPoints: this.calculateHitPoints(character.class, level, abilityModifiers.constitution),
          armorClass: this.calculateArmorClass(abilityModifiers.dexterity),
          proficiencyBonus,
          speed: this.getBaseSpeed(character.race),
          abilityModifiers,
          savingThrows,
          skillModifiers,
        },
      },
      
      source: 'TTRPG_System_Web',
      exportedBy,
      notes,
    };
  }
  
  /**
   * Export character to D&D Beyond compatible format
   */
  static exportToDNDBeyond(character: WizardFormData, additionalData?: any): DNDBeyondExport {
    const level = additionalData?.level || 1;
    const abilityModifiers = {
      strength: this.calculateModifier(character.strength),
      dexterity: this.calculateModifier(character.dexterity),
      constitution: this.calculateModifier(character.constitution),
      intelligence: this.calculateModifier(character.intelligence),
      wisdom: this.calculateModifier(character.wisdom),
      charisma: this.calculateModifier(character.charisma),
    };
    
    // Map ability scores to D&D Beyond format (1-6 IDs)
    const stats = [
      { id: 1, value: character.strength },    // STR
      { id: 2, value: character.dexterity },   // DEX
      { id: 3, value: character.constitution }, // CON
      { id: 4, value: character.intelligence }, // INT
      { id: 5, value: character.wisdom },      // WIS
      { id: 6, value: character.charisma },    // CHA
    ];
    
    const hitDice: Record<string, number> = {
      'Barbarian': 12, 'Fighter': 10, 'Paladin': 10, 'Ranger': 10,
      'Bard': 8, 'Cleric': 8, 'Druid': 8, 'Monk': 8, 'Rogue': 8, 'Warlock': 8,
      'Sorcerer': 6, 'Wizard': 6,
    };
    
    return {
      character: {
        name: character.name,
        race: {
          fullName: character.race,
          baseRaceName: character.race,
        },
        classes: [{
          definition: {
            name: character.class,
            hitDie: hitDice[character.class] || 8,
          },
          level,
          hitDieUsed: 0,
        }],
        background: {
          definition: {
            name: character.background,
          },
        },
        stats,
        modifiers: [],
        baseHitPoints: this.calculateHitPoints(character.class, level, abilityModifiers.constitution),
        bonusHitPoints: 0,
        removedHitPoints: 0,
        temporaryHitPoints: 0,
      },
    };
  }
  
  /**
   * Export character to character sheet format
   */
  static exportToCharacterSheet(character: WizardFormData, additionalData?: any): CharacterSheetExport {
    const level = additionalData?.level || 1;
    const abilityModifiers = {
      strength: this.calculateModifier(character.strength),
      dexterity: this.calculateModifier(character.dexterity),
      constitution: this.calculateModifier(character.constitution),
      intelligence: this.calculateModifier(character.intelligence),
      wisdom: this.calculateModifier(character.wisdom),
      charisma: this.calculateModifier(character.charisma),
    };
    
    const proficiencyBonus = this.calculateProficiencyBonus(level);
    const savingThrowProfs = this.getSavingThrowProficiencies(character.class);
    
    // Create skills array
    const skills = this.createSkillsArray(character.skills, abilityModifiers, proficiencyBonus);
    const savingThrows = this.createSavingThrowsArray(savingThrowProfs, abilityModifiers, proficiencyBonus);
    
    const spellcastingAbility = this.getSpellcastingAbility(character.class);
    let spellData;
    
    if (character.spells && spellcastingAbility) {
      const spellAbilityModifier = abilityModifiers[spellcastingAbility];
      spellData = {
        spellcastingAbility: spellcastingAbility.charAt(0).toUpperCase() + spellcastingAbility.slice(1),
        spellAttackBonus: spellAbilityModifier + proficiencyBonus,
        spellSaveDC: 8 + spellAbilityModifier + proficiencyBonus,
        cantrips: character.spells.cantrips,
        spells: [
          ...character.spells.knownSpells.map(name => ({ level: 1, name, prepared: false })),
          ...character.spells.preparedSpells.map(name => ({ level: 1, name, prepared: true })),
        ],
      };
    }
    
    return {
      character: {
        name: character.name,
        classAndLevel: `${character.class} ${level}`,
        background: character.background,
        race: character.race,
        
        abilityScores: {
          strength: character.strength,
          dexterity: character.dexterity,
          constitution: character.constitution,
          intelligence: character.intelligence,
          wisdom: character.wisdom,
          charisma: character.charisma,
        },
        
        modifiers: abilityModifiers,
        proficiencyBonus,
        armorClass: this.calculateArmorClass(abilityModifiers.dexterity),
        hitPoints: this.calculateHitPoints(character.class, level, abilityModifiers.constitution),
        speed: this.getBaseSpeed(character.race),
        
        skills,
        savingThrows,
        spells: spellData,
      },
    };
  }
  
  /**
   * Calculate skill modifiers for all D&D 5e skills
   */
  private static calculateSkillModifiers(
    proficientSkills: string[],
    abilityModifiers: Record<string, number>,
    proficiencyBonus: number
  ): Record<string, { value: number; proficient: boolean }> {
    const skillAbilityMap: Record<string, keyof typeof abilityModifiers> = {
      'Acrobatics': 'dexterity',
      'Animal Handling': 'wisdom',
      'Arcana': 'intelligence',
      'Athletics': 'strength',
      'Deception': 'charisma',
      'History': 'intelligence',
      'Insight': 'wisdom',
      'Intimidation': 'charisma',
      'Investigation': 'intelligence',
      'Medicine': 'wisdom',
      'Nature': 'intelligence',
      'Perception': 'wisdom',
      'Performance': 'charisma',
      'Persuasion': 'charisma',
      'Religion': 'intelligence',
      'Sleight of Hand': 'dexterity',
      'Stealth': 'dexterity',
      'Survival': 'wisdom',
    };
    
    const result: Record<string, { value: number; proficient: boolean }> = {};
    
    for (const [skill, ability] of Object.entries(skillAbilityMap)) {
      const isProficient = proficientSkills.includes(skill);
      const baseModifier = abilityModifiers[ability];
      const totalModifier = baseModifier + (isProficient ? proficiencyBonus : 0);
      
      result[skill] = {
        value: totalModifier,
        proficient: isProficient,
      };
    }
    
    return result;
  }
  
  /**
   * Create skills array for character sheet
   */
  private static createSkillsArray(
    proficientSkills: string[],
    abilityModifiers: Record<string, number>,
    proficiencyBonus: number
  ): Array<{ name: string; modifier: number; proficient: boolean }> {
    const skillModifiers = this.calculateSkillModifiers(proficientSkills, abilityModifiers, proficiencyBonus);
    
    return Object.entries(skillModifiers).map(([name, data]) => ({
      name,
      modifier: data.value,
      proficient: data.proficient,
    }));
  }
  
  /**
   * Create saving throws array for character sheet
   */
  private static createSavingThrowsArray(
    proficiencies: string[],
    abilityModifiers: Record<string, number>,
    proficiencyBonus: number
  ): Array<{ name: string; modifier: number; proficient: boolean }> {
    const abilities = ['strength', 'dexterity', 'constitution', 'intelligence', 'wisdom', 'charisma'] as const;
    
    return abilities.map(ability => {
      const isProficient = proficiencies.includes(ability);
      const modifier = abilityModifiers[ability] + (isProficient ? proficiencyBonus : 0);
      
      return {
        name: ability.charAt(0).toUpperCase() + ability.slice(1),
        modifier,
        proficient: isProficient,
      };
    });
  }
  
  /**
   * Download character data as JSON file
   */
  static downloadAsJSON(characterData: any, filename: string): void {
    const jsonString = JSON.stringify(characterData, null, 2);
    const blob = new Blob([jsonString], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    
    const link = document.createElement('a');
    link.href = url;
    link.download = `${filename}.json`;
    document.body.appendChild(link);
    link.click();
    
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  }
  
  /**
   * Generate character sheet filename
   */
  static generateFilename(characterName: string, format: string): string {
    const sanitizedName = characterName.replace(/[^a-zA-Z0-9]/g, '_');
    const timestamp = new Date().toISOString().split('T')[0];
    return `${sanitizedName}_${format}_${timestamp}`;
  }
}

/**
 * Character Import Service
 * Imports characters from various formats (JSON, D&D Beyond, Roll20, etc.)
 */

import type { D5eCharacterExport, WizardFormData } from '@features/character';

interface DNDBeyondExport {
  // Placeholder for D&D Beyond export format
  [key: string]: unknown;
}

export interface ImportResult {
  success: boolean;
  character?: WizardFormData;
  errors?: string[];
  warnings?: string[];
}

export interface ImportValidationResult {
  valid: boolean;
  errors: string[];
  warnings: string[];
  character?: Partial<WizardFormData>;
}

export class CharacterImportService {
  private static readonly SUPPORTED_FORMATS = ['d5e', 'dndBeyond', 'json'] as const;
  
  /**
   * Detect import format from file content or structure
   */
  static detectFormat(data: any): string | null {
    // Check for our D5e format
    if (data.version && data.source === 'TTRPG_System_Web' && data.character) {
      return 'd5e';
    }
    
    // Check for D&D Beyond format
    if (data.character?.race?.fullName && data.character?.classes && data.character?.stats) {
      return 'dndBeyond';
    }
    
    // Check for basic character data structure
    if (data.race && data.class && data.name && data.strength !== undefined) {
      return 'json';
    }
    
    // Check for Roll20 format characteristics
    if (data.schema_version && data.character && data.character.attribs) {
      return 'roll20';
    }
    
    return null;
  }
  
  /**
   * Import character from D&D 5e export format
   */
  static importFromD5e(data: D5eCharacterExport): ImportResult {
    try {
      const character = data.character;
      
      const wizardData: WizardFormData = {
        name: character.name,
        race: character.race,
        class: character.class,
        background: character.background,
        
        strength: character.abilities.strength,
        dexterity: character.abilities.dexterity,
        constitution: character.abilities.constitution,
        intelligence: character.abilities.intelligence,
        wisdom: character.abilities.wisdom,
        charisma: character.abilities.charisma,
        
        skills: character.skills,
        spells: character.spells ? {
          cantrips: character.spells.cantrips,
          knownSpells: character.spells.knownSpells,
          preparedSpells: character.spells.preparedSpells,
        } : undefined,
        
        bio: character.personality?.bio,
        image: character.personality?.image,
      };
      
      const validation = this.validateCharacterData(wizardData);
      
      if (!validation.valid) {
        return {
          success: false,
          errors: validation.errors,
          warnings: validation.warnings,
        };
      }
      
      return {
        success: true,
        character: wizardData,
        warnings: validation.warnings,
      };
      
    } catch (error) {
      return {
        success: false,
        errors: [`Failed to parse D5e character: ${(error as Error).message}`],
      };
    }
  }
  
  /**
   * Import character from D&D Beyond export format
   */
  static importFromDNDBeyond(data: DNDBeyondExport): ImportResult {
    try {
      const character = data.character as any;
      
      if (!character.classes || character.classes.length === 0) {
        return {
          success: false,
          errors: ['D&D Beyond character missing class information'],
        };
      }
      
      if (!character.stats || character.stats.length !== 6) {
        return {
          success: false,
          errors: ['D&D Beyond character missing or invalid ability scores'],
        };
      }
      
      // Map D&D Beyond stats (ID 1-6) to ability scores
      const statsMap = character.stats.reduce((acc: Record<string, number>, stat: any) => {
        const abilities = ['strength', 'dexterity', 'constitution', 'intelligence', 'wisdom', 'charisma'];
        acc[abilities[stat.id - 1]] = stat.value;
        return acc;
      }, {} as Record<string, number>);
      
      const primaryClass = character.classes[0];
      
      const wizardData: WizardFormData = {
        name: character.name,
        race: character.race.baseRaceName || character.race.fullName,
        class: primaryClass.definition.name,
        background: character.background?.definition?.name || 'Unknown',
        
        strength: statsMap.strength || 10,
        dexterity: statsMap.dexterity || 10,
        constitution: statsMap.constitution || 10,
        intelligence: statsMap.intelligence || 10,
        wisdom: statsMap.wisdom || 10,
        charisma: statsMap.charisma || 10,
        
        skills: [], // D&D Beyond doesn't provide skill proficiencies in basic format
        spells: undefined, // Would need more complex parsing for spells
      };
      
      const validation = this.validateCharacterData(wizardData);
      
      // Add warnings for missing data
      const warnings = [...(validation.warnings || [])];
      if (!wizardData.skills.length) {
        warnings.push('Skill proficiencies not imported - please select manually');
      }
      if (this.isSpellcaster(wizardData.class) && !wizardData.spells) {
        warnings.push('Spells not imported - please select manually');
      }
      
      if (!validation.valid) {
        return {
          success: false,
          errors: validation.errors,
          warnings,
        };
      }
      
      return {
        success: true,
        character: wizardData,
        warnings,
      };
      
    } catch (error) {
      return {
        success: false,
        errors: [`Failed to parse D&D Beyond character: ${(error as Error).message}`],
      };
    }
  }
  
  /**
   * Import character from generic JSON format
   */
  static importFromJSON(data: any): ImportResult {
    try {
      const wizardData: WizardFormData = {
        name: data.name || 'Unnamed Character',
        race: data.race || '',
        class: data.class || data.character_class || '', // Support both formats
        background: data.background || 'Folk Hero',
        
        strength: data.strength || data.ability_scores?.STR || data.abilities?.strength || 10,
        dexterity: data.dexterity || data.ability_scores?.DEX || data.abilities?.dexterity || 10,
        constitution: data.constitution || data.ability_scores?.CON || data.abilities?.constitution || 10,
        intelligence: data.intelligence || data.ability_scores?.INT || data.abilities?.intelligence || 10,
        wisdom: data.wisdom || data.ability_scores?.WIS || data.abilities?.wisdom || 10,
        charisma: data.charisma || data.ability_scores?.CHA || data.abilities?.charisma || 10,
        
        skills: data.skills || data.skill_proficiencies || [],
        spells: data.spells || undefined,
        
        bio: data.bio || data.personality || undefined,
        image: data.image || undefined,
      };
      
      const validation = this.validateCharacterData(wizardData);
      
      if (!validation.valid) {
        return {
          success: false,
          errors: validation.errors,
          warnings: validation.warnings,
        };
      }
      
      return {
        success: true,
        character: wizardData,
        warnings: validation.warnings,
      };
      
    } catch (error) {
      return {
        success: false,
        errors: [`Failed to parse JSON character: ${(error as Error).message}`],
      };
    }
  }
  
  /**
   * Import character from Roll20 export format
   */
  static importFromRoll20(data: any): ImportResult {
    try {
      if (!data.character || !data.character.attribs) {
        return {
          success: false,
          errors: ['Invalid Roll20 character format - missing character.attribs'],
        };
      }
      
      // Roll20 stores attributes as an array of {name, current, max} objects
      const attribs = data.character.attribs;
      const getAttr = (name: string) => {
        const attr = attribs.find((a: any) => a.name === name);
        return attr ? (attr.current || attr.max || 0) : 0;
      };
      
      const wizardData: WizardFormData = {
        name: getAttr('character_name') || 'Roll20 Character',
        race: getAttr('race') || '',
        class: getAttr('class') || '',
        background: getAttr('background') || 'Folk Hero',
        
        strength: parseInt(getAttr('strength') || '10'),
        dexterity: parseInt(getAttr('dexterity') || '10'),
        constitution: parseInt(getAttr('constitution') || '10'),
        intelligence: parseInt(getAttr('intelligence') || '10'),
        wisdom: parseInt(getAttr('wisdom') || '10'),
        charisma: parseInt(getAttr('charisma') || '10'),
        
        skills: [], // Roll20 skill parsing would be complex, left for manual selection
        spells: undefined, // Roll20 spell parsing would be complex
      };
      
      const validation = this.validateCharacterData(wizardData);
      const warnings = [...(validation.warnings || [])];
      
      warnings.push('Roll20 import: Skills and spells require manual selection');
      
      if (!validation.valid) {
        return {
          success: false,
          errors: validation.errors,
          warnings,
        };
      }
      
      return {
        success: true,
        character: wizardData,
        warnings,
      };
      
    } catch (error) {
      return {
        success: false,
        errors: [`Failed to parse Roll20 character: ${(error as Error).message}`],
      };
    }
  }
  
  /**
   * Universal import method that detects format and imports accordingly
   */
  static importCharacter(data: any): ImportResult {
    const format = this.detectFormat(data);
    
    if (!format) {
      return {
        success: false,
        errors: ['Unable to detect character format. Supported formats: D5e JSON, D&D Beyond, Roll20, generic JSON'],
      };
    }
    
    switch (format) {
      case 'd5e':
        return this.importFromD5e(data as D5eCharacterExport);
      case 'dndBeyond':
        return this.importFromDNDBeyond(data as DNDBeyondExport);
      case 'roll20':
        return this.importFromRoll20(data);
      case 'json':
      default:
        return this.importFromJSON(data);
    }
  }
  
  /**
   * Import character from file
   */
  static async importFromFile(file: File): Promise<ImportResult> {
    try {
      const text = await file.text();
      const data = JSON.parse(text);
      return this.importCharacter(data);
    } catch (error) {
      return {
        success: false,
        errors: [`Failed to read file: ${(error as Error).message}`],
      };
    }
  }
  
  /**
   * Import character from URL
   */
  static async importFromURL(url: string): Promise<ImportResult> {
    try {
      const response = await fetch(url);
      
      if (!response.ok) {
        return {
          success: false,
          errors: [`Failed to fetch character: ${response.status} ${response.statusText}`],
        };
      }
      
      const data = await response.json();
      return this.importCharacter(data);
    } catch (error) {
      return {
        success: false,
        errors: [`Failed to import from URL: ${(error as Error).message}`],
      };
    }
  }
  
  /**
   * Validate imported character data
   */
  private static validateCharacterData(character: WizardFormData): ImportValidationResult {
    const errors: string[] = [];
    const warnings: string[] = [];
    
    // Required fields
    if (!character.name || character.name.trim().length === 0) {
      errors.push('Character name is required');
    }
    
    if (!character.race) {
      errors.push('Race is required');
    }
    
    if (!character.class) {
      errors.push('Class is required');
    }
    
    if (!character.background) {
      errors.push('Background is required');
    }
    
    // Ability scores validation
    const abilities = ['strength', 'dexterity', 'constitution', 'intelligence', 'wisdom', 'charisma'] as const;
    for (const ability of abilities) {
      const score = character[ability];
      if (score < 1 || score > 30) {
        errors.push(`${ability} score must be between 1 and 30 (got ${score})`);
      }
      if (score < 8 || score > 15) {
        warnings.push(`${ability} score ${score} is outside typical range (8-15) for character creation`);
      }
    }
    
    // Class validation
    const validClasses = [
      'Barbarian', 'Bard', 'Cleric', 'Druid', 'Fighter', 'Monk', 
      'Paladin', 'Ranger', 'Rogue', 'Sorcerer', 'Warlock', 'Wizard'
    ];
    if (character.class && !validClasses.includes(character.class)) {
      warnings.push(`Class '${character.class}' may not be fully supported`);
    }
    
    // Race validation
    const validRaces = [
      'Human', 'Elf', 'Dwarf', 'Halfling', 'Dragonborn', 'Gnome', 
      'Half-Elf', 'Half-Orc', 'Tiefling'
    ];
    if (character.race && !validRaces.includes(character.race)) {
      warnings.push(`Race '${character.race}' may not be fully supported`);
    }
    
    // Spellcaster validation
    if (this.isSpellcaster(character.class)) {
      if (!character.spells) {
        warnings.push(`${character.class} is a spellcasting class but no spells are defined`);
      }
    }
    
    // Skills validation
    if (character.skills && character.skills.length === 0) {
      warnings.push('No skills selected - characters typically have skill proficiencies');
    }
    
    return {
      valid: errors.length === 0,
      errors,
      warnings,
      character: errors.length === 0 ? character : undefined,
    };
  }
  
  /**
   * Check if class is a spellcaster
   */
  private static isSpellcaster(className: string): boolean {
    const spellcastingClasses = [
      'Bard', 'Cleric', 'Druid', 'Paladin', 'Ranger', 
      'Sorcerer', 'Warlock', 'Wizard'
    ];
    return spellcastingClasses.includes(className);
  }
  
  /**
   * Get supported import formats
   */
  static getSupportedFormats(): readonly string[] {
    return this.SUPPORTED_FORMATS;
  }
  
  /**
   * Validate file before import
   */
  static async validateFile(file: File): Promise<{ valid: boolean; errors: string[] }> {
    const errors: string[] = [];
    
    // Check file size (max 10MB)
    if (file.size > 10 * 1024 * 1024) {
      errors.push('File size too large (max 10MB)');
    }
    
    // Check file type
    if (!file.type.includes('json') && !file.name.endsWith('.json')) {
      errors.push('File must be JSON format');
    }
    
    // Try to parse JSON
    try {
      const text = await file.text();
      JSON.parse(text);
    } catch {
      errors.push('File contains invalid JSON');
    }
    
    return {
      valid: errors.length === 0,
      errors,
    };
  }
  
  /**
   * Create character backup before import
   */
  static createBackup(existingCharacter: WizardFormData): string {
    const backup = {
      timestamp: new Date().toISOString(),
      character: existingCharacter,
      source: 'pre-import-backup',
    };
    
    return JSON.stringify(backup, null, 2);
  }
}

// Type-safe conversion utilities for equipment <-> wizard item <-> inventory item
// Wizard equipment item type
export type WizardEquipmentItem = {
  equipment: {
    name: string;
    weight: number;
    cost: {
      amount: number;
      unit: string;
    };
  };
  quantity: number;
  equipped?: boolean;
};

/**
 * Convert Equipment to Wizard equipment item
 */
export function equipmentToWizardItem(equipment: Equipment, quantity: number, equipped?: boolean): WizardEquipmentItem {
  return {
    equipment: {
      name: equipment.name,
      weight: equipment.weight,
      cost: {
        amount: equipment.cost.quantity,
        unit: equipment.cost.unit
      }
    },
    quantity,
    ...(equipped !== undefined ? { equipped } : {})
  };
}

/**
 * Convert Wizard equipment item to InventoryItem (using a lookup for full Equipment if needed)
 */
export function wizardItemToInventoryItem(
  item: WizardEquipmentItem,
  equipmentLookup: (name: string) => Equipment
): InventoryItem {
  return {
    equipment: equipmentLookup(item.equipment.name),
    quantity: item.quantity,
    equipped: item.equipped
  };
}

/**
 * Convert InventoryItem to Wizard equipment item
 */
export function inventoryItemToWizardItem(item: InventoryItem): WizardEquipmentItem {
  return equipmentToWizardItem(item.equipment, item.quantity, item.equipped);
}
/**
 * D&D 5e Equipment Management Service
 * Handles equipment selection, inventory management, and starting equipment
 */

// Equipment Categories
export const EquipmentCategory = {
  WEAPON: 'weapon',
  ARMOR: 'armor',
  SHIELD: 'shield',
  TOOL: 'tool',
  GEAR: 'gear',
  MOUNT: 'mount',
  VEHICLE: 'vehicle',
  TREASURE: 'treasure',
  CONSUMABLE: 'consumable'
} as const;

export type EquipmentCategoryType = typeof EquipmentCategory[keyof typeof EquipmentCategory];

export const WeaponType = {
  SIMPLE_MELEE: 'simple_melee',
  SIMPLE_RANGED: 'simple_ranged',
  MARTIAL_MELEE: 'martial_melee',
  MARTIAL_RANGED: 'martial_ranged'
} as const;

export type WeaponTypeType = typeof WeaponType[keyof typeof WeaponType];

export const ArmorType = {
  LIGHT: 'light',
  MEDIUM: 'medium',
  HEAVY: 'heavy'
} as const;

export type ArmorTypeType = typeof ArmorType[keyof typeof ArmorType];

export const DamageType = {
  SLASHING: 'slashing',
  PIERCING: 'piercing',
  BLUDGEONING: 'bludgeoning',
  ACID: 'acid',
  COLD: 'cold',
  FIRE: 'fire',
  FORCE: 'force',
  LIGHTNING: 'lightning',
  NECROTIC: 'necrotic',
  POISON: 'poison',
  PSYCHIC: 'psychic',
  RADIANT: 'radiant',
  THUNDER: 'thunder'
} as const;

export type DamageTypeType = typeof DamageType[keyof typeof DamageType];

export interface Damage {
  dice: string; // e.g., "1d8", "2d6"
  type: DamageTypeType;
}

export interface WeaponProperties {
  light?: boolean;
  finesse?: boolean;
  thrown?: { range_normal: number; range_long: number };
  two_handed?: boolean;
  versatile?: { damage: string }; // e.g., "1d10"
  reach?: boolean;
  heavy?: boolean;
  loading?: boolean;
  ammunition?: boolean;
  special?: string;
}

export interface Equipment {
  name: string;
  category: EquipmentCategoryType;
  cost: {
    quantity: number;
    unit: 'cp' | 'sp' | 'ep' | 'gp' | 'pp';
  };
  weight: number; // in pounds
  description: string;
  source?: string;
}

export interface Weapon extends Equipment {
  category: typeof EquipmentCategory.WEAPON;
  weapon_type: WeaponTypeType;
  damage: Damage;
  properties: WeaponProperties;
  proficiency_required: string; // e.g., "Simple weapons", "Martial weapons"
}

export interface Armor extends Equipment {
  category: typeof EquipmentCategory.ARMOR;
  armor_type: ArmorTypeType;
  armor_class: {
    base: number;
    dex_bonus?: boolean;
    max_bonus?: number;
  };
  stealth_disadvantage?: boolean;
  strength_requirement?: number;
}

export interface Shield extends Equipment {
  category: typeof EquipmentCategory.SHIELD;
  armor_class_bonus: number;
}

export interface AdventuringGear extends Equipment {
  category: typeof EquipmentCategory.GEAR;
  uses?: number;
  special_properties?: string[];
}

export interface Tool extends Equipment {
  category: typeof EquipmentCategory.TOOL;
  tool_type: 'artisan' | 'gaming' | 'musical' | 'other';
  proficiency_type?: string; // e.g., "Thieves' tools", "Smith's tools"
}

// Starting Equipment by Class
export interface StartingEquipmentChoice {
  choose: number;
 from: Equipment[];
  type: 'equipment' | 'equipment_pack';
}

export interface StartingEquipment {
  equipment: Equipment[];
  equipment_choices: StartingEquipmentChoice[];
  starting_wealth?: {
    dice: string; // e.g., "4d4"
    multiplier: number; // multiply by 10 for gp
  };
}

// Character Equipment/Inventory
export interface InventoryItem {
  equipment: Equipment;
  quantity: number;
  equipped?: boolean;
  identified?: boolean;
  notes?: string;
}

export interface CharacterInventory {
  items: InventoryItem[];
  currency: {
    cp: number;
    sp: number;
    ep: number;
    gp: number;
    pp: number;
  };
  carrying_capacity: {
    current_weight: number;
    max_weight: number;
    encumbered_at: number;
    heavily_encumbered_at: number;
  };
}

