        option.textContent = opt;
        select.appendChild(option);
      });
      labelEl.appendChild(select);
    } else {
      const input = document.createElement('input');
      input.setAttribute('aria-label', label);
      input.type = 'text';
      input.id = `mock-input-${index}`;
      labelEl.appendChild(input);
