        expect(screen.getByText(/dc: 10/i)).toBeInTheDocument(); // Half damage (7) or 10, whichever higher
      });
      
      // If concentration is lost, spell ends
      const rollConcentrationButton = screen.getByTestId('mock-concentration-button');
