            onClick={() => setShowFilters(!showFilters)}
            className={`monster-btn monster-btn-secondary ${showFilters ? 'active' : ''}`}
          >
            Filters
          </button>
        </div>
        
        <div className="monster-search-controls">
          <div className="monster-sort-controls">
