import { useGameStore } from '@/store';
import type { Color } from '@/types';
import { useRenderEngine } from '@features/canvas';
import { useProtocol } from '@lib/api';
import {
    Flame,
    Lightbulb,
    Moon,
    MoveHorizontal,
    Sparkles,
    Sun,
    Trash2,
    X,
} from 'lucide-react';
import React, { useEffect, useMemo, useRef, useState } from 'react';
import styles from './LightingPanel.module.css';

function lightToSprite(light: Light, tableId: string): Record<string, any> {
  const converter = useGameStore.getState().getUnitConverter();
  const radiusUnits = converter.toUnits(light.radius);
  return {
    id: light.id,
    x: light.x,
    y: light.y,
    scale_x: light.radius * 2,
    scale_y: light.radius * 2,
    rotation: 0,
    texture_path: '__LIGHT__',
    layer: 'light',
    table_id: tableId,
    metadata: JSON.stringify({
      isLight: true,
      presetName: light.presetName,
      color: light.color,
      intensity: light.intensity,
      radius: light.radius,
      radius_units: radiusUnits,
      isOn: light.isOn,
    }),
  };
}

function spriteToLight(sprite: any): Light | null {
  const texturePath = sprite.texture_path || sprite.texture;
  if (sprite.layer !== 'light' || texturePath !== '__LIGHT__') return null;

  let meta: any = {};
  try {
    meta = typeof sprite.metadata === 'string' ? JSON.parse(sprite.metadata) : (sprite.metadata ?? {});
  } catch {
    // keep defaults
  }

  if (meta.isLight === false) return null;

  // Prefer radius_units (game units) тЖТ convert to px; fall back to legacy radius (px)
  let radius: number;
  if (meta.radius_units != null) {
    const converter = useGameStore.getState().getUnitConverter();
    radius = converter.toPixels(meta.radius_units);
  } else {
    radius = meta.radius ?? 100;
  }

  return {
    id: sprite.id || sprite.sprite_id,
    x: sprite.x ?? 0,
    y: sprite.y ?? 0,
    presetName: meta.presetName,
    color: meta.color || { r: 1, g: 1, b: 1, a: 1 },
    intensity: meta.intensity ?? 1.0,
    radius,
    isOn: meta.isOn !== false,
  };
}

interface Light {
  id: string;
  x: number;
  y: number;
  presetName?: string;
  color: Color;
  intensity: number;
  radius: number;
  isOn: boolean;
}

// Preset radii in game units (feet) тАФ D&D PHB values
const LIGHT_PRESETS = [
  { name: 'Torch',     radiusFt: 20, intensity: 1.0, color: { r: 1.0, g: 0.6, b: 0.2, a: 1.0 }, Icon: Flame },
  { name: 'Candle',   radiusFt: 5,  intensity: 0.7, color: { r: 1.0, g: 0.7, b: 0.3, a: 1.0 }, Icon: Lightbulb },
  { name: 'Daylight', radiusFt: 60, intensity: 1.0, color: { r: 1.0, g: 1.0, b: 0.9, a: 1.0 }, Icon: Sun },
  { name: 'Moonlight',radiusFt: 40, intensity: 0.4, color: { r: 0.6, g: 0.7, b: 1.0, a: 1.0 }, Icon: Moon },
  { name: 'Fire',     radiusFt: 20, intensity: 0.9, color: { r: 1.0, g: 0.4, b: 0.1, a: 1.0 }, Icon: Flame },
  { name: 'Magic',    radiusFt: 30, intensity: 0.8, color: { r: 0.5, g: 0.2, b: 1.0, a: 1.0 }, Icon: Sparkles },
];

export const LightingPanel: React.FC = () => {
  const engine = useRenderEngine();
  const { protocol } = useProtocol();
  const sprites = useGameStore(s => s.sprites);
  const activeTableId = useGameStore(s => s.activeTableId);
  const ambientLight = useGameStore(s => s.ambientLight);
  const setAmbientLight = useGameStore(s => s.setAmbientLight);
  const getUnitConverter = useGameStore(s => s.getUnitConverter);
  const distanceUnit = useGameStore(s => s.distanceUnit);

  const [selectedLightId, setSelectedLightId] = useState<string | null>(null);
  const [placementMode, setPlacementMode] = useState<typeof LIGHT_PRESETS[0] | null>(null);

  // Derive lights directly from store  single source of truth
  const lights = useMemo(() => {
    return sprites
      .filter(s => s.layer === 'light' && (!activeTableId || (s as any).tableId === activeTableId || (s as any).table_id === activeTableId))
      .map(spriteToLight)
      .filter((l): l is Light => l !== null);
  }, [sprites, activeTableId]);

  // Track which light IDs are in WASM so we can add/remove incrementally
  const prevLightIdsRef = useRef<Set<string>>(new Set());

  // Single WASM sync effect  replaces the 3 competing ones
  useEffect(() => {
    if (!engine) return;

    const currentIds = new Set(lights.map(l => l.id));
    const prev = prevLightIdsRef.current;

    for (const light of lights) {
      if (!prev.has(light.id)) {
        try {
          engine.add_light(light.id, light.x, light.y);
          engine.set_light_color(light.id, light.color.r, light.color.g, light.color.b, light.color.a);
          engine.set_light_intensity(light.id, light.intensity);
          engine.set_light_radius(light.id, light.radius);
          if (!light.isOn) engine.toggle_light(light.id);
        } catch {}
      }
    }

    for (const id of prev) {
      if (!currentIds.has(id)) {
        try { engine.remove_light(id); } catch {}
      }
    }

    prevLightIdsRef.current = currentIds;
  }, [engine, lights]);

  // Handle light placed on canvas
  useEffect(() => {
    const handler = (e: Event) => {
      const { x, y, preset } = (e as CustomEvent).detail;
      if (!engine || !preset) return;

      if (preset.isMoving && preset.existingLightId) {
        try { engine.update_light_position(preset.existingLightId, x, y); } catch {}
        protocol?.moveSprite(preset.existingLightId, x, y);
        setPlacementMode(null);
        return;
      }

      const lightId = `${preset.name}_${Date.now()}`;
      const converter = useGameStore.getState().getUnitConverter();
      const radiusPx = converter.toPixels(converter.fromFeet(preset.radiusFt));
      const newLight: Light = { id: lightId, x, y, presetName: preset.name, color: preset.color, intensity: preset.intensity, radius: radiusPx, isOn: true };

      // Add to WASM immediately
      try {
        engine.add_light(lightId, x, y);
        engine.set_light_color(lightId, newLight.color.r, newLight.color.g, newLight.color.b, newLight.color.a);
        engine.set_light_intensity(lightId, newLight.intensity);
        engine.set_light_radius(lightId, newLight.radius);
      } catch {}

      prevLightIdsRef.current.add(lightId);
      // Add to Zustand immediately (optimistic) so WASM sync effect seeds prevLightIdsRef
      // and server confirmation doesn't reset the position if user moves it first
      if (activeTableId) {
        const spritePayload = lightToSprite(newLight, activeTableId);
        useGameStore.getState().addSprite({ ...spritePayload, texture: '__LIGHT__' } as any);
      }

      setSelectedLightId(lightId);
      setPlacementMode(null);

      if (protocol && activeTableId) {
        protocol.createSprite(lightToSprite(newLight, activeTableId));
      }
    };

    window.addEventListener('lightPlaced', handler);
    return () => window.removeEventListener('lightPlaced', handler);
  }, [engine, protocol, activeTableId]);

  const removeLight = (lightId: string) => {
    if (!engine) return;
    try { engine.remove_light(lightId); } catch {}
    if (selectedLightId === lightId) setSelectedLightId(null);
    // Optimistically remove from store so the panel updates immediately
    useGameStore.getState().removeSprite(lightId);
    protocol?.removeSprite(lightId);
  };

  const updateLightProperty = (lightId: string, property: keyof Light, value: any) => {
    if (!engine) return;
    const light = lights.find(l => l.id === lightId);
    if (!light) return;

    try {
      switch (property) {
        case 'color': engine.set_light_color(lightId, value.r, value.g, value.b, value.a); break;
        case 'intensity': engine.set_light_intensity(lightId, value); break;
        case 'radius': engine.set_light_radius(lightId, value); break;
        case 'isOn': engine.toggle_light(lightId); break;
        case 'x': case 'y': engine.update_light_position(lightId, property === 'x' ? value : light.x, property === 'y' ? value : light.y); break;
      }
    } catch {}

    const updated = { ...light, [property]: value };
    const spriteData = lightToSprite(updated, activeTableId ?? 'default_table');
    if (protocol) protocol.updateSprite(lightId, spriteData);
    useGameStore.getState().updateSprite(lightId, { x: updated.x, y: updated.y, metadata: spriteData.metadata } as any);
  };

  const startPlacingLight = (preset: typeof LIGHT_PRESETS[0]) => {
    setPlacementMode(preset);
    window.dispatchEvent(new CustomEvent('startLightPlacement', { detail: { preset } }));
  };

  const startMovingLight = (light: Light) => {
    const movePreset = { ...LIGHT_PRESETS[0], name: light.id, radius: light.radius, intensity: light.intensity, color: light.color, isMoving: true, existingLightId: light.id };
    setPlacementMode(movePreset as any);
    window.dispatchEvent(new CustomEvent('startLightPlacement', { detail: { preset: movePreset } }));
  };

  const toggleAllLights = () => {
    if (!engine) return;
    const allOn = lights.every(l => l.isOn);
    for (const l of lights) {
      if (l.isOn === allOn) try { engine.toggle_light(l.id); } catch {}
    }
    for (const l of lights) {
      const updated = { ...l, isOn: !allOn };
      protocol?.updateSprite(l.id, lightToSprite(updated, activeTableId ?? ''));
      useGameStore.getState().updateSprite(l.id, { metadata: lightToSprite(updated, activeTableId ?? '').metadata } as any);
    }
  };

  const clearAllLights = () => {
    if (!engine) return;
    for (const l of lights) {
      try { engine.remove_light(l.id); } catch {}
      protocol?.removeSprite(l.id);
    }
    setSelectedLightId(null);
  };

  const selectedLight = lights.find(l => l.id === selectedLightId);

  return (
    <div className={styles['lighting-panel']}>
      <div className={styles['panel-header']}>
        <h3>Lighting System</h3>
      </div>

      {placementMode && (
        <div className={styles['placement-indicator']}>
          <span>Placing: {placementMode.name}</span>
          <button aria-label="Cancel" onClick={() => { setPlacementMode(null); window.dispatchEvent(new CustomEvent('cancelLightPlacement')); }}>
            <X size={14} />
          </button>
        </div>
      )}

      <div className={styles['preset-section']}>
        <h4>Quick Place Lights</h4>
        <div className={styles['preset-buttons']}>
          {LIGHT_PRESETS.map((preset) => (
            <button
              key={preset.name}
              className={styles['preset-button']}
              onClick={() => startPlacingLight(preset)}
              style={{
                background: `radial-gradient(circle, rgba(${preset.color.r * 255}, ${preset.color.g * 255}, ${preset.color.b * 255}, 0.3), rgba(${preset.color.r * 255}, ${preset.color.g * 255}, ${preset.color.b * 255}, 0))`,
                border: `2px solid rgba(${preset.color.r * 255}, ${preset.color.g * 255}, ${preset.color.b * 255}, 0.8)`,
              }}
              title={`${preset.name} тАФ ${preset.radiusFt} ft тАв I:${preset.intensity}`}
            >
              <preset.Icon size={16} />
              <span>{preset.name}</span>
            </button>
          ))}
        </div>
      </div>

      <div className={styles['ambient-controls']}>
        <h4>Ambient Lighting</h4>
        <label htmlFor="ambient-light">Ambient Light: {(ambientLight * 100).toFixed(0)}%</label>
        <input
          id="ambient-light"
          type="range"
          min="0"
          max="1"
          step="0.05"
          value={ambientLight}
          onChange={(e) => {
            const v = parseFloat(e.target.value);
            setAmbientLight(v);
            try { (engine as any)?.set_ambient_light(v); } catch {}
          }}
        />
      </div>

      <div className={styles['light-controls']}>
        <button onClick={toggleAllLights} disabled={lights.length === 0}>
          {lights.every(l => l.isOn) ? 'Turn Off All' : 'Turn On All'}
        </button>
        <button onClick={clearAllLights} disabled={lights.length === 0}>
          <Trash2 size={14} /> Clear All
        </button>
      </div>

      <div className={styles['light-list']}>
        <h4>Lights ({lights.length})</h4>
        {lights.length === 0 ? (
          <p className={styles['empty-message']}>No lights placed</p>
        ) : (
          lights.map(light => {
            const Preset = LIGHT_PRESETS.find(p => p.name === light.presetName);
            const Icon = Preset?.Icon ?? Lightbulb;
            return (
              <div
                key={light.id}
                className={`${styles['light-item']} ${selectedLightId === light.id ? styles.selected : ''}`}
                onClick={() => setSelectedLightId(light.id)}
              >
                <div className={styles['light-header']}>
                  <span className={styles['light-name']}>
                    <Icon size={14} /> {light.presetName ?? light.id}
                  </span>
                  <div className={styles['light-actions']}>
                    <button title="Move" onClick={(e) => { e.stopPropagation(); startMovingLight(light); }}>
                      <MoveHorizontal size={14} />
                    </button>
                    <button
                      title="Toggle"
                      className={styles[light.isOn ? 'on' : 'off']}
                      onClick={(e) => { e.stopPropagation(); updateLightProperty(light.id, 'isOn', !light.isOn); }}
                    >
                      <Sun size={14} />
                    </button>
                    <button title="Remove" onClick={(e) => { e.stopPropagation(); removeLight(light.id); }}>
                      <X size={14} />
                    </button>
                  </div>
                </div>
                <div className={styles['light-preview']}>
                  <div
                    className={styles['color-indicator']}
                    style={{
                      backgroundColor: `rgba(${Math.round(light.color.r * 255)}, ${Math.round(light.color.g * 255)}, ${Math.round(light.color.b * 255)}, ${light.color.a})`,
                      opacity: light.intensity,
                    }}
                  />
                  <span className={styles['light-stats']}>{getUnitConverter().toUnits(light.radius).toFixed(0)} {distanceUnit} тАв I:{light.intensity.toFixed(2)}</span>
                </div>
              </div>
            );
          })
        )}
      </div>

      {selectedLight && (
        <div className={styles['light-properties']}>
          <h4>Properties: {selectedLight.id}</h4>

          <div className={styles['property-group']}>
            <label>Position</label>
            <div className={styles['position-controls']}>
              <input type="number" placeholder="X" value={selectedLight.x} onChange={(e) => updateLightProperty(selectedLight.id, 'x', parseFloat(e.target.value) || 0)} />
              <input type="number" placeholder="Y" value={selectedLight.y} onChange={(e) => updateLightProperty(selectedLight.id, 'y', parseFloat(e.target.value) || 0)} />
            </div>
          </div>

          <div className={styles['property-group']}>
            <label>Color</label>
            <div className={styles['color-controls']}>
              <input
                type="color"
                value={`#${Math.round(selectedLight.color.r * 255).toString(16).padStart(2, '0')}${Math.round(selectedLight.color.g * 255).toString(16).padStart(2, '0')}${Math.round(selectedLight.color.b * 255).toString(16).padStart(2, '0')}`}
                onChange={(e) => {
                  const h = e.target.value;
                  updateLightProperty(selectedLight.id, 'color', {
                    r: parseInt(h.slice(1, 3), 16) / 255,
                    g: parseInt(h.slice(3, 5), 16) / 255,
                    b: parseInt(h.slice(5, 7), 16) / 255,
                    a: selectedLight.color.a,
                  });
                }}
              />
            </div>
          </div>

          <div className={styles['property-group']}>
            <label>Intensity: {selectedLight.intensity.toFixed(2)}</label>
            <input type="range" min="0" max="2" step="0.01" value={selectedLight.intensity} onChange={(e) => updateLightProperty(selectedLight.id, 'intensity', parseFloat(e.target.value))} />
          </div>

          <div className={styles['property-group']}>
            {(() => {
              const conv = getUnitConverter();
              const radiusUnits = conv.toUnits(selectedLight.radius);
              return (
                <>
                  <label>Radius: {radiusUnits.toFixed(0)} {distanceUnit}</label>
                  <input
                    type="range"
                    min="5"
                    max="300"
                    step="5"
                    value={radiusUnits}
                    onChange={(e) => {
                      const px = conv.toPixels(parseFloat(e.target.value));
                      updateLightProperty(selectedLight.id, 'radius', px);
                    }}
                  />
                </>
              );
            })()}
          </div>
        </div>
      )}
    </div>
  );
};

import { useGameStore } from '@/store';
import { fireEvent, render, screen } from '@testing-library/react';
import { beforeEach, describe, expect, it, vi } from 'vitest';
import { LightingPanel } from '../LightingPanel';

// ---- render engine mock ----
const engineMock = {
  add_light: vi.fn(),
  remove_light: vi.fn(),
  set_light_color: vi.fn(),
  set_light_intensity: vi.fn(),
  set_light_radius: vi.fn(),
  toggle_light: vi.fn(),
  update_light_position: vi.fn(),
  set_ambient_light: vi.fn(),
};

vi.mock('@features/canvas', () => ({
  useRenderEngine: () => engineMock,
}));

// ---- protocol mock ----
const protocolMock = {
  createSprite: vi.fn(),
  removeSprite: vi.fn(),
  updateSprite: vi.fn(),
  moveSprite: vi.fn(),
};

vi.mock('@lib/api', () => ({
  useProtocol: () => ({ protocol: protocolMock }),
}));

// ---- helpers ----
function makeLight(overrides: Record<string, any> = {}) {
  return {
    id: 'torch_1',
    sprite_id: 'torch_1',
    layer: 'light',
    texture_path: '__LIGHT__',
    x: 100,
    y: 200,
    table_id: 'table-1',
    metadata: JSON.stringify({
      isLight: true,
      presetName: 'Torch',
      color: { r: 1, g: 0.6, b: 0.2, a: 1 },
      intensity: 1.0,
      radius: 150,
      isOn: true,
    }),
    ...overrides,
  };
}

beforeEach(() => {
  vi.clearAllMocks();
  useGameStore.setState({ sprites: [], activeTableId: 'table-1', ambientLight: 1.0 } as any);
});

describe('LightingPanel', () => {
  describe('empty state', () => {
    it('shows "No lights placed" when no sprites exist', () => {
      render(<LightingPanel />);
      expect(screen.getByText(/no lights placed/i)).toBeInTheDocument();
    });

    it('shows all 6 preset buttons', () => {
      render(<LightingPanel />);
      for (const name of ['Torch', 'Candle', 'Daylight', 'Moonlight', 'Fire', 'Magic']) {
        expect(screen.getByRole('button', { name: new RegExp(name, 'i') })).toBeInTheDocument();
      }
    });

    it('shows light count 0 in header', () => {
      render(<LightingPanel />);
      expect(screen.getByText(/lights \(0\)/i)).toBeInTheDocument();
    });
  });

  describe('with lights in store', () => {
    beforeEach(() => {
      useGameStore.setState({ sprites: [makeLight() as any], activeTableId: 'table-1', ambientLight: 1.0 } as any);
    });

    it('shows light preset name in list', () => {
      render(<LightingPanel />);
      expect(screen.getByText(/lights \(1\)/i)).toBeInTheDocument();
    });

    it('does not show empty message', () => {
      render(<LightingPanel />);
      expect(screen.queryByText(/no lights placed/i)).not.toBeInTheDocument();
    });

    it('ignores sprites from other tables', () => {
      useGameStore.setState({ sprites: [makeLight({ table_id: 'other' }) as any] } as any);
      render(<LightingPanel />);
      expect(screen.getByText(/no lights placed/i)).toBeInTheDocument();
    });

    it('ignores sprites with wrong texture_path', () => {
      useGameStore.setState({ sprites: [makeLight({ texture_path: 'hero.png' }) as any] } as any);
      render(<LightingPanel />);
      expect(screen.getByText(/no lights placed/i)).toBeInTheDocument();
    });

    it('ignores sprites with isLight=false in metadata', () => {
      const bad = makeLight({ metadata: JSON.stringify({ isLight: false, presetName: 'X', color: {}, intensity: 1, radius: 1, isOn: true }) });
      useGameStore.setState({ sprites: [bad as any] } as any);
      render(<LightingPanel />);
      expect(screen.getByText(/no lights placed/i)).toBeInTheDocument();
    });
  });

  describe('light placement', () => {
    it('dispatches startLightPlacement when Torch preset is clicked', () => {
      const spy = vi.fn();
      window.addEventListener('startLightPlacement', spy);
      render(<LightingPanel />);
      fireEvent.click(screen.getByRole('button', { name: /torch/i }));
      expect(spy).toHaveBeenCalledOnce();
      expect((spy.mock.calls[0][0] as CustomEvent).detail.preset.name).toBe('Torch');
      window.removeEventListener('startLightPlacement', spy);
    });

    it('shows placement indicator after clicking preset', () => {
      render(<LightingPanel />);
      fireEvent.click(screen.getByRole('button', { name: /candle/i }));
      expect(screen.getByText(/placing.*candle/i)).toBeInTheDocument();
    });

    it('calls protocol.createSprite when lightPlaced event fires', () => {
      render(<LightingPanel />);
      fireEvent.click(screen.getByRole('button', { name: /torch/i }));
      window.dispatchEvent(new CustomEvent('lightPlaced', {
        detail: {
          x: 300, y: 400,
          preset: { name: 'Torch', radius: 150, intensity: 1.0, color: { r: 1, g: 0.6, b: 0.2, a: 1 } },
        },
      }));
      expect(protocolMock.createSprite).toHaveBeenCalledOnce();
      const arg = protocolMock.createSprite.mock.calls[0][0];
      expect(arg.layer).toBe('light');
      expect(arg.texture_path).toBe('__LIGHT__');
      expect(arg.x).toBe(300);
    });
  });

  describe('ambient lighting', () => {
    it('renders ambient slider', () => {
      render(<LightingPanel />);
      expect(screen.getByRole('slider', { name: /ambient/i })).toBeInTheDocument();
    });
  });
});

import { useGameStore } from '@/store';
import { afterEach, beforeEach, describe, expect, it, vi } from 'vitest';
import { visionService } from '../vision.service';

// ---- WASM render manager mock ----
const rm = {
  set_dynamic_lighting_enabled: vi.fn(),
  set_gm_mode: vi.fn(),
  compute_visibility_polygon: vi.fn().mockReturnValue([]),
  add_fog_polygon: vi.fn(),
  remove_fog_polygon: vi.fn(),
};

function baseStore(overrides: Record<string, any> = {}) {
  return {
    sprites: [],
    userId: 1,
    dynamicLightingEnabled: true,
    fogExplorationMode: 'none',
    ...overrides,
  };
}

function makeSprite(overrides: Record<string, any> = {}) {
  return {
    id: 'hero_1',
    x: 200,
    y: 400,
    width: 0,
    height: 0,
    layer: 'tokens',
    ...overrides,
  };
}

beforeEach(() => {
  vi.clearAllMocks();
  (window as any).rustRenderManager = rm;
  useGameStore.setState(baseStore() as any);
});

afterEach(() => {
  visionService.stop();
});

describe('VisionService.start()', () => {
  it('calls set_dynamic_lighting_enabled(true) on start', () => {
    visionService.start();
    expect(rm.set_dynamic_lighting_enabled).toHaveBeenCalledWith(true);
  });

  it('does not run twice if already started', () => {
    visionService.start();
    visionService.start();
    expect(rm.set_dynamic_lighting_enabled).toHaveBeenCalledTimes(1);
  });

  it('calls set_dynamic_lighting_enabled(false) on stop', () => {
    visionService.start();
    visionService.stop();
    expect(rm.set_dynamic_lighting_enabled).toHaveBeenCalledWith(false);
  });

  it('waits for dynamicLightingEnabled before registering', () => {
    useGameStore.setState({ dynamicLightingEnabled: false } as any);
    visionService.start();
    expect(rm.set_dynamic_lighting_enabled).not.toHaveBeenCalled();
  });
});

describe('getVisionSources (via recompute)', () => {
  it('excludes sprites without vision_radius', () => {
    useGameStore.setState({ sprites: [makeSprite({ controlled_by: [1] })] } as any);
    visionService.start();
    expect(rm.compute_visibility_polygon).not.toHaveBeenCalled();
  });

  it('excludes sprites with vision_radius=0', () => {
    useGameStore.setState({ sprites: [makeSprite({ controlled_by: [1], vision_radius: 0 })] } as any);
    visionService.start();
    expect(rm.compute_visibility_polygon).not.toHaveBeenCalled();
  });

  it('excludes sprites with no controlled_by array', () => {
    useGameStore.setState({ sprites: [makeSprite({ vision_radius: 150 })] } as any);
    visionService.start();
    expect(rm.compute_visibility_polygon).not.toHaveBeenCalled();
  });

  it('excludes sprites controlled by other users', () => {
    useGameStore.setState({
      sprites: [makeSprite({ controlled_by: [99], vision_radius: 150 })],
      userId: 1,
    } as any);
    visionService.start();
    expect(rm.compute_visibility_polygon).not.toHaveBeenCalled();
  });

  it('includes sprite controlled by current userId', () => {
    useGameStore.setState({
      sprites: [makeSprite({ controlled_by: [1], vision_radius: 150 })],
      userId: 1,
    } as any);
    visionService.start();
    expect(rm.compute_visibility_polygon).toHaveBeenCalledOnce();
    expect(rm.compute_visibility_polygon).toHaveBeenCalledWith(200, 400, expect.any(Float32Array), 150);
  });

  it('handles camelCase controlledBy and visionRadius fields', () => {
    useGameStore.setState({
      sprites: [makeSprite({ controlledBy: [1], visionRadius: 120 })],
      userId: 1,
    } as any);
    visionService.start();
    expect(rm.compute_visibility_polygon).toHaveBeenCalledWith(200, 400, expect.any(Float32Array), 120);
  });

  it('adds darkvision polygon when has_darkvision is true', () => {
    useGameStore.setState({
      sprites: [makeSprite({ controlled_by: [1], vision_radius: 150, has_darkvision: true, darkvision_radius: 60 })],
      userId: 1,
    } as any);
    visionService.start();
    expect(rm.compute_visibility_polygon).toHaveBeenCalledTimes(2);
    // vision + darkvision
    expect(rm.add_fog_polygon).toHaveBeenCalledTimes(2);
  });

  it('skips darkvision when darkvision_radius is 0', () => {
    useGameStore.setState({
      sprites: [makeSprite({ controlled_by: [1], vision_radius: 150, has_darkvision: true, darkvision_radius: 0 })],
      userId: 1,
    } as any);
    visionService.start();
    expect(rm.compute_visibility_polygon).toHaveBeenCalledTimes(1);
  });
});

describe('buildObstacles (via recompute)', () => {
  it('ignores non-obstacle sprites', () => {
    useGameStore.setState({
      sprites: [
        makeSprite({ controlled_by: [1], vision_radius: 150 }),
        { id: 'wall', x: 0, y: 0, layer: 'walls' }, // walls layer тАФ not obstacles
      ],
    } as any);
    visionService.start();
    // Float32Array passed to compute_visibility_polygon should be empty (length 0)
    const obstacles: Float32Array = rm.compute_visibility_polygon.mock.calls[0][2];
    expect(obstacles.length).toBe(0);
  });

  it('converts obstacle rectangle to 4 edge segments (8 numbers)', () => {
    useGameStore.setState({
      sprites: [
        makeSprite({ controlled_by: [1], vision_radius: 150 }),
        { id: 'box', x: 0, y: 0, layer: 'obstacles', width: 64, height: 64, rotation: 0 },
      ],
    } as any);
    visionService.start();
    const obstacles: Float32Array = rm.compute_visibility_polygon.mock.calls[0][2];
    expect(obstacles.length).toBe(16); // 4 edges ├Ч 4 numbers each
  });

  it('converts polygon obstacle by vertices', () => {
    useGameStore.setState({
      sprites: [
        makeSprite({ controlled_by: [1], vision_radius: 150 }),
        {
          id: 'poly',
          x: 0,
          y: 0,
          layer: 'obstacles',
          obstacle_type: 'polygon',
          polygon_vertices: [[0, 0], [100, 0], [100, 100]],
        },
      ],
    } as any);
    visionService.start();
    const obstacles: Float32Array = rm.compute_visibility_polygon.mock.calls[0][2];
    expect(obstacles.length).toBe(12); // 3 edges ├Ч 4 numbers each
  });
});

describe('DM preview mode', () => {
  it('uses dmPreviewUserId instead of store userId', () => {
    useGameStore.setState({
      sprites: [makeSprite({ controlled_by: [42], vision_radius: 200 })],
      userId: 1,
      dynamicLightingEnabled: false,
    } as any);
    visionService.startDmPreview(42);
    expect(rm.compute_visibility_polygon).toHaveBeenCalledWith(200, 400, expect.any(Float32Array), 200);
  });

  it('stops dm preview and disables lighting', () => {
    visionService.startDmPreview(5);
    visionService.stopDmPreview();
    expect(rm.set_dynamic_lighting_enabled).toHaveBeenLastCalledWith(false);
    expect(rm.set_gm_mode).toHaveBeenCalledWith(true);
  });
});

import { useGameStore } from '@/store';

class VisionService {
  private unsubscribe: (() => void) | null = null;
  private activeIds = new Set<string>();
  private exploredIds = new Set<string>();
  private lastPositions = new Map<string, string>();
  private lastObstaclesKey: string | null = null;
  private isRunning = false;
  private dmPreviewUserId: number | null = null;
  private pendingRecompute = false;
  // Live position cache updated by sprite-moved / sprite-drag-preview events (top-left coords)
  private spritePositions = new Map<string, { x: number; y: number }>();
  private spriteMovedListener: ((e: Event) => void) | null = null;
  private spriteDragPreviewListener: ((e: Event) => void) | null = null;
  private renderManagerReadyListener: (() => void) | null = null;

  start(): void {
    if (this.isRunning) return;

    const state = useGameStore.getState();

    if (!state.dynamicLightingEnabled) {
      const unsub = useGameStore.subscribe((s) => {
        if (s.dynamicLightingEnabled) {
          unsub();
          this.start();
        }
      });
      this.unsubscribe = unsub;
      return;
    }

    const rm = (window as any).rustRenderManager;
    if (!rm) {
      if (this.renderManagerReadyListener) return; // already waiting
      const onReady = () => {
        window.removeEventListener('render-manager-ready', onReady);
        this.renderManagerReadyListener = null;
        this.start();
      };
      this.renderManagerReadyListener = onReady;
      window.addEventListener('render-manager-ready', onReady);
      return;
    }

    rm.set_dynamic_lighting_enabled(true);
    this.isRunning = true;
    this.recompute();
    this.attachSpriteMoveListener();

    let prevSprites = state.sprites;
    let prevLighting: boolean = state.dynamicLightingEnabled;
    let prevFogMode = state.fogExplorationMode;

    this.unsubscribe = useGameStore.subscribe((s) => {
      if (!s.dynamicLightingEnabled && prevLighting) {
        prevLighting = false;
        this.stop();
        return;
      }
      prevLighting = s.dynamicLightingEnabled;

      if (s.sprites !== prevSprites) {
        prevSprites = s.sprites;
        this.scheduleRecompute();
      }

      if (s.fogExplorationMode !== prevFogMode) {
        if (s.fogExplorationMode !== 'persist_dimmed') this.clearExploredPolygons();
        prevFogMode = s.fogExplorationMode;
        this.scheduleRecompute();
      }
    });
  }

  private clearExploredPolygons(): void {
    const rm = (window as any).rustRenderManager;
    for (const id of this.exploredIds) {
      try { rm?.remove_fog_polygon(id); } catch {}
    }
    this.exploredIds.clear();
  }

  stop(): void {
    if (this.renderManagerReadyListener) {
      window.removeEventListener('render-manager-ready', this.renderManagerReadyListener);
      this.renderManagerReadyListener = null;
    }
    this.unsubscribe?.();
    this.unsubscribe = null;
    this.isRunning = false;
    this.dmPreviewUserId = null;

    const rm = (window as any).rustRenderManager;
    for (const id of this.activeIds) {
      try { rm?.remove_fog_polygon(id); } catch {}
    }
    this.clearExploredPolygons();
    rm?.set_dynamic_lighting_enabled(false);

    this.activeIds.clear();
    this.lastPositions.clear();
    this.lastObstaclesKey = null;
    this.spritePositions.clear();
    this.detachSpriteMoveListener();
  }

  startDmPreview(userId: number): void {
    this.stop();
    this.dmPreviewUserId = userId;

    const rm = (window as any).rustRenderManager;
    if (!rm) return;

    rm.set_gm_mode(false);
    rm.set_dynamic_lighting_enabled(true);
    this.isRunning = true;
    this.recompute();
    this.attachSpriteMoveListener();

    let prevSprites = useGameStore.getState().sprites;
    this.unsubscribe = useGameStore.subscribe((s) => {
      if (s.sprites !== prevSprites) {
        prevSprites = s.sprites;
        this.scheduleRecompute();
      }
    });
  }

  stopDmPreview(): void {
    this.stop();
    const rm = (window as any).rustRenderManager;
    rm?.set_gm_mode(true);
    rm?.set_dynamic_lighting_enabled(false);
  }

  private scheduleRecompute(): void {
    if (this.pendingRecompute) return;
    this.pendingRecompute = true;
    requestAnimationFrame(() => {
      this.pendingRecompute = false;
      this.recompute();
    });
  }

  private recompute(): void {
    const rm = (window as any).rustRenderManager;
    if (!rm) return;

    const obstacles = this.buildObstacles();
    const obstaclesKey = this.obstaclesKey(obstacles);
    const obstaclesChanged = obstaclesKey !== this.lastObstaclesKey;
    const { fogExplorationMode } = useGameStore.getState();
    const persistExplored = fogExplorationMode === 'persist_dimmed';
    if (!persistExplored && this.exploredIds.size > 0) this.clearExploredPolygons();
    const sources = this.getVisionSources();
    const seenIds = new Set<string>();

    for (const src of sources) {
      const id = `vision_${src.id}`;
      const posKey = `${src.x.toFixed(1)},${src.y.toFixed(1)},${src.radius}`;
      const moved = this.lastPositions.get(src.id) !== posKey;

      if (moved || obstaclesChanged) {
        const rawPoly: { x: number; y: number }[] = rm.compute_visibility_polygon(src.x, src.y, obstacles, src.radius);
        const poly = [{ x: src.x, y: src.y }, ...rawPoly];

        if (persistExplored && moved && this.lastPositions.has(src.id)) {
          const expId = `explored_${src.id}`;
          try { rm.add_fog_polygon(expId, poly); } catch {}
          this.exploredIds.add(expId);
        }

        try { rm.add_fog_polygon(id, poly); } catch {}
        this.lastPositions.set(src.id, posKey);
      }
      seenIds.add(id);
      this.activeIds.add(id);

      if (src.darkvisionRadius) {
        const dvId = `darkvision_${src.id}`;
        const dvPosKey = `${src.x.toFixed(1)},${src.y.toFixed(1)},dv${src.darkvisionRadius}`;
        const dvMoved = this.lastPositions.get(dvId) !== dvPosKey;

        if (dvMoved || obstaclesChanged) {
          const rawDv: { x: number; y: number }[] = rm.compute_visibility_polygon(src.x, src.y, obstacles, src.darkvisionRadius);
          try { rm.add_fog_polygon(dvId, [{ x: src.x, y: src.y }, ...rawDv]); } catch {}
          this.lastPositions.set(dvId, dvPosKey);
        }
        seenIds.add(dvId);
        this.activeIds.add(dvId);
      }
    }

    // Also reveal areas illuminated by active lights (vision union light)
    const allSprites = (useGameStore.getState().sprites || []) as any[];
    for (const ls of allSprites) {
      if (ls.layer !== 'light') continue;
      let meta: any = {};
      try { meta = typeof ls.metadata === 'string' ? JSON.parse(ls.metadata) : (ls.metadata ?? {}); } catch {}
      if (meta.isOn === false) continue;
      // meta.radius is stored in pixels (LightingPanel converts at placement)
      // Fallback: 20ft torch at default 10px/ft = 200px
      const lightRadius = meta.radius ?? useGameStore.getState().getUnitConverter().toPixels(20);
      const lightFogId = `fog_light_${ls.id}`;
      const lx = ls.x ?? 0;
      const ly = ls.y ?? 0;
      const lightPosKey = `${lx.toFixed(1)},${ly.toFixed(1)},${lightRadius}`;
      const lightMoved = this.lastPositions.get(lightFogId) !== lightPosKey;
      if (lightMoved || obstaclesChanged) {
        const rawLight: { x: number; y: number }[] = rm.compute_visibility_polygon(lx, ly, obstacles, lightRadius);
        const lightPoly = [{ x: lx, y: ly }, ...rawLight];
        try { rm.add_fog_polygon(lightFogId, lightPoly); } catch {}
        this.lastPositions.set(lightFogId, lightPosKey);
      }
      seenIds.add(lightFogId);
      this.activeIds.add(lightFogId);
    }

    for (const id of [...this.activeIds]) {
      if (!seenIds.has(id)) {
        try { rm.remove_fog_polygon(id); } catch {}
        this.activeIds.delete(id);
      }
    }

    this.lastObstaclesKey = obstaclesKey;
  }

  private buildObstacles(): Float32Array {
    const rm = (window as any).rustRenderManager;
    // Prefer live WASM data тАФ always reflects current drag positions
    if (rm?.get_obstacle_segments_flat) {
      const segs: number[] = rm.get_obstacle_segments_flat();
      return new Float32Array(segs);
    }

    // Fallback: compute from store (when WASM isn't ready yet)
    const sprites = (useGameStore.getState().sprites || []) as any[];
    const segs: number[] = [];

    for (const s of sprites) {
      if (s.layer !== 'obstacles') continue;

      const obstacleType = s.obstacle_type || s.obstacleType;
      if (obstacleType === 'polygon' && s.polygon_vertices) {
        const verts: number[][] = s.polygon_vertices;
        for (let i = 0; i < verts.length; i++) {
          const next = (i + 1) % verts.length;
          segs.push(verts[i][0], verts[i][1], verts[next][0], verts[next][1]);
        }
        continue;
      }

      const w = s.width ?? ((s.scale_x ?? 1) * 64);
      const h = s.height ?? ((s.scale_y ?? 1) * 64);
      const cx = s.x + w / 2;
      const cy = s.y + h / 2;
      const angle = (s.rotation ?? 0) * (Math.PI / 180);
      const cosA = Math.cos(angle);
      const sinA = Math.sin(angle);
      const hw = w / 2;
      const hh = h / 2;
      const corners: [number, number][] = [
        [cx + (-hw) * cosA - (-hh) * sinA, cy + (-hw) * sinA + (-hh) * cosA],
        [cx + hw * cosA - (-hh) * sinA, cy + hw * sinA + (-hh) * cosA],
        [cx + hw * cosA - hh * sinA, cy + hw * sinA + hh * cosA],
        [cx + (-hw) * cosA - hh * sinA, cy + (-hw) * sinA + hh * cosA],
      ];
      for (let i = 0; i < 4; i++) {
        const n = (i + 1) % 4;
        segs.push(corners[i][0], corners[i][1], corners[n][0], corners[n][1]);
      }
    }

    return new Float32Array(segs);
  }

  private getVisionSources(): { id: string; x: number; y: number; radius: number; darkvisionRadius?: number }[] {
    const { sprites, userId, dynamicLightingEnabled } = useGameStore.getState();
    if (!dynamicLightingEnabled && this.dmPreviewUserId == null) return [];

    const targetUserId = this.dmPreviewUserId ?? userId;
    const converter = useGameStore.getState().getUnitConverter();
    const out: { id: string; x: number; y: number; radius: number; darkvisionRadius?: number }[] = [];

    for (const s of (sprites || []) as any[]) {
      const controlled: number[] = s.controlledBy ?? s.controlled_by ?? [];
      if (controlled.length === 0) continue;
      if (targetUserId != null && !controlled.includes(targetUserId)) continue;

      // Prefer game-unit fields, convert to pixels; fall back to legacy pixel fields
      let radiusPx: number;
      if (s.visionRadiusUnits != null || s.vision_radius_units != null) {
        radiusPx = converter.toPixels(s.visionRadiusUnits ?? s.vision_radius_units);
      } else {
        radiusPx = s.visionRadius ?? s.vision_radius ?? 0;
      }
      if (radiusPx <= 0) continue;

      const hasDv = s.hasDarkvision || s.has_darkvision;
      let dvRadiusPx = 0;
      if (hasDv) {
        if (s.darkvisionRadiusUnits != null || s.darkvision_radius_units != null) {
          dvRadiusPx = converter.toPixels(s.darkvisionRadiusUnits ?? s.darkvision_radius_units);
        } else if (s.darkvisionRadius != null || s.darkvision_radius != null) {
          dvRadiusPx = s.darkvisionRadius ?? s.darkvision_radius ?? 0;
        } else {
          // Auto-populate from compendium race data (already in feet)
          const raceDvFt: number = s.characterData?.race?.darkvision ?? s.race_darkvision ?? 0;
          if (raceDvFt > 0) dvRadiusPx = converter.toPixels(converter.fromFeet(raceDvFt));
        }
      }

      const pos = this.spritePositions.get(s.id) ?? { x: s.x, y: s.y };
      const w = s.width ?? ((s.scale_x ?? 1) * 64);
      const h = s.height ?? ((s.scale_y ?? 1) * 64);

      out.push({
        id: s.id,
        x: pos.x + w / 2,
        y: pos.y + h / 2,
        radius: radiusPx,
        darkvisionRadius: dvRadiusPx > 0 ? dvRadiusPx : undefined,
      });
    }

    return out;
  }

  private attachSpriteMoveListener(): void {
    if (!this.spriteMovedListener) {
      this.spriteMovedListener = (e: Event) => {
        const d = (e as CustomEvent).detail as any;
        const id = d?.sprite_id || d?.id;
        const pos: { x: number; y: number } | null =
          d?.to ?? d?.position ?? (d?.x !== undefined ? { x: d.x, y: d.y } : null);
        if (id && pos) {
          this.spritePositions.set(id, pos);
          this.scheduleRecompute();
        }
      };
      window.addEventListener('sprite-moved', this.spriteMovedListener);
    }

    if (!this.spriteDragPreviewListener) {
      // sprite-drag-preview fires every mousemove during local drag (player's own sprite)
      // detail: { spriteId, x, y } тАФ top-left world coords from WASM
      this.spriteDragPreviewListener = (e: Event) => {
        const d = (e as CustomEvent).detail as any;
        const id = d?.spriteId;
        if (id && d?.x !== undefined && d?.y !== undefined) {
          this.spritePositions.set(id, { x: d.x, y: d.y });
          this.scheduleRecompute();
        }
      };
      window.addEventListener('sprite-drag-preview', this.spriteDragPreviewListener);
    }
  }

  private detachSpriteMoveListener(): void {
    if (this.spriteMovedListener) {
      window.removeEventListener('sprite-moved', this.spriteMovedListener);
      this.spriteMovedListener = null;
    }
    if (this.spriteDragPreviewListener) {
      window.removeEventListener('sprite-drag-preview', this.spriteDragPreviewListener);
      this.spriteDragPreviewListener = null;
    }
  }

  private obstaclesKey(arr: Float32Array): string {
    if (arr.length === 0) return 'empty';
    let sum = 0;
    for (let i = 0; i < Math.min(16, arr.length); i++) sum += arr[i];
    return `${arr.length}:${sum.toFixed(3)}`;
  }
}

export const visionService = new VisionService();

export function startDmPreview(userId: number): void {
  visionService.startDmPreview(userId);
}

export function stopDmPreview(): void {
  visionService.stopDmPreview();
}

import {
  advancedMeasurementSystem,
  type GeometricShape,
  type GridConfiguration,
  type MeasurementLine,
  type MeasurementSettings,
  type MeasurementTemplate
} from '@features/measurement/services/advancedMeasurement.service';
import { useCallback, useEffect, useRef, useState } from 'react';
import type { TabType } from './TabNavigation';
import type { ActiveTool } from './ToolSelection';

type ShapeType = 'circle' | 'rectangle' | 'polygon' | 'arc' | 'ellipse';

interface UseAdvancedMeasurementProps {
  isOpen: boolean;
  canvasRef: React.RefObject<HTMLCanvasElement>;
  onMeasurementStart?: (point: { x: number; y: number }) => void;
  onMeasurementUpdate?: (measurementId: string, endPoint: { x: number; y: number }) => void;
  onMeasurementComplete?: (measurement: MeasurementLine) => void;
}

export const useAdvancedMeasurement = ({
  isOpen,
  canvasRef,
  onMeasurementStart,
  onMeasurementUpdate,
  onMeasurementComplete
}: UseAdvancedMeasurementProps) => {
  const [activeTool, setActiveTool] = useState<ActiveTool>(null);
  const [measurements, setMeasurements] = useState<MeasurementLine[]>([]);
  const [shapes, setShapes] = useState<GeometricShape[]>([]);
  const [grids, setGrids] = useState<GridConfiguration[]>([]);
  const [templates, setTemplates] = useState<MeasurementTemplate[]>([]);
  const [settings, setSettings] = useState<MeasurementSettings | null>(null);
  const [activeGrid, setActiveGrid] = useState<GridConfiguration | null>(null);
  const [selectedTab, setSelectedTab] = useState<TabType>('measure');
  
  const [selectedShapeType, setSelectedShapeType] = useState<ShapeType>('rectangle');
  const [selectedTemplate, setSelectedTemplate] = useState<string | null>(null);
  const [isCreatingShape, setIsCreatingShape] = useState(false);
  const [shapePoints, setShapePoints] = useState<{ x: number; y: number }[]>([]);
  const [activeMeasurement, setActiveMeasurement] = useState<string | null>(null);
  
  const [searchQuery, setSearchQuery] = useState('');
  const [showAdvancedSettings, setShowAdvancedSettings] = useState(false);
  const [error, setError] = useState<string | null>(null);
  
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (!isOpen) return;

    try {
      setMeasurements(advancedMeasurementSystem.getMeasurements());
      setShapes(advancedMeasurementSystem.getShapes());
      setGrids(advancedMeasurementSystem.getGrids());
      setTemplates(advancedMeasurementSystem.getTemplates());
      setSettings(advancedMeasurementSystem.getSettings());
      setActiveGrid(advancedMeasurementSystem.getActiveGrid());
    } catch (err) {
      setError('Failed to load measurement system data: ' + (err as Error).message);
    }
  }, [isOpen]);

  useEffect(() => {
    const handleMeasurementEvent = (event: string, data: any) => {
      switch (event) {
        case 'measurementStarted':
          setActiveMeasurement(data.measurement.id);
          onMeasurementStart?.(data.measurement.start);
          break;
        case 'measurementUpdated':
          onMeasurementUpdate?.(data.measurement.id, data.measurement.end);
          break;
        case 'measurementCompleted':
          setActiveMeasurement(null);
          setMeasurements(advancedMeasurementSystem.getMeasurements());
          onMeasurementComplete?.(data.measurement);
          break;
        case 'shapeCreated':
          setShapes(advancedMeasurementSystem.getShapes());
          setIsCreatingShape(false);
          setShapePoints([]);
          break;
        case 'activeGridChanged':
          setActiveGrid(advancedMeasurementSystem.getActiveGrid());
          break;
        case 'settingsUpdated':
          setSettings(data.settings);
          break;
        default:
          break;
      }
    };

    advancedMeasurementSystem.subscribe('ui', handleMeasurementEvent);

    return () => {
      advancedMeasurementSystem.unsubscribe('ui');
    };
  }, [onMeasurementStart, onMeasurementUpdate, onMeasurementComplete]);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas || !isOpen) return;

    const handleCanvasClick = (event: MouseEvent) => {
      const rect = canvas.getBoundingClientRect();
      const x = event.clientX - rect.left;
      const y = event.clientY - rect.top;
      const point = { x, y };

      try {
        switch (activeTool) {
          case 'measure':
            if (activeMeasurement) {
              advancedMeasurementSystem.completeMeasurement(activeMeasurement);
            } else {
              advancedMeasurementSystem.startMeasurement(point);
            }
            break;

          case 'shape':
            if (isCreatingShape) {
              const newPoints = [...shapePoints, point];
              setShapePoints(newPoints);

              if ((selectedShapeType === 'rectangle' || selectedShapeType === 'circle' || selectedShapeType === 'ellipse') && newPoints.length === 2) {
                advancedMeasurementSystem.createShape(selectedShapeType, newPoints);
              } else if (selectedShapeType === 'polygon' && event.detail === 2) {
                advancedMeasurementSystem.createShape(selectedShapeType, newPoints);
              }
            } else {
              setIsCreatingShape(true);
              setShapePoints([point]);
            }
            break;

          case 'template':
            if (selectedTemplate) {
              console.log('Template placement at:', point, 'template:', selectedTemplate);
            }
            break;

          default:
            break;
        }
      } catch (err) {
        setError('Tool operation failed: ' + (err as Error).message);
      }
    };

    const handleCanvasMouseMove = (event: MouseEvent) => {
      if (activeMeasurement) {
        const rect = canvas.getBoundingClientRect();
        const x = event.clientX - rect.left;
        const y = event.clientY - rect.top;
        advancedMeasurementSystem.updateMeasurement(activeMeasurement, { x, y });
      }
    };

    canvas.addEventListener('click', handleCanvasClick);
    canvas.addEventListener('mousemove', handleCanvasMouseMove);

    return () => {
      canvas.removeEventListener('click', handleCanvasClick);
      canvas.removeEventListener('mousemove', handleCanvasMouseMove);
    };
  }, [canvasRef, isOpen, activeTool, activeMeasurement, isCreatingShape, shapePoints, selectedShapeType, selectedTemplate]);

  const handleToolSelect = useCallback((tool: ActiveTool) => {
    setActiveTool(tool);
    
    if (activeMeasurement) {
      advancedMeasurementSystem.cancelMeasurement(activeMeasurement);
    }
    setIsCreatingShape(false);
    setShapePoints([]);
    setError(null);
  }, [activeMeasurement]);

  const handleClearMeasurements = useCallback(() => {
    if (window.confirm('Clear all measurements? This cannot be undone.')) {
      advancedMeasurementSystem.clearMeasurements(true);
      setMeasurements([]);
    }
  }, []);

  const handleGridChange = useCallback((gridId: string) => {
    advancedMeasurementSystem.setActiveGrid(gridId);
  }, []);

  const handleGridUpdate = useCallback((gridId: string, updates: Partial<GridConfiguration>) => {
    advancedMeasurementSystem.updateGrid(gridId, updates);
    setGrids(advancedMeasurementSystem.getGrids());
    if (activeGrid?.id === gridId) {
      setActiveGrid(advancedMeasurementSystem.getActiveGrid());
    }
  }, [activeGrid]);

  const handleSettingsUpdate = useCallback((updates: Partial<MeasurementSettings>) => {
    advancedMeasurementSystem.updateSettings(updates);
  }, []);

  const handleExportData = useCallback(() => {
    try {
      const data = advancedMeasurementSystem.exportData();
      const blob = new Blob([data], { type: 'application/json' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `measurements_${new Date().toISOString().split('T')[0]}.json`;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      URL.revokeObjectURL(url);
    } catch (err) {
      setError('Failed to export data: ' + (err as Error).message);
    }
  }, []);

  const handleImportData = useCallback(() => {
    fileInputRef.current?.click();
  }, []);

  const handleFileImport = useCallback((event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const content = e.target?.result as string;
        advancedMeasurementSystem.importData(content);
        
        setMeasurements(advancedMeasurementSystem.getMeasurements());
        setShapes(advancedMeasurementSystem.getShapes());
        setGrids(advancedMeasurementSystem.getGrids());
        setTemplates(advancedMeasurementSystem.getTemplates());
        setActiveGrid(advancedMeasurementSystem.getActiveGrid());
      } catch (err) {
        setError('Failed to import data: ' + (err as Error).message);
      }
    };
    reader.readAsText(file);
  }, []);

  const handleCreateCustomTemplate = useCallback(() => {
    const name = prompt('Template name:');
    if (!name) return;
    
    const size = parseFloat(prompt('Size (in current units):') || '10');
    if (isNaN(size)) return;

    try {
      advancedMeasurementSystem.createTemplate({
        name,
        type: 'custom',
        size,
        color: '#ff6b35',
        fillColor: '#ff6b3533',
        opacity: 0.7,
        rotatable: true,
        snapToGrid: true,
        showArea: true,
        description: `Custom ${name} template`
      });
      setTemplates(advancedMeasurementSystem.getTemplates());
    } catch (err) {
      setError('Failed to create template: ' + (err as Error).message);
    }
  }, []);

  const filteredMeasurements = measurements.filter(m => 
    !searchQuery || m.label?.toLowerCase().includes(searchQuery.toLowerCase()) || m.id.includes(searchQuery)
  );

  const filteredShapes = shapes.filter(s => 
    !searchQuery || s.label?.toLowerCase().includes(searchQuery.toLowerCase()) || s.type.includes(searchQuery.toLowerCase())
  );

  return {
    activeTool,
    measurements,
    shapes,
    grids,
    templates,
    settings,
    activeGrid,
    selectedTab,
    setSelectedTab,
    selectedShapeType,
    setSelectedShapeType,
    selectedTemplate,
    setSelectedTemplate,
    isCreatingShape,
    shapePoints,
    activeMeasurement,
    searchQuery,
    setSearchQuery,
    showAdvancedSettings,
    setShowAdvancedSettings,
    error,
    setError,
    fileInputRef,
    handleToolSelect,
    handleClearMeasurements,
    handleGridChange,
    handleGridUpdate,
    handleSettingsUpdate,
    handleExportData,
    handleImportData,
    handleFileImport,
    handleCreateCustomTemplate,
    filteredMeasurements,
    filteredShapes
  };
};

export type { ShapeType };

