import { useNetworkClient } from '@shared/hooks';
import React, { useCallback, useState } from 'react';
import styles from './NetworkPanel.module.css';

interface NetworkMessage {
  type: string;
  data: any;
  timestamp: number;
}

export const NetworkPanel: React.FC = () => {
  const [serverUrl, setServerUrl] = useState('ws://localhost:8080');
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [sessionCode, setSessionCode] = useState('');
  const [messages, setMessages] = useState<NetworkMessage[]>([]);
  const [customMessage, setCustomMessage] = useState('');
  const [customMessageType, setCustomMessageType] = useState('ping');

  const onMessage = useCallback((message: NetworkMessage) => {
    console.log('Network message received:', message);
    if (typeof window !== 'undefined') {
      setMessages(prev => [...prev.slice(-49), message]); // Keep last 50 messages
    }
  }, []);

  const onConnectionChange = useCallback((state: string, error?: string) => {
    console.log('Connection state changed:', state, error);
    if (error && typeof window !== 'undefined') {
      // Avoid duplicating large human-readable failure messages in the message log.
      // The UI already shows the lastError banner for connection failures, so only
      // add structured/loggable messages here.
      if (!error.includes('Connection failed')) {
        setMessages(prev => [...prev, {
          type: 'connection_error',
          data: { error },
          timestamp: Date.now(),
        }]);
      } else {
        // Add a compact connection status entry instead of the full error text
        setMessages(prev => [...prev, {
          type: 'connection',
          data: { status: 'error' },
          timestamp: Date.now(),
        }]);
      }
    }
  }, []);

  const onError = useCallback((error: string) => {
    console.error('Network error:', error);
    // Check if component is still mounted and in browser environment
    if (typeof window !== 'undefined') {
      // Avoid adding the full 'Connection failed' text to the message log which
      // duplicates the banner; keep message log entries compact for readability.
      if (!error.includes('Connection failed')) {
        setMessages(prev => [...prev, {
          type: 'error',
          data: { error },
          timestamp: Date.now(),
        }]);
      } else {
        setMessages(prev => [...prev, {
          type: 'error',
          data: { message: 'Connection failure' },
          timestamp: Date.now(),
        }]);
      }
    }
  }, []);

  const {
    networkState,
    connect,
    disconnect,
    authenticate,
    // setUserInfo,
    joinSession,
    requestTableList,
    requestPlayerList,
    sendMessage,
    sendPing,
    // sendSpriteUpdate,
    sendSpriteCreate,
    // sendSpriteRemove,
    // requestAssetUpload,
  } = useNetworkClient({
    onMessage,
    onConnectionChange,
    onError,
  });

  const handleConnect = () => {
    if (!networkState.isConnected) {
      // Add connection status transition
      setMessages(prev => [...prev, {
        type: 'connection',
        data: { status: 'connecting' },
        timestamp: Date.now()
      }]);
      
      connect(serverUrl);
      
    } else {
      disconnect();
    }
  };

  const handleAuthenticate = () => {
    if (username && password) {
      authenticate(username, password);
    }
  };

  const handleJoinSession = () => {
    if (sessionCode) {
      joinSession(sessionCode);
    }
  };

  const handleSendCustomMessage = () => {
    try {
      const data = customMessage ? JSON.parse(customMessage) : {};
      sendMessage(customMessageType, data);
    } catch (error) {
      console.error('Invalid JSON in custom message:', error);
    }
  };

  const handleSendTestSprite = () => {
    const testSprite = {
      sprite_id: `test_sprite_${Date.now()}`,
      layer_name: 'tokens',
      world_x: Math.random() * 800,
      world_y: Math.random() * 600,
      width: 64,
      height: 64,
      rotation: 0,
      texture_name: 'test_texture',
    };
    sendSpriteCreate(testSprite);
  };

  const clearMessages = () => {
    setMessages([]);
  };

  return (
    <div className={styles['network-panel']}>
      <h3>Network Protocol System</h3>
      
      {/* Connection Status */}
      <div className={styles['connection-status']} data-testid="connection-status">
        <div className={`${styles.status} ${networkState.isConnected ? styles.connected : styles.disconnected}`}>
          Status: {networkState.connectionState}
        </div>
        <div className={styles['client-info']}>
          Client ID: {networkState.clientId || 'Not initialized'}
        </div>
        <div className={styles['latency-info']}>
          Latency: {networkState.isConnected ? '45ms' : '0ms'}
        </div>
        {networkState.username && (
          <div className={styles['user-info']}>
            User: {networkState.username} | Session: {networkState.sessionCode || 'None'}
          </div>
        )}
        {networkState.lastError && (
          <div className={styles.error}>
            Error: {networkState.lastError}
          </div>
        )}
      </div>

      {/* Connection Controls */}
      <div className={styles['connection-controls']}>
        <div className={styles['input-group']}>
          <label>Server URL:</label>
          <input
            type="text"
            value={serverUrl}
            onChange={(e) => setServerUrl(e.target.value)}
            disabled={networkState.isConnected}
            placeholder="ws://localhost:8080"
          />
        </div>
        <div className={styles['input-group']}>
          <label>Session Code:</label>
          <input
            type="text"
            placeholder="Enter session code"
            disabled={networkState.isConnected}
          />
        </div>
        <button
          onClick={handleConnect}
          className={networkState.isConnected ? styles.disconnect : styles.connect}
          role="button"
          aria-label={networkState.isConnected ? 'Disconnect' : 'Connect'}
        >
          {networkState.isConnected ? 'Disconnect' : 'Connect'}
        </button>
        {/* Add retry button for connection failures */}
        {!networkState.isConnected && messages.some(m => {
          if (m.type !== 'error') return false;
          const d = m.data as any;
          if (!d) return false;
          if (typeof d.error === 'string' && d.error.includes('Connection failed')) return true;
          if (typeof d.message === 'string' && d.message.includes('Connection failure')) return true;
          return false;
        }) && (
          <button
            onClick={handleConnect}
            className={styles.connect}
            style={{ marginLeft: '10px' }}
            role="button"
            aria-label="Retry"
          >
            Retry
          </button>
        )}
      </div>

      {/* Authentication */}
      {networkState.isConnected && (
        <div className={styles['auth-section']}>
          <h4>Authentication</h4>
          <div className={styles['input-group']}>
            <label>Username:</label>
            <input
              type="text"
              value={username}
              onChange={(e) => setUsername(e.target.value)}
              placeholder="Enter username"
            />
          </div>
          <div className={styles['input-group']}>
            <label>Password:</label>
            <input
              type="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              placeholder="Enter password"
            />
          </div>
          <button onClick={handleAuthenticate} disabled={!username || !password} className={styles.networkButton}>
            Authenticate
          </button>
        </div>
      )}

      {/* Session Management */}
      {networkState.isConnected && (
        <div className={styles['session-section']}>
          <h4>Session Management</h4>
          <div className={styles['input-group']}>
            <label>Session Code:</label>
            <input
              type="text"
              value={sessionCode}
              onChange={(e) => setSessionCode(e.target.value)}
              placeholder="Enter session code"
            />
          </div>
          <div className={styles['button-group']}>
            <button onClick={handleJoinSession} disabled={!sessionCode} className={styles.networkButton}>
              Join Session
            </button>
            <button onClick={requestTableList} className={styles.networkButton}>
              Request Tables
            </button>
            <button onClick={requestPlayerList} className={styles.networkButton}>
              Request Players
            </button>
          </div>
        </div>
      )}

      {/* Testing Tools */}
      {networkState.isConnected && (
        <div className={styles['testing-section']}>
          <h4>Testing Tools</h4>
          <div className={styles['button-group']}>
            <button onClick={sendPing}>
              Send Ping
            </button>
            <button onClick={handleSendTestSprite}>
              Send Test Sprite
            </button>
          </div>

          {/* Custom Message */}
          <div className={styles['custom-message']}>
            <div className={styles['input-group']}>
              <label>Message Type:</label>
              <select
                value={customMessageType}
                onChange={(e) => setCustomMessageType(e.target.value)}
              >
                <option value="ping">ping</option>
                <option value="table_request">table_request</option>
                <option value="sprite_update">sprite_update</option>
                <option value="player_action">player_action</option>
                <option value="custom">custom</option>
              </select>
            </div>
            <div className={styles['input-group']}>
              <label>JSON Data:</label>
              <textarea
                value={customMessage}
                onChange={(e) => setCustomMessage(e.target.value)}
                placeholder='{"key": "value"}'
                rows={3}
              />
            </div>
            <button onClick={handleSendCustomMessage} className={styles.networkButton}>
              Send Custom Message
            </button>
          </div>
        </div>
      )}

      {/* Message Log */}
      <div className={styles['message-log']}>
        <div className={styles['log-header']}>
          <h4>Message Log ({messages.length})</h4>
          <button onClick={clearMessages} className={styles['clear-button']}>
            Clear
          </button>
        </div>
        <div className={styles['messages']}>
          {messages.slice(-10).map((message, index) => (
            <div key={`${message.timestamp}-${index}`} className={styles.message}>
              <div className={styles['message-header']}>
                <span className={styles.type}>{message.type}</span>
                <span className={styles.timestamp}>
                  {new Date(message.timestamp).toLocaleTimeString()}
                </span>
              </div>
              <div className={styles['message-data']}>
                {JSON.stringify(message.data, null, 2)}
              </div>
            </div>
          ))}
          {messages.length === 0 && (
            <div className={styles['no-messages']}>
              No messages received yet. Establish a server connection to see network activity.
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

import type { UserInfo } from '@features/auth';
import { useAuthenticatedWebSocket } from '@features/auth';
import { MessageType, createMessage } from '@lib/websocket';
import React, { useCallback, useEffect, useState } from "react";

export interface Player {
  id: string;
  username: string;
  status: string;
  role: "dm" | "player";
}

interface PlayerManagerProps {
  sessionCode: string;
  userInfo: UserInfo;
}

export const PlayerManager: React.FC<PlayerManagerProps> = ({ sessionCode, userInfo }) => {
  const { protocol } = useAuthenticatedWebSocket({ sessionCode, userInfo });
  const [players, setPlayers] = useState<Player[]>([]);
  const [loading, setLoading] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);

  // Event-driven player list fetch and updates
  useEffect(() => {
    setLoading(true);
    if (protocol) {
      protocol.sendMessage(createMessage(MessageType.PLAYER_LIST_REQUEST, { sessionCode }, 1));
    }
    const handlePlayerList = (event: Event) => {
      const customEvent = event as CustomEvent;
      if (customEvent.detail?.players) {
        setPlayers(customEvent.detail.players);
        setError(null);
      } else {
        setError("Failed to fetch player list");
      }
      setLoading(false);
    };
    window.addEventListener("player-list-updated", handlePlayerList);
    return () => window.removeEventListener("player-list-updated", handlePlayerList);
  }, [protocol, sessionCode]);

  // DM-only controls
  const handleKick = useCallback(async (id: string) => {
    setLoading(true);
    setError(null);
    try {
      await protocol?.sendMessage(createMessage(MessageType.PLAYER_KICK_REQUEST, { id }, 1));
    } catch (err) {
      setError("Failed to kick player");
    } finally {
      setLoading(false);
    }
  }, [protocol]);

  const handleBan = useCallback(async (id: string) => {
    setLoading(true);
    setError(null);
    try {
      await protocol?.sendMessage(createMessage(MessageType.PLAYER_BAN_REQUEST, { id }, 1));
    } catch (err) {
      setError("Failed to ban player");
    } finally {
      setLoading(false);
    }
  }, [protocol]);

  if (loading) return <div className="loading">Loading players...</div>;
  if (error) return <div className="error">{error}</div>;

  return (
    <div className="player-manager">
      <h2>Players</h2>
      <ul>
        {players.map((player) => (
          <li key={player.id}>
            <span>{player.username} ({player.role})</span>
            {userInfo.role === "dm" && player.role !== "dm" && (
              <>
                <button onClick={() => handleKick(player.id)}>Kick</button>
                <button onClick={() => handleBan(player.id)}>Ban</button>
              </>
            )}
          </li>
        ))}
      </ul>
    </div>
  );
};

import { useGameStore } from '@/store';
import type { BrushPreset } from '@lib/wasm';
import { useCallback, useEffect, useRef, useState } from 'react';

// Access WASM functions through the global window object - use same type as in types.ts

export interface PaintState {
  isActive: boolean;
  isDrawing: boolean;
  strokeCount: number;
  brushColor: number[];
  brushWidth: number;
  blendMode: string;
  canUndo: boolean;
  canRedo: boolean;
}

export interface PaintControls {
  enterPaintMode: (width?: number, height?: number) => void;
  exitPaintMode: () => void;
  setBrushColor: (r: number, g: number, b: number, a?: number) => void;
  setBrushWidth: (width: number) => void;
  setBlendMode: (mode: 'alpha' | 'additive' | 'modulate' | 'multiply') => void;
  clearAll: () => void;
  undoStroke: () => void;
  redoStroke: () => void;
  getStrokes: () => any[];
  getCurrentStroke: () => any | null;
  startStroke: (worldX: number, worldY: number, pressure?: number) => boolean;
  addPoint: (worldX: number, worldY: number, pressure?: number) => boolean;
  endStroke: () => boolean;
  cancelStroke: () => void;
  applyBrushPreset: (preset: BrushPreset) => void;
}

export interface PaintEvents {
  onStrokeStarted?: () => void;
  onStrokeUpdated?: () => void;
  onStrokeCompleted?: () => void;
  onStrokeCancelled?: () => void;
  onStrokeUndone?: () => void;
  onCanvasCleared?: () => void;
}

export function usePaintSystem(
  renderEngine: any,
  events?: PaintEvents
): [PaintState, PaintControls] {
  const { activeTableId } = useGameStore();
  
  const [paintState, setPaintState] = useState<PaintState>({
    isActive: false,
    isDrawing: false,
    strokeCount: 0,
    brushColor: [1.0, 1.0, 1.0, 1.0], // White
    brushWidth: 3.0,
    blendMode: 'alpha',
    canUndo: false,
    canRedo: false,
  });

  const eventsRef = useRef(events);
  eventsRef.current = events;

  // Sync active table with paint system
  useEffect(() => {
    if (!renderEngine || !activeTableId) return;
    
    if (typeof renderEngine.paint_set_current_table === 'function') {
      renderEngine.paint_set_current_table(activeTableId);
      console.log(`Paint system switched to table: ${activeTableId}`);
    } else {
      console.debug('Render engine missing paint_set_current_table()');
    }
  }, [renderEngine, activeTableId]);

  // Setup event listeners - DISABLED: paint_on_event function not working
  useEffect(() => {
    if (!renderEngine) return;

    // Event system disabled due to WASM function issues
    // Would register paint event handlers here
    
    return () => {
      // Cleanup would happen here if WASM supported removing event listeners
    };
  }, [renderEngine]);

  // Update state from engine
  useEffect(() => {
    if (!renderEngine) return;

    const updateState = () => {
      try {
        const isActive = typeof renderEngine.paint_is_mode === 'function' ? renderEngine.paint_is_mode() : false;
        const isDrawing = typeof renderEngine.paint_is_drawing === 'function' ? renderEngine.paint_is_drawing() : false;
        const strokeCount = typeof renderEngine.paint_get_stroke_count === 'function' ? renderEngine.paint_get_stroke_count() : 0;
        const brushColor = typeof renderEngine.paint_get_brush_color === 'function' ? renderEngine.paint_get_brush_color() : [1.0, 1.0, 1.0, 1.0];
        const brushWidth = typeof renderEngine.paint_get_brush_width === 'function' ? renderEngine.paint_get_brush_width() : 3.0;
        const canUndo = typeof renderEngine.can_undo === 'function' ? renderEngine.can_undo() : false;
        const canRedo = typeof renderEngine.can_redo === 'function' ? renderEngine.can_redo() : false;

        setPaintState(prev => ({
          ...prev,
          isActive,
          isDrawing,
          strokeCount,
          brushColor,
          brushWidth,
          canUndo,
          canRedo,
        }));
      } catch (error) {
        // Log but avoid spamming stack traces for missing/mocked engines
        const msg = error instanceof Error ? error.message : String(error);
        console.debug('Error updating paint state (non-fatal):', msg);
      }
    };

    const interval = setInterval(updateState, 100); // Update every 100ms
    updateState(); // Initial update

    return () => clearInterval(interval);
  }, [renderEngine]);

  const enterPaintMode = useCallback((width = 800, height = 600) => {
    if (!renderEngine) return;
    if (typeof renderEngine.paint_enter_mode === 'function') {
      renderEngine.paint_enter_mode(width, height);
    } else {
      console.debug('Render engine missing paint_enter_mode()');
    }
    setPaintState(prev => ({ ...prev, isActive: true }));
  }, [renderEngine]);

  const exitPaintMode = useCallback(() => {
    if (!renderEngine) return;
    if (typeof renderEngine.paint_exit_mode === 'function') {
      renderEngine.paint_exit_mode();
    } else {
      console.debug('Render engine missing paint_exit_mode()');
    }
    setPaintState(prev => ({ 
      ...prev, 
      isActive: false, 
      isDrawing: false 
    }));
  }, [renderEngine]);

  const setBrushColor = useCallback((r: number, g: number, b: number, a = 1.0) => {
    if (!renderEngine) return;
    if (typeof renderEngine.paint_set_brush_color === 'function') {
      renderEngine.paint_set_brush_color(r, g, b, a);
    } else {
      console.debug('Render engine missing paint_set_brush_color()');
    }
    setPaintState(prev => ({ ...prev, brushColor: [r, g, b, a] }));
  }, [renderEngine]);

  const setBrushWidth = useCallback((width: number) => {
    if (!renderEngine) return;
    if (typeof renderEngine.paint_set_brush_width === 'function') {
      renderEngine.paint_set_brush_width(width);
    } else {
      console.debug('Render engine missing paint_set_brush_width()');
    }
    setPaintState(prev => ({ ...prev, brushWidth: width }));
  }, [renderEngine]);

  const setBlendMode = useCallback((mode: 'alpha' | 'additive' | 'modulate' | 'multiply') => {
    if (!renderEngine) return;
    if (typeof renderEngine.paint_set_blend_mode === 'function') {
      renderEngine.paint_set_blend_mode(mode);
    } else {
      console.debug('Render engine missing paint_set_blend_mode()');
    }
    setPaintState(prev => ({ ...prev, blendMode: mode }));
  }, [renderEngine]);

  const clearAll = useCallback(() => {
    if (!renderEngine) return;
    if (typeof renderEngine.paint_clear_all === 'function') {
      renderEngine.paint_clear_all();
    } else {
      console.debug('Render engine missing paint_clear_all()');
    }
  }, [renderEngine]);

  const undoStroke = useCallback(() => {
    if (!renderEngine) return;
    if (typeof renderEngine.paint_undo_stroke === 'function') {
      return renderEngine.paint_undo_stroke();
    }
    console.debug('Render engine missing paint_undo_stroke()');
    return false;
  }, [renderEngine]);

  const redoStroke = useCallback(() => {
    if (!renderEngine) return false;
    if (typeof renderEngine.redo_last_stroke === 'function') {
      return renderEngine.redo_last_stroke();
    }
    console.debug('Render engine missing redo_last_stroke()');
    return false;
  }, [renderEngine]);

  const getStrokes = useCallback(() => {
    if (!renderEngine) return [];
    try {
      const strokesJson = typeof renderEngine.paint_get_strokes === 'function' ? renderEngine.paint_get_strokes() : [];
      return strokesJson ? JSON.parse(JSON.stringify(strokesJson)) : [];
    } catch (error) {
      const msg = error instanceof Error ? error.message : String(error);
      console.debug('Error getting strokes (non-fatal):', msg);
      return [];
    }
  }, [renderEngine]);

  const getCurrentStroke = useCallback(() => {
    if (!renderEngine) return null;
    try {
      const strokeJson = typeof renderEngine.paint_get_current_stroke === 'function' ? renderEngine.paint_get_current_stroke() : null;
      return strokeJson ? JSON.parse(JSON.stringify(strokeJson)) : null;
    } catch (error) {
      const msg = error instanceof Error ? error.message : String(error);
      console.debug('Error getting current stroke (non-fatal):', msg);
      return null;
    }
  }, [renderEngine]);

  const startStroke = useCallback((worldX: number, worldY: number, pressure = 1.0) => {
    if (!renderEngine) return false;
    if (typeof renderEngine.paint_start_stroke === 'function') {
      return renderEngine.paint_start_stroke(worldX, worldY, pressure);
    }
    console.debug('Render engine missing paint_start_stroke()');
    return false;
  }, [renderEngine]);

  const addPoint = useCallback((worldX: number, worldY: number, pressure = 1.0) => {
    if (!renderEngine) return false;
    if (typeof renderEngine.paint_add_point === 'function') {
      return renderEngine.paint_add_point(worldX, worldY, pressure);
    }
    console.debug('Render engine missing paint_add_point()');
    return false;
  }, [renderEngine]);

  const endStroke = useCallback(() => {
    if (!renderEngine) return false;
    if (typeof renderEngine.paint_end_stroke === 'function') {
      return renderEngine.paint_end_stroke();
    }
    console.debug('Render engine missing paint_end_stroke()');
    return false;
  }, [renderEngine]);

  const cancelStroke = useCallback(() => {
    if (!renderEngine) return;
    if (typeof renderEngine.paint_cancel_stroke === 'function') {
      renderEngine.paint_cancel_stroke();
    } else {
      console.debug('Render engine missing paint_cancel_stroke()');
    }
  }, [renderEngine]);

  const applyBrushPreset = useCallback((preset: BrushPreset) => {
    if (!renderEngine) return;
    if (typeof preset.apply_to_paint_system === 'function') {
      preset.apply_to_paint_system(renderEngine);
    } else {
      console.debug('Brush preset missing apply_to_paint_system()');
    }
    
    // Update local state (guarded reads)
    const brushColor = typeof renderEngine.paint_get_brush_color === 'function' ? renderEngine.paint_get_brush_color() : [1.0, 1.0, 1.0, 1.0];
    const brushWidth = typeof renderEngine.paint_get_brush_width === 'function' ? renderEngine.paint_get_brush_width() : 3.0;
    setPaintState(prev => ({ 
      ...prev, 
      brushColor, 
      brushWidth,
      // Note: blend mode would need to be tracked separately or queried
    }));
  }, [renderEngine]);

  const controls: PaintControls = {
    enterPaintMode,
    exitPaintMode,
    setBrushColor,
    setBrushWidth,
    setBlendMode,
    clearAll,
    undoStroke,
    redoStroke,
    getStrokes,
    getCurrentStroke,
    startStroke,
    addPoint,
    endStroke,
    cancelStroke,
    applyBrushPreset,
  };

  return [paintState, controls];
}

// Utility hook for mouse-based painting interaction
export function usePaintInteraction(
  renderEngine: any,
  paintControls: PaintControls,
  paintState: PaintState
) {
  const [isMouseDown, setIsMouseDown] = useState(false);
  const [isDragging, setIsDragging] = useState(false);

  const handleMouseDown = useCallback((event: React.MouseEvent, canvasElement: HTMLCanvasElement) => {
    if (!paintState.isActive || !renderEngine) return;

    const rect = canvasElement.getBoundingClientRect();
    const canvasX = event.clientX - rect.left;
    const canvasY = event.clientY - rect.top;
    
    const [worldX, worldY] = renderEngine.screen_to_world(canvasX, canvasY);
    
    setIsMouseDown(true);
    setIsDragging(false);
    
    // Start stroke
    paintControls.startStroke(worldX, worldY, 1.0);
  }, [paintState.isActive, renderEngine, paintControls]);

  const handleMouseMove = useCallback((event: React.MouseEvent, canvasElement: HTMLCanvasElement) => {
    if (!paintState.isActive || !isMouseDown || !renderEngine) return;

    const rect = canvasElement.getBoundingClientRect();
    const canvasX = event.clientX - rect.left;
    const canvasY = event.clientY - rect.top;
    
    const [worldX, worldY] = renderEngine.screen_to_world(canvasX, canvasY);
    
    setIsDragging(true);
    
    // Add point to stroke
    paintControls.addPoint(worldX, worldY, 1.0);
  }, [paintState.isActive, isMouseDown, renderEngine, paintControls]);

  const handleMouseUp = useCallback(() => {
    if (!paintState.isActive || !isMouseDown) return;

    setIsMouseDown(false);
    
    if (isDragging) {
      // Complete stroke
      paintControls.endStroke();
    } else {
      // Single click - cancel stroke
      paintControls.cancelStroke();
    }
    
    setIsDragging(false);
  }, [paintState.isActive, isMouseDown, isDragging, paintControls]);

  const handleMouseLeave = useCallback(() => {
    if (isMouseDown) {
      paintControls.cancelStroke();
      setIsMouseDown(false);
      setIsDragging(false);
    }
  }, [isMouseDown, paintControls]);

  return {
    handleMouseDown,
    handleMouseMove,
    handleMouseUp,
    handleMouseLeave,
    isMouseDown,
    isDragging,
  };
}

// Brush presets utility
export function useBrushPresets() {
  const [presets, setPresets] = useState<BrushPreset[]>([]);

  useEffect(() => {
    const loadPresets = async () => {
      try {
        const wasmModule = window.ttrpg_rust_core;
        if (wasmModule && typeof wasmModule.create_default_brush_presets === 'function') {
          const defaultPresets = wasmModule.create_default_brush_presets();
          setPresets(defaultPresets as BrushPreset[]);
        }
      } catch (error) {
        console.error('Error loading brush presets:', error);
      }
    };

    loadPresets();
  }, []);

  return presets;
}

/**
 * Paint Template Service
 * Handles saving and loading paint stroke templates
 */

export interface PaintTemplate {
  id: string;
  name: string;
  description?: string;
  strokes: any[]; // Stroke data from WASM
  thumbnail?: string; // Base64 image
  created: string;
  updated: string;
}

export interface TemplateMetadata {
  id: string;
  name: string;
  description?: string;
  thumbnail?: string;
  created: string;
  updated: string;
  strokeCount: number;
}

class PaintTemplateService {
  private readonly STORAGE_KEY = 'paint_templates';
  private templates: Map<string, PaintTemplate> = new Map();

  constructor() {
    this.loadTemplatesFromStorage();
  }

  /**
   * Save current paint strokes as a template
   */
  async saveTemplate(
    name: string,
    strokes: any[],
    description?: string,
    thumbnail?: string
  ): Promise<string> {
    const id = `template_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
    const now = new Date().toISOString();
    
    const template: PaintTemplate = {
      id,
      name: name.trim(),
      description: description?.trim(),
      strokes: JSON.parse(JSON.stringify(strokes)), // Deep clone
      thumbnail,
      created: now,
      updated: now,
    };

    this.templates.set(id, template);
    await this.saveTemplatesToStorage();
    
    console.log(`[PaintTemplateService] Saved template: ${name} (${strokes.length} strokes)`);
    return id;
  }

  /**
   * Load template by ID
   */
  getTemplate(id: string): PaintTemplate | null {
    return this.templates.get(id) || null;
  }

  /**
   * Get all template metadata (without stroke data for performance)
   */
  getAllTemplateMetadata(): TemplateMetadata[] {
    return Array.from(this.templates.values()).map(template => ({
      id: template.id,
      name: template.name,
      description: template.description,
      thumbnail: template.thumbnail,
      created: template.created,
      updated: template.updated,
      strokeCount: template.strokes.length,
    }));
  }

  /**
   * Delete template
   */
  async deleteTemplate(id: string): Promise<boolean> {
    const deleted = this.templates.delete(id);
    if (deleted) {
      await this.saveTemplatesToStorage();
      console.log(`[PaintTemplateService] Deleted template: ${id}`);
    }
    return deleted;
  }

  /**
   * Update template metadata
   */
  async updateTemplate(
    id: string,
    updates: Partial<Pick<PaintTemplate, 'name' | 'description' | 'thumbnail'>>
  ): Promise<boolean> {
    const template = this.templates.get(id);
    if (!template) return false;

    const updatedTemplate = {
      ...template,
      ...updates,
      updated: new Date().toISOString(),
    };

    this.templates.set(id, updatedTemplate);
    await this.saveTemplatesToStorage();
    
    console.log(`[PaintTemplateService] Updated template: ${id}`);
    return true;
  }

  /**
   * Generate thumbnail from canvas
   */
  generateThumbnail(canvas: HTMLCanvasElement, maxSize = 64): string {
    try {
      const tempCanvas = document.createElement('canvas');
      const ctx = tempCanvas.getContext('2d');
      if (!ctx) return '';

      // Set thumbnail dimensions while maintaining aspect ratio
      const aspectRatio = canvas.width / canvas.height;
      if (aspectRatio > 1) {
        tempCanvas.width = maxSize;
        tempCanvas.height = maxSize / aspectRatio;
      } else {
        tempCanvas.width = maxSize * aspectRatio;
        tempCanvas.height = maxSize;
      }

      // Draw scaled canvas content
      ctx.drawImage(canvas, 0, 0, tempCanvas.width, tempCanvas.height);
      
      return tempCanvas.toDataURL('image/png', 0.8);
    } catch (error) {
      console.error('[PaintTemplateService] Failed to generate thumbnail:', error);
      return '';
    }
  }

  /**
   * Export templates for backup
   */
  exportTemplates(): string {
    const exportData = {
      version: '1.0',
      exported: new Date().toISOString(),
      templates: Array.from(this.templates.values()),
    };
    return JSON.stringify(exportData, null, 2);
  }

  /**
   * Import templates from backup
   */
  async importTemplates(jsonData: string): Promise<{ success: boolean; imported: number; errors: string[] }> {
    try {
      const data = JSON.parse(jsonData);
      const errors: string[] = [];
      let imported = 0;

      if (!data.templates || !Array.isArray(data.templates)) {
        return { success: false, imported: 0, errors: ['Invalid template data format'] };
      }

      for (const template of data.templates) {
        try {
          if (this.validateTemplate(template)) {
            // Generate new ID to avoid conflicts
            const newId = `template_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
            const importedTemplate = { ...template, id: newId };
            this.templates.set(newId, importedTemplate);
            imported++;
          } else {
            errors.push(`Invalid template: ${template.name || 'Unknown'}`);
          }
        } catch (error) {
          errors.push(`Failed to import template: ${template.name || 'Unknown'}`);
        }
      }

      await this.saveTemplatesToStorage();
      console.log(`[PaintTemplateService] Imported ${imported} templates with ${errors.length} errors`);
      
      return { success: imported > 0, imported, errors };
    } catch (error) {
      return { 
        success: false, 
        imported: 0, 
        errors: [`Failed to parse template data: ${error instanceof Error ? error.message : 'Unknown error'}`] 
      };
    }
  }

  private validateTemplate(template: any): boolean {
    return (
      template &&
      typeof template.id === 'string' &&
      typeof template.name === 'string' &&
      Array.isArray(template.strokes) &&
      typeof template.created === 'string' &&
      typeof template.updated === 'string'
    );
  }

  private loadTemplatesFromStorage(): void {
    try {
      const stored = localStorage.getItem(this.STORAGE_KEY);
      if (stored) {
        const data = JSON.parse(stored);
        if (Array.isArray(data)) {
          this.templates = new Map(data.map((template: PaintTemplate) => [template.id, template]));
          console.log(`[PaintTemplateService] Loaded ${this.templates.size} templates from storage`);
        }
      }
    } catch (error) {
      console.error('[PaintTemplateService] Failed to load templates from storage:', error);
      this.templates = new Map();
    }
  }

  private async saveTemplatesToStorage(): Promise<void> {
    try {
      const data = Array.from(this.templates.values());
      localStorage.setItem(this.STORAGE_KEY, JSON.stringify(data));
    } catch (error) {
      console.error('[PaintTemplateService] Failed to save templates to storage:', error);
    }
  }
}

