      render(<SessionManagementPanel sessionCode={sessionCode} />);

      expect(screen.getByText('Players: 2')).toBeInTheDocument();
    });

    it('indicates when game master can modify player settings', () => {
      mockSessionManagement.canManagePlayers = true;

      render(<SessionManagementPanel sessionCode={sessionCode} />);

      expect(screen.getByText('Can modify: yes')).toBeInTheDocument();
    });

    it('shows restricted view when game master lacks permissions', () => {
      mockSessionManagement.canManagePlayers = false;

      render(<SessionManagementPanel sessionCode={sessionCode} />);

      expect(screen.getByText('Can modify: no')).toBeInTheDocument();
    });

    it('collapses panel when close button is clicked', async () => {
      render(<SessionManagementPanel sessionCode={sessionCode} />);

      await user.click(screen.getByText('├Ч'));

      expect(mockSessionManagement.toggleExpanded).toHaveBeenCalledTimes(1);
    });
  });

  describe('Invitation management workflow', () => {
    it('shows invitation management when requested', () => {
      mockSessionManagement.showInvites = true;

      render(<SessionManagementPanel sessionCode={sessionCode} />);

      expect(screen.getByTestId('invitation-manager')).toBeInTheDocument();
      expect(screen.getByText(`Managing invites for: ${sessionCode}`)).toBeInTheDocument();
    });

    it('allows game master to open invitation manager', async () => {
      render(<SessionManagementPanel sessionCode={sessionCode} />);

      const inviteButton = screen.getByText('Manage Invitations');
      await user.click(inviteButton);

      expect(mockSessionManagement.toggleInvites).toHaveBeenCalledTimes(1);
    });

    it('closes invitation manager when requested', async () => {
      mockSessionManagement.showInvites = true;

      render(<SessionManagementPanel sessionCode={sessionCode} />);

      await user.click(screen.getByText('Close Invitations'));

      expect(mockSessionManagement.closeInvites).toHaveBeenCalledTimes(1);
    });

    it('overlays invitation manager over main panel', () => {
      mockSessionManagement.showInvites = true;

      render(<SessionManagementPanel sessionCode={sessionCode} />);

      // Both should be present - invitation manager as overlay
      expect(screen.getByTestId('player-list')).toBeInTheDocument();
      expect(screen.getByTestId('invitation-manager')).toBeInTheDocument();
    });
  });

  describe('Loading and error states', () => {
    it('shows loading indicator while data loads', () => {
      mockSessionManagement.loading = true;

      render(<SessionManagementPanel sessionCode={sessionCode} />);

      expect(screen.getByText('Loading session data...')).toBeInTheDocument();
      
      // Player list should not be shown when loading
      expect(screen.queryByTestId('player-list')).not.toBeInTheDocument();
    });

    it('displays error message when something goes wrong', () => {
      mockSessionManagement.error = 'Failed to connect to session server';

      render(<SessionManagementPanel sessionCode={sessionCode} />);

      expect(screen.getByText('Error: Failed to connect to session server')).toBeInTheDocument();
      expect(screen.getByText('Retry')).toBeInTheDocument();
    });

    it('allows retry when there is an error', async () => {
      mockSessionManagement.error = 'Connection timeout';

      render(<SessionManagementPanel sessionCode={sessionCode} />);

      await user.click(screen.getByText('Retry'));

      expect(mockSessionManagement.refetch).toHaveBeenCalledTimes(1);
    });

    it('shows when operations are in progress', () => {
      mockSessionManagement.changing = true;

      render(<SessionManagementPanel sessionCode={sessionCode} />);

      // Should indicate something is happening
      const managementPanel = screen.getByText('Session Management').closest('div')?.parentElement;
      expect(managementPanel).toHaveClass('changing');
    });
  });

  describe('Real-world usage scenarios', () => {
    it('handles game master workflow: expand, manage players, close', async () => {
      // Start collapsed
      mockSessionManagement.isExpanded = false;
      const { rerender } = render(<SessionManagementPanel sessionCode={sessionCode} />);

      // Expand panel
      await user.click(screen.getByText('Expand Management'));
      expect(mockSessionManagement.toggleExpanded).toHaveBeenCalled();

      // Simulate expansion
      mockSessionManagement.isExpanded = true;
      rerender(<SessionManagementPanel sessionCode={sessionCode} />);

      // Should now see player management
      expect(screen.getByTestId('player-list')).toBeInTheDocument();

      // Close panel
      await user.click(screen.getByText('├Ч'));
      expect(mockSessionManagement.toggleExpanded).toHaveBeenCalledTimes(2);
    });

    it('handles invitation workflow: open invites, manage, close', async () => {
      render(<SessionManagementPanel sessionCode={sessionCode} />);

      // Open invitations
      await user.click(screen.getByText('Manage Invitations'));
      expect(mockSessionManagement.toggleInvites).toHaveBeenCalled();

      // Simulate invitation panel opening
      mockSessionManagement.showInvites = true;
      const { rerender } = render(<SessionManagementPanel sessionCode={sessionCode} />);

      // Should see invitation manager
      expect(screen.getByTestId('invitation-manager')).toBeInTheDocument();

      // Close invitations
      await user.click(screen.getByText('Close Invitations'));
      expect(mockSessionManagement.closeInvites).toHaveBeenCalled();
    });

    it('adapts to different session states gracefully', () => {
      // Empty session
      mockSessionManagement.players = [];
      const { rerender } = render(<SessionManagementPanel sessionCode={sessionCode} />);

      expect(screen.getByText('Players: 0')).toBeInTheDocument();

      // Busy session
      mockSessionManagement.players = new Array(8).fill(0).map((_, i) => ({
        id: `player-${i}`,
        username: `Player ${i + 1}`,
        role: 'player'
      }));
      rerender(<SessionManagementPanel sessionCode={sessionCode} />);

      expect(screen.getByText('Players: 8')).toBeInTheDocument();
    });
  });

  describe('Component orchestration', () => {
    it('passes correct props to PlayerList component', () => {
      const testPlayers = [{ id: '1', username: 'Test', role: 'player' }];
      mockSessionManagement.players = testPlayers;
      mockSessionManagement.canManagePlayers = true;

      render(<SessionManagementPanel sessionCode={sessionCode} />);

      // PlayerList should receive the right data and permissions
      expect(screen.getByText('Players: 1')).toBeInTheDocument();
      expect(screen.getByText('Can modify: yes')).toBeInTheDocument();
    });

    it('passes sessionCode to all sub-components that need it', () => {
      mockSessionManagement.showInvites = true;
      
      render(<SessionManagementPanel sessionCode={sessionCode} />);

      // InvitationManager should receive sessionCode
      expect(screen.getByText(`Managing invites for: ${sessionCode}`)).toBeInTheDocument();
    });

    it('coordinates state between sub-components effectively', () => {
      render(<SessionManagementPanel sessionCode={sessionCode} />);

      // Main panel should show current state
      expect(screen.getByText('Session Management')).toBeInTheDocument();
      
      // Should not show invitation manager initially
      expect(screen.queryByTestId('invitation-manager')).not.toBeInTheDocument();
    });
  });

  describe('Accessibility and user experience', () => {
    it('maintains focus when switching between modes', async () => {
      render(<SessionManagementPanel sessionCode={sessionCode} />);

      const inviteButton = screen.getByText('Manage Invitations');
      inviteButton.focus();
      
      await user.click(inviteButton);

      // Focus should be managed appropriately
      expect(mockSessionManagement.toggleInvites).toHaveBeenCalled();
    });

    it('provides appropriate headings for screen readers', () => {
      render(<SessionManagementPanel sessionCode={sessionCode} />);

      expect(screen.getByRole('heading', { name: 'Session Management' })).toBeInTheDocument();
    });

    it('shows meaningful status messages', () => {
      mockSessionManagement.loading = true;
      const { rerender } = render(<SessionManagementPanel sessionCode={sessionCode} />);

      expect(screen.getByText('Loading session data...')).toBeInTheDocument();

      mockSessionManagement.loading = false;
      mockSessionManagement.error = 'Network error';
      rerender(<SessionManagementPanel sessionCode={sessionCode} />);

      expect(screen.getByText('Error: Network error')).toBeInTheDocument();
    });
  });
});

import { useInvitations } from '@features/session';
import { act, renderHook, waitFor } from '@testing-library/react';
import { beforeEach, describe, expect, it, vi } from 'vitest';
import { invitationService } from '../../services/invitation.service';
import type { SessionInvitation } from '../../types/invitations';

vi.mock('../../services/invitation.service', () => ({
  invitationService: {
    listSessionInvitations: vi.fn(),
    createInvitation: vi.fn(),
    revokeInvitation: vi.fn(),
    deleteInvitation: vi.fn(),
  },
}));

const mockInvitations: SessionInvitation[] = [
  {
    id: 1,
    invite_code: 'CODE1',
    session_code: 'TEST123',
    pre_assigned_role: 'player',
    created_at: new Date().toISOString(),
    expires_at: new Date(Date.now() + 24 * 60 * 60 * 1000).toISOString(),
    max_uses: 10,
    uses_count: 0,
    is_active: true,
    is_valid: true,
    invite_url: 'http://localhost/join/CODE1',
  },
  {
    id: 2,
    invite_code: 'CODE2',
    session_code: 'TEST123',
    pre_assigned_role: 'spectator',
    created_at: new Date().toISOString(),
    max_uses: 1,
    uses_count: 1,
    is_active: false,
    is_valid: false,
    invite_url: 'http://localhost/join/CODE2',
  },
];

describe('useInvitations', () => {
  const sessionCode = 'TEST123';

  beforeEach(() => {
    vi.clearAllMocks();
    vi.mocked(invitationService.listSessionInvitations).mockResolvedValue([...mockInvitations]);
    vi.mocked(invitationService.createInvitation).mockResolvedValue({ ...mockInvitations[0], id: 3 });
    vi.mocked(invitationService.revokeInvitation).mockResolvedValue(undefined as any);
    vi.mocked(invitationService.deleteInvitation).mockResolvedValue(undefined as any);
  });

  describe('Initialization', () => {
    it('starts with empty state before fetch completes', () => {
      vi.mocked(invitationService.listSessionInvitations).mockReturnValue(new Promise(() => {}));
      const { result } = renderHook(() => useInvitations(sessionCode));

      expect(result.current.invitations).toEqual([]);
      expect(result.current.error).toBeNull();
    });

    it('loads invitations on mount', async () => {
      const { result } = renderHook(() => useInvitations(sessionCode));

      await waitFor(() => {
        expect(result.current.invitations).toHaveLength(2);
      });

      expect(result.current.invitations[0].pre_assigned_role).toBe('player');
      expect(result.current.invitations[1].pre_assigned_role).toBe('spectator');
      expect(result.current.loading).toBe(false);
    });

    it('does not fetch when sessionCode is null', () => {
      renderHook(() => useInvitations(null));
      expect(invitationService.listSessionInvitations).not.toHaveBeenCalled();
    });

    it('sets error when fetch fails', async () => {
      vi.mocked(invitationService.listSessionInvitations).mockRejectedValueOnce(
        new Error('Network error')
      );
      const { result } = renderHook(() => useInvitations(sessionCode));

      await waitFor(() => {
        expect(result.current.error).toBe('Network error');
      });

      expect(result.current.invitations).toEqual([]);
      expect(result.current.loading).toBe(false);
    });
  });

  describe('createInvitation', () => {
    it('calls service with the provided data', async () => {
      const { result } = renderHook(() => useInvitations(sessionCode));
      await waitFor(() => expect(result.current.invitations).toHaveLength(2));

      const createData = { session_code: sessionCode, pre_assigned_role: 'player', max_uses: 5 };

      await act(async () => {
        await result.current.createInvitation(createData);
      });

      expect(invitationService.createInvitation).toHaveBeenCalledWith(createData);
    });

    it('refetches after creation', async () => {
      const { result } = renderHook(() => useInvitations(sessionCode));
      await waitFor(() => expect(result.current.invitations).toHaveLength(2));

      await act(async () => {
        await result.current.createInvitation({ session_code: sessionCode, pre_assigned_role: 'player', max_uses: 1 });
      });

      expect(invitationService.listSessionInvitations).toHaveBeenCalledTimes(2);
    });

    it('returns null and sets error on failure', async () => {
      vi.mocked(invitationService.createInvitation).mockRejectedValueOnce(new Error('Create failed'));
      const { result } = renderHook(() => useInvitations(sessionCode));

      let created: SessionInvitation | null = undefined as any;
      await act(async () => {
        created = await result.current.createInvitation({ session_code: sessionCode, pre_assigned_role: 'player', max_uses: 1 });
      });

      expect(created).toBeNull();
      expect(result.current.error).toBe('Create failed');
    });
  });

  describe('revokeInvitation', () => {
    it('calls service with invitation id', async () => {
      const { result } = renderHook(() => useInvitations(sessionCode));
      await waitFor(() => expect(result.current.invitations).toHaveLength(2));

      await act(async () => {
        await result.current.revokeInvitation(1);
      });

      expect(invitationService.revokeInvitation).toHaveBeenCalledWith(1);
    });

    it('refetches after revoke', async () => {
      const { result } = renderHook(() => useInvitations(sessionCode));
      await waitFor(() => expect(result.current.invitations).toHaveLength(2));

      await act(async () => {
        await result.current.revokeInvitation(1);
      });

      expect(invitationService.listSessionInvitations).toHaveBeenCalledTimes(2);
    });

    it('returns false and sets error on failure', async () => {
      vi.mocked(invitationService.revokeInvitation).mockRejectedValueOnce(new Error('Revoke failed'));
      const { result } = renderHook(() => useInvitations(sessionCode));

      let success = true;
      await act(async () => {
        success = await result.current.revokeInvitation(1);
      });

      expect(success).toBe(false);
      expect(result.current.error).toBe('Revoke failed');
    });
  });

  describe('deleteInvitation', () => {
    it('calls service with invitation id', async () => {
      const { result } = renderHook(() => useInvitations(sessionCode));
      await waitFor(() => expect(result.current.invitations).toHaveLength(2));

      await act(async () => {
        await result.current.deleteInvitation(2);
      });

      expect(invitationService.deleteInvitation).toHaveBeenCalledWith(2);
    });

    it('refetches after delete', async () => {
      const { result } = renderHook(() => useInvitations(sessionCode));
      await waitFor(() => expect(result.current.invitations).toHaveLength(2));

      await act(async () => {
        await result.current.deleteInvitation(2);
      });

      expect(invitationService.listSessionInvitations).toHaveBeenCalledTimes(2);
    });

    it('returns false and sets error on failure', async () => {
      vi.mocked(invitationService.deleteInvitation).mockRejectedValueOnce(new Error('Delete failed'));
      const { result } = renderHook(() => useInvitations(sessionCode));

      let success = true;
      await act(async () => {
        success = await result.current.deleteInvitation(2);
      });

      expect(success).toBe(false);
      expect(result.current.error).toBe('Delete failed');
    });
  });

  describe('refetch', () => {
    it('fetches invitations again when called manually', async () => {
      const { result } = renderHook(() => useInvitations(sessionCode));
      await waitFor(() => expect(result.current.invitations).toHaveLength(2));

      await act(async () => {
        await result.current.refetch();
      });

      expect(invitationService.listSessionInvitations).toHaveBeenCalledTimes(2);
    });
  });
});

import { useRoleManagement } from '@features/session';
import { act, renderHook } from '@testing-library/react';
import { beforeEach, describe, expect, it, vi } from 'vitest';

// Mock the session management service
vi.mock('@features/session/services/sessionManagement.service', () => ({
  sessionManagementService: {
    changePlayerRole: vi.fn(),
    kickPlayer: vi.fn()
  }
}));

describe('useRoleManagement', () => {
  const mockSessionCode = 'TEST123';

  beforeEach(() => {
    vi.clearAllMocks();
  });

  describe('Initialization', () => {
    it('initializes with default state', () => {
      const { result } = renderHook(() => useRoleManagement(mockSessionCode));

      expect(result.current.changing).toBe(false);
      expect(result.current.error).toBeNull();
      expect(typeof result.current.changeRole).toBe('function');
      expect(typeof result.current.kickPlayer).toBe('function');
    });

    it('handles null session code', () => {
      const { result } = renderHook(() => useRoleManagement(null));

      expect(result.current.changing).toBe(false);
      expect(result.current.error).toBeNull();
    });
  });

  describe('changeRole', () => {
    it('changes player role successfully', async () => {
      const { sessionManagementService } = await import('@features/session/services/sessionManagement.service');
      vi.mocked(sessionManagementService.changePlayerRole).mockResolvedValue({
        success: true,
        message: 'Role changed',
        new_role: 'trusted_player'
      });

      const { result } = renderHook(() => useRoleManagement(mockSessionCode));

      let response: any;
      await act(async () => {
        response = await result.current.changeRole(101, 'trusted_player');
      });

      expect(response).toEqual({
        success: true,
        message: 'Role changed',
        new_role: 'trusted_player'
      });
      expect(result.current.changing).toBe(false);
      expect(result.current.error).toBeNull();
    });

    it('sets changing state during role change', async () => {
      const { sessionManagementService } = await import('@features/session/services/sessionManagement.service');
      let resolveChange: any;
      const changePromise = new Promise(resolve => {
        resolveChange = resolve;
      });
      vi.mocked(sessionManagementService.changePlayerRole).mockReturnValue(changePromise as any);

      const { result } = renderHook(() => useRoleManagement(mockSessionCode));

      // Start change
      act(() => {
        result.current.changeRole(101, 'co_dm');
      });

      // Should be changing
      expect(result.current.changing).toBe(true);

      // Complete change
      await act(async () => {
        resolveChange({ success: true, message: 'Done', new_role: 'co_dm' });
        await changePromise;
      });

      expect(result.current.changing).toBe(false);
    });

    it('handles role change error', async () => {
      const { sessionManagementService } = await import('@features/session/services/sessionManagement.service');
      vi.mocked(sessionManagementService.changePlayerRole).mockRejectedValue(
        new Error('Permission denied')
      );

      const { result } = renderHook(() => useRoleManagement(mockSessionCode));

      let response: any;
      await act(async () => {
        response = await result.current.changeRole(101, 'owner');
      });

      expect(response).toBeNull();
      expect(result.current.error).toBe('Permission denied');
      expect(result.current.changing).toBe(false);
    });

    it('returns null when session code is null', async () => {
      const { result } = renderHook(() => useRoleManagement(null));

      let response: any;
      await act(async () => {
        response = await result.current.changeRole(101, 'player');
      });

      expect(response).toBeNull();
    });

    it('clears previous error on successful change', async () => {
      const { sessionManagementService } = await import('@features/session/services/sessionManagement.service');
      
      // First call fails
      vi.mocked(sessionManagementService.changePlayerRole).mockRejectedValueOnce(
        new Error('First error')
      );

      const { result } = renderHook(() => useRoleManagement(mockSessionCode));

      await act(async () => {
        await result.current.changeRole(101, 'player');
      });

      expect(result.current.error).toBe('First error');

      // Second call succeeds
      vi.mocked(sessionManagementService.changePlayerRole).mockResolvedValueOnce({
        success: true,
        message: 'Success',
        new_role: 'trusted_player'
      });

      await act(async () => {
        await result.current.changeRole(101, 'trusted_player');
      });

      expect(result.current.error).toBeNull();
    });
  });

  describe('kickPlayer', () => {
    it('kicks player successfully', async () => {
      const { sessionManagementService } = await import('@features/session/services/sessionManagement.service');
      vi.mocked(sessionManagementService.kickPlayer).mockResolvedValue(undefined);

      const { result } = renderHook(() => useRoleManagement(mockSessionCode));

      let response: boolean;
      await act(async () => {
        response = await result.current.kickPlayer(101);
      });

      expect(response!).toBe(true);
      expect(sessionManagementService.kickPlayer).toHaveBeenCalledWith(mockSessionCode, 101);
      expect(result.current.changing).toBe(false);
      expect(result.current.error).toBeNull();
    });

    it('sets changing state during kick', async () => {
      const { sessionManagementService } = await import('@features/session/services/sessionManagement.service');
      let resolveKick: any;
      const kickPromise = new Promise(resolve => {
        resolveKick = resolve;
      });
      vi.mocked(sessionManagementService.kickPlayer).mockReturnValue(kickPromise as any);

      const { result } = renderHook(() => useRoleManagement(mockSessionCode));

      // Start kick
      act(() => {
        result.current.kickPlayer(101);
      });

      // Should be changing
      expect(result.current.changing).toBe(true);

      // Complete kick
      await act(async () => {
        resolveKick(undefined);
        await kickPromise;
      });

      expect(result.current.changing).toBe(false);
    });

    it('handles kick error', async () => {
      const { sessionManagementService } = await import('@features/session/services/sessionManagement.service');
      vi.mocked(sessionManagementService.kickPlayer).mockRejectedValue(
        new Error('Cannot kick owner')
      );

      const { result } = renderHook(() => useRoleManagement(mockSessionCode));

      let response: boolean;
      await act(async () => {
        response = await result.current.kickPlayer(999);
      });

      expect(response!).toBe(false);
      expect(result.current.error).toBe('Cannot kick owner');
      expect(result.current.changing).toBe(false);
    });

    it('returns false when session code is null', async () => {
      const { result } = renderHook(() => useRoleManagement(null));

      let response: boolean;
      await act(async () => {
        response = await result.current.kickPlayer(101);
      });

      expect(response!).toBe(false);
    });

    it('handles generic error without message', async () => {
      const { sessionManagementService } = await import('@features/session/services/sessionManagement.service');
      vi.mocked(sessionManagementService.kickPlayer).mockRejectedValue('Unknown error');

      const { result } = renderHook(() => useRoleManagement(mockSessionCode));

      await act(async () => {
        await result.current.kickPlayer(101);
      });

      expect(result.current.error).toBe('Failed to kick player');
    });
  });

  describe('Error Handling', () => {
    it('handles network errors gracefully', async () => {
      const { sessionManagementService } = await import('@features/session/services/sessionManagement.service');
      vi.mocked(sessionManagementService.changePlayerRole).mockRejectedValue(
        new Error('Network error: timeout')
      );

      const { result } = renderHook(() => useRoleManagement(mockSessionCode));

      await act(async () => {
        await result.current.changeRole(101, 'player');
      });

      expect(result.current.error).toBe('Network error: timeout');
    });

    it('handles generic errors with fallback message for role change', async () => {
      const { sessionManagementService } = await import('@features/session/services/sessionManagement.service');
      vi.mocked(sessionManagementService.changePlayerRole).mockRejectedValue('Generic error');

      const { result } = renderHook(() => useRoleManagement(mockSessionCode));

      await act(async () => {
        await result.current.changeRole(101, 'player');
      });

      expect(result.current.error).toBe('Failed to change role');
    });
  });
});

import { useSessionManagement } from '@features/session';
import { act, renderHook, waitFor } from '@testing-library/react';
import { beforeEach, describe, expect, it, vi } from 'vitest';

// vi.hoisted ensures these refs are available when vi.mock factories run
const mockSessionService = vi.hoisted(() => ({
  updateSessionSettings: vi.fn(),
  getSessionStats: vi.fn(),
  deleteSession: vi.fn(),
  getAuditLog: vi.fn(),
  transferOwnership: vi.fn()
}));

vi.mock('../../services/sessionManagement.service', () => ({
  sessionManagementService: mockSessionService
}));

// Mock protocol for real-time communication
const mockProtocol = vi.hoisted(() => ({
  sendEvent: vi.fn(),
