import { useEffect, useState } from 'react';
import { invitationService } from '../services/invitation.service';
import type { CreateInvitationRequest, SessionInvitation } from '../types/invitations';

export const useInvitations = (sessionCode: string | null) => {
  const [invitations, setInvitations] = useState<SessionInvitation[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const fetchInvitations = async () => {
    if (!sessionCode) return;

    setLoading(true);
    setError(null);

    try {
      const data = await invitationService.listSessionInvitations(sessionCode);
      setInvitations(data);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to fetch invitations');
    } finally {
      setLoading(false);
    }
  };

  const createInvitation = async (data: CreateInvitationRequest): Promise<SessionInvitation | null> => {
    setLoading(true);
    setError(null);

    try {
      const result = await invitationService.createInvitation(data);
      await fetchInvitations();
      return result;
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to create invitation');
      return null;
    } finally {
      setLoading(false);
    }
  };

  const revokeInvitation = async (invitationId: number): Promise<boolean> => {
    setLoading(true);
    setError(null);

    try {
      await invitationService.revokeInvitation(invitationId);
      await fetchInvitations();
      return true;
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to revoke invitation');
      return false;
    } finally {
      setLoading(false);
    }
  };

  const deleteInvitation = async (invitationId: number): Promise<boolean> => {
    setLoading(true);
    setError(null);

    try {
      await invitationService.deleteInvitation(invitationId);
      await fetchInvitations();
      return true;
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to delete invitation');
      return false;
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchInvitations();
  }, [sessionCode]);

  return { invitations, loading, error, createInvitation, revokeInvitation, deleteInvitation, refetch: fetchInvitations };
};

/**
 * Session Management Hook
 * Main hook for SessionManagementPanel following the refactoring pattern
 */

import { useAuth, useProtocol } from '@app/providers';
import { useEffect, useState } from 'react';
import { toast } from 'react-toastify';
import type { SessionPlayer, SessionRole } from '../types/roles';
import { useRoleManagement } from './useRoleManagement';
import { useSessionPlayers } from './useSessionPlayers';

export const useSessionManagement = (sessionCode: string) => {
  const { user } = useAuth();
  const { protocol } = useProtocol();
  const { players, loading, error, refetch } = useSessionPlayers(sessionCode);
  const { changeRole, kickPlayer, changing } = useRoleManagement(sessionCode);

  // UI State
  const [isExpanded, setIsExpanded] = useState(false);
  const [showInvites, setShowInvites] = useState(false);

  // Derived state
  const currentPlayer = players.find(p => p.user_id === user?.id);
  const isOwner = currentPlayer?.role === 'owner';
  const canManagePlayers = currentPlayer?.permissions.includes('change_roles') || isOwner;

  // Protocol event handling
  useEffect(() => {
    if (!protocol) return;

    const handlePlayerEvent = (message: any) => {
      const eventType = message.data?.event;
      if (eventType === 'PLAYER_JOINED' ||
          eventType === 'PLAYER_ROLE_CHANGED' ||
          eventType === 'PLAYER_KICKED') {
        refetch();
      }
    };

    protocol.registerHandler('CUSTOM', handlePlayerEvent);

    return () => {
      protocol.unregisterHandler('CUSTOM');
    };
  }, [protocol, refetch]);

  const handleRoleChange = async (targetPlayer: SessionPlayer, newRole: SessionRole) => {
    if (!canManagePlayers) return false;

    const result = await changeRole(targetPlayer.user_id, newRole);
    if (result) {
      toast.success(`Changed ${targetPlayer.username}'s role to ${newRole}`);
      refetch();
      return true;
    }
    return false;
  };

  const handleKick = async (targetPlayer: SessionPlayer) => {
    if (!canManagePlayers) return false;
    if (!confirm(`Kick ${targetPlayer.username}?`)) return false;

    const success = await kickPlayer(targetPlayer.user_id);
    if (success) {
      toast.success(`${targetPlayer.username} kicked`);
      refetch();
      return true;
    }
    return false;
  };

  const toggleExpanded = () => setIsExpanded(!isExpanded);
  const toggleInvites = () => setShowInvites(true);
  const closeInvites = () => setShowInvites(false);

  return {
    // State
    players,
    loading,
    error,
    isExpanded,
    showInvites,
    changing,
    
    // Permissions
    currentPlayer,
    canManagePlayers,
    
    // Actions
    handleRoleChange,
    handleKick,
    toggleExpanded,
    toggleInvites,
    closeInvites,
    refetch
  };
};

import { useEffect, useState } from 'react';
import { sessionManagementService } from '../services/sessionManagement.service';
import type { SessionPlayer } from '../types';

export const useSessionPlayers = (sessionCode: string | null) => {
  const [players, setPlayers] = useState<SessionPlayer[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const fetchPlayers = async () => {
    if (!sessionCode) return;

    setLoading(true);
    setError(null);

    try {
      const data = await sessionManagementService.getPlayers(sessionCode);
      setPlayers(data);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to fetch players');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchPlayers();
  }, [sessionCode]);

  return { players, loading, error, refetch: fetchPlayers };
};

import type { UserInfo } from '@features/auth';

export interface SessionInfo {
  id: string;
  code: string;
  hostUserId: string;
  name: string;
  isActive: boolean;
  participants: UserInfo[];
  createdAt: Date;
  lastActivity: Date;
}

export interface SessionCreateOptions {
  name: string;
  isPublic?: boolean;
  maxParticipants?: number;
}

export interface SessionJoinOptions {
  code: string;
  userInfo: UserInfo;
}

export class SessionManager {
  private currentSession: SessionInfo | null = null;
  private websocket: WebSocket | null = null;
  private reconnectAttempts = 0;
  private maxReconnectAttempts = 5;
  private reconnectDelay = 1000;
  private heartbeatInterval: ReturnType<typeof setInterval> | null = null;
  private eventListeners: Map<string, Function[]> = new Map();
  private baseUrl: string;

  constructor(baseUrl: string = typeof window !== 'undefined' 
    ? `ws://${window.location.hostname}:${window.location.port}/ws`
    : 'ws://localhost:12345/ws') {
    this.baseUrl = baseUrl;
  }

  /**
   * Create a new session with unique code
   */
  async createSession(options: SessionCreateOptions, hostUser: UserInfo): Promise<SessionInfo> {
    const sessionCode = this.generateSessionCode();
    const session: SessionInfo = {
      id: crypto.randomUUID(),
      code: sessionCode,
      hostUserId: hostUser.id.toString(),
      name: options.name,
      isActive: true,
      participants: [hostUser],
      createdAt: new Date(),
      lastActivity: new Date()
    };

    this.currentSession = session;
    await this.connectWebSocket(session.code, hostUser);
    this.emit('sessionCreated', session);
    
    return session;
  }

  /**
   * Join existing session with code validation
   */
  async joinSession(options: SessionJoinOptions): Promise<SessionInfo> {
    if (!this.validateSessionCode(options.code)) {
      throw new Error('Invalid session code format');
    }

    await this.connectWebSocket(options.code, options.userInfo);
    
    // Send join request and wait for response
    return new Promise((resolve, reject) => {
      const timeoutId = setTimeout(() => {
        reject(new Error('Session join timeout'));
      }, 10000);

      this.once('sessionJoined', (session: SessionInfo) => {
        clearTimeout(timeoutId);
        this.currentSession = session;
        resolve(session);
      });

      this.once('sessionJoinError', (error: string) => {
        clearTimeout(timeoutId);
        reject(new Error(error));
      });

      this.sendMessage('join_session', {
        code: options.code,
        userInfo: options.userInfo
      });
    });
  }

  /**
   * Leave current session
   */
  async leaveSession(): Promise<void> {
    if (this.currentSession) {
      this.sendMessage('leave_session', { sessionId: this.currentSession.id });
      this.emit('sessionLeft', this.currentSession);
      this.currentSession = null;
    }
    this.disconnectWebSocket();
  }

  /**
   * Get current session info
   */
  getCurrentSession(): SessionInfo | null {
    return this.currentSession;
  }

  /**
   * Send real-time message to session participants
   */
  sendMessage(type: string, data: any): void {
    if (this.websocket && this.websocket.readyState === WebSocket.OPEN) {
      this.websocket.send(JSON.stringify({ type, data, timestamp: Date.now() }));
    } else {
      console.warn('WebSocket not connected, message not sent:', type, data);
    }
  }

  /**
   * Broadcast token movement to all participants
   */
  broadcastTokenMovement(tokenId: string, position: { x: number; y: number }): void {
    this.sendMessage('token_movement', {
      tokenId,
      position,
      userId: this.getCurrentUserId()
    });
  }

  /**
   * Broadcast dice roll result
   */
  broadcastDiceRoll(result: any): void {
    this.sendMessage('dice_roll', {
      result,
      userId: this.getCurrentUserId(),
      timestamp: Date.now()
    });
  }

  /**
   * Send chat message
   */
  sendChatMessage(message: string): void {
    this.sendMessage('chat_message', {
      message,
      userId: this.getCurrentUserId(),
      timestamp: Date.now()
    });
  }

  /**
   * Event listener management
   */
  on(event: string, callback: Function): void {
    if (!this.eventListeners.has(event)) {
      this.eventListeners.set(event, []);
    }
    this.eventListeners.get(event)!.push(callback);
  }

  once(event: string, callback: Function): void {
    const wrappedCallback = (...args: any[]) => {
      this.off(event, wrappedCallback);
      callback(...args);
    };
    this.on(event, wrappedCallback);
  }

  off(event: string, callback: Function): void {
    const listeners = this.eventListeners.get(event);
    if (listeners) {
      const index = listeners.indexOf(callback);
      if (index > -1) {
        listeners.splice(index, 1);
      }
    }
  }

  private emit(event: string, ...args: any[]): void {
    const listeners = this.eventListeners.get(event);
    if (listeners) {
      listeners.forEach(callback => callback(...args));
    }
  }

  /**
   * WebSocket connection management
   */
  private async connectWebSocket(sessionCode: string, userInfo: UserInfo): Promise<void> {
    return new Promise((resolve, reject) => {
      const wsUrl = `${this.baseUrl}/session/${sessionCode}?userId=${userInfo.id}&username=${encodeURIComponent(userInfo.username)}`;
      
      this.websocket = new WebSocket(wsUrl);
      
      this.websocket.onopen = () => {
        console.log('WebSocket connected to session:', sessionCode);
        this.reconnectAttempts = 0;
        this.startHeartbeat();
        resolve();
      };

      this.websocket.onmessage = (event) => {
        try {
          const message = JSON.parse(event.data);
          this.handleWebSocketMessage(message);
        } catch (error) {
          console.error('Failed to parse WebSocket message:', error);
        }
      };

      this.websocket.onclose = (event) => {
        console.log('WebSocket disconnected:', event.code, event.reason);
        this.stopHeartbeat();
        
        if (!event.wasClean && this.reconnectAttempts < this.maxReconnectAttempts) {
          this.attemptReconnect(sessionCode, userInfo);
        }
        
        this.emit('connectionClosed', event);
      };

      this.websocket.onerror = (error) => {
        console.error('WebSocket error:', error);
        this.emit('connectionError', error);
        reject(error);
      };

      // Connection timeout
      setTimeout(() => {
        if (this.websocket?.readyState !== WebSocket.OPEN) {
          reject(new Error('WebSocket connection timeout'));
        }
      }, 10000);
    });
  }

  private disconnectWebSocket(): void {
    this.stopHeartbeat();
    if (this.websocket) {
      this.websocket.close(1000, 'Session ended');
      this.websocket = null;
    }
  }

  private handleWebSocketMessage(message: any): void {
    const { type, data } = message;
    
    switch (type) {
      case 'session_joined':
        this.emit('sessionJoined', data.session);
        break;
      case 'session_join_error':
        this.emit('sessionJoinError', data.error);
        break;
      case 'participant_joined':
        this.emit('participantJoined', data.participant);
        break;
      case 'participant_left':
        this.emit('participantLeft', data.participant);
        break;
      case 'token_movement':
        this.emit('tokenMoved', data);
        break;
      case 'dice_roll':
        this.emit('diceRolled', data);
        break;
      case 'chat_message':
        this.emit('chatMessage', data);
        break;
      case 'session_updated':
        if (this.currentSession) {
          this.currentSession = { ...this.currentSession, ...data.session };
          this.emit('sessionUpdated', this.currentSession);
        }
        break;
      case 'heartbeat_response':
        // Heartbeat acknowledged
        break;
      default:
        console.warn('Unknown WebSocket message type:', type);
        this.emit('unknownMessage', message);
    }
  }

  private attemptReconnect(sessionCode: string, userInfo: UserInfo): void {
    this.reconnectAttempts++;
    const delay = this.reconnectDelay * Math.pow(2, this.reconnectAttempts - 1);
    
    console.log(`Attempting to reconnect (${this.reconnectAttempts}/${this.maxReconnectAttempts}) in ${delay}ms`);
    
    setTimeout(async () => {
      try {
        await this.connectWebSocket(sessionCode, userInfo);
        this.emit('reconnected');
      } catch (error) {
        console.error('Reconnection failed:', error);
        if (this.reconnectAttempts >= this.maxReconnectAttempts) {
          this.emit('reconnectionFailed');
        }
      }
    }, delay);
  }

  private startHeartbeat(): void {
    this.heartbeatInterval = setInterval(() => {
      if (this.websocket?.readyState === WebSocket.OPEN) {
        this.sendMessage('heartbeat', { timestamp: Date.now() });
      }
    }, 30000); // 30 seconds
  }

  private stopHeartbeat(): void {
    if (this.heartbeatInterval) {
      clearInterval(this.heartbeatInterval);
      this.heartbeatInterval = null;
    }
  }

  private generateSessionCode(): string {
    // Generate 6-character alphanumeric code
    const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789';
    let result = '';
    for (let i = 0; i < 6; i++) {
      result += chars.charAt(Math.floor(Math.random() * chars.length));
    }
    return result;
  }

  private validateSessionCode(code: string): boolean {
    return /^[A-Z0-9]{6}$/.test(code);
  }

  private getCurrentUserId(): string {
    return this.currentSession?.participants.find(p => p.id)?.id.toString() || 'unknown';
  }

  /**
   * Get connection status
   */
  isConnected(): boolean {
    return this.websocket?.readyState === WebSocket.OPEN;
  }

  /**
   * Get session participants
   */
  getParticipants(): UserInfo[] {
    return this.currentSession?.participants || [];
  }

  /**
   * Check if current user is session host
   */
  isHost(userId: string): boolean {
    return this.currentSession?.hostUserId === userId;
  }
}

// Singleton instance
export const sessionManager = new SessionManager();
export default SessionManager;

import { useRenderEngine } from '@features/canvas';
import { ProtocolService } from '@lib/api';
import React, { useCallback, useEffect, useRef, useState } from 'react';
import { useGameStore } from '../../../store';

interface GridSettings {
  enabled: boolean;
  size: number;
  color: string;
  opacity: number;
  snapToGrid: boolean;
  type: 'square' | 'hex';
}

interface MapSettings {
  width: number;
  height: number;
  backgroundColor: string;
  gridSettings: GridSettings;
}

interface MapPanelProps extends React.HTMLProps<HTMLDivElement> {}

const gridPresets = [
  { name: 'D&D 5ft', size: 50, type: 'square' as const },
  { name: 'D&D 10ft', size: 100, type: 'square' as const },
  { name: 'Pathfinder', size: 50, type: 'square' as const },
  { name: 'Hex Large', size: 60, type: 'hex' as const },
  { name: 'Hex Small', size: 40, type: 'hex' as const },
];

function hexToRgb(hex: string): [number, number, number] {
  const h = hex.replace('#', '');
  return [
    parseInt(h.slice(0, 2), 16) / 255,
    parseInt(h.slice(2, 4), 16) / 255,
    parseInt(h.slice(4, 6), 16) / 255,
  ];
}

export const MapPanel: React.FC<MapPanelProps> = ({ className, style, id, ...rest }) => {
  const engine = useRenderEngine();
  const { activeTableId, gridEnabled, gridCellPx, gridSnapping, gridColorHex, backgroundColorHex } = useGameStore();

  const [settings, setSettings] = useState<MapSettings>(() => ({
    width: 2000,
    height: 2000,
    backgroundColor: backgroundColorHex ?? '#2a3441',
    gridSettings: {
      enabled: gridEnabled,
      size: gridCellPx,
      color: gridColorHex ?? '#ffffff',
      opacity: 0.4,
      snapToGrid: gridSnapping,
      type: 'square',
    },
  }));

  const initialized = useRef(false);
  const sendTimer = useRef<ReturnType<typeof setTimeout> | null>(null);

  useEffect(() => {
    if (!initialized.current) return;
    setSettings(prev => ({
      ...prev,
      backgroundColor: backgroundColorHex ?? prev.backgroundColor,
      gridSettings: {
        ...prev.gridSettings,
        enabled: gridEnabled,
        size: gridCellPx,
        snapToGrid: gridSnapping,
        color: gridColorHex ?? prev.gridSettings.color,
      },
    }));
  }, [gridEnabled, gridCellPx, gridSnapping, gridColorHex, backgroundColorHex]);

  useEffect(() => {
    initialized.current = true;
  }, []);

  const applyToWasm = useCallback((s: MapSettings) => {
    if (!engine) return;
    const g = s.gridSettings;
    engine.set_grid_enabled?.(g.enabled);
    engine.set_grid_size?.(g.size);
    engine.set_snap_to_grid?.(g.snapToGrid);
    if (engine.set_grid_color) {
      const [r, gv, b] = hexToRgb(g.color);
      engine.set_grid_color(r, gv, b, g.opacity);
    }
    if (engine.set_background_color) {
      const [r, gv, b] = hexToRgb(s.backgroundColor);
      engine.set_background_color(r, gv, b, 1.0);
    }
  }, [engine]);

  const sendToServer = useCallback((s: MapSettings) => {
    if (!activeTableId || !ProtocolService.hasProtocol()) return;
    const g = s.gridSettings;
    ProtocolService.getProtocol().sendTableSettingsUpdate(activeTableId, {
      grid_cell_px: g.size,
      grid_enabled: g.enabled,
      snap_to_grid: g.snapToGrid,
      grid_color_hex: g.color,
      background_color_hex: s.backgroundColor,
    });
  }, [activeTableId]);

  const updateSettings = useCallback((next: MapSettings) => {
    setSettings(next);
    applyToWasm(next);
    if (sendTimer.current) clearTimeout(sendTimer.current);
    sendTimer.current = setTimeout(() => sendToServer(next), 300);
  }, [applyToWasm, sendToServer]);

  const updateGrid = useCallback((updates: Partial<GridSettings>) => {
    setSettings(prev => {
      const next = { ...prev, gridSettings: { ...prev.gridSettings, ...updates } };
      applyToWasm(next);
      if (sendTimer.current) clearTimeout(sendTimer.current);
      sendTimer.current = setTimeout(() => sendToServer(next), 300);
      return next;
    });
  }, [applyToWasm, sendToServer]);

  const resetCamera = useCallback(() => {
    engine?.reset_camera?.();
  }, [engine]);

  const centerOnMap = useCallback(() => {
    engine?.set_camera_position?.(settings.width / 2, settings.height / 2);
  }, [engine, settings.width, settings.height]);

  const fitToScreen = useCallback(() => {
    const scale = Math.min(window.innerWidth / settings.width, window.innerHeight / settings.height) * 0.9;
    engine?.set_camera_scale?.(scale);
  }, [engine, settings.width, settings.height]);

  const handleExportMap = useCallback(() => {
    const canvas = document.querySelector('canvas');
    if (!canvas) return;
    const link = document.createElement('a');
    link.download = `map_${Date.now()}.png`;
    link.href = canvas.toDataURL();
    link.click();
  }, []);

  const clearMap = useCallback(() => {
    if (!engine) return;
    if (confirm('Clear all sprites from the map? This cannot be undone.')) {
      engine.clear_all_sprites?.();
    }
  }, [engine]);

  return (
    <div className={`map-panel ${className || ''}`} style={style} id={id} {...rest}>
      <div className="panel-header">
        <h3>Map & Grid</h3>
      </div>

      <div className="panel-content">
        <div className="settings-section">
          <h4>Map Settings</h4>
          <div className="setting-row">
            <label>Width:</label>
            <input
              type="number" min="500" max="10000" step="100"
              value={settings.width}
              onChange={e => updateSettings({ ...settings, width: parseInt(e.target.value) || 2000 })}
            />
            <span>px</span>
          </div>
          <div className="setting-row">
            <label>Height:</label>
            <input
              type="number" min="500" max="10000" step="100"
              value={settings.height}
              onChange={e => updateSettings({ ...settings, height: parseInt(e.target.value) || 2000 })}
            />
            <span>px</span>
          </div>
          <div className="setting-row">
            <label>Background:</label>
            <input
              type="color"
              value={settings.backgroundColor}
              onChange={e => updateSettings({ ...settings, backgroundColor: e.target.value })}
            />
          </div>
        </div>

        <div className="settings-section">
          <h4>Grid Settings</h4>
          <div className="setting-row">
            <label>
              <input
                type="checkbox"
                checked={settings.gridSettings.enabled}
                onChange={e => updateGrid({ enabled: e.target.checked })}
              />
              Enable Grid
            </label>
          </div>
          <div className="setting-row">
            <label>Grid Size:</label>
            <input
              type="number" min="10" max="200"
              value={settings.gridSettings.size}
              onChange={e => updateGrid({ size: parseInt(e.target.value) || 50 })}
              disabled={!settings.gridSettings.enabled}
            />
            <span>px</span>
          </div>
          <div className="setting-row">
            <label>Grid Type:</label>
            <select
              value={settings.gridSettings.type}
              onChange={e => updateGrid({ type: e.target.value as 'square' | 'hex' })}
              disabled={!settings.gridSettings.enabled}
            >
              <option value="square">Square</option>
              <option value="hex">Hexagonal</option>
            </select>
          </div>
          <div className="setting-row">
            <label>Grid Color:</label>
            <input
              type="color"
              value={settings.gridSettings.color}
              onChange={e => updateGrid({ color: e.target.value })}
              disabled={!settings.gridSettings.enabled}
            />
          </div>
          <div className="setting-row">
            <label>Opacity:</label>
            <input
              type="range" min="0" max="1" step="0.05"
              value={settings.gridSettings.opacity}
              onChange={e => updateGrid({ opacity: parseFloat(e.target.value) })}
              disabled={!settings.gridSettings.enabled}
            />
            <span>{Math.round(settings.gridSettings.opacity * 100)}%</span>
          </div>
          <div className="setting-row">
            <label>
              <input
                type="checkbox"
                checked={settings.gridSettings.snapToGrid}
                onChange={e => updateGrid({ snapToGrid: e.target.checked })}
                disabled={!settings.gridSettings.enabled}
              />
              Snap to Grid
            </label>
          </div>
        </div>

        <div className="settings-section">
          <h4>Grid Presets</h4>
          <div className="preset-buttons">
            {gridPresets.map(preset => (
              <button
                key={preset.name}
                className="preset-btn"
                onClick={() => updateGrid({ size: preset.size, type: preset.type })}
              >
                {preset.name}
              </button>
            ))}
          </div>
        </div>

        <div className="settings-section">
          <h4>Camera</h4>
          <div className="button-row">
            <button className="action-btn" onClick={resetCamera}>Reset</button>
            <button className="action-btn" onClick={centerOnMap}>Center</button>
            <button className="action-btn" onClick={fitToScreen}>Fit Screen</button>
          </div>
        </div>

        <div className="settings-section">
          <h4>Actions</h4>
          <div className="button-row">
            <button className="action-btn" onClick={handleExportMap}>Export PNG</button>
            <button className="action-btn danger-btn" onClick={clearMap}>Clear Map</button>
          </div>
        </div>
      </div>
    </div>
  );
};

