import type { TableInfo } from '@/store';
import { useGameStore } from '@/store';
import { tableThumbnailService } from '@features/table/services/tableThumbnail.service';
import { useEffect, useMemo, useState } from 'react';
import { TABLE_TEMPLATES } from './utils';

export const useTableManagement = () => {
  const {
    tables,
    activeTableId,
    tablesLoading,
    setTables,
    setTablesLoading,
    requestTableList,
    createNewTable,
    deleteTable,
    switchToTable
  } = useGameStore();

 const [showCreateForm, setShowCreateForm] = useState(false);
 const [newTableName, setNewTableName] = useState('');
 const [newTableWidth, setNewTableWidth] = useState(2000);
 const [newTableHeight, setNewTableHeight] = useState(2000);
 const [deleteConfirmId, setDeleteConfirmId] = useState<string | null>(null);
  
 const [settingsTableId, setSettingsTableId] = useState<string | null>(null);
 const [settingsName, setSettingsName] = useState('');
 const [settingsWidth, setSettingsWidth] = useState(2000);
 const [settingsHeight, setSettingsHeight] = useState(2000);
 const [settingsGridSize, setSettingsGridSize] = useState(50);
 const [settingsGridEnabled, setSettingsGridEnabled] = useState(true);

 const [searchQuery, setSearchQuery] = useState('');
 const [sortBy, setSortBy] = useState<'name' | 'date' | 'size'>('name');
 const [sortOrder, setSortOrder] = useState<'asc' | 'desc'>('asc');
  
 const [autoSync, setAutoSync] = useState(true);
 const [showSettings, setShowSettings] = useState(false);

 const [selectedTables, setSelectedTables] = useState<Set<string>>(new Set());
 const [bulkMode, setBulkMode] = useState(false);

  // Request table list on mount if already connected and store is empty
  useEffect(() => {
    if (tables.length === 0) {
      requestTableList();
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
 }, []);

  useEffect(() => {
    const handleTableListUpdate = (event: Event) => {
      const customEvent = event as CustomEvent;
      const data = customEvent.detail;
      
      if (data.tables) {
        const serverTables = Object.entries(data.tables).map(([id, tableData]: [string, any]) => ({
          table_id: id,
          ...tableData,
          syncStatus: 'synced' as const,
          lastSyncTime: Date.now()
        }));
        
        const currentTables = useGameStore.getState().tables;
        const localTables = currentTables.filter((t: TableInfo) => {
          const isInServerList = serverTables.some(st => st.table_id === t.table_id);
          const isLocal = t.syncStatus === 'local' || t.syncStatus === 'syncing';
          return !isInServerList && isLocal;
        });
        
        const mergedTables = [...serverTables, ...localTables];
        setTables(mergedTables);
      }
      setTablesLoading(false);
    };

    const handleTableCreated = (event: Event) => {
      const customEvent = event as CustomEvent;
      const responseData = customEvent.detail;
      
      const localTableId = responseData.local_table_id;
      const serverTableData = responseData.table_data;
      
      if (localTableId && serverTableData) {
        const currentTables = useGameStore.getState().tables;
        const updated: TableInfo[] = currentTables.map((t: TableInfo): TableInfo => {
          if (t.table_id === localTableId) {
            return {
              ...t,
              table_id: serverTableData.id || serverTableData.table_id || t.table_id,
              table_name: serverTableData.table_name || t.table_name,
              width: serverTableData.width || t.width,
              height: serverTableData.height || t.height,
              syncStatus: 'synced' as const,
              lastSyncTime: Date.now(),
              syncError: undefined
            } as TableInfo;
          }
          return t;
        });
        setTables(updated);
      } else {
        requestTableList();
      }
      
      setShowCreateForm(false);
      setNewTableName('');
    };

    const handleTableDeleted = () => {
      requestTableList();
      setDeleteConfirmId(null);
    };

    const handleProtocolConnected = () => {
      requestTableList();
    };

    window.addEventListener('table-list-updated', handleTableListUpdate);
    window.addEventListener('new-table-response', handleTableCreated);
    window.addEventListener('table-deleted', handleTableDeleted);
    window.addEventListener('protocol-connected', handleProtocolConnected);

    return () => {
      window.removeEventListener('table-list-updated', handleTableListUpdate);
      window.removeEventListener('new-table-response', handleTableCreated);
      window.removeEventListener('table-deleted', handleTableDeleted);
      window.removeEventListener('protocol-connected', handleProtocolConnected);
    };
 }, [setTables, setTablesLoading, requestTableList]);

  const handleCreateTable = () => {
    if (!newTableName.trim()) {
      alert('Table name is required');
      return;
    }
    createNewTable(newTableName.trim(), newTableWidth, newTableHeight);
  };

  const handleDeleteTable = (tableId: string) => {
    setDeleteConfirmId(tableId);
  };

  const confirmDeleteTable = () => {
    if (deleteConfirmId) {
      deleteTable(deleteConfirmId);
    }
  };

  const handleTableSelect = (tableId: string) => {
    switchToTable(tableId);
  };

  const handleDiagnoseThumbnails = async () => {
    console.group(' Thumbnail Diagnostic Report');
    
    const wasmReady = (window as any).wasmInitialized;
    console.log('1. WASM Status:', wasmReady ? ' Initialized' : ' Not Initialized');
    
    const mainCanvas = document.querySelector('[data-testid="game-canvas"]') as HTMLCanvasElement;
 console.log('2. Main Canvas:', mainCanvas ? {
      found: 'Yes',
      dimensions: `${mainCanvas.width}x${mainCanvas.height}`,
      inDOM: mainCanvas.parentElement ? 'In DOM': 'Not in DOM'
    } : 'Not Found');
    
    const renderEngine = tableThumbnailService.getRenderEngine();
    console.log('3. Active Table:', tables[0]?.table_name || ' None');
    console.log('5. Render Engine:', renderEngine ? ' Available' : ' Not Available');
    
    if (mainCanvas) {
      const ctx = mainCanvas.getContext('2d');
      if (ctx) {
        const centerPixel = ctx.getImageData(
          Math.floor(mainCanvas.width / 2),
          Math.floor(mainCanvas.height / 2),
          1, 1
        ).data;
        const isBlack = centerPixel[0] === 0 && centerPixel[1] === 0 && centerPixel[2] === 0;
        console.log('6. Canvas Content (center pixel):', isBlack ? ' Black (empty?)' : ' Has Content', centerPixel);
      }
    }
    
    if (activeTableId) {
      const table = tables.find(t => t.table_id === activeTableId);
      if (table) {
 console.log('7. Attempting to regenerate thumbnail for active table:', table.table_name);
        try {
          const imageData = await tableThumbnailService.generateThumbnail(
            table.table_id,
            table.width,
            table.height,
            160,
            120,
            true
          );
          console.log(' Result:', imageData ? ` Generated ${imageData.width}x${imageData.height}` : ' Returned null');
        } catch (error) {
          console.error(' Error:', error);
        }
      }
    }
    
    const cacheStats = tableThumbnailService.getCacheStats();
 console.log('8. Cache Statistics:', {
      totalCached: cacheStats.size,
      tablesWithCache: cacheStats.tables
    });
    
 console.groupEnd();
    
    alert(`Thumbnail Diagnostic Complete\n\nCheck browser console (F12) for detailed report.\n\nQuick Summary:\n- WASM: ${wasmReady ? '': ''}\n- Canvas: ${mainCanvas ? '': ''}\n- Active Table: ${activeTableId ? '': ''}\n- Cached: ${cacheStats.size} thumbnails`);
  };

  const handleOpenSettings = (tableId: string) => {
    const table = tables.find(t => t.table_id === tableId);
    if (table) {
      setSettingsTableId(tableId);
      setSettingsName(table.table_name);
      setSettingsWidth(table.width);
      setSettingsHeight(table.height);
      setSettingsGridSize(50);
      setSettingsGridEnabled(true);
    }
  };

  const handleCloseSettings = () => {
    setSettingsTableId(null);
  };

  const handleSaveSettings = () => {
    if (!settingsTableId) return;
    
    window.dispatchEvent(new CustomEvent('protocol-send-message', {
      detail: {
        type: 'table_update',
        data: {
          category: 'table',
          type: 'table_update',
          data: {
            table_id: settingsTableId,
            table_name: settingsName,
            width: settingsWidth,
            height: settingsHeight,
            grid_size: settingsGridSize,
            grid_enabled: settingsGridEnabled
          }
        }
      }
    }));

    setTables(tables.map(t => 
      t.table_id === settingsTableId 
        ? { ...t, table_name: settingsName, width: settingsWidth, height: settingsHeight }
        : t
    ));

    if (activeTableId === settingsTableId) {
      const updatedTableDataForWasm = {
        table_data: {
          table_id: settingsTableId,
          table_name: settingsName,
          width: settingsWidth,
          height: settingsHeight,
          grid_size: settingsGridSize,
          grid_enabled: settingsGridEnabled,
          grid_snapping: false,
          layers: {
 map: [],
 tokens: [],
 dungeon_master: [],
 light: [],
 height: [],
 obstacles: [],
 fog_of_war: []
          }
        }
      };
      
      window.dispatchEvent(new CustomEvent('table-data-received', {
        detail: updatedTableDataForWasm
      }));
      
      window.dispatchEvent(new CustomEvent('protocol-send-message', {
        detail: {
          type: 'table_request',
          data: {
            table_id: settingsTableId
          }
        }
      }));
    }

    setTimeout(() => {
      requestTableList();
    }, 500);

    setSettingsTableId(null);
  };

  const filteredAndSortedTables = useMemo(() => {
    let filtered = tables;

    if (searchQuery.trim()) {
      const query = searchQuery.toLowerCase();
      filtered = filtered.filter(t => 
        (t.table_name || '').toLowerCase().includes(query) ||
        (t.table_id || '').toLowerCase().includes(query)
      );
    }

 const sorted = [...filtered].sort((a, b) => {
      let comparison = 0;
      
      switch (sortBy) {
        case 'name':
          comparison = (a.table_name || '').localeCompare(b.table_name || '');
          break;
        case 'date':
          const dateA = a.created_at ? new Date(a.created_at).getTime() : 0;
          const dateB = b.created_at ? new Date(b.created_at).getTime() : 0;
          comparison = dateB - dateA;
          break;
        case 'size':
          const sizeA = (a.width || 0) * (a.height || 0);
          const sizeB = (b.width || 0) * (b.height || 0);
          comparison = sizeA - sizeB;
          break;
      }
      
      return sortOrder === 'asc' ? comparison : -comparison;
    });

    return sorted;
 }, [tables, searchQuery, sortBy, sortOrder]);

  const handleDuplicateTable = (tableId: string) => {
    const table = tables.find(t => t.table_id === tableId);
    if (table) {
      createNewTable(`${table.table_name} (Copy)`, table.width, table.height);
    }
  };

  const toggleTableSelection = (tableId: string) => {
    const newSelection = new Set(selectedTables);
    if (newSelection.has(tableId)) {
      newSelection.delete(tableId);
    } else {
      newSelection.add(tableId);
    }
    setSelectedTables(newSelection);
  };

  const toggleSelectAll = () => {
    if (selectedTables.size === filteredAndSortedTables.length) {
      setSelectedTables(new Set());
    } else {
      setSelectedTables(new Set(filteredAndSortedTables.map(t => t.table_id)));
    }
  };

  const handleBulkDelete = () => {
    if (selectedTables.size === 0) return;
    if (!confirm(`Delete ${selectedTables.size} table(s)?`)) return;
    
    selectedTables.forEach(tableId => {
      deleteTable(tableId);
    });
    setSelectedTables(new Set());
    setBulkMode(false);
  };

  const handleBulkDuplicate = () => {
    if (selectedTables.size === 0) return;
    
    selectedTables.forEach(tableId => {
      handleDuplicateTable(tableId);
    });
    setSelectedTables(new Set());
  };

  const handleImportTable = () => {
    const input = document.createElement('input');
    input.type = 'file';
    input.accept = '.json';
    input.onchange = async (e: any) => {
      const file = e.target.files[0];
      if (!file) return;

      try {
        const text = await file.text();
        const data = JSON.parse(text);

        if (!data.table_name || !data.width || !data.height) {
          alert('Invalid table export file');
          return;
        }

        createNewTable(
          `${data.table_name} (Imported)`,
          data.width,
          data.height
        );
      } catch (err) {
        alert('Failed to import table: ' + err);
      }
    };
    input.click();
  };

  const applyTemplate = (templateKey: keyof typeof TABLE_TEMPLATES) => {
    const template = TABLE_TEMPLATES[templateKey];
    setNewTableWidth(template.width);
    setNewTableHeight(template.height);
  };

  return {
    tables,
    activeTableId,
    tablesLoading,
    filteredAndSortedTables,
    showCreateForm,
    setShowCreateForm,
    newTableName,
    setNewTableName,
    newTableWidth,
    setNewTableWidth,
    newTableHeight,
    setNewTableHeight,
    deleteConfirmId,
    setDeleteConfirmId,
    settingsTableId,
    settingsName,
    setSettingsName,
    settingsWidth,
    setSettingsWidth,
    settingsHeight,
    setSettingsHeight,
    settingsGridSize,
    setSettingsGridSize,
    settingsGridEnabled,
    setSettingsGridEnabled,
    searchQuery,
    setSearchQuery,
    sortBy,
    setSortBy,
    sortOrder,
    setSortOrder,
    autoSync,
    setAutoSync,
    showSettings,
    setShowSettings,
    selectedTables,
    bulkMode,
    setBulkMode,
    handleCreateTable,
    handleDeleteTable,
    confirmDeleteTable,
    handleTableSelect,
    handleDiagnoseThumbnails,
    handleOpenSettings,
    handleCloseSettings,
    handleSaveSettings,
    handleDuplicateTable,
    toggleTableSelection,
    toggleSelectAll,
    handleBulkDelete,
    handleBulkDuplicate,
    handleImportTable,
    applyTemplate,
    requestTableList
  };
};

import { useGameStore } from '@/store';
import clsx from 'clsx';
import React, { useRef, useState } from 'react';
import type { TableInfo } from '../hooks/useTableManager';
import { useTableManager } from '../hooks/useTableManager';
import styles from './TablePanel.module.css';
import { TablePreview } from './TablePreview';

const TablePanel: React.FC = () => {
  const { setActiveTableId: setGlobalActiveTableId } = useGameStore();
  const {
    activeTableId,
    tables,
    createTable,
    setActiveTable,
    setTableGrid,
    removeTable,
    panViewport,
    zoomTable,
  } = useTableManager();

  const [showCreateForm, setShowCreateForm] = useState(false);
  const [newTableName, setNewTableName] = useState('');
  const [newTableWidth, setNewTableWidth] = useState(2000);
  const [newTableHeight, setNewTableHeight] = useState(2000);
  const zoomRef = useRef(1.0);

  const handleCreateTable = () => {
    if (!newTableName.trim()) return;
    
    const tableId = `table_${Date.now()}`;
    const success = createTable(tableId, newTableName, newTableWidth, newTableHeight);
    
    if (success) {
      setNewTableName('');
      setShowCreateForm(false);
      // Update local WASM state
      setActiveTable(tableId);
      // Update global store state (triggers server persistence)
      setGlobalActiveTableId(tableId);
    }
  };

  const handleTableSelect = (tableId: string) => {
    // Update local WASM state
    setActiveTable(tableId);
    // Update global store state (triggers server persistence)
    setGlobalActiveTableId(tableId);
  };

  const handleToggleGrid = (tableId: string, currentShowGrid: boolean, cellSize: number) => {
    setTableGrid(tableId, !currentShowGrid, cellSize);
  };

  const handlePanTable = (tableId: string, direction: string) => {
    const panAmount = 100;
    switch (direction) {
      case 'up':
        panViewport(tableId, 0, -panAmount);
        break;
      case 'down':
        panViewport(tableId, 0, panAmount);
        break;
      case 'left':
        panViewport(tableId, -panAmount, 0);
        break;
      case 'right':
        panViewport(tableId, panAmount, 0);
        break;
    }
  };

  const handleZoomTable = (tableId: string, zoomIn: boolean) => {
    const factor = zoomIn ? 1.2 : 0.8;
    const newZoom = Math.max(0.1, Math.min(5.0, zoomRef.current * factor));
    zoomRef.current = newZoom;
    const rm = (window as any).rustRenderManager;
    if (rm?.set_zoom) rm.set_zoom(newZoom);
    zoomTable(tableId, factor, 400, 300);
  };

  return (
    <div className={styles.tablePanel}>
      <div className={styles.tablePanelHeader}>
        <h3>Tables</h3>
        <button 
          className={styles.createTableBtn}
          onClick={() => setShowCreateForm(!showCreateForm)}
        >
          +
        </button>
      </div>

      {showCreateForm && (
        <div className={styles.createTableForm}>
          <input
            type="text"
            placeholder="Table name"
            value={newTableName}
            onChange={(e) => setNewTableName(e.target.value)}
          />
          <div className={styles.sizeInputs}>
            <label>
              Width:
              <input
                type="number"
                value={newTableWidth}
                onChange={(e) => setNewTableWidth(Number(e.target.value))}
                min="500"
                max="10000"
              />
            </label>
            <label>
              Height:
              <input
                type="number"
                value={newTableHeight}
                onChange={(e) => setNewTableHeight(Number(e.target.value))}
                min="500"
                max="10000"
              />
            </label>
          </div>
          <div className={styles.formButtons}>
            <button onClick={handleCreateTable}>Create</button>
            <button onClick={() => setShowCreateForm(false)}>Cancel</button>
          </div>
        </div>
      )}

      <div className={styles.tablesList} role="listbox" aria-label="Available tables">
        {tables.map((table: TableInfo) => (
          <div 
            key={table.table_id}
            role="option"
            aria-selected={table.table_id === activeTableId}
            aria-label={table.table_name}
            className={clsx(styles.tableItem, table.table_id === activeTableId && styles.active)}
          >
            <div className={styles.tablePreviewWrapper} onClick={() => handleTableSelect(table.table_id)}>
              <TablePreview table={table as any} width={160} height={90} />
            </div>

            <div className={styles.tableHeader}>
              <span 
                className={styles.tableName}
                onClick={() => handleTableSelect(table.table_id)}
              >
                {table.table_name}
              </span>
              <button 
                className={styles.removeTableBtn}
                onClick={() => removeTable(table.table_id)}
                title="Remove table"
                aria-label={`Delete ${table.table_name}`}
              >
                ├Ч
              </button>
            </div>
            
            <div className={styles.tableInfo}>
              <div className={styles.tableSize}>
                {table.width}├Ч{table.height}
              </div>
              <div className={styles.tableScale}>
                Scale: {table.table_scale.toFixed(2)}x
              </div>
            </div>

            {table.table_id === activeTableId && (
              <div className={styles.tableControls}>
                <div className={styles.gridControls}>
                  <label>
                    <input
                      type="checkbox"
                      checked={table.show_grid}
                      onChange={() => handleToggleGrid(table.table_id, table.show_grid, table.cell_side)}
                    />
                    Show Grid
                  </label>
                  {table.show_grid && (
                    <input
                      type="number"
                      value={table.cell_side}
                      onChange={(e) => setTableGrid(table.table_id, true, Number(e.target.value))}
                      min="5"
                      max="200"
                      title="Grid cell size"
                    />
                  )}
                </div>

                <div className={styles.panControls}>
                  <div className={styles.panLabel}>Pan:</div>
                  <div className={styles.panButtons}>
                    <button onClick={() => handlePanTable(table.table_id, 'up')}>тЖС</button>
                    <div className={styles.panRow}>
                      <button onClick={() => handlePanTable(table.table_id, 'left')}>тЖР</button>
                      <button onClick={() => handlePanTable(table.table_id, 'right')}>тЖТ</button>
                    </div>
                    <button onClick={() => handlePanTable(table.table_id, 'down')}>тЖУ</button>
                  </div>
                </div>

                <div className={styles.zoomControls}>
                  <div className={styles.zoomLabel}>Zoom:</div>
                  <div className={styles.zoomButtons}>
                    <button onClick={() => handleZoomTable(table.table_id, false)}>-</button>
                    <button onClick={() => handleZoomTable(table.table_id, true)}>+</button>
                  </div>
                </div>

                <div className={styles.viewportInfo}>
                  <div>Viewport: ({table.viewport_x.toFixed(0)}, {table.viewport_y.toFixed(0)})</div>
                </div>
              </div>
            )}
          </div>
        ))}
      </div>

      {tables.length === 0 && (
        <div className={styles.noTables}>
          No tables created. Click + to create your first table.
        </div>
      )}
    </div>
  );
};

export { TablePanel };

import type { TableInfo } from '@/store';
import { wasmIntegrationService } from '@lib/wasm';
import React, { useEffect, useRef, useState } from 'react';
import { tableThumbnailService } from '../services/tableThumbnail.service';

interface TablePreviewProps {
  table: TableInfo;
  width?: number;
  height?: number;
}

export const TablePreview: React.FC<TablePreviewProps> = ({ 
  table, 
  width = 160, 
  height = 120 
}) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  // Add refresh trigger state
  const [refreshTrigger, setRefreshTrigger] = useState(0);
  
  // Expose regenerate method globally for debugging
  React.useEffect(() => {
    (window as any).__regenerateThumbnail = (tableId: string) => {
      if (tableId === table.table_id) {
        console.log(`[TablePreview] Manual regeneration triggered for ${tableId}`);
        tableThumbnailService.invalidateThumbnail(table.table_id, width, height);
        setRefreshTrigger(prev => prev + 1);
      }
    };
  }, [table.table_id, width, height]);
  
  // Listen for sprite loading completion to trigger thumbnail regeneration
  useEffect(() => {
    const handleSpritesLoaded = (event: Event) => {
      const customEvent = event as CustomEvent<{ tableId: string; spriteCount: number; timestamp: number }>;
      const { tableId, spriteCount } = customEvent.detail;
      
      // Only regenerate thumbnail if this event is for our table
      if (tableId === table.table_id) {
        console.log(`[TablePreview] Sprites loaded for table ${tableId} (${spriteCount} sprites), regenerating thumbnail`);
        
        // Force regeneration by clearing cache
        tableThumbnailService.invalidateThumbnail(table.table_id, width, height);
        
        // Trigger immediate thumbnail generation
        setRefreshTrigger(prev => prev + 1);
      }
    };
    
    window.addEventListener('table-sprites-loaded', handleSpritesLoaded);
    
    return () => {
      window.removeEventListener('table-sprites-loaded', handleSpritesLoaded);
    };
  }, [table.table_id, width, height]);
  
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let isCancelled = false;

    const renderThumbnail = async () => {
      setIsLoading(true);
      setError(null);
      
      // Draw loading state immediately
      ctx.fillStyle = '#1a1a1a';
      ctx.fillRect(0, 0, width, height);
      
      ctx.strokeStyle = '#444';
      ctx.lineWidth = 2;
      ctx.strokeRect(1, 1, width - 2, height - 2);
      
      ctx.fillStyle = '#888';
      ctx.font = '12px sans-serif';
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      ctx.fillText('Loading...', width / 2, height / 2);

      try {
        // Get the render engine
        const renderEngine = wasmIntegrationService.getRenderEngine();
        if (!renderEngine) {
          throw new Error('Render engine not initialized');
        }

        // Initialize the thumbnail service if needed
        if (!tableThumbnailService.isInitialized()) {
          tableThumbnailService.initialize(renderEngine);
        }

        // Generate thumbnail using real WASM rendering
        const imageData = await tableThumbnailService.generateThumbnail(
          table.table_id,
          table.width,
          table.height,
          width,
          height,
          false // Don't force refresh, use cache if available
        );

        // Only update if not cancelled
        if (!isCancelled) {
          if (imageData) {
            console.log(`[TablePreview] Rendering thumbnail for ${table.table_id}: ${imageData.width}x${imageData.height}`);
            ctx.putImageData(imageData, 0, 0);
          } else {
            // Table not active - show "Not Loaded" placeholder
            console.log(`[TablePreview] Table ${table.table_id} not active, showing placeholder`);
            
            ctx.fillStyle = '#1a1a1a';
            ctx.fillRect(0, 0, width, height);
            
            // Draw dashed border
            ctx.setLineDash([5, 5]);
            ctx.strokeStyle = '#666';
            ctx.lineWidth = 2;
            ctx.strokeRect(2, 2, width - 4, height - 4);
            ctx.setLineDash([]);
            
            // Draw icon (table symbol)
            ctx.strokeStyle = '#888';
            ctx.lineWidth = 2;
            const iconSize = 32;
            const iconX = width / 2;
            const iconY = height / 2 - 10;
            
            // Draw simple table icon (grid)
            ctx.strokeRect(iconX - iconSize/2, iconY - iconSize/2, iconSize, iconSize);
            ctx.beginPath();
            ctx.moveTo(iconX - iconSize/2, iconY - iconSize/6);
            ctx.lineTo(iconX + iconSize/2, iconY - iconSize/6);
            ctx.moveTo(iconX - iconSize/2, iconY + iconSize/6);
            ctx.lineTo(iconX + iconSize/2, iconY + iconSize/6);
            ctx.moveTo(iconX - iconSize/6, iconY - iconSize/2);
            ctx.lineTo(iconX - iconSize/6, iconY + iconSize/2);
            ctx.moveTo(iconX + iconSize/6, iconY - iconSize/2);
            ctx.lineTo(iconX + iconSize/6, iconY + iconSize/2);
            ctx.stroke();
            
            // Draw text
            ctx.fillStyle = '#888';
            ctx.font = '11px sans-serif';
            ctx.textAlign = 'center';
            ctx.textBaseline = 'top';
            ctx.fillText('Not Loaded', width / 2, height / 2 + 20);
            ctx.font = '9px sans-serif';
            ctx.fillStyle = '#666';
            ctx.fillText('(Switch to table to preview)', width / 2, height / 2 + 34);
          }
          setIsLoading(false);
        }
      } catch (err) {
        console.error('Failed to render table thumbnail:', err);
        if (!isCancelled) {
          setError(err instanceof Error ? err.message : 'Failed to render thumbnail');
          
          // Draw error state - red border
          ctx.fillStyle = '#1a1a1a';
          ctx.fillRect(0, 0, width, height);
          
          ctx.strokeStyle = '#ff4444';
          ctx.lineWidth = 2;
          ctx.strokeRect(1, 1, width - 2, height - 2);
          
          ctx.fillStyle = '#ff4444';
          ctx.font = '12px sans-serif';
          ctx.textAlign = 'center';
          ctx.textBaseline = 'middle';
          ctx.fillText('Error', width / 2, height / 2);
          
          setIsLoading(false);
        }
      }
    };

    renderThumbnail();

    return () => {
      isCancelled = true;
    };
  }, [table.table_id, table.width, table.height, width, height, refreshTrigger]);

  return (
    <canvas
      ref={canvasRef}
      width={width}
      height={height}
      className="table-preview-canvas"
      style={{
        display: 'block',
        width: '100%',
        height: '100%',
        objectFit: 'contain',
        imageRendering: 'auto',
        opacity: isLoading ? 0.5 : 1,
        transition: 'opacity 0.2s ease-in-out'
      }}
      title={error || (isLoading ? 'Loading thumbnail...' : `Table: ${table.table_name}`)}
    />
  );
};

import { useNetworkClient } from '@shared/hooks/useNetworkClient';
import { useEffect, useState } from 'react';
import { useTableSync } from '../hooks/useTableSync';
import styles from './TableSyncPanel.module.css';

interface ActivityLog {
  id: number;
  timestamp: Date;
  type: 'info' | 'success' | 'error' | 'warning';
  message: string;
  emoji: string;
}

function TableSyncPanel() {
  const { tableSync, isLoading, error } = useTableSync();
  const { networkState } = useNetworkClient();
  const isConnected = networkState.isConnected;
  const [activityLog, setActivityLog] = useState<ActivityLog[]>([]);
  const [currentTableId, setCurrentTableId] = useState<string>('');
  const [newTableName, setNewTableName] = useState<string>('');
  const [spriteData, setSpriteData] = useState({
    name: 'Test Sprite',
    x: 100,
    y: 100,
    width: 50,
    height: 50,
    imageUrl: '',
    rotation: 0
  });
  const [mutationQueue, setMutationQueue] = useState<Array<{ type: 'create'|'update'|'delete'; payload: any; tempId?: string }>>([]);

  const addLog = (type: ActivityLog['type'], message: string, emoji: string) => {
    const newLog: ActivityLog = {
      id: Date.now(),
      timestamp: new Date(),
      type,
      message,
      emoji
    };
    setActivityLog(prev => [newLog, ...prev.slice(0, 49)]); // Keep last 50 entries
  };

  useEffect(() => {
    if (isConnected) {
      addLog('success', 'Connected to table sync service', '[ok]');
    } else {
      addLog('warning', 'Disconnected from table sync service', '[x]');
    }
  }, [isConnected]);

  useEffect(() => {
    if (error) {
      addLog('error', `Error: ${error}`, '[x]');
    }
  }, [error]);

  // Optimistic update helpers for table CRUD
  const optimisticCreateTable = (name: string) => {
    const tempId = `temp-table-${Date.now()}`;
    addLog('info', `Optimistically creating table: ${name}`, 'ЁЯЖХ');
    setMutationQueue(q => [...q, { type: 'create', payload: { name }, tempId }]);
  };

  const optimisticRequestTable = (tableId: string) => {
    addLog('info', `Optimistically requesting table: ${tableId}`, '[->]');
    setMutationQueue(q => [...q, { type: 'update', payload: { tableId } }]);
  };

  // Reconcile mutations with server responses
  useEffect(() => {
    if (!tableSync || mutationQueue.length === 0) return;
    const processQueue = async () => {
      for (const mutation of mutationQueue) {
        try {
          if (mutation.type === 'create') {
            await tableSync.request_new_table(mutation.payload.name);
            addLog('success', `Table created: ${mutation.payload.name}`, '[ok]');
          } else if (mutation.type === 'update') {
            await tableSync.request_table(mutation.payload.tableId);
            addLog('success', `Table requested: ${mutation.payload.tableId}`, '[ok]');
          }
        } catch (err) {
          addLog('error', `Failed to ${mutation.type} table: ${err}`, '[x]');
        }
      }
      setMutationQueue([]);
    };
    processQueue();
  }, [mutationQueue, tableSync]);

  const handleRequestTable = async () => {
    if (!tableSync || !currentTableId.trim()) {
      addLog('warning', 'Please enter a table ID', '[!]');
      return;
    }
    optimisticRequestTable(currentTableId.trim());
  };

  const handleCreateNewTable = async () => {
    if (!tableSync || !newTableName.trim()) {
      addLog('warning', 'Please enter a table name', '[!]');
      return;
    }
    optimisticCreateTable(newTableName.trim());
    setNewTableName('');
  };

  const handleAddSprite = async () => {
    if (!tableSync) {
      addLog('warning', 'Table sync not available', '[!]');
      return;
    }

    try {
      const spriteId = `sprite_${Date.now()}`;
      addLog('info', `Adding sprite: ${spriteData.name}`, '[~]');
      
      await tableSync.add_sprite(
        spriteId,
        spriteData.name,
        spriteData.x,
        spriteData.y,
        spriteData.width,
        spriteData.height,
        spriteData.imageUrl,
        spriteData.rotation
      );
      
      addLog('success', `Sprite added: ${spriteData.name} (${spriteId})`, '[ok]');
    } catch (err) {
      addLog('error', `Failed to add sprite: ${err}`, '[x]');
    }
  };

  const handleUpdateSprite = async () => {
    if (!tableSync) {
      addLog('warning', 'Table sync not available', '[!]');
      return;
    }

    try {
      const spriteId = `sprite_${Date.now() - 1000}`; // Use a recent ID for demo
      addLog('info', `Updating sprite: ${spriteData.name}`, '[e]');
      
      await tableSync.update_sprite(
        spriteId,
        spriteData.name,
        spriteData.x,
        spriteData.y,
        spriteData.width,
        spriteData.height,
        spriteData.imageUrl,
        spriteData.rotation
      );
      
      addLog('success', `Sprite updated: ${spriteData.name} (${spriteId})`, '[ok]');
    } catch (err) {
      addLog('error', `Failed to update sprite: ${err}`, '[x]');
    }
  };

  const handleRemoveSprite = async () => {
    if (!tableSync) {
      addLog('warning', 'Table sync not available', '[!]');
      return;
    }

    try {
      const spriteId = `sprite_${Date.now() - 1000}`; // Use a recent ID for demo
      addLog('info', `Removing sprite: ${spriteId}`, '[del]');
      
      await tableSync.remove_sprite(spriteId);
      addLog('success', `Sprite removed: ${spriteId}`, '[ok]');
    } catch (err) {
      addLog('error', `Failed to remove sprite: ${err}`, '[x]');
    }
  };

  const handleAddTestLine = async () => {
    if (!tableSync) {
      addLog('warning', 'Table sync not available', '[!]');
      return;
    }

    try {
      const spriteId = `line_${Date.now()}`;
      addLog('info', `Adding test line segment`, '[--]');
      
      await tableSync.add_sprite(
        spriteId,
        'Test Line',
        150,  // x
        150,  // y
        100,  // width (length)
        5,    // height (thickness)
        '',
        0
      );
      
      addLog('success', `Line segment added: ${spriteId}`, '[ok]');
    } catch (err) {
      addLog('error', `Failed to add line: ${err}`, '[x]');
    }
  };

  const handleAddTestCircle = async () => {
    if (!tableSync) {
      addLog('warning', 'Table sync not available', '[!]');
      return;
    }

    try {
      const spriteId = `circle_${Date.now()}`;
      addLog('info', `Adding test circle`, '[o]');
      
      await tableSync.add_sprite(
        spriteId,
        'Test Circle',
        200,  // x
        200,  // y
        60,   // width (diameter)
        60,   // height (diameter)
        '',
        0
      );
      
      addLog('success', `Circle added: ${spriteId}`, '[ok]');
    } catch (err) {
      addLog('error', `Failed to add circle: ${err}`, '[x]');
    }
  };

  const clearLog = () => {
    setActivityLog([]);
    addLog('info', 'Activity log cleared', '[c]');
  };

  if (isLoading) {
    return (
      <div className="panel-base">
        <div className="loading-state">
          <div className="loading-spinner">...</div>
          <p>Loading table sync...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="panel-base">
      <div className={styles.panelHeader}>
        <h3>Table Sync</h3>
        <div className={`status-indicator ${isConnected ? 'connected' : 'disconnected'}`}>
          <span>{isConnected ? '[ok]' : '[x]'}</span>
          <span>{isConnected ? 'Connected' : 'Disconnected'}</span>
        </div>
      </div>

      {error && (
        <div className="error-banner">
          <span>[x] {error}</span>
        </div>
      )}

      <div className="panel-section">
        <h4>Table Operations</h4>
        <div className="control-group">
          <div className="input-group">
            <label>Table ID</label>
            <input
              type="text"
              placeholder="Enter table ID"
              value={currentTableId}
              onChange={(e) => setCurrentTableId(e.target.value)}
              className="panel-input"
            />
          </div>
          <button 
            onClick={handleRequestTable}
            disabled={!tableSync || !isConnected}
            className="panel-button primary"
          >
            Request Table
          </button>
        </div>
        
        <div className="control-group">
          <div className="input-group">
            <label>New Table Name</label>
            <input
              type="text"
              placeholder="Enter new table name"
              value={newTableName}
              onChange={(e) => setNewTableName(e.target.value)}
              className="panel-input"
            />
          </div>
          <button 
            onClick={handleCreateNewTable}
            disabled={!tableSync || !isConnected}
            className="panel-button success"
          >
            ЁЯЖХ Create New Table
          </button>
        </div>
      </div>

      <div className="panel-section">
        <h4>Sprite Operations</h4>
        <div className="control-group">
          <div className="input-grid">
            <div className="input-group">
              <label>Name</label>
              <input
                type="text"
                placeholder="Sprite name"
                value={spriteData.name}
                onChange={(e) => setSpriteData(prev => ({ ...prev, name: e.target.value }))}
                className="panel-input"
              />
            </div>
            <div className="input-group">
              <label>Image URL</label>
              <input
                type="text"
                placeholder="Image URL (optional)"
                value={spriteData.imageUrl}
                onChange={(e) => setSpriteData(prev => ({ ...prev, imageUrl: e.target.value }))}
                className="panel-input"
              />
            </div>
          </div>
          
          <div className="input-grid">
            <div className="input-group">
              <label>X Position</label>
              <input
                type="number"
                placeholder="X"
                value={spriteData.x}
                onChange={(e) => setSpriteData(prev => ({ ...prev, x: parseInt(e.target.value) || 0 }))}
                className="panel-input"
              />
            </div>
            <div className="input-group">
              <label>Y Position</label>
              <input
                type="number"
                placeholder="Y"
                value={spriteData.y}
                onChange={(e) => setSpriteData(prev => ({ ...prev, y: parseInt(e.target.value) || 0 }))}
                className="panel-input"
              />
            </div>
          </div>
          
          <div className="input-grid three-col">
            <div className="input-group">
              <label>Width</label>
              <input
                type="number"
                placeholder="Width"
                value={spriteData.width}
                onChange={(e) => setSpriteData(prev => ({ ...prev, width: parseInt(e.target.value) || 0 }))}
                className="panel-input"
              />
            </div>
            <div className="input-group">
              <label>Height</label>
              <input
                type="number"
                placeholder="Height"
                value={spriteData.height}
                onChange={(e) => setSpriteData(prev => ({ ...prev, height: parseInt(e.target.value) || 0 }))}
                className="panel-input"
              />
            </div>
            <div className="input-group">
              <label>Rotation</label>
              <input
                type="number"
                placeholder="Degrees"
                value={spriteData.rotation}
                onChange={(e) => setSpriteData(prev => ({ ...prev, rotation: parseInt(e.target.value) || 0 }))}
                className="panel-input"
              />
            </div>
          </div>
          
          <div style={{ display: 'flex', gap: '8px', flexWrap: 'wrap' }}>
            <button 
              onClick={handleAddSprite}
              disabled={!tableSync || !isConnected}
              className="panel-button success"
            >
              + Add Sprite
            </button>
            <button 
              onClick={handleUpdateSprite}
              disabled={!tableSync || !isConnected}
              className="panel-button primary"
            >
              Update Sprite
            </button>
            <button 
              onClick={handleRemoveSprite}
              disabled={!tableSync || !isConnected}
              className="panel-button danger"
            >
              Remove Sprite
            </button>
          </div>
          
          <div style={{ marginTop: '12px', paddingTop: '12px', borderTop: '1px solid #333' }}>
            <div style={{ marginBottom: '8px', color: 'var(--text-muted)', fontSize: '12px' }}>
              Quick Test Sprites:
            </div>
            <div style={{ display: 'flex', gap: '8px', flexWrap: 'wrap' }}>
              <button 
                onClick={handleAddTestLine}
                disabled={!tableSync || !isConnected}
                className="panel-button"
                title="Add horizontal line segment (100x5)"
              >
                Line Segment
              </button>
              <button 
                onClick={handleAddTestCircle}
                disabled={!tableSync || !isConnected}
                className="panel-button"
                title="Add circle (60px diameter)"
              >
                Circle
              </button>
            </div>
          </div>
        </div>
      </div>

      <div className="panel-section">
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '12px' }}>
          <h4>Activity Log</h4>
          <button onClick={clearLog} className="panel-button">
            Clear
          </button>
        </div>
        
        <div className="activity-log">
          {activityLog.length === 0 ? (
            <div className="empty-state">
              <span>No activity yet. Try requesting a table or adding a sprite!</span>
            </div>
          ) : (
            activityLog.map((log) => (
              <div key={log.id} className={`log-entry ${log.type}`}>
                <span>{log.emoji}</span>
                <span className="log-timestamp">
                  {log.timestamp.toLocaleTimeString()}
                </span>
                <span className="log-message">{log.message}</span>
              </div>
            ))
          )}
        </div>
      </div>
    </div>
  );
}

