// Mock the hook that provides table data
// Define mock data outside vi.mock but it will be captured
const mockTableData = {
  tableManager: {} as any,
  activeTableId: 'table_1',
  tables: [
    {
      table_id: 'table_1',
      table_name: 'Main Dungeon',
