  private async handleSpriteResponse(message: Message): Promise<void> {
    // Confirm pending action - server echoes action_id back to the originating client
    // via sprite_response (broadcasts go to others without action_id)
    if (message.data?.action_id && message.data?.success) {
      window.dispatchEvent(new CustomEvent('sprite-action-confirmed', { detail: { actionId: message.data.action_id } }));
    }
    window.dispatchEvent(new CustomEvent('sprite-response', { detail: message.data }));
  }

  private async handleSpriteData(message: Message): Promise<void> {
    console.log('Protocol: Sprite data received:', message.data);
    window.dispatchEvent(new CustomEvent('sprite-data-received', { detail: message.data }));
  }

  // File transfer handlers
  private async handleFileData(message: Message): Promise<void> {
    console.log('Protocol: File data received:', message.data);
    window.dispatchEvent(new CustomEvent('file-data-received', { detail: message.data }));
  }

  // Asset management handlers
  private async handleAssetDeleteResponse(message: Message): Promise<void> {
    console.log('Protocol: Asset delete response:', message.data);
    window.dispatchEvent(new CustomEvent('asset-delete-response', { detail: message.data }));
  }

  private async handleAssetHashCheck(message: Message): Promise<void> {
    console.log('Protocol: Asset hash check:', message.data);
    window.dispatchEvent(new CustomEvent('asset-hash-check', { detail: message.data }));
  }

  // Character management handlers
  private async handleCharacterDeleteResponse(message: Message): Promise<void> {
    console.log('Protocol: Character delete response:', message.data);
    
    const success = message.data?.success;
    const characterId = String(message.data?.character_id || '');
    const error = message.data?.error;
    
    if (success && characterId) {
      console.log(`Character deletion confirmed: ${characterId}`);
      // Character already removed optimistically, just confirm
      const store = useGameStore.getState();
      // Ensure character is removed from store
      store.removeCharacter(characterId);
      showToast.success('Character deleted successfully');
    } else if (!success) {
      // Deletion failed - need to restore the character
      console.error(`Character deletion failed:`, error);
      showToast.error(`Failed to delete character: ${error || 'Unknown error'}`);
      
      // Try to restore from backup if available
      // The UI component should handle rollback via pendingOperationsRef
    }
    
    window.dispatchEvent(new CustomEvent('character-delete-response', { detail: message.data }));
  }

  // Public API methods for new message types
  requestPlayerStatus(clientId?: string): void {
    this.sendMessage(createMessage(MessageType.PLAYER_STATUS, { client_id: clientId }));
  }

  sendPlayerAction(actionType: string, actionData: Record<string, unknown>): void {
    this.sendMessage(createMessage(MessageType.PLAYER_ACTION, {
      action_type: actionType,
      action_data: actionData
    }));
  }

  setPlayerReady(): void {
    this.sendMessage(createMessage(MessageType.PLAYER_READY));
  }

  setPlayerUnready(): void {
    this.sendMessage(createMessage(MessageType.PLAYER_UNREADY));
  }

  kickPlayer(playerId: string): void {
    this.sendMessage(createMessage(MessageType.PLAYER_KICK_REQUEST, { player_id: playerId }));
  }

  banPlayer(playerId: string): void {
    this.sendMessage(createMessage(MessageType.PLAYER_BAN_REQUEST, { player_id: playerId }));
  }

  requestConnectionStatus(): void {
    this.sendMessage(createMessage(MessageType.CONNECTION_STATUS_REQUEST));
  }

  requestSpriteData(spriteId: string, tableId: string): void {
    this.sendMessage(createMessage(MessageType.SPRITE_REQUEST, {
      sprite_id: spriteId,
      table_id: tableId
    }));
  }

  sendFileData(fileId: string, chunkData: string, chunkIndex: number, totalChunks: number): void {
    this.sendMessage(createMessage(MessageType.FILE_DATA, {
      file_id: fileId,
      chunk_data: chunkData,
      chunk_index: chunkIndex,
      total_chunks: totalChunks
    }));
  }

  checkAssetHash(assetId: string, hash: string): void {
    this.sendMessage(createMessage(MessageType.ASSET_HASH_CHECK, {
      asset_id: assetId,
      hash: hash
    }));
  }

  deleteAsset(assetId: string): void {
    this.sendMessage(createMessage(MessageType.ASSET_DELETE_REQUEST, { asset_id: assetId }));
  }

  /**
   * Delete a character from the server
   * @param characterId - The ID of the character to delete
   * @param userId - Optional user ID (uses instance userId if not provided)
   */
  deleteCharacter(characterId: string, userId?: number): void {
    const effectiveUserId = userId ?? this.userId;
    if (effectiveUserId === null) {
      console.error('Cannot delete character: user ID not set');
      return;
    }

    this.sendMessage(createMessage(MessageType.CHARACTER_DELETE_REQUEST, {
      character_id: characterId,
      user_id: effectiveUserId,
      session_code: this.sessionCode
    }));
  }

  scaleTable(tableId: string, scale: number): void {
    this.sendMessage(createMessage(MessageType.TABLE_SCALE, {
      table_id: tableId,
      scale: scale
    }));
  }

  moveTable(tableId: string, xMoved: number, yMoved: number): void {
    this.sendMessage(createMessage(MessageType.TABLE_MOVE, {
      table_id: tableId,
      x_moved: xMoved,
      y_moved: yMoved
    }));
  }

  sendTestMessage(data: Record<string, unknown>): void {
    this.sendMessage(createMessage(MessageType.TEST, data));
  }
}

import type { TableInfo } from '@/store';

const UUID_REGEX = /^[0-9a-f]{8}-[0-9a-f]{4}-[4][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i;

export function isValidUUID(value: string): boolean {
  return UUID_REGEX.test(value);
}

export function validateTableId(tableId: string): void {
  if (!isValidUUID(tableId)) {
    throw new Error(`Invalid table UUID: ${tableId}`);
  }
}

export function transformServerTableToClient(serverTable: any): TableInfo {
  const uuid = serverTable.table_id || serverTable.id;
  if (!uuid || !isValidUUID(uuid)) {
    throw new Error(`Server table missing valid UUID: ${JSON.stringify(serverTable)}`);
  }
  
  const displayName = serverTable.table_name || serverTable.display_name || serverTable.name || 'Unknown Table';
  
  return {
    table_id: uuid,
    table_name: displayName,
    width: serverTable.width || 100,
    height: serverTable.height || 100
  };
}

export function transformServerTablesToClient(serverTables: any[]): TableInfo[] {
  return serverTables.map(transformServerTableToClient);
}

import { useGameStore } from '@/store';
import { assetIntegrationService, useAssetManager } from '@features/assets';
import { spriteCreationService } from '@features/canvas/services/spriteCreation.service';
import { useProtocol } from '@lib/api';
import { createMessage, MessageType } from '@lib/websocket';
import React, { useCallback, useEffect, useRef, useState } from 'react';

interface DragDropImageHandlerProps {
  children: React.ReactNode;
}

interface UploadState {
  status: 'idle' | 'requesting' | 'uploading' | 'processing' | 'completed' | 'failed';
  progress: number;
  message: string;
  fileName?: string;
}

interface PendingUpload {
  file: File;
  dropPosition: { x: number; y: number };
  assetId: string;
  fileName: string;
}

export const DragDropImageHandler: React.FC<DragDropImageHandlerProps> = ({
  children
}) => {
  const _protocolCtx = useProtocol();
  const protocol = _protocolCtx?.protocol ?? null;
  const { camera, sessionId } = useGameStore();
  const { calculateHash } = useAssetManager();
  
  const [uploadState, setUploadState] = useState<UploadState>({
    status: 'idle',
    progress: 0,
    message: ''
  });
  
  const [dragOver, setDragOver] = useState(false);
  const pendingUploadsRef = useRef<Map<string, PendingUpload>>(new Map());

  // Handle asset upload response from server
  const handleAssetUploadResponse = useCallback((event: CustomEvent) => {
    const data = event.detail;
    console.log('DragDrop: Asset upload response received:', data);
    
    if (data.success && data.asset_id) {
      // Look up pending upload by asset_id
      const pendingUpload = pendingUploadsRef.current.get(data.asset_id);
      
      if (pendingUpload) {
        if (data.upload_url) {
          // Case 1: New asset - need to upload to R2
          setUploadState({
            status: 'uploading',
            progress: 0,
            message: `Uploading ${pendingUpload.fileName}...`,
            fileName: pendingUpload.fileName
          });
          
          // Upload file to R2 and let server handle sprite creation
          uploadFileToR2(data.upload_url, pendingUpload)
            .then(() => {
              // Upload successful - server will create and broadcast sprite
              setUploadState({
                status: 'processing',
                progress: 100,
                message: `Processing ${pendingUpload.fileName}...`,
                fileName: pendingUpload.fileName
              });
              
              // Clean up pending upload
              pendingUploadsRef.current.delete(data.asset_id);
              
              // Server will broadcast sprite creation, so we wait for that
              // Reset UI after a delay
              setTimeout(() => {
                setUploadState({
                  status: 'idle',
                  progress: 0,
                  message: ''
                });
              }, 3000);
            })
            .catch(error => {
              console.error('Upload failed:', error);
              setUploadState({
                status: 'failed',
                progress: 0,
                message: `Upload failed: ${error.message}`,
                fileName: pendingUpload.fileName
              });
              pendingUploadsRef.current.delete(data.asset_id);
            });
        } else {
          // Case 2: Asset already exists - directly create sprite
          console.log('DragDrop: Asset already exists, creating sprite directly');
          
          setUploadState({
            status: 'processing',
            progress: 100,
            message: `Creating sprite from existing asset: ${pendingUpload.fileName}...`,
            fileName: pendingUpload.fileName
          });

          // No upload occurred, so don't dispatch upload completion event
          
          // Create sprite directly since asset already exists
          if (protocol) {
            const worldX = (pendingUpload.dropPosition.x - camera.x) / camera.zoom;
            const worldY = (pendingUpload.dropPosition.y - camera.y) / camera.zoom;
            
            spriteCreationService.createSprite({
              assetId: data.asset_id,
              fileName: pendingUpload.fileName,
              worldX: worldX,
              worldY: worldY,
              sessionId: sessionId || ''
            });
          }
          
          // Clean up pending upload
          pendingUploadsRef.current.delete(data.asset_id);
          
          // Reset UI after a delay
          setTimeout(() => {
            setUploadState({
              status: 'idle',
              progress: 0,
              message: ''
            });
          }, 2000);
        }
      } else {
        console.error('DragDrop: No matching upload request found for asset_id:', data.asset_id);
        setUploadState({
          status: 'failed',
          progress: 0,
          message: 'Upload request not found',
          fileName: ''
        });
      }
    } else {
      setUploadState({
        status: 'failed',
        progress: 0,
        message: `Upload failed: ${data.error || 'Unknown error'}`,
        fileName: uploadState.fileName || ''
      });
      
      // Clear all pending uploads on error
      pendingUploadsRef.current.clear();
    }
  }, [uploadState.fileName]);

  // Upload file to R2 (server-first approach - no local sprite creation)
  const uploadFileToR2 = async (
    uploadUrl: string,
    pendingUpload: PendingUpload
  ): Promise<void> => {
    const { file, assetId } = pendingUpload;
    
    // Calculate file hash for required header
    const fileBuffer = await file.arrayBuffer();
    const fileData = new Uint8Array(fileBuffer);
    const fullHash = calculateHash(fileData);
    
    if (!fullHash) {
      throw new Error('Failed to calculate file hash for upload header');
    }
    
    return new Promise((resolve, reject) => {
      const xhr = new XMLHttpRequest();
      
      xhr.upload.onprogress = (event) => {
        if (event.lengthComputable) {
          const progress = Math.round((event.loaded / event.total) * 100);
          setUploadState(prev => ({
            ...prev,
            progress,
            message: `Uploading ${file.name}... ${progress}%`
          }));
        }
      };

      xhr.onload = () => {
        console.log('Upload response status:', xhr.status);
        console.log('Upload response headers:', xhr.getAllResponseHeaders());
        
        if (xhr.status >= 200 && xhr.status < 300) {
          console.log('File uploaded successfully to R2');        
         
          // Dispatch upload completion event for AssetIntegrationService to handle
          window.dispatchEvent(new CustomEvent('asset-upload-completed', {
            detail: {
              asset_id: assetId,
              success: true,
              file_size: file.size,
              content_type: file.type
            }
          }));
          
          // Send sprite creation request to server with asset reference
          if (protocol) {
            const worldX = (pendingUpload.dropPosition.x - camera.x) / camera.zoom;
            const worldY = (pendingUpload.dropPosition.y - camera.y) / camera.zoom;
            
            spriteCreationService.createSprite({
              assetId: assetId,
              fileName: pendingUpload.fileName,
              worldX: worldX,
              worldY: worldY,
              sessionId: sessionId || 'default'
            }).catch(error => {
              console.error('DragDrop: Failed to create sprite:', error);
            });
          }
          
          resolve();
        } else {
          console.error('Upload failed with status:', xhr.status, xhr.statusText);
          reject(new Error(`Upload failed with status ${xhr.status}: ${xhr.statusText}`));
        }
      };

      xhr.onerror = () => {
        console.error('Upload network error');
        reject(new Error('Upload failed due to network error'));
      };
      
      xhr.open('PUT', uploadUrl);
      xhr.setRequestHeader('Content-Type', file.type);
      xhr.setRequestHeader('x-amz-meta-xxhash', fullHash);
      xhr.setRequestHeader('x-amz-meta-upload-timestamp', Math.floor(Date.now() / 1000).toString());
      
      console.log('Starting upload to R2:', {
        file: file.name,
        size: file.size,
        type: file.type,
        assetId: assetId
      });
      
      xhr.send(file);
    });
  };

  // Handle drag events
  const handleDragOver = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    
    const types = Array.from(e.dataTransfer.types);
    if (types.includes('Files') || types.includes('application/json')) {
      setDragOver(true);
      e.dataTransfer.dropEffect = 'copy';
    }
  }, []);

  const handleDragLeave = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    
    // Only set dragOver to false if we're leaving the container
    if (!e.currentTarget.contains(e.relatedTarget as Node)) {
      setDragOver(false);
    }
  }, []);

  const handleDrop = useCallback(async (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setDragOver(false);

    const files = Array.from(e.dataTransfer.files);
    const imageFiles = files.filter(file => file.type.startsWith('image/'));
    
    if (imageFiles.length === 0) {
      // Handle compendium entry drops
      const jsonData = e.dataTransfer.getData('application/json');
      if (jsonData) {
        try {
          const entry = JSON.parse(jsonData);
          const rect = e.currentTarget.getBoundingClientRect();
          window.dispatchEvent(new CustomEvent('compendium-drop', {
            detail: { ...entry, dropX: e.clientX - rect.left, dropY: e.clientY - rect.top }
          }));
        } catch {}
      }
      return;
    }

    if (!protocol) {
      console.error('Protocol not available for upload');
      return;
    }

    // Get drop position relative to the container
    const rect = e.currentTarget.getBoundingClientRect();
    const dropPosition = {
      x: e.clientX - rect.left,
      y: e.clientY - rect.top
    };

    // Process first image file
    const file = imageFiles[0];
    console.log(`DragDrop: Processing dropped image: ${file.name} at position:`, dropPosition);

    try {
      setUploadState({
        status: 'requesting',
        progress: 0,
        message: `Requesting upload for ${file.name}...`,
        fileName: file.name
      });

      // Calculate file hash for server verification
      const fileBuffer = await file.arrayBuffer();
      const fileData = new Uint8Array(fileBuffer);
      const assetId = calculateHash(fileData);
      
      if (!assetId) {
        throw new Error('Failed to calculate file hash');
      }

      // Store pending upload for later processing
      const pendingUpload: PendingUpload = {
        file,
        dropPosition,
        assetId,
        fileName: file.name
      };
      
      pendingUploadsRef.current.set(assetId, pendingUpload);

      // тФАтФА Local optimistic texture load тФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФА
      // We already have the image bytes locally, so tell WASM to load the
      // texture right now instead of waiting for the server download round-trip.
      // The object URL is revoked automatically after the image loads.
      const localObjectUrl = URL.createObjectURL(file);
      window.dispatchEvent(new CustomEvent('local-texture-ready', {
        detail: { asset_id: assetId, url: localObjectUrl }
      }));
      // тФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФАтФА

      // Request presigned upload URL from server
      protocol.sendMessage(createMessage(MessageType.ASSET_UPLOAD_REQUEST, {
        filename: file.name,
        file_size: file.size,
        content_type: file.type,
        xxhash: assetId,
        asset_id: assetId,
        session_code: sessionId || ''
      }, 2));
      
      // Notify WasmIntegration service that this asset upload is starting
      window.dispatchEvent(new CustomEvent('asset-upload-started', {
        detail: { asset_id: assetId }
      }));
      
      console.log('DragDrop: Requested upload URL for asset:', assetId);

    } catch (error) {
      console.error('Error handling drop:', error);
      setUploadState({
        status: 'failed',
        progress: 0,
        message: `Error: ${error instanceof Error ? error.message : 'Unknown error'}`,
        fileName: file.name
      });
    }
  }, [protocol, camera, sessionId, calculateHash]);

  // Listen for asset upload responses and sprite creation broadcasts
  useEffect(() => {
    // Initialize sprite creation service with protocol
    if (protocol) {
      spriteCreationService.setProtocol(protocol);
      assetIntegrationService.setProtocol(protocol);
    }
    
    window.addEventListener('asset-uploaded', handleAssetUploadResponse as EventListener);
    
    return () => {
      window.removeEventListener('asset-uploaded', handleAssetUploadResponse as EventListener);
    };
  }, [handleAssetUploadResponse, protocol]);

  // Prevent default browser drag-and-drop behavior
  useEffect(() => {
    const preventDefault = (e: DragEvent) => {
      e.preventDefault();
    };

    const preventDefaults = (e: DragEvent) => {
      e.preventDefault();
      e.stopPropagation();
    };

    // Prevent default drag behaviors on document
    document.addEventListener('dragenter', preventDefaults, false);
    document.addEventListener('dragover', preventDefaults, false);
    document.addEventListener('dragleave', preventDefault, false);
    document.addEventListener('drop', preventDefaults, false);

    return () => {
      document.removeEventListener('dragenter', preventDefaults, false);
      document.removeEventListener('dragover', preventDefaults, false);
      document.removeEventListener('dragleave', preventDefault, false);
      document.removeEventListener('drop', preventDefaults, false);
    };
  }, []);

  return (
    <div
      onDragOver={handleDragOver}
      onDragLeave={handleDragLeave}
      onDrop={handleDrop}
      style={{
        position: 'relative',
        width: '100%',
        height: '100%',
      }}
    >
      {children}
      
      {/* Drag overlay */}
      {dragOver && (
        <div
          style={{
            position: 'absolute',
            top: 0,
            left: 0,
            right: 0,
            bottom: 0,
            backgroundColor: 'rgba(59, 130, 246, 0.1)',
            border: '2px dashed #3b82f6',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            zIndex: 1000,
            pointerEvents: 'none',
          }}
        >
          <div
            style={{
              backgroundColor: 'rgba(0, 0, 0, 0.8)',
              color: 'white',
              padding: '20px',
              borderRadius: '8px',
              textAlign: 'center',
              fontSize: '18px',
              fontWeight: 'bold',
            }}
          >
            Drop image here to create sprite
          </div>
        </div>
      )}
      
      {/* Upload status overlay */}
      {uploadState.status !== 'idle' && (
        <div
          style={{
            position: 'absolute',
            top: '20px',
            right: '20px',
            backgroundColor: 'rgba(0, 0, 0, 0.9)',
            color: 'white',
            padding: '12px 16px',
            borderRadius: '8px',
            zIndex: 1001,
            minWidth: '200px',
          }}
        >
          <div style={{ marginBottom: '8px', fontSize: '14px' }}>
            {uploadState.message}
          </div>
          {uploadState.status === 'uploading' && (
            <div
              style={{
                width: '100%',
                height: '4px',
                backgroundColor: 'rgba(255, 255, 255, 0.2)',
                borderRadius: '2px',
                overflow: 'hidden',
              }}
            >
              <div
                style={{
                  width: `${uploadState.progress}%`,
                  height: '100%',
                  backgroundColor: '#3b82f6',
                  transition: 'width 0.2s ease',
                }}
              />
            </div>
          )}
          {uploadState.status === 'completed' && (
            <div style={{ color: '#10b981', fontSize: '12px' }}>
              Success!
            </div>
          )}
          {uploadState.status === 'failed' && (
            <div style={{ color: '#f87171', fontSize: '12px' }}>
              Failed
            </div>
          )}
        </div>
      )}
    </div>
  );
};

import { AlertTriangle, BookOpen, CloudFog, Lightbulb, LogIn, Paintbrush, RefreshCw, RotateCcw } from 'lucide-react';
import type { ErrorInfo, ReactNode } from 'react';
import React, { Component } from 'react';
import styles from './ErrorBoundary.module.css';

// Extend Window interface for error tracking
declare global {
  interface Window {
    errorTracker?: {
      captureException: (error: Error, options?: any) => void;
    };
  }
}

interface ErrorBoundaryState {
  hasError: boolean;
  error?: Error;
  errorInfo?: ErrorInfo;
  retryCount: number;
}

interface ErrorBoundaryProps {
  children: ReactNode;
  fallback?: React.ComponentType<ErrorFallbackProps> | React.ReactElement;
  onError?: (error: Error, errorInfo: ErrorInfo) => void;
  maxRetries?: number;
  componentName?: string;
}

interface ErrorFallbackProps {
  error?: Error;
  errorInfo?: ErrorInfo;
  onRetry: () => void;
  canRetry: boolean;
  componentName?: string;
}

class PanelErrorBoundary extends Component<ErrorBoundaryProps, ErrorBoundaryState> {
  constructor(props: ErrorBoundaryProps) {
    super(props);
    this.state = {
      hasError: false,
      retryCount: 0
    };
  }

  static getDerivedStateFromError(error: Error): Partial<ErrorBoundaryState> {
    return {
      hasError: true,
      error
    };
  }

  componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    console.error(`${this.props.componentName || 'Component'} error:`, error, errorInfo);
    
    // Report to error tracking service if available
    if (window.errorTracker) {
      window.errorTracker.captureException(error, {
        extra: errorInfo,
        tags: { 
          component: this.props.componentName || 'unknown',
          boundary: 'panel'
        }
      });
    }
    
    // Call custom error handler if provided
    if (this.props.onError) {
      this.props.onError(error, errorInfo);
    }
    
    this.setState({
      error,
      errorInfo
    });
  }

  handleRetry = () => {
    const maxRetries = this.props.maxRetries || 3;
    if (this.state.retryCount < maxRetries) {
      this.setState({
        hasError: false,
        error: undefined,
        errorInfo: undefined,
        retryCount: this.state.retryCount + 1
      });
    }
  };

  render() {
    if (this.state.hasError) {
      const fallback = this.props.fallback;
      const maxRetries = this.props.maxRetries || 3;
      
      // Handle both component and element types
      if (React.isValidElement(fallback)) {
        return fallback;
      }
      
      const FallbackComponent = fallback || DefaultErrorFallback;
      
      return (
        <FallbackComponent
          error={this.state.error}
          errorInfo={this.state.errorInfo}
          onRetry={this.handleRetry}
          canRetry={this.state.retryCount < maxRetries}
          componentName={this.props.componentName}
        />
      );
    }

    return this.props.children;
  }
}

