              if (this.onclose) this.onclose(new CloseEvent('close'));
            }, 5);
          } else {
            // Succeed on 3rd attempt and beyond
            this.readyState = 0; // CONNECTING
            setTimeout(() => {
              this.readyState = 1; // OPEN
              if (this.onopen) this.onopen(new Event('open'));
            }, 10);
          }
        }
        
        send() {}
        close() {}
      } as any;

