        }));
      },

      createNewTable: (name: string, width: number, height: number) => {
        // BEST PRACTICE: Create table locally first (optimistic UI)
        const newTable: TableInfo = {
          table_id: `local_${Date.now()}`, // Local ID until synced to server
          table_name: name,
          width,
          height,
